def _render_preschool_view():
    """Preschool gorunumu — dispatch blogu."""
    from views.yabanci_dil import (
        _render_grade_flipbook, _render_grade_resources, _build_vocab_html,
    )
    from views.yd_tools import (
        _build_prek_animal_parade_html, _build_prek_balloon_colors_html,
        _build_prek_bedtime_words_html, _build_prek_body_tap_html,
        _build_prek_color_hunt_html, _build_prek_dress_up_html,
        _build_prek_emoji_feelings_html, _build_prek_farm_sounds_html,
        _build_prek_fruit_splash_html, _build_prek_magic_bag_html,
        _build_prek_move_say_html, _build_prek_number_jump_html,
        _build_prek_opposites_flip_html, _build_prek_room_cleanup_html,
        _build_prek_shadow_match_html, _build_prek_shape_builder_html,
        _build_prek_sound_pop_html, _build_prek_story_peek_html,
        _build_prek_toy_store_html, _build_prek_weather_window_html,
        _get_today_plan_btn_types, _dispatch_activity_html,
    )
    # ── Gunluk Plan Paneli ──
    _render_daily_plan_panel("preschool")
    # ══════════════════════════════════════════════════════════════════
    # OKUL ÖNCESİ (5-6 Yaş) — 36 Hafta × 10 Saat = 360 Saat
    # İlkokul/Ortaokul mantığında 15 alt sekme
    # Okuma-yazma bilmiyor: %100 görsel + işitsel + kinestetik
    # ══════════════════════════════════════════════════════════════════
    _pk_info = _PRESCHOOL_CEFR_INFO
    st.markdown(
        f'<div style="background:linear-gradient(135deg,#0c4a6e10,#0369a110);'
        f'border-left:4px solid #0ea5e9;'
        f'border-radius:0 8px 8px 0;padding:12px 16px;margin-bottom:12px">'
        f'<div style="font-weight:700;color:#0ea5e9;font-size:.95rem">'
        f'\U0001F3AF Okul \u00D6ncesi \u2014 CEFR {_pk_info["level"]}</div>'
        f'<div style="font-size:.8rem;color:#999;margin-top:4px">{_pk_info["desc"]}</div>'
        f'<div style="font-size:.75rem;color:#777;margin-top:2px">\U0001F4CC Odak: {_pk_info["focus"]}</div>'
        f'<div style="font-size:.7rem;color:#38bdf8;margin-top:4px;font-weight:600;">'
        f'\U0001F4CA 36 Hafta \u00D7 10 Saat = 360 Saat | Ya\u015F: 5-6 | Okuma-Yazma Bilmiyor</div>'
        f'</div>',
        unsafe_allow_html=True,
    )

    # 36 haftalık tema kartları — gunluk plan ile ayni hafta hesabi
    _pk_tpi = _get_today_plan_info()
    _pk_current_week = _pk_tpi["week_num"]
    _pk_themes = _PRESCHOOL_36_WEEK_THEMES
    with st.expander(f"\U0001F4C5 36 Haftal\u0131k Tema Haritas\u0131 (360 Saat)", expanded=False):
        _theme_cols = st.columns(6)
        for _ti, _tw in enumerate(_pk_themes):
            with _theme_cols[_ti % 6]:
                _is_cur = _tw["week"] == _pk_current_week
                _bg = "rgba(14,165,233,.2)" if _is_cur else "rgba(255,255,255,.03)"
                _bd = "#0ea5e9" if _is_cur else "rgba(255,255,255,.1)"
                st.markdown(
                    f'<div style="background:{_bg};border:1px solid {_bd};border-radius:8px;'
                    f'padding:6px;margin-bottom:6px;text-align:center;font-size:.65rem;">'
                    f'<div style="font-weight:700;color:#38bdf8;">H{_tw["week"]}</div>'
                    f'<div style="color:#e2e8f0;font-size:.6rem;">{_tw["theme_tr"]}</div></div>',
                    unsafe_allow_html=True,
                )

    # Hafta seçici — tüm beceri sekmeleri bu haftanın temasıyla çalışır
    _pk_curriculum = _EXT_CURRICULUM_PRESCHOOL
    _pk_week_opts = {
        w["week"]: f"Hafta {w['week']}: {w.get('theme_tr', w.get('theme', ''))}"
        for w in _pk_curriculum
    }
    _pk_default_week_idx = min(_pk_current_week - 1, len(_pk_week_opts) - 1)
    _pk_col_w, _pk_col_info = st.columns([1, 2])
    with _pk_col_w:
        _pk_sel_week = st.selectbox(
            "\U0001F4C5 Hafta Se\u00E7:",
            list(_pk_week_opts.keys()),
            index=_pk_default_week_idx,
            format_func=lambda w: _pk_week_opts[w],
            key="pk_week_sel",
        )
    # Seçilen haftanın verisini bul
    _pk_week_data = None
    for _w in _pk_curriculum:
        if _w["week"] == _pk_sel_week:
            _pk_week_data = _w
            break
    if not _pk_week_data:
        _pk_week_data = _pk_curriculum[0] if _pk_curriculum else {}
    with _pk_col_info:
        _pw = _pk_week_data
        _pw_vocab_tags = " ".join(
            f'<span style="display:inline-block;padding:2px 8px;margin:2px;border-radius:6px;'
            f'font-size:.7rem;font-weight:600;background:rgba(14,165,233,.1);color:#38bdf8;'
            f'border:1px solid rgba(14,165,233,.2);">'
            f'{_PRESCHOOL_WORD_EMOJI.get(v, "\U0001F539")} {v}</span>'
            for v in _pw.get("vocab", [])
        )
        st.markdown(
            f'<div style="background:rgba(14,165,233,.05);border:1px solid rgba(14,165,233,.15);'
            f'border-radius:10px;padding:10px 14px;margin-top:8px">'
            f'<div style="font-weight:700;color:#0ea5e9;font-size:.85rem">'
            f'\U0001F3AF {_pw.get("theme", "")} \u2014 {_pw.get("theme_tr", "")}</div>'
            f'<div style="font-size:.7rem;color:#94a3b8;margin:4px 0">'
            f'Kal\u0131p: <b>{_pw.get("structure", "\u2014")}</b></div>'
            f'<div style="margin-top:4px">{_pw_vocab_tags}</div></div>',
            unsafe_allow_html=True,
        )

    # --- Preschool Kazanim Expander ---
    _render_preschool_outcomes_expander(_pk_sel_week)
    # --- Preschool Etkileşimli Ders Planı ---
    _render_interactive_lesson_plan_expander("preschool")

    # 15 alt sekme — selectbox ile lazy rendering (GPU crash fix)
    _pk_tab_labels = [
        "\U0001F3A7 Dinleme",                    # 0
        "\U0001F5E3\uFE0F Konu\u015Fma",         # 1
        "\U0001F4D6 Hikaye Dinle",                # 2
        "\U0001F3A8 \u00C7iz & Boya",             # 3
        "\U0001F9E9 Kal\u0131plar",               # 4
        "\U0001F4DA Kelimeler",                    # 5
        "\U0001F524 Sesler",                       # 6
        "\U0001F9E9 E\u015Fle\u015Ftir",          # 7
        "\U0001F4AC G\u00FCnl\u00FCk \u0130fadeler",  # 8
        "\U0001F938 TPR & Hareket",                # 9
        "\U0001F5FA\uFE0F \u00D6\u011Frenme Yolu", # 10
        "\U0001F31F KDG",                          # 11
        "\U0001F4D6 Hikaye Kitaplar\u0131",        # 12
        "\U0001F310 Kaynaklar",                    # 13
        "\U0001F3AE \u0130nteraktif \u00C7al\u0131\u015Fmalar",  # 14
        "\U0001F4D5 Coursebook",                   # 15
        "\U0001F388 Play & Learn",                 # 16
        "\U0001F50A Sounds Ready",                 # 17
        "\U0001F3B5 Sing, Move & Smile",           # 18
        "\U0001F3AF Etkinlik Kitabi",              # 19
        "\U0001F4CB Ders Plani",                   # 20
    ]
    _pk_sel = st.selectbox(
        "\U0001F3AF B\u00F6l\u00FCm Se\u00E7:",
        range(len(_pk_tab_labels)),
        format_func=lambda i: _pk_tab_labels[i],
        key="pk_section_sel",
    )

    # Bugünün planındaki btn_type'ları al (preschool)
    _pk_btns, _pk_plan_wdata, _pk_plan_day = _get_today_plan_btn_types("preschool")
    _PK_BTN_TO_TAB = {
        "listening": 0, "speaking": 1, "dialog": 1,
        "cb_story": 2, "writing": 3,
        "grammar": 4, "flashcard": 5, "game_flashcard": 5,
        "phonics": 6, "spelling": 6, "pron_word": 6, "pron_phrase": 6,
        "game_memory": 7, "functional": 8,
        "strategies": 9,
    }

    def _pk_render_plan_expander(tab_idx):
        """Preschool sekmesinde bugünün planından ilgili etkinliği expander ile gösterir."""
        _pk_matching_b = [b for b, t in _PK_BTN_TO_TAB.items() if t == tab_idx and b in _pk_btns]
        if not _pk_matching_b or not _pk_plan_wdata:
            return
        from datetime import datetime as _dt_pk
        _day_tr = {"mon": "Pazartesi", "tue": "Sal\u0131", "wed": "\u00C7ar\u015Famba",
                   "thu": "Per\u015Fembe", "fri": "Cuma"}
        _dow = min(_dt_pk.now().weekday(), 4)
        _today_lbl = _day_tr.get(["mon","tue","wed","thu","fri"][_dow], "")
        _theme = _pk_plan_wdata.get("theme_tr", _pk_plan_wdata.get("theme", ""))
        _bl = {"listening": "\U0001F3A7 Dinleme", "speaking": "\U0001F5E3\uFE0F Konu\u015Fma",
               "dialog": "\U0001F4AC Diyalog", "cb_story": "\U0001F4DA Hikaye",
               "writing": "\u270F\uFE0F Yazma", "grammar": "\U0001F9E9 Kal\u0131plar",
               "flashcard": "\U0001F4DA Kelimeler", "game_flashcard": "\U0001F3AE Kelime Oyunu",
               "phonics": "\U0001F524 Sesler", "spelling": "\u270F\uFE0F Heceleme",
               "pron_word": "\U0001F3A4 Telaffuz", "pron_phrase": "\U0001F4AC C\u00FCmle",
               "game_memory": "\U0001F9E9 Haf\u0131za", "functional": "\U0001F4AC G\u00FCnl\u00FCk \u0130fadeler",
               "strategies": "\U0001F91D Stratejiler"}
        for btn in _pk_matching_b:
            lbl = _bl.get(btn, btn.title())
            with st.expander(f"\U0001F4CB Bug\u00FCn\u00FCn Plan\u0131: {lbl} \u2014 {_theme} ({_today_lbl})", expanded=False):
                html = _dispatch_activity_html(btn, _pk_plan_wdata, "preschool")
                if html:
                    st.components.v1.html(html, height=650, scrolling=True)
                else:
                    st.info("Bu etkinlik i\u00E7in i\u00E7erik haz\u0131rlanamad\u0131.")

    # 0: Dinleme — Ses duyma + resim eşleştirme (hafta temasına göre)
    if _pk_sel == 0:
        _pk_render_plan_expander(0)
        st.components.v1.html(_build_preschool_listening_html(_pk_week_data), height=750, scrolling=True)
        _eng_render_completion_button("ps", "pk_listening", _pk_sel_week, f"Dinleme H{_pk_sel_week}")

    # 1: Konuşma — Tekrar Et
    elif _pk_sel == 1:
        _pk_render_plan_expander(1)
        st.components.v1.html(_build_preschool_speaking_html(_pk_week_data), height=750, scrolling=True)
        _eng_render_completion_button("ps", "pk_speaking", _pk_sel_week, f"Konu\u015Fma H{_pk_sel_week}")

    # 2: Hikaye Dinle
    elif _pk_sel == 2:
        _pk_render_plan_expander(2)
        st.components.v1.html(_build_preschool_story_listen_html(_pk_week_data), height=750, scrolling=True)
        _eng_render_completion_button("ps", "pk_story", _pk_sel_week, f"Hikaye H{_pk_sel_week}")

    # 3: Çiz & Boya
    elif _pk_sel == 3:
        _pk_render_plan_expander(3)
        st.components.v1.html(_build_preschool_draw_color_html(_pk_week_data), height=750, scrolling=True)
        _eng_render_completion_button("ps", "pk_draw", _pk_sel_week, f"\u00C7iz & Boya H{_pk_sel_week}")

    # 4: Kalıplar
    elif _pk_sel == 4:
        _pk_render_plan_expander(4)
        st.components.v1.html(_build_preschool_patterns_html(_pk_week_data), height=750, scrolling=True)
        _eng_render_completion_button("ps", "pk_patterns", _pk_sel_week, f"Kal\u0131plar H{_pk_sel_week}")

    # 5: Kelimeler — Resimli Kartlar
    elif _pk_sel == 5:
        _pk_render_plan_expander(5)
        st.components.v1.html(_build_preschool_vocabulary_html(_pk_week_data), height=750, scrolling=True)
        _eng_render_completion_button("ps", "pk_vocab", _pk_sel_week, f"Kelimeler H{_pk_sel_week}")

    # 6: Sesler — ABC Phonics
    elif _pk_sel == 6:
        _pk_render_plan_expander(6)
        st.components.v1.html(_build_preschool_phonics_html(_pk_week_data), height=750, scrolling=True)
        _eng_render_completion_button("ps", "pk_phonics", _pk_sel_week, f"Sesler H{_pk_sel_week}")

    # 7: Eşleştir — Hafıza Oyunu
    elif _pk_sel == 7:
        _pk_render_plan_expander(7)
        st.components.v1.html(_build_preschool_matching_html(_pk_week_data), height=750, scrolling=True)
        _eng_render_completion_button("ps", "pk_matching", _pk_sel_week, f"E\u015Fle\u015Ftir H{_pk_sel_week}")

    # 8: Günlük İfadeler
    elif _pk_sel == 8:
        _pk_render_plan_expander(8)
        st.components.v1.html(_build_preschool_daily_expressions_html(_pk_week_data), height=750, scrolling=True)
        _eng_render_completion_button("ps", "pk_daily", _pk_sel_week, f"G\u00FCnl\u00FCk H{_pk_sel_week}")

    # 9: TPR & Hareket
    elif _pk_sel == 9:
        _pk_render_plan_expander(9)
        st.components.v1.html(_build_preschool_tpr_html(_pk_week_data), height=750, scrolling=True)
        _eng_render_completion_button("ps", "pk_tpr", _pk_sel_week, f"TPR H{_pk_sel_week}")

    # 10: Öğrenme Yolu — İlerleme Takibi
    elif _pk_sel == 10:
        _pk_skill_names = ["pk_listening", "pk_speaking", "pk_story", "pk_draw",
                           "pk_patterns", "pk_vocab", "pk_phonics", "pk_matching",
                           "pk_daily", "pk_tpr"]
        _pk_skill_labels = ["\U0001F3A7 Dinleme", "\U0001F5E3 Konu\u015Fma", "\U0001F4D6 Hikaye",
                            "\U0001F3A8 \u00C7iz & Boya", "\U0001F9E9 Kal\u0131plar", "\U0001F4DA Kelimeler",
                            "\U0001F524 Sesler", "\U0001F9E9 E\u015Fle\u015Ftir",
                            "\U0001F4AC G\u00FCnl\u00FCk", "\U0001F938 TPR"]
        _pk_store = _get_eng_store()
        _pk_sid = _get_eng_student_id()
        _pk_comps_html = ""
        _pk_done_count = 0
        for _si, _sn in enumerate(_pk_skill_names):
            _is_done = False
            if _pk_sid != "anonymous":
                _sc = _pk_store.get_student_completions(_pk_sid, level="ps")
                _is_done = any(c["exercise_id"] == _sn for c in _sc)
            if _is_done:
                _pk_done_count += 1
            _icon = "\u2705" if _is_done else "\u2B1C"
            _pk_comps_html += (
                f'<div style="display:flex;align-items:center;gap:8px;padding:8px 12px;'
                f'background:rgba(255,255,255,.03);border-radius:8px;margin:4px 0;'
                f'border-left:3px solid {"#22c55e" if _is_done else "#475569"}">'
                f'<span style="font-size:16px">{_icon}</span>'
                f'<span style="color:{"#22c55e" if _is_done else "#94a3b8"};font-weight:600;font-size:.85rem">'
                f'{_pk_skill_labels[_si]}</span></div>'
            )
        _pk_pct = int((_pk_done_count / len(_pk_skill_names)) * 100)
        st.markdown(
            f'<div style="background:rgba(255,255,255,.05);border-radius:16px;padding:20px;'
            f'border:1px solid rgba(14,165,233,.15)">'
            f'<div style="text-align:center;margin-bottom:16px">'
            f'<div style="font-size:2rem">\U0001F5FA\uFE0F</div>'
            f'<div style="font-size:1.1rem;font-weight:700;color:#38bdf8">Okul \u00D6ncesi \u00D6\u011Frenme Yolu</div>'
            f'<div style="font-size:.8rem;color:#94a3b8;margin-top:4px">'
            f'36 Hafta \u00D7 10 Saat = 360 Saat | {_pk_done_count}/{len(_pk_skill_names)} Beceri Tamamland\u0131</div>'
            f'<div style="background:#94A3B8;border-radius:10px;height:12px;margin:12px auto;max-width:400px;overflow:hidden">'
            f'<div style="background:linear-gradient(90deg,#0369a1,#0ea5e9);height:100%;width:{_pk_pct}%;'
            f'border-radius:10px;transition:width .5s"></div></div>'
            f'<div style="color:#38bdf8;font-size:.8rem;font-weight:600">{_pk_pct}% Tamamland\u0131</div>'
            f'</div>{_pk_comps_html}</div>',
            unsafe_allow_html=True,
        )

    # 11: KDG
    elif _pk_sel == 11:
        auth = st.session_state.get("auth_user", {})
        username = auth.get("username", "misafir")
        from views.kdg_engine import build_ortaokul_html
        html = build_ortaokul_html(username, "0", "Pre-A1")
        st.components.v1.html(html, height=750, scrolling=True)

    # 12: Hikaye Kitapları (Flipbook)
    elif _pk_sel == 12:
        _render_grade_flipbook("preschool")

    # 13: Kaynaklar
    elif _pk_sel == 13:
        _render_grade_resources("preschool")

    # 14: İnteraktif Çalışmalar — Tüm oyunlar + etkinlikler burada
    elif _pk_sel == 14:
        _prek_fun_game_names = [
            "\U0001F50A Sound Pop", "\U0001F534 Color Hunt", "\U0001F43E Animal Parade",
            "\U0001F45C Magic Bag", "\U0001F536 Shape Builder", "\U0001F60A Emoji Feelings",
            "\U0001F697 Toy Store", "\U0001F9B4 Body Tap", "\U0001F34E Fruit Splash",
            "\u26C5 Weather Window", "\U0001F522 Number Jump", "\U0001F9F9 Room Clean-up",
            "\U0001F455 Dress-up", "\U0001F404 Farm Sounds", "\U0001F4D6 Story Peek",
            "\U0001F500 Opposites Flip", "\U0001F388 Balloon Colors", "\U0001F5DD Shadow Match",
            "\U0001F3C3 Move & Say", "\U0001F319 Bedtime Words",
        ]
        _prek_fun_game_builders = [
            _build_prek_sound_pop_html, _build_prek_color_hunt_html, _build_prek_animal_parade_html,
            _build_prek_magic_bag_html, _build_prek_shape_builder_html, _build_prek_emoji_feelings_html,
            _build_prek_toy_store_html, _build_prek_body_tap_html, _build_prek_fruit_splash_html,
            _build_prek_weather_window_html, _build_prek_number_jump_html, _build_prek_room_cleanup_html,
            _build_prek_dress_up_html, _build_prek_farm_sounds_html, _build_prek_story_peek_html,
            _build_prek_opposites_flip_html, _build_prek_balloon_colors_html, _build_prek_shadow_match_html,
            _build_prek_move_say_html, _build_prek_bedtime_words_html,
        ]
        _render_preschool_english(key_prefix="ps", etkinlik_level="preschool",
                                     curriculum_level="preschool", writing_level=None,
                                     phonics_level=None, listening_level=None,
                                     extra_game_names=_prek_fun_game_names,
                                     extra_game_builders=_prek_fun_game_builders)
        from views.yd_tools import _render_eba_games
        _render_eba_games("preschool")

    elif _pk_sel == 15:
        from views.yd_tools import _render_coursebook_section
