# Yardımcı: kelime listesinden emoji-word çiftleri üret
def _pk_vocab_to_items(vocab_list):
    """Kelime listesinden [(emoji, word), ...] çiftleri üretir."""
    items = []
    for w in vocab_list:
        e = _PRESCHOOL_WORD_EMOJI.get(w, _PRESCHOOL_WORD_EMOJI.get(w.lower(), "🔹"))
        items.append((e, w))
    return items

# Yardımcı: distraktör emojileri üret
def _pk_distractors(correct_emoji, n=3):
    """Doğru emojiden farklı n tane distraktör emoji seç."""
    all_emojis = list(set(_PRESCHOOL_WORD_EMOJI.values()))
    pool = [e for e in all_emojis if e != correct_emoji]
    return random.sample(pool, min(n, len(pool)))


def _build_preschool_listening_html(week_data=None):
    """Okul Öncesi Dinleme — Hafta temasına göre dinamik ses-resim eşleştirme."""
    import json, random
    if week_data:
        vocab = week_data.get("vocab", [])
        theme_tr = week_data.get("theme_tr", "")
        week_num = week_data.get("week", 1)
    else:
        vocab = ["cat","dog","apple","sun","fish","ball","milk","bird","red","happy","car","star"]
        theme_tr = "Genel"
        week_num = 0
    vocab_items = _pk_vocab_to_items(vocab)
    items = []
    for e, w in vocab_items:
        distractors = _pk_distractors(e, 3)
        opts = [e] + distractors
        random.shuffle(opts)
        items.append({"word": w, "emoji": e, "options": opts, "audio": w})
    data_json = json.dumps(items, ensure_ascii=False)
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'>"
        "<style>"
        "*{margin:0;padding:0;box-sizing:border-box}"
        "body{background:linear-gradient(135deg,#1a0533,#0d0221);font-family:'Segoe UI',system-ui,sans-serif;"
        "min-height:100vh;display:flex;justify-content:center;color:#e2e8f0}"
        ".w{width:100%;max-width:800px;padding:20px}"
        ".hdr{text-align:center;padding:16px 0;border-bottom:2px solid rgba(245,158,11,.3)}"
        ".hdr h2{font-size:22px;color:#fbbf24;font-weight:800}"
        ".hdr p{color:#94a3b8;font-size:13px;margin-top:4px}"
        ".score{text-align:center;padding:8px;margin:12px 0;font-size:16px;font-weight:700;"
        "color:#fbbf24;background:rgba(245,158,11,.1);border-radius:12px;border:1px solid rgba(245,158,11,.2)}"
        ".qcard{background:rgba(255,255,255,.05);border-radius:16px;padding:24px;margin:16px 0;"
        "border:1px solid rgba(245,158,11,.15);text-align:center}"
        ".listen-btn{background:linear-gradient(135deg,#f59e0b,#d97706);color:#fff;border:none;"
        "padding:14px 32px;border-radius:50px;font-size:18px;font-weight:700;cursor:pointer;"
        "box-shadow:0 4px 15px rgba(245,158,11,.3);transition:all .2s}"
        ".listen-btn:hover{transform:scale(1.05);box-shadow:0 6px 20px rgba(245,158,11,.5)}"
        ".opts{display:grid;grid-template-columns:repeat(2,1fr);gap:12px;margin-top:20px}"
        ".opt{font-size:48px;padding:20px;background:rgba(255,255,255,.05);border:3px solid rgba(255,255,255,.1);"
        "border-radius:16px;cursor:pointer;transition:all .2s;text-align:center}"
        ".opt:hover{background:rgba(245,158,11,.1);border-color:#f59e0b;transform:scale(1.05)}"
        ".opt.correct{background:rgba(34,197,94,.2);border-color:#22c55e;animation:pop .3s}"
        ".opt.wrong{background:rgba(239,68,68,.2);border-color:#ef4444;animation:shake .3s}"
        ".next-btn{background:linear-gradient(135deg,#22c55e,#16a34a);color:#fff;border:none;"
        "padding:10px 24px;border-radius:25px;font-size:14px;cursor:pointer;margin-top:12px}"
        "@keyframes pop{0%{transform:scale(1)}50%{transform:scale(1.1)}100%{transform:scale(1)}}"
        "@keyframes shake{0%,100%{transform:translateX(0)}25%{transform:translateX(-5px)}75%{transform:translateX(5px)}}"
        ".done{text-align:center;padding:40px}.done h2{color:#fbbf24;font-size:28px}"
        ".done .big{font-size:64px;margin:16px 0}"
        "</style></head><body><div class='w'>"
        f"<div class='hdr'><h2>🎧 Dinleme — Duy ve Eşleştir</h2>"
        f"<p>Hafta {week_num}: {theme_tr} — Sesi dinle, doğru resmi seç!</p></div>"
        "<div class='score' id='sc'>⭐ 0 / 0</div>"
        "<div id='area'></div></div>"
        "<script>"
        f"var D={data_json},ci=0,score=0;"
        "function speak(w){if(!window._uc){if(!window._ucL){window._ucL=1;document.addEventListener('click',function(){window._uc=1});document.addEventListener('touchstart',function(){window._uc=1})}return;}try{var u=new SpeechSynthesisUtterance(w);u.lang='en-US';u.rate=0.7;"
        "u.pitch=1.1;speechSynthesis.cancel();speechSynthesis.speak(u)}catch(e){}}"
        "function shuffle(a){for(var i=a.length-1;i>0;i--){var j=Math.floor(Math.random()*(i+1));"
        "[a[i],a[j]]=[a[j],a[i]]}return a}"
        "function render(){var a=document.getElementById('area');"
        "if(ci>=D.length){a.innerHTML='<div class=\"done\"><div class=\"big\">🏆</div>"
        "<h2>Harika! '+score+'/'+D.length+' Doğru!</h2>"
        "<p style=\"color:#94a3b8;margin-top:8px\">Tüm sesleri dinledin ve eşleştirdin!</p></div>';return}"
        "var d=D[ci],opts=shuffle([...d.options]);"
        "var h='<div class=\"qcard\"><div style=\"font-size:14px;color:#94a3b8;margin-bottom:8px\">"
        "Soru '+(ci+1)+'/'+D.length+'</div>"
        "<button class=\"listen-btn\" onclick=\"speak(\\''+d.audio+'\\')\">🔊 Dinle</button>"
        "<div class=\"opts\">';"
        "for(var i=0;i<opts.length;i++){h+='<div class=\"opt\" data-e=\"'+opts[i]+'\" "
        "onclick=\"check(this,\\''+d.emoji+'\\')\">'+opts[i]+'</div>'}"
        "h+='</div></div>';a.innerHTML=h;setTimeout(function(){speak(d.audio)},300)}"
        "function check(el,correct){if(el.parentNode.querySelector('.correct,.wrong'))return;"
        "if(el.dataset.e===correct){el.classList.add('correct');score++;speak('yes');"
        "setTimeout(function(){ci++;document.getElementById('sc').textContent='⭐ '+score+' / '+(ci);"
        "render()},800)}else{el.classList.add('wrong');speak('try again');"
        "setTimeout(function(){el.classList.remove('wrong')},500)}}"
        "render();</script></body></html>"
    )


def _build_preschool_speaking_html(week_data=None):
    """Okul Öncesi Konuşma — Hafta temasına göre dinamik Tekrar Et."""
