        # Kelimelerden konuşma kartları üret
        phrases = []
        for w in vocab:
            e = _PRESCHOOL_WORD_EMOJI.get(w, "🔹")
            phrases.append({"phrase": w.capitalize() + "!", "emoji": e, "tr": w})
