            {"e": "👋", "en": "Goodbye!", "tr": "Hosca kal!"},
            {"e": "🙏", "en": "Thank you!", "tr": "Tesekkurler!"},
            {"e": "🤲", "en": "Please!", "tr": "Lutfen!"},
