        "<!DOCTYPE html><html><head><meta charset='utf-8'>"
        "<style>"
        "*{margin:0;padding:0;box-sizing:border-box}"
        "body{background:linear-gradient(135deg,#1a0533,#0d0221);font-family:'Segoe UI',system-ui,sans-serif;"
        "min-height:100vh;display:flex;justify-content:center;color:#e2e8f0}"
        ".w{width:100%;max-width:800px;padding:20px}"
        ".hdr{text-align:center;padding:16px 0;border-bottom:2px solid rgba(251,146,60,.3)}"
        ".hdr h2{font-size:22px;color:#fb923c;font-weight:800}"
        ".groups{display:flex;flex-wrap:wrap;gap:8px;justify-content:center;margin:12px 0}"
        ".gbtn{padding:8px 14px;border-radius:20px;background:rgba(255,255,255,.05);"
        "border:1px solid rgba(251,146,60,.2);color:#fb923c;cursor:pointer;font-size:13px;font-weight:600}"
        ".gbtn:hover,.gbtn.sel{background:rgba(251,146,60,.15);border-color:#fb923c}"
        ".cards{display:grid;grid-template-columns:repeat(2,1fr);gap:10px;margin:16px 0}"
        ".icard{background:rgba(255,255,255,.05);border-radius:14px;padding:16px;text-align:center;"
        "cursor:pointer;border:2px solid rgba(255,255,255,.1);transition:all .3s}"
        ".icard:hover{border-color:#fb923c;background:rgba(251,146,60,.1);transform:scale(1.03)}"
