        "background:linear-gradient(180deg,rgba(124,58,237,0.25),transparent);"
        "border-bottom:1px solid rgba(168,85,247,0.2);}"
        ".ps-header-emoji{font-size:40px;display:block;margin-bottom:2px;}"
        ".ps-header-text{font-size:20px;font-weight:800;color:#e9d5ff;"
        "text-shadow:0 0 20px rgba(168,85,247,0.6);letter-spacing:1.5px;}"
        ".ps-progress{display:flex;justify-content:center;gap:6px;margin:10px 0 6px;}"
        ".ps-dot{width:16px;height:16px;border-radius:50%;"
        "background:rgba(168,85,247,0.25);border:2px solid rgba(168,85,247,0.4);"
        "transition:all 0.5s cubic-bezier(0.34,1.56,0.64,1);}"
        ".ps-dot.done{background:linear-gradient(135deg,#34d399,#10b981);"
        "border-color:#6ee7b7;box-shadow:0 0 10px rgba(52,211,153,0.6);transform:scale(1.1);}"
        ".ps-dot.current{background:linear-gradient(135deg,#fbbf24,#f59e0b);"
        "border-color:#fcd34d;box-shadow:0 0 14px rgba(251,191,36,0.7);"
        "transform:scale(1.4);animation:dotPulse 1.5s ease-in-out infinite;}"
        "@keyframes dotPulse{0%,100%{box-shadow:0 0 14px rgba(251,191,36,0.7)}"
