def _ps_memory_template():
    """Hafiza Kartlari oyunu — 4x3 grid, 6 cift kart eslestirme."""
    all_w = _ps_all_words()
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'>"
        "<style>"
        "*{margin:0;padding:0;box-sizing:border-box;}"
        "html,body{height:100%;overflow:hidden;}"
        "body{background:linear-gradient(135deg,#1a0533 0%,#0d0221 50%,#150530 100%);"
        "font-family:'Segoe UI Emoji','Apple Color Emoji','Noto Color Emoji','Segoe UI',system-ui,sans-serif;display:flex;flex-direction:column;"
        "align-items:center;}"
        ".ps-wrap{width:100%;max-width:820px;height:100vh;position:relative;overflow:hidden;"
        "background:linear-gradient(180deg,rgba(30,10,60,0.95),rgba(10,5,30,0.98));"
        "border-left:2px solid rgba(168,85,247,0.3);border-right:2px solid rgba(168,85,247,0.3);}"
        "#pCanvas{position:absolute;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:0;}"
        ".ps-header{text-align:center;padding:14px 0 8px;position:relative;z-index:1;"
        "background:linear-gradient(180deg,rgba(124,58,237,0.25),transparent);"
        "border-bottom:1px solid rgba(168,85,247,0.2);}"
        ".ps-header-emoji{font-size:36px;display:block;margin-bottom:2px;"
        "filter:drop-shadow(0 0 12px rgba(168,85,247,0.7));}"
        ".ps-header-title{font-size:22px;font-weight:800;color:#e9d5ff;"
        "text-shadow:0 0 20px rgba(168,85,247,0.5);}"
        ".ps-score{position:relative;z-index:1;text-align:center;padding:6px;"
        "display:flex;justify-content:center;gap:30px;}"
        ".ps-score span{color:#c4b5fd;font-size:15px;font-weight:600;"
        "background:rgba(124,58,237,0.15);padding:4px 14px;border-radius:20px;"
        "border:1px solid rgba(168,85,247,0.25);}"
        ".mem-grid{position:relative;z-index:1;display:grid;grid-template-columns:repeat(4,1fr);"
        "gap:10px;padding:10px 20px;max-width:480px;margin:8px auto;}"
        ".mem-card{aspect-ratio:1;border-radius:16px;cursor:pointer;"
        "background:linear-gradient(145deg,rgba(124,58,237,0.4),rgba(88,28,135,0.6));"
        "border:2px solid rgba(168,85,247,0.3);display:flex;align-items:center;"
        "justify-content:center;font-size:42px;transition:all 0.3s;"
        "box-shadow:0 4px 15px rgba(88,28,135,0.4);user-select:none;"
        "backdrop-filter:blur(10px);}"
        ".mem-card:hover{transform:scale(1.05);border-color:rgba(168,85,247,0.6);"
        "box-shadow:0 6px 25px rgba(124,58,237,0.5);}"
        ".mem-card.flipped{background:linear-gradient(145deg,rgba(30,10,60,0.9),rgba(20,5,40,0.95));"
        "border-color:rgba(168,85,247,0.5);}"
        ".mem-card.matched{background:linear-gradient(145deg,rgba(34,197,94,0.3),rgba(22,163,74,0.4));"
        "border-color:rgba(34,197,94,0.5);box-shadow:0 0 20px rgba(34,197,94,0.3);}"
        ".mem-card .card-back{font-size:28px;color:rgba(168,85,247,0.5);}"
        "@keyframes cardBounce{0%{transform:scale(1)}50%{transform:scale(1.15)}100%{transform:scale(1)}}"
        ".mem-card.bounce{animation:cardBounce 0.4s ease;}"
        ".ps-end{position:absolute;top:0;left:0;width:100%;height:100%;z-index:10;"
        "display:flex;flex-direction:column;align-items:center;justify-content:center;"
        "background:rgba(10,2,33,0.95);backdrop-filter:blur(20px);}"
        ".ps-end h2{font-size:36px;color:#e9d5ff;margin:10px 0;"
        "text-shadow:0 0 30px rgba(168,85,247,0.6);}"
        ".ps-end p{color:#c4b5fd;font-size:18px;margin:5px 0;}"
        ".ps-replay-btn{margin-top:20px;padding:14px 40px;font-size:18px;font-weight:700;"
        "color:#fff;background:linear-gradient(135deg,#7c3aed,#a855f7);"
        "border:none;border-radius:30px;cursor:pointer;"
        "box-shadow:0 4px 20px rgba(124,58,237,0.5);}"
        ".ps-replay-btn:hover{transform:scale(1.05);box-shadow:0 6px 30px rgba(168,85,247,0.6);}"
        "</style></head><body><div class='ps-wrap'>"
        "<canvas id='pCanvas'></canvas>"
        "<div class='ps-header'>"
        "<span class='ps-header-emoji' id='hdrE'></span>"
        "<span class='ps-header-title'>Memory Match</span></div>"
        "<div class='ps-score'>"
        "<span id='sMoves'>Moves: 0</span>"
        "<span id='sPairs'>Pairs: 0/6</span>"
        "<span id='sTime'>Time: 0s</span></div>"
        "<div class='mem-grid' id='grid'></div>"
        "<div id='psArea'></div>"
        "</div><script>"
        "try{window.speechSynthesis.cancel()}catch(e){}"
        # --- particles ---
        "var cv=document.getElementById('pCanvas'),cx=cv.getContext('2d');"
        "function szCv(){cv.width=cv.parentElement.offsetWidth;cv.height=cv.parentElement.offsetHeight;}"
        "szCv();window.addEventListener('resize',szCv);"
        "var dots=[];for(var i=0;i<40;i++)dots.push({x:Math.random()*cv.width,"
        "y:Math.random()*cv.height,r:Math.random()*2+1,dx:(Math.random()-0.5)*0.5,"
        "dy:(Math.random()-0.5)*0.5,a:Math.random()*0.3+0.1});"
        "function drawP(){cx.clearRect(0,0,cv.width,cv.height);"
        "dots.forEach(function(d){cx.beginPath();cx.arc(d.x,d.y,d.r,0,Math.PI*2);"
        "cx.fillStyle='rgba(168,85,247,'+d.a+')';cx.fill();"
        "d.x+=d.dx;d.y+=d.dy;"
        "if(d.x<0||d.x>cv.width)d.dx*=-1;"
        "if(d.y<0||d.y>cv.height)d.dy*=-1;});"
        "requestAnimationFrame(drawP);}drawP();"
        # --- sound ---
        "var _aC=null;function _getAC(){if(!_aC)try{_aC=new(window.AudioContext||window.webkitAudioContext)();}catch(e){}return _aC;}"
        "function playNote(f,d,t){var c=_getAC();if(!c)return;var o=c.createOscillator(),g=c.createGain();"
        "o.connect(g);g.connect(c.destination);o.frequency.value=f;o.type='sine';"
        "g.gain.setValueAtTime(0.15,c.currentTime+t);g.gain.exponentialRampToValueAtTime(0.01,c.currentTime+t+d);"
        "o.start(c.currentTime+t);o.stop(c.currentTime+t+d);}"
        "function melodyCorrect(){playNote(523,0.12,0);playNote(659,0.12,0.1);playNote(784,0.12,0.2);playNote(1047,0.2,0.3);}"
        "function melodyFinish(){playNote(523,0.15,0);playNote(659,0.15,0.15);playNote(784,0.15,0.3);playNote(1047,0.15,0.45);playNote(1319,0.3,0.6);}"
        "var _bV=null;function fBV(){if(_bV)return _bV;var vs=speechSynthesis.getVoices();"
        "var pr=['Google UK English Female','Google US English','Microsoft Zira','Microsoft Jenny','Samantha','Karen','Daniel','Moira'];"
        "for(var p=0;p<pr.length;p++){for(var i=0;i<vs.length;i++){if(vs[i].name.indexOf(pr[p])>=0&&vs[i].lang.indexOf('en')===0){_bV=vs[i];return _bV}}}"
        "for(var i=0;i<vs.length;i++){if(vs[i].lang.indexOf('en')===0){_bV=vs[i];return _bV}}return null}"
        "function speak(w){if(!window._uc){if(!window._ucL){window._ucL=1;document.addEventListener('click',function(){window._uc=1});document.addEventListener('touchstart',function(){window._uc=1})}return;}try{var u=new SpeechSynthesisUtterance(w);u.lang='en-US';u.rate=0.7;u.pitch=1.15;u.volume=1.0;"
        "var bv=fBV();if(bv)u.voice=bv;"
        "speechSynthesis.speak(u);}catch(e){}}"
        # --- header emoji ---
        "document.getElementById('hdrE').textContent=String.fromCodePoint(0x1F9E0);"
        # --- game logic ---
        "var ALL=" + all_w + ";"
        "var _TW='https://cdn.jsdelivr.net/gh/twitter/twemoji@14.0.2/assets/svg/';"
        "var ITEMS=ALL.map(function(r){"
        "var cp=r[0];var e=String.fromCodePoint(cp);"
        "if(cp<0x10000)e+='\\uFE0F';"
        "return{e:e,w:r[1],cp:cp,img:_TW+cp.toString(16)+'.svg'};});"
        "function imgFB(el){"
        "el.onerror=null;el.style.display='none';"
        "el.parentElement.insertAdjacentText('beforeend',String.fromCodePoint(parseInt(el.dataset.cp)));}"
        "function eImg(it,sz){"
        "return '<img src=\"'+it.img+'\" data-cp=\"'+it.cp+'\" style=\"width:'+sz+'px;height:'+sz+'px\" onerror=\"imgFB(this)\">';}"
        "var cards=[],flipped=[],matched=0,moves=0,locked=false,timer=0,timerID=null;"
        ""
        "function shuffle(a){for(var i=a.length-1;i>0;i--){var j=Math.floor(Math.random()*(i+1));"
        "var t=a[i];a[i]=a[j];a[j]=t;}return a;}"
        ""
        "function startGame(){"
        "matched=0;moves=0;locked=false;flipped=[];timer=0;"
        "if(timerID)clearInterval(timerID);"
        "document.getElementById('sMoves').textContent='Moves: 0';"
        "document.getElementById('sPairs').textContent='Pairs: 0/6';"
        "document.getElementById('sTime').textContent='Time: 0s';"
        "document.getElementById('psArea').innerHTML='';"
        "var pool=shuffle(ITEMS.slice()).slice(0,6);"
        "cards=shuffle(pool.concat(pool.map(function(p){return{e:p.e,w:p.w};})));"
        "var g=document.getElementById('grid');g.innerHTML='';"
        "cards.forEach(function(c,idx){"
        "var d=document.createElement('div');d.className='mem-card';d.dataset.idx=idx;"
        "d.innerHTML='<span class=\"card-back\">?</span>';"
        "d.onclick=function(){flipCard(idx,d);};g.appendChild(d);});"
        "timerID=setInterval(function(){timer++;document.getElementById('sTime').textContent='Time: '+timer+'s';},1000);}"
        ""
        "function flipCard(idx,el){"
        "if(locked||el.classList.contains('flipped')||el.classList.contains('matched'))return;"
        "el.classList.add('flipped');el.innerHTML=eImg(cards[idx],42);"
        "speak(cards[idx].w);flipped.push({idx:idx,el:el});"
        "if(flipped.length===2){locked=true;moves++;"
        "document.getElementById('sMoves').textContent='Moves: '+moves;"
        "var a=flipped[0],b=flipped[1];"
        "if(cards[a.idx].w===cards[b.idx].w){"
        "setTimeout(function(){a.el.classList.add('matched','bounce');b.el.classList.add('matched','bounce');"
        "melodyCorrect();matched++;document.getElementById('sPairs').textContent='Pairs: '+matched+'/6';"
        "if(matched===6){clearInterval(timerID);setTimeout(showEnd,600);}"
        "flipped=[];locked=false;},400);"
        "}else{"
        "setTimeout(function(){a.el.classList.remove('flipped');a.el.innerHTML='<span class=\"card-back\">?</span>';"
        "b.el.classList.remove('flipped');b.el.innerHTML='<span class=\"card-back\">?</span>';"
        "flipped=[];locked=false;},900);"
        "}}}"
        ""
        "function showEnd(){"
        "melodyFinish();"
        "var stars=moves<=8?String.fromCodePoint(0x2B50)+String.fromCodePoint(0x2B50)+String.fromCodePoint(0x2B50):"
        "moves<=12?String.fromCodePoint(0x2B50)+String.fromCodePoint(0x2B50):String.fromCodePoint(0x2B50);"
        "document.getElementById('psArea').innerHTML="
        "'<div class=\"ps-end\"><h2>'+String.fromCodePoint(0x1F389)+' Amazing!</h2>"
        "<p>'+stars+'</p>"
        "<p>Moves: '+moves+' | Time: '+timer+'s</p>"
        "<button class=\"ps-replay-btn\" id=\"psReplay\">\\u21BB PLAY AGAIN</button></div>';"
        "document.getElementById('psReplay').onclick=startGame;}"
        ""
        "startGame();"
        "</script></body></html>"
    )


