def _ps_song_template(title, emoji_cp, bpm, melody_js, lyrics_js):
    """Diamond Premium sarki sablonu — enstrumantal melodi + karaoke sozler."""
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'>"
        "<style>"
        "*{margin:0;padding:0;box-sizing:border-box}"
        "html,body{height:100%;overflow:hidden}"
        "body{background:linear-gradient(135deg,#1a0533 0%,#0d0221 50%,#150530 100%);"
        "font-family:'Segoe UI',system-ui,sans-serif;display:flex;flex-direction:column;"
        "align-items:center}"
        ".ps-wrap{width:100%;max-width:820px;height:100vh;position:relative;overflow:hidden;"
        "background:linear-gradient(180deg,rgba(30,10,60,0.95),rgba(10,5,30,0.98));"
        "border-left:2px solid rgba(168,85,247,0.3);border-right:2px solid rgba(168,85,247,0.3)}"
        "#pCv{position:absolute;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:0}"
        ".ps-hd{text-align:center;padding:10px 0 4px;position:relative;z-index:1;"
        "background:linear-gradient(180deg,rgba(124,58,237,0.25),transparent);"
        "border-bottom:1px solid rgba(168,85,247,0.2)}"
        ".ps-hd-e{font-size:34px;display:block;margin-bottom:1px;"
        "filter:drop-shadow(0 0 12px rgba(168,85,247,0.7))}"
        ".ps-hd-t{font-size:18px;font-weight:800;color:#e9d5ff;"
        "text-shadow:0 0 20px rgba(168,85,247,0.5)}"
        ".s-stg{position:relative;z-index:1;text-align:center;padding:12px 0 8px;"
        "min-height:160px;display:flex;align-items:center;justify-content:center}"
        ".s-emo{font-size:76px;transition:all 0.5s}"
        "@keyframes sB{0%,100%{transform:translateY(0) scale(1)}50%{transform:translateY(-18px) scale(1.08)}}"
        "@keyframes sW{0%,100%{transform:rotate(0)}25%{transform:rotate(-7deg)}75%{transform:rotate(7deg)}}"
        "@keyframes sP{0%,100%{transform:scale(1);filter:drop-shadow(0 0 18px rgba(168,85,247,0.5))}"
        "50%{transform:scale(1.06);filter:drop-shadow(0 0 30px rgba(251,191,36,0.6))}}"
        ".s-emo.ab{animation:sB 0.55s ease infinite}"
        ".s-emo.aw{animation:sW 0.45s ease infinite}"
        ".s-emo.ap{animation:sP 0.9s ease infinite}"
        ".s-lyr{position:relative;z-index:1;text-align:center;padding:6px 20px;"
        "min-height:64px;display:flex;align-items:center;justify-content:center}"
        ".s-ln{font-size:22px;font-weight:700;color:#fbbf24;"
        "text-shadow:0 0 14px rgba(251,191,36,0.4);opacity:0;"
        "transition:opacity 0.35s,transform 0.35s;transform:translateY(8px)}"
        ".s-ln.on{opacity:1;transform:translateY(0)}"
        ".s-prg{position:relative;z-index:1;width:80%;max-width:400px;"
        "height:7px;border-radius:4px;background:rgba(168,85,247,0.2);"
        "margin:6px auto;overflow:hidden}"
        ".s-prg-b{height:100%;border-radius:4px;"
        "background:linear-gradient(90deg,#7c3aed,#a855f7,#fbbf24);"
        "transition:width 0.3s;width:0%}"
        ".s-ctrl{position:relative;z-index:1;display:flex;"
        "justify-content:center;gap:12px;padding:10px 0;align-items:center}"
        ".sb{width:54px;height:54px;border-radius:50%;border:2px solid rgba(168,85,247,0.4);"
        "background:linear-gradient(145deg,rgba(124,58,237,0.3),rgba(88,28,135,0.5));"
        "color:#e9d5ff;font-size:22px;cursor:pointer;display:flex;align-items:center;"
        "justify-content:center;transition:all 0.3s;backdrop-filter:blur(10px);"
        "box-shadow:0 4px 15px rgba(88,28,135,0.4)}"
        ".sb:hover{transform:scale(1.1);border-color:rgba(168,85,247,0.7)}"
        ".sb.big{width:72px;height:72px;font-size:30px;"
        "background:linear-gradient(145deg,rgba(124,58,237,0.5),rgba(88,28,135,0.7));"
        "border-color:rgba(168,85,247,0.6);box-shadow:0 0 22px rgba(124,58,237,0.4)}"
        ".sb.act{border-color:rgba(251,191,36,0.8);box-shadow:0 0 18px rgba(251,191,36,0.4)}"
        ".s-st{position:relative;z-index:1;text-align:center;color:#c4b5fd;"
        "font-size:13px;padding:3px 0}"
        ".sp-btn{position:relative;z-index:1;margin:4px auto;display:block;"
        "padding:6px 18px;border-radius:20px;border:1px solid rgba(168,85,247,0.3);"
        "background:rgba(124,58,237,0.15);color:#c4b5fd;font-size:13px;cursor:pointer;"
        "backdrop-filter:blur(6px);transition:all 0.3s}"
        ".sp-btn:hover{background:rgba(124,58,237,0.3);color:#e9d5ff}"
        "</style></head><body><div class='ps-wrap'>"
        "<canvas id='pCv'></canvas>"
        "<div class='ps-hd'>"
        "<span class='ps-hd-e' id='hE'></span>"
        "<span class='ps-hd-t'>" + title + "</span></div>"
        "<div class='s-stg'><span class='s-emo' id='sE'></span></div>"
        "<div class='s-lyr'><span class='s-ln' id='sL'></span></div>"
        "<div class='s-prg'><div class='s-prg-b' id='pB'></div></div>"
        "<div class='s-ctrl'>"
        "<div class='sb' id='bRe' title='Restart'>&#x21BB;</div>"
        "<div class='sb big' id='bPl' title='Play'>&#x25B6;</div>"
        "<div class='sb' id='bRp' title='Repeat'>&#x1F501;</div>"
        "</div>"
        "<button class='sp-btn' id='bSp'>&#x1F50A; Pronounce</button>"
        "<div class='s-st' id='sSt'>Press play to start!</div>"
        "</div><script>"
        "try{window.speechSynthesis.cancel()}catch(e){}"
        # --- STOP leaked audio ---
        "try{window.speechSynthesis.cancel()}catch(e){}"
        # --- particles ---
        "var cv=document.getElementById('pCv'),cx=cv.getContext('2d');"
        "function szC(){cv.width=cv.parentElement.offsetWidth;cv.height=cv.parentElement.offsetHeight}"
        "szC();window.addEventListener('resize',szC);"
        "var dots=[];for(var i=0;i<35;i++)dots.push({x:Math.random()*cv.width,"
        "y:Math.random()*cv.height,r:Math.random()*2+1,dx:(Math.random()-0.5)*0.4,"
        "dy:(Math.random()-0.5)*0.4,a:Math.random()*0.3+0.1});"
        "var fln=[];"
        "function spN(){if(_pl&&Math.random()<0.12){"
        "fln.push({x:Math.random()*cv.width,y:cv.height+20,vy:-(1+Math.random()*1.5),"
        "vx:(Math.random()-0.5)*0.8,sz:14+Math.random()*12,a:0.7,"
        "ch:Math.random()<0.5?String.fromCodePoint(0x1F3B5):String.fromCodePoint(0x1F3B6)})}}"
        "function drP(){cx.clearRect(0,0,cv.width,cv.height);"
        "dots.forEach(function(d){cx.beginPath();cx.arc(d.x,d.y,d.r,0,Math.PI*2);"
        "cx.fillStyle='rgba(168,85,247,'+d.a+')';cx.fill();"
        "d.x+=d.dx;d.y+=d.dy;"
        "if(d.x<0||d.x>cv.width)d.dx*=-1;if(d.y<0||d.y>cv.height)d.dy*=-1});"
        "spN();for(var i=fln.length-1;i>=0;i--){var n=fln[i];n.y+=n.vy;n.x+=n.vx;n.a-=0.007;"
        "if(n.a<=0){fln.splice(i,1);continue}"
        "cx.globalAlpha=n.a;cx.font=n.sz+'px serif';cx.fillText(n.ch,n.x,n.y);cx.globalAlpha=1}"
        "requestAnimationFrame(drP)}drP();"
        # --- ULTRA PREMIUM AUDIO ENGINE — Multi-layer stereo + Vocal TTS ---
        "var _ac=null,_mg=null,_rv=null,_pnL=null,_pnR=null,_pnV=0,_vGain=null;"
        # --- Best voice finder ---
        "var _bestVoice=null;"
        "function findBestVoice(){"
        "if(_bestVoice)return _bestVoice;"
        "var vs=speechSynthesis.getVoices();"
        "var prefs=['Google UK English Female','Google US English','Microsoft Zira',"
        "'Microsoft Jenny','Microsoft Jenny Online (Natural)','Samantha','Karen','Victoria','Moira','Fiona','Tessa',"
        "'Google UK English','Google US English','Daniel','Microsoft David'];"
        "for(var p=0;p<prefs.length;p++){for(var i=0;i<vs.length;i++){"
        "if(vs[i].name.indexOf(prefs[p])>=0&&vs[i].lang.indexOf('en')===0)"
        "{_bestVoice=vs[i];return _bestVoice}}}"
        "for(var i=0;i<vs.length;i++){var nm=vs[i].name.toLowerCase();"
        "if(vs[i].lang.indexOf('en')===0&&(nm.indexOf('female')>=0||nm.indexOf('woman')>=0))"
        "{_bestVoice=vs[i];return _bestVoice}}"
        "for(var i=0;i<vs.length;i++){if(vs[i].lang.indexOf('en')===0&&!vs[i].localService)"
        "{_bestVoice=vs[i];return _bestVoice}}"
        "for(var i=0;i<vs.length;i++){if(vs[i].lang.indexOf('en')===0)"
        "{_bestVoice=vs[i];return _bestVoice}}"
        "return null}"
        # --- AudioContext init with full FX chain ---
        "function gAC(){if(!_ac){try{"
        "_ac=new(window.AudioContext||window.webkitAudioContext)();"
        # Instrument bus
        "_mg=_ac.createGain();_mg.gain.value=0.22;"
        # Vocal bus (separate gain for TTS-sync)
        "_vGain=_ac.createGain();_vGain.gain.value=0.9;"
        # Stereo widener: 2 panners for L/R spread
        "_pnL=_ac.createStereoPanner();_pnL.pan.value=-0.3;"
        "_pnR=_ac.createStereoPanner();_pnR.pan.value=0.3;"
        # Reverb: 1.2s impulse, stereo
        "_rv=_ac.createConvolver();"
        "var rvLen=Math.floor(_ac.sampleRate*1.2);"
        "var rvBuf=_ac.createBuffer(2,rvLen,_ac.sampleRate);"
        "for(var ch=0;ch<2;ch++){var d=rvBuf.getChannelData(ch);"
        "for(var i=0;i<rvLen;i++){var t=i/_ac.sampleRate;"
        "d[i]=(Math.random()*2-1)*Math.exp(-3*t)*(1+0.3*Math.sin(2*Math.PI*0.5*t))}}"
        "_rv.buffer=rvBuf;"
        "var rvG=_ac.createGain();rvG.gain.value=0.28;"
        # Compressor for balanced output
        "var comp=_ac.createDynamicsCompressor();"
        "comp.threshold.value=-24;comp.knee.value=12;"
        "comp.ratio.value=4;comp.attack.value=0.003;comp.release.value=0.25;"
        # Routing: instruments -> L panner + R panner -> compressor -> destination
        "_mg.connect(_pnL);_mg.connect(_pnR);"
        "_pnL.connect(comp);_pnR.connect(comp);"
        "comp.connect(_ac.destination);"
        # Reverb send: instruments -> reverb -> rvGain -> destination
        "_mg.connect(_rv);_rv.connect(rvG);rvG.connect(_ac.destination)"
        "}catch(e){}}return _ac}"
        "var _oscs=[];"
        "function stopOsc(){_oscs.forEach(function(o){try{o.stop()}catch(e){}});_oscs=[];"
        "if(_ac){try{_ac.close()}catch(e){}_ac=null;_mg=null;_rv=null;_pnL=null;_pnR=null;_vGain=null}}"
        # --- Piano: triangle + sine + detuned for warmth ---
        "function pN(f,dur,t){"
        "var c=gAC();if(!c||!_mg||f<=0)return;"
        "var s=c.currentTime+t;"
        # Stereo: alternate L/R pan per note
        "_pnV=_pnV>0?-0.3:0.3;"
        "if(_pnL)_pnL.pan.setValueAtTime(_pnV,s);"
        "if(_pnR)_pnR.pan.setValueAtTime(-_pnV,s);"
        # Main voice: triangle (warm piano tone)
        "var o1=c.createOscillator(),g1=c.createGain();"
        "o1.type='triangle';o1.frequency.value=f;"
        "o1.connect(g1);g1.connect(_mg);"
        "g1.gain.setValueAtTime(0.001,s);"
        "g1.gain.linearRampToValueAtTime(0.7,s+0.015);"
        "g1.gain.exponentialRampToValueAtTime(0.3,s+dur*0.25);"
        "g1.gain.exponentialRampToValueAtTime(0.01,s+dur-0.02);"
        # Harmonic 2: sine octave up (brightness)
        "var o2=c.createOscillator(),g2=c.createGain();"
        "o2.type='sine';o2.frequency.value=f*2;"
        "o2.connect(g2);g2.connect(_mg);"
        "g2.gain.setValueAtTime(0.001,s);"
        "g2.gain.linearRampToValueAtTime(0.12,s+0.01);"
        "g2.gain.exponentialRampToValueAtTime(0.01,s+dur*0.4);"
        # Harmonic 3: sine detuned +3Hz (chorus/warmth)
        "var o3=c.createOscillator(),g3=c.createGain();"
        "o3.type='sine';o3.frequency.value=f+3;"
        "o3.connect(g3);g3.connect(_mg);"
        "g3.gain.setValueAtTime(0.001,s);"
        "g3.gain.linearRampToValueAtTime(0.08,s+0.02);"
        "g3.gain.exponentialRampToValueAtTime(0.01,s+dur*0.6);"
        "o1.start(s);o1.stop(s+dur);o2.start(s);o2.stop(s+dur);o3.start(s);o3.stop(s+dur);"
        "_oscs.push(o1,o2,o3);"
        "[o1,o2,o3].forEach(function(o){o.onended=function(){var i=_oscs.indexOf(o);if(i>-1)_oscs.splice(i,1)}})}"
        # --- Strings pad (sustained, soft) ---
        "function pS(f,dur,t){"
        "var c=gAC();if(!c||!_mg||f<=0)return;var s=c.currentTime+t;"
        "var notes=[f,f*1.5,f*2,f*0.5];"
        "notes.forEach(function(fr){"
        "var o=c.createOscillator(),g=c.createGain();"
        "o.type='sine';o.frequency.value=fr;"
        "o.connect(g);g.connect(_mg);"
        "g.gain.setValueAtTime(0.001,s);"
        "g.gain.linearRampToValueAtTime(0.04,s+0.15);"
        "g.gain.setValueAtTime(0.035,s+dur*0.7);"
        "g.gain.exponentialRampToValueAtTime(0.001,s+dur-0.05);"
        "o.start(s);o.stop(s+dur);_oscs.push(o);"
        "o.onended=function(){var i=_oscs.indexOf(o);if(i>-1)_oscs.splice(i,1)}})}"
        # --- Bass (octave down, round) ---
        "function pB(f,dur,t){"
        "var c=gAC();if(!c||!_mg||f<=0)return;var s=c.currentTime+t;"
        "var o=c.createOscillator(),g=c.createGain();"
        "o.type='sine';o.frequency.value=f/2;"
        "o.connect(g);g.connect(_mg);"
        "g.gain.setValueAtTime(0.001,s);"
        "g.gain.linearRampToValueAtTime(0.1,s+0.03);"
        "g.gain.exponentialRampToValueAtTime(0.01,s+dur-0.02);"
        "o.start(s);o.stop(s+dur);_oscs.push(o);"
        "o.onended=function(){var i=_oscs.indexOf(o);if(i>-1)_oscs.splice(i,1)}}"
        # --- Kick drum ---
        "function pK(t){"
        "var c=gAC();if(!c||!_mg)return;var s=c.currentTime+t;"
        "var o=c.createOscillator(),g=c.createGain();"
        "o.type='sine';o.connect(g);g.connect(_mg);"
        "g.gain.setValueAtTime(0.001,s);g.gain.linearRampToValueAtTime(0.07,s+0.004);"
        "g.gain.exponentialRampToValueAtTime(0.001,s+0.12);"
        "o.frequency.setValueAtTime(120,s);o.frequency.exponentialRampToValueAtTime(40,s+0.08);"
        "o.start(s);o.stop(s+0.15);_oscs.push(o)}"
        # --- Hi-hat ---
        "function pH(t){"
        "var c=gAC();if(!c||!_mg)return;var s=c.currentTime+t;"
        "var buf=c.createBuffer(1,Math.floor(c.sampleRate*0.04),c.sampleRate);"
        "var d=buf.getChannelData(0);for(var i=0;i<d.length;i++)d[i]=(Math.random()*2-1);"
        "var hp=c.createBiquadFilter();hp.type='highpass';hp.frequency.value=7000;"
        "var n=c.createBufferSource(),g=c.createGain();"
        "n.buffer=buf;n.connect(hp);hp.connect(g);g.connect(_mg);"
        "g.gain.setValueAtTime(0.03,s);g.gain.exponentialRampToValueAtTime(0.001,s+0.04);"
        "n.start(s);_oscs.push(n)}"
        # --- Shaker (softer noise) ---
        "function pSh(t){"
        "var c=gAC();if(!c||!_mg)return;var s=c.currentTime+t;"
        "var buf=c.createBuffer(1,Math.floor(c.sampleRate*0.06),c.sampleRate);"
        "var d=buf.getChannelData(0);for(var i=0;i<d.length;i++)d[i]=(Math.random()*2-1)*0.5;"
        "var bp=c.createBiquadFilter();bp.type='bandpass';bp.frequency.value=5000;bp.Q.value=2;"
        "var n=c.createBufferSource(),g=c.createGain();"
        "n.buffer=buf;n.connect(bp);bp.connect(g);g.connect(_mg);"
        "g.gain.setValueAtTime(0.02,s);g.gain.exponentialRampToValueAtTime(0.001,s+0.06);"
        "n.start(s);_oscs.push(n)}"
        # --- Ultra Premium TTS — human-like singing voice ---
        "var _singQueue=[],_singBusy=false;"
        "function spkLn(txt){"
        "try{speechSynthesis.cancel();"
        "var u=new SpeechSynthesisUtterance(txt);u.lang='en-US';"
        "u.rate=0.82;u.pitch=1.1;u.volume=1.0;"
        "var bv=findBestVoice();if(bv)u.voice=bv;"
        "speechSynthesis.speak(u)}catch(e){}}"
        # --- Vocal sing-along: TTS synced with melody lines ---
        "function singLine(txt,delay){"
        "_singQueue.push({text:txt,delay:delay});"
        "if(!_singBusy)procSing()}"
        "function procSing(){"
        "if(_singQueue.length===0){_singBusy=false;return}"
        "_singBusy=true;var item=_singQueue.shift();"
        "setTimeout(function(){"
        "try{var u=new SpeechSynthesisUtterance(item.text);u.lang='en-US';"
        "u.rate=0.75;u.pitch=1.15;u.volume=0.92;"
        "var bv=findBestVoice();if(bv)u.voice=bv;"
        "u.onend=function(){procSing()};"
        "u.onerror=function(){procSing()};"
        "speechSynthesis.speak(u)}catch(e){procSing()}"
        "},item.delay)}"
        # --- header emoji ---
        "document.getElementById('hE').textContent=String.fromCodePoint(" + emoji_cp + ");"
        # --- parse data ---
        "var BPM=" + str(bpm) + ";"
        "var bD=60.0/BPM;"
        "var ML=" + melody_js + ";"
        "var LR=" + lyrics_js + ".map(function(l){"
        "return{text:l.text,emojis:l.emojis.map(function(c){return String.fromCodePoint(c)}),beat:l.beat}});"
        # --- calc total ---
        "var tB=0;ML.forEach(function(n){tB+=n.b});"
        "var tD=tB*bD;"
        # --- state ---
        "var _pl=false,_pa=false,_st=0,_pt=0,_rp=false;"
        "var _lt=[],_cl=0;"
        "var anm=['ab','aw','ap'];"
        # --- schedule melody (multi-layer orchestra) ---
        "function schM(){"
        "var t=0;for(var i=0;i<ML.length;i++){var n=ML[i];var d=n.b*bD;"
        "if(n.f>0){"
        # Piano melody (every note)
        "pN(n.f,d*0.92,t);"
        # Strings pad (every 4th note, sustained 4 beats)
        "if(i%4===0){pS(n.f/2,d*4,t)}"
        # Bass (every 2nd note)
        "if(i%2===0){pB(n.f,d*1.8,t)}"
        # Kick on beat 1 and 3 (every 4th note)
        "if(i%4===0){pK(t)}"
        # Hi-hat on beat 2 and 4
        "if(i%4===2){pH(t)}"
        # Shaker on every note (soft)
        "pSh(t+d*0.25)"
        "}"
        "t+=d}}"
        # --- schedule lyrics ---
        "function schL(){"
        "_lt.forEach(function(t){clearTimeout(t)});_lt=[];"
        "for(var i=0;i<LR.length;i++){(function(idx){"
        "var dl=LR[idx].beat*bD*1000;"
        "_lt.push(setTimeout(function(){shLn(idx)},dl))"
        "})(i)}"
        "_lt.push(setTimeout(function(){onEnd()},tD*1000+200))}"
        # --- show line + vocal sing-along ---
        "function shLn(idx){"
        "_cl=idx;var ln=LR[idx];"
        "var el=document.getElementById('sL');"
        "el.className='s-ln';el.textContent=ln.text;"
        "setTimeout(function(){el.className='s-ln on'},40);"
        "var eE=document.getElementById('sE');"
        "eE.textContent=ln.emojis.join(' ');"
        "eE.className='s-emo '+anm[idx%3];"
        "document.getElementById('sSt').textContent=(idx+1)+' / '+LR.length;"
        # Vocal TTS: speak each line as it appears (guide vocal)
        "if(_pl){try{speechSynthesis.cancel();"
        "var u=new SpeechSynthesisUtterance(ln.text);u.lang='en-US';"
        # Calculate speech rate based on time until next line
        "var nxtBeat=idx<LR.length-1?(LR[idx+1].beat-ln.beat)*bD:3;"
        "var wc=ln.text.split(' ').length;"
        "var idealRate=Math.max(0.6,Math.min(1.1,wc/(nxtBeat*2.5)));"
        "u.rate=idealRate;u.pitch=1.12;u.volume=0.95;"
        "var bv=findBestVoice();if(bv)u.voice=bv;"
        "speechSynthesis.speak(u)}catch(e){}}}"
        # --- progress ---
        "var _rf=null;"
        "function trPr(){if(!_pl)return;"
        "var el=(Date.now()-_st)/1000;"
        "var pc=Math.min(100,Math.round((el/tD)*100));"
        "document.getElementById('pB').style.width=pc+'%';"
        "_rf=requestAnimationFrame(trPr)}"
        # --- on end ---
        "function onEnd(){"
        "document.getElementById('sSt').textContent='Finished! '+String.fromCodePoint(0x1F389);"
        "document.getElementById('pB').style.width='100%';"
        "document.getElementById('bPl').innerHTML='&#x25B6;';"
        "_pl=false;"
        "if(_rf)cancelAnimationFrame(_rf);"
        "if(_rp)setTimeout(goSong,1200)}"
        # --- start ---
        "function goSong(){"
        "fStop();_pl=true;_pa=false;_cl=0;"
        "document.getElementById('bPl').innerHTML='&#x23F8;';"
        "document.getElementById('pB').style.width='0%';"
        "_st=Date.now();"
        "schM();schL();trPr()}"
        # --- full stop ---
        "function fStop(){"
        "_pl=false;_pa=false;"
        "try{speechSynthesis.cancel()}catch(e){}"
        "_singQueue=[];_singBusy=false;"
        "_lt.forEach(function(t){clearTimeout(t)});_lt=[];"
        "if(_rf)cancelAnimationFrame(_rf);"
        "stopOsc();"
        "document.getElementById('bPl').innerHTML='&#x25B6;'}"
        # --- controls ---
        "document.getElementById('bPl').onclick=function(){"
        "if(!_pl&&!_pa){goSong()}"
        "else if(_pa){_pa=false;_pl=true;"
        "document.getElementById('bPl').innerHTML='&#x23F8;';"
        "_st=Date.now()-_pt;"
        "schM();schL();trPr()}"
        "else{_pa=true;_pt=Date.now()-_st;"
        "fStop();_pa=true;"
        "document.getElementById('bPl').innerHTML='&#x25B6;'}};"
        "document.getElementById('bRe').onclick=function(){fStop();goSong()};"
        "document.getElementById('bRp').onclick=function(){"
        "_rp=!_rp;"
        "document.getElementById('bRp').className=_rp?'sb act':'sb'};"
        "document.getElementById('bSp').onclick=function(){"
        "if(LR[_cl])spkLn(LR[_cl].text)};"
        # --- stop audio on tab switch ---
        "document.addEventListener('visibilitychange',function(){if(document.hidden)fStop()});"
        "window.addEventListener('beforeunload',function(){fStop()});"
        "if(window.speechSynthesis)speechSynthesis.getVoices();"
        "</script></body></html>"
    )


