# ── Okul Oncesi Diyalog Sablonu — Diamond Premium ────────────────────────────

def _ps_dialog_template(title, emoji_cp, chars_js, dialog_js):
    """Okul oncesi diyalog sablonu — Diamond Premium.
    chars_js: [{name:'Tom',cp:0x1F466},{name:'Lily',cp:0x1F467}]
    dialog_js: [{s:0,t:'Hello!',e:[0x1F44B]}, ...]  (s=speaker idx)
    """
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'>"
        "<style>"
        "*{margin:0;padding:0;box-sizing:border-box;}"
        "html,body{height:100%;overflow:hidden;}"
        "body{background:linear-gradient(135deg,#1a0533 0%,#0d0221 50%,#150530 100%);"
        "font-family:'Segoe UI Emoji','Apple Color Emoji','Noto Color Emoji','Segoe UI',system-ui,sans-serif;display:flex;flex-direction:column;"
        "align-items:center;}"
        ".dg-wrap{width:100%;max-width:820px;height:100vh;position:relative;overflow:hidden;"
        "background:linear-gradient(180deg,rgba(30,10,60,0.95),rgba(10,5,30,0.98));"
        "border-left:2px solid rgba(168,85,247,0.3);border-right:2px solid rgba(168,85,247,0.3);}"
        ".dg-header{text-align:center;padding:10px 0 6px;"
        "background:linear-gradient(180deg,rgba(124,58,237,0.25),transparent);"
        "border-bottom:1px solid rgba(168,85,247,0.2);}"
        ".dg-header-emoji{font-size:32px;display:block;margin-bottom:2px;"
        "filter:drop-shadow(0 0 12px rgba(168,85,247,0.8));}"
        ".dg-header-text{font-size:17px;font-weight:800;color:#e9d5ff;"
        "text-shadow:0 0 20px rgba(168,85,247,0.6);letter-spacing:1.5px;}"
        ".dg-chars{display:flex;justify-content:space-around;padding:8px 30px;}"
        ".dg-char{display:flex;flex-direction:column;align-items:center;}"
        ".dg-char-emoji{font-size:46px;transition:transform 0.3s;"
        "filter:drop-shadow(0 0 10px rgba(168,85,247,0.4));}"
        ".dg-char-emoji.speaking{animation:dgBounce 0.6s ease infinite;}"
        ".dg-char-name{font-size:12px;font-weight:700;margin-top:2px;}"
        ".dg-char-name.c0{color:#c4b5fd;}.dg-char-name.c1{color:#6ee7b7;}"
        "@keyframes dgBounce{0%,100%{transform:translateY(0) scale(1)}"
        "50%{transform:translateY(-8px) scale(1.12)}}"
        ".dg-chat{flex:1;overflow-y:auto;padding:8px 14px;display:flex;"
        "flex-direction:column;gap:6px;scroll-behavior:smooth;}"
        ".dg-chat::-webkit-scrollbar{width:6px;}"
        ".dg-chat::-webkit-scrollbar-thumb{background:rgba(168,85,247,0.3);border-radius:3px;}"
        ".dg-bbl{max-width:82%;padding:10px 16px;border-radius:20px;font-size:17px;"
        "font-weight:600;opacity:0.25;transition:all 0.4s ease;position:relative;"
        "line-height:1.4;}"
        ".dg-bbl.active{opacity:1;transform:scale(1.03);}"
        ".dg-bbl.done{opacity:0.65;}"
        ".dg-bbl.left{align-self:flex-start;"
        "background:linear-gradient(135deg,rgba(124,58,237,0.35),rgba(99,45,200,0.25));"
        "border:1.5px solid rgba(168,85,247,0.35);color:#e9d5ff;border-bottom-left-radius:4px;}"
        ".dg-bbl.right{align-self:flex-end;text-align:right;"
        "background:linear-gradient(135deg,rgba(16,185,129,0.25),rgba(5,150,105,0.2));"
        "border:1.5px solid rgba(52,211,153,0.35);color:#a7f3d0;border-bottom-right-radius:4px;}"
        ".dg-bbl.active.left{box-shadow:0 0 20px rgba(168,85,247,0.5);"
        "border-color:rgba(168,85,247,0.8);}"
        ".dg-bbl.active.right{box-shadow:0 0 20px rgba(52,211,153,0.5);"
        "border-color:rgba(52,211,153,0.8);}"
        ".dg-bbl-emoji{font-size:20px;margin-left:6px;}"
        ".dg-bbl-name{font-size:10px;font-weight:700;opacity:0.55;margin-bottom:2px;}"
        ".dg-ctrls{display:flex;justify-content:center;gap:10px;padding:10px;}"
        ".dg-btn{width:46px;height:46px;border-radius:50%;"
        "border:2px solid rgba(196,181,253,0.3);cursor:pointer;font-size:20px;color:#fff;"
        "background:linear-gradient(135deg,#7c3aed,#6d28d9);"
        "box-shadow:0 0 15px rgba(124,58,237,0.4);transition:all 0.3s;"
        "display:flex;align-items:center;justify-content:center;}"
        ".dg-btn:hover{transform:scale(1.15);box-shadow:0 0 25px rgba(124,58,237,0.7);}"
        ".dg-btn:active{transform:scale(0.9);}"
        ".dg-btn.playing{background:linear-gradient(135deg,#ef4444,#dc2626);"
        "border-color:rgba(252,165,165,0.4);box-shadow:0 0 15px rgba(239,68,68,0.5);}"
        ".dg-prog{display:flex;justify-content:center;gap:4px;padding:4px 8px;flex-wrap:wrap;}"
        ".dg-dot{width:9px;height:9px;border-radius:50%;"
        "background:rgba(168,85,247,0.2);border:1px solid rgba(168,85,247,0.3);transition:all 0.3s;}"
        ".dg-dot.done{background:#34d399;border-color:#6ee7b7;}"
        ".dg-dot.cur{background:#fbbf24;border-color:#fcd34d;transform:scale(1.4);"
        "box-shadow:0 0 8px rgba(251,191,36,0.6);}"
        "#dgCv{position:absolute;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:0;}"
        "#dgCt{position:relative;z-index:1;width:100%;height:100%;display:flex;flex-direction:column;}"
        ".dg-prac-fb{text-align:center;padding:6px;min-height:28px;font-size:15px;font-weight:600;color:#c4b5fd;transition:all .3s}"
        ".dg-prac-fb.ok{color:#34d399}.dg-prac-fb.no{color:#f87171}.dg-prac-fb.close{color:#fbbf24}"
        ".dg-prac-sc{text-align:center;font-size:13px;color:#c4b5fd;padding:2px;min-height:18px}"
        ".dg-btn.prac{background:linear-gradient(135deg,#f59e0b,#d97706);border-color:rgba(251,191,36,0.4)}"
        ".dg-btn.prac.on{box-shadow:0 0 20px rgba(251,191,36,0.6)}"
        ".dg-btn.mic{background:linear-gradient(135deg,#ef4444,#dc2626);"
        "border-color:rgba(252,165,165,0.4);animation:dgPulse 1s ease infinite}"
        "@keyframes dgPulse{0%,100%{box-shadow:0 0 15px rgba(239,68,68,0.3)}"
        "50%{box-shadow:0 0 30px rgba(239,68,68,0.7)}}"
        "</style></head><body>"
        "<div class='dg-wrap'><canvas id='dgCv'></canvas>"
        "<div id='dgCt'>"
        "<div class='dg-header'>"
        "<span class='dg-header-emoji' id='dgHE'></span>"
        "<div class='dg-header-text' id='dgHT'></div></div>"
        "<div class='dg-chars' id='dgChrs'></div>"
        "<div class='dg-chat' id='dgChat'></div>"
        "<div class='dg-prac-fb' id='dgPFb'></div>"
        "<div class='dg-prac-sc' id='dgPSc'></div>"
        "<div class='dg-prog' id='dgProg'></div>"
        "<div class='dg-ctrls'>"
        "<div class='dg-btn' onclick='dgPrev()'>&#9198;</div>"
        "<div class='dg-btn' id='dgBPlay' onclick='dgToggle()'>&#9654;&#65039;</div>"
        "<div class='dg-btn' onclick='dgNext()'>&#9197;</div>"
        "<div class='dg-btn' onclick='dgReplay()'>&#128260;</div>"
        "<div class='dg-btn' onclick='dgSpkCur()'>&#128266;</div>"
        "<div class='dg-btn prac' id='dgBPrac' onclick='dgTogglePrac()' title='Practice Mode'>&#127919;</div>"
        "</div></div></div>"
        "<script>"
        "try{window.speechSynthesis.cancel()}catch(e){}"
        "var DT='" + title.replace("'", "\\'") + "',DE=" + emoji_cp + ","
        "DC=" + chars_js + ","
        "DD=" + dialog_js + ";"
        "var di=0,dp=false,dtm=null;"
        "function dgInit(){"
        "document.getElementById('dgHE').textContent=String.fromCodePoint(DE);"
        "document.getElementById('dgHT').textContent=DT;"
        "var ch=document.getElementById('dgChrs');"
        "DC.forEach(function(c,i){"
        "var d=document.createElement('div');d.className='dg-char';"
        "d.innerHTML='<span class=\"dg-char-emoji\" id=\"dgC'+i+'\">'+String.fromCodePoint(c.cp)"
        "+'</span><span class=\"dg-char-name c'+i+'\">'+c.name+'</span>';"
        "ch.appendChild(d);});"
        "var ct=document.getElementById('dgChat');"
        "DD.forEach(function(d,i){"
        "var b=document.createElement('div');"
        "b.className='dg-bbl '+(d.s===0?'left':'right');"
        "b.id='dgB'+i;"
        "var em=d.e.map(function(c){return String.fromCodePoint(c)}).join('');"
        "b.innerHTML='<div class=\"dg-bbl-name\">'+DC[d.s].name+'</div>'"
        "+d.t+' <span class=\"dg-bbl-emoji\">'+em+'</span>';"
        "ct.appendChild(b);});"
        "var pg=document.getElementById('dgProg');"
        "DD.forEach(function(_,i){"
        "var dt=document.createElement('div');dt.className='dg-dot';dt.id='dgD'+i;"
        "pg.appendChild(dt);});"
        "dgShow(0);}"
        "function dgShow(n){"
        "di=n;"
        "DD.forEach(function(_,i){"
        "var b=document.getElementById('dgB'+i);"
        "b.classList.remove('active','done');"
        "if(i<n)b.classList.add('done');"
        "else if(i===n)b.classList.add('active');});"
        "DD.forEach(function(_,i){"
        "var d=document.getElementById('dgD'+i);"
        "d.classList.remove('done','cur');"
        "if(i<n)d.classList.add('done');"
        "else if(i===n)d.classList.add('cur');});"
        "DC.forEach(function(_,i){document.getElementById('dgC'+i).classList.remove('speaking');});"
        "document.getElementById('dgC'+DD[n].s).classList.add('speaking');"
        "document.getElementById('dgB'+n).scrollIntoView({behavior:'smooth',block:'center'});"
        "}"
        "function dgSpk(n,cb){"
        "var u=new SpeechSynthesisUtterance(DD[n].t);"
        "u.lang='en-US';u.rate=0.75;u.pitch=1.1;"
        "var vs=speechSynthesis.getVoices();"
        "var pr=['Google UK English Female','Google US English','Microsoft Zira','Microsoft Jenny','Samantha','Karen','Daniel','Moira'];"
        "var bv=null;for(var p=0;p<pr.length&&!bv;p++){for(var vi=0;vi<vs.length;vi++){if(vs[vi].name.indexOf(pr[p])>=0&&vs[vi].lang.indexOf('en')===0){bv=vs[vi];break;}}}"
        "if(!bv){for(var vi=0;vi<vs.length;vi++){if(vs[vi].lang.indexOf('en')===0){bv=vs[vi];break;}}}"
        "if(bv)u.voice=bv;"
        "u.onend=function(){if(cb)cb();};"
        "speechSynthesis.cancel();speechSynthesis.speak(u);}"
        "function dgSpkCur(){dgSpk(di);}"
        "function dgPlayNext(){"
        "if(!dp)return;"
        "if(di>=DD.length-1){dp=false;"
        "document.getElementById('dgBPlay').classList.remove('playing');"
        "document.getElementById('dgBPlay').innerHTML='&#9654;&#65039;';return;}"
        "di++;dgShow(di);dgSpk(di,function(){dtm=setTimeout(dgPlayNext,700);});}"
        "function dgToggle(){"
        "if(dp){dp=false;speechSynthesis.cancel();clearTimeout(dtm);"
        "document.getElementById('dgBPlay').classList.remove('playing');"
        "document.getElementById('dgBPlay').innerHTML='&#9654;&#65039;';"
        "}else{dp=true;"
        "document.getElementById('dgBPlay').classList.add('playing');"
        "document.getElementById('dgBPlay').innerHTML='&#9208;';"
        "dgShow(di);dgSpk(di,function(){dtm=setTimeout(dgPlayNext,700);});}}"
        "function dgNext(){if(di<DD.length-1){di++;dgShow(di);if(!dp)dgSpk(di);}}"
        "function dgPrev(){if(di>0){di--;dgShow(di);if(!dp)dgSpk(di);}}"
        "function dgReplay(){dp=false;speechSynthesis.cancel();clearTimeout(dtm);"
        "di=0;dgShow(0);document.getElementById('dgBPlay').classList.remove('playing');"
        "document.getElementById('dgBPlay').innerHTML='&#9654;&#65039;';}"
        "var cv=document.getElementById('dgCv'),cx=cv.getContext('2d');"
        "function rsz(){cv.width=cv.offsetWidth;cv.height=cv.offsetHeight;}rsz();"
        "window.addEventListener('resize',rsz);"
        "var pts=[];for(var i=0;i<35;i++)pts.push({x:Math.random()*cv.width,"
        "y:Math.random()*cv.height,r:Math.random()*2+0.8,"
        "dx:(Math.random()-0.5)*0.4,dy:(Math.random()-0.5)*0.4,"
        "a:Math.random()*0.4+0.1});"
        "function drw(){cx.clearRect(0,0,cv.width,cv.height);"
        "pts.forEach(function(p){p.x+=p.dx;p.y+=p.dy;"
        "if(p.x<0)p.x=cv.width;if(p.x>cv.width)p.x=0;"
        "if(p.y<0)p.y=cv.height;if(p.y>cv.height)p.y=0;"
        "cx.beginPath();cx.arc(p.x,p.y,p.r,0,Math.PI*2);"
        "cx.fillStyle='rgba(168,85,247,'+p.a+')';cx.fill();});"
        "requestAnimationFrame(drw);}drw();"
        "window.addEventListener('beforeunload',function(){speechSynthesis.cancel();});"
        "document.addEventListener('visibilitychange',function(){"
        "if(document.hidden){speechSynthesis.cancel();dp=false;clearTimeout(dtm);}});"
        # --- Practice Mode (Faz 5) ---
        "var pracOn=false,pracOk=0,pracTot=0,pracBCnt=0;"
        "var SRec=window.SpeechRecognition||window.webkitSpeechRecognition;"
        # Levenshtein for practice
        "function dgLev(a,b){"
        "var m=[];for(var i=0;i<=b.length;i++){m[i]=[i];"
        "for(var j=1;j<=a.length;j++){m[i][j]=i===0?j:"
        "Math.min(m[i-1][j]+1,m[i][j-1]+1,m[i-1][j-1]+(a[j-1]===b[i-1]?0:1))}}"
        "return m[b.length][a.length]}"
        # Toggle practice mode
        "function dgTogglePrac(){"
        "if(pracOn){pracOn=false;speechSynthesis.cancel();clearTimeout(dtm);"
        "document.getElementById('dgBPrac').classList.remove('on');"
        "document.getElementById('dgPFb').textContent='';"
        "document.getElementById('dgPSc').textContent='';return;}"
        # Start practice
        "pracOn=true;pracOk=0;pracTot=0;"
        "pracBCnt=DD.filter(function(d){return d.s===1}).length;"
        "document.getElementById('dgBPrac').classList.add('on');"
        "document.getElementById('dgPFb').textContent='Practice Mode! Listen to A, speak B\\'s lines.';"
        "document.getElementById('dgPFb').className='dg-prac-fb';"
        "document.getElementById('dgPSc').textContent='Score: 0 / '+pracBCnt;"
        # Stop normal play
        "dp=false;speechSynthesis.cancel();clearTimeout(dtm);"
        "document.getElementById('dgBPlay').classList.remove('playing');"
        "document.getElementById('dgBPlay').innerHTML='&#9654;&#65039;';"
        "di=0;dgShow(0);dgPracStep()}"
        # Practice step
        "function dgPracStep(){"
        "if(!pracOn||di>=DD.length){"
        "if(pracOn){"
        "var pct=pracTot>0?Math.round(pracOk/pracTot*100):0;"
        "var msg=pct>=90?'Outstanding! \\u2B50\\u2B50\\u2B50 '"
        ":pct>=70?'Great job! \\u2B50\\u2B50 '"
        ":pct>=50?'Good effort! \\u2B50 ':'Keep practicing! ';"
        "document.getElementById('dgPFb').textContent=msg+pracOk+'/'+pracTot;"
        "document.getElementById('dgPFb').className='dg-prac-fb ok';"
        "pracOn=false;document.getElementById('dgBPrac').classList.remove('on')}"
        "return}"
        "dgShow(di);"
        "if(DD[di].s===0){"
        # Speaker A — play via TTS, then auto-advance
        "dgSpk(di,function(){setTimeout(function(){di++;dgPracStep()},500)})"
        "}else{"
        # Speaker B — student's turn
        "document.getElementById('dgPFb').textContent='\\U0001F3A4 Your turn! Say: \\\"'+DD[di].t+'\\\"';"
        "document.getElementById('dgPFb').className='dg-prac-fb';"
        "setTimeout(dgPracListen,600)}}"
        # Listen for student speech
        "function dgPracListen(){"
        "if(!SRec||!pracOn){document.getElementById('dgPFb').textContent='Speech Recognition not available.';return}"
        "var rc=new SRec();rc.lang='en-US';rc.interimResults=false;rc.maxAlternatives=8;rc.continuous=false;"
        "rc.onresult=function(e){"
        "var tgt=DD[di].t.toLowerCase().replace(/[!?.,]/g,'').trim();"
        "var wc=tgt.split(' ').length;"
        "var exTol=Math.max(2,Math.floor(wc*0.4));"
        "var clTol=Math.max(4,wc);"
        "var matched=false,bestH='',bestD=99;"
        "for(var i=0;i<e.results[0].length;i++){"
        "var h=e.results[0][i].transcript.toLowerCase().replace(/[!?.,]/g,'').trim();"
        "var d=dgLev(h,tgt);if(d<bestD){bestD=d;bestH=h}"
        "if(h===tgt||d<=exTol){matched=true;bestH=h;break}}"
        "pracTot++;"
        "if(matched){pracOk++;"
        "document.getElementById('dgPFb').textContent='Perfect! \\u2705';"
        "document.getElementById('dgPFb').className='dg-prac-fb ok'}"
        "else if(bestD<=clTol){"
        "document.getElementById('dgPFb').textContent='Almost! You said: \\\"'+bestH+'\\\"';"
        "document.getElementById('dgPFb').className='dg-prac-fb close'}"
        "else{"
        "document.getElementById('dgPFb').textContent='Correct: \\\"'+DD[di].t+'\\\"';"
        "document.getElementById('dgPFb').className='dg-prac-fb no'}"
        "document.getElementById('dgPSc').textContent='Score: '+pracOk+' / '+pracBCnt;"
        "setTimeout(function(){di++;dgPracStep()},1500)};"
        "rc.onerror=function(e){"
        "if(!pracOn)return;"
        "var msg=e.error==='no-speech'?'No speech detected. Try again!':'Could not hear. Try again!';"
        "document.getElementById('dgPFb').textContent=msg;"
        "document.getElementById('dgPFb').className='dg-prac-fb no';"
        "setTimeout(function(){if(pracOn)dgPracListen()},1000)};"
        "rc.start()}"
        # --- End Practice Mode ---
        "dgInit();"
        "</script></body></html>"
    )


