def _build_pk_missing_letter_html():
    """Eksik Harf oyunu — kelimede bir harf eksik, dogrusunu sec."""
    all_w = _ps_all_words()
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'>"
        "<style>"
        "*{margin:0;padding:0;box-sizing:border-box}"
        "html,body{height:100%;overflow:hidden}"
        "body{background:linear-gradient(135deg,#1a0533,#0d0221,#150530);"
        "font-family:'Segoe UI',system-ui,sans-serif;display:flex;justify-content:center}"
        ".w{width:100%;max-width:820px;height:100vh;position:relative;overflow:hidden;"
        "background:linear-gradient(180deg,rgba(30,10,60,.95),rgba(10,5,30,.98));"
        "border-left:2px solid rgba(168,85,247,.3);border-right:2px solid rgba(168,85,247,.3)}"
        "canvas{position:absolute;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:0}"
        ".ct{position:relative;z-index:1;width:100%;height:100%;display:flex;flex-direction:column;"
        "align-items:center}"
        ".hdr{text-align:center;padding:12px 0 8px;"
        "background:linear-gradient(180deg,rgba(124,58,237,.25),transparent);"
        "border-bottom:1px solid rgba(168,85,247,.2);width:100%}"
        ".hdr h2{font-size:18px;color:#e9d5ff;font-weight:800;"
        "text-shadow:0 0 20px rgba(168,85,247,.6)}"
        ".score{color:#c4b5fd;font-size:14px;margin:6px 0;font-weight:600;"
        "background:rgba(124,58,237,.15);padding:4px 18px;border-radius:20px;"
        "border:1px solid rgba(168,85,247,.25)}"
        ".emoji{font-size:90px;margin:16px 0;"
        "filter:drop-shadow(0 0 25px rgba(168,85,247,.5));"
        "animation:ef 3s ease-in-out infinite}"
        "@keyframes ef{0%,100%{transform:translateY(0) scale(1)}"
        "50%{transform:translateY(-10px) scale(1.05)}}"
        ".word{font-size:42px;font-weight:800;color:#e9d5ff;letter-spacing:6px;"
        "text-shadow:0 0 20px rgba(168,85,247,.5);margin:8px 0}"
        ".word .blank{color:#fbbf24;border-bottom:3px solid #fbbf24;padding:0 2px;"
        "text-shadow:0 0 15px rgba(251,191,36,.6)}"
        ".opts{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;"
        "max-width:400px;margin:20px auto;padding:0 20px}"
        ".opt{height:70px;border-radius:18px;border:2px solid rgba(168,85,247,.4);"
        "background:linear-gradient(145deg,rgba(40,20,80,.6),rgba(20,10,50,.8));"
        "cursor:pointer;font-size:32px;font-weight:700;color:#e9d5ff;"
        "display:flex;align-items:center;justify-content:center;"
        "transition:all .3s cubic-bezier(.34,1.56,.64,1);"
        "box-shadow:0 4px 15px rgba(0,0,0,.3)}"
        ".opt:hover{transform:scale(1.1);border-color:rgba(168,85,247,.8);"
        "box-shadow:0 6px 25px rgba(124,58,237,.5)}"
        ".opt.ok{background:linear-gradient(145deg,rgba(16,185,129,.4),rgba(5,150,105,.6));"
        "border-color:#34d399;box-shadow:0 0 30px rgba(52,211,153,.5)}"
        ".opt.no{background:linear-gradient(145deg,rgba(239,68,68,.3),rgba(220,38,38,.4));"
        "border-color:#f87171;animation:sh .4s ease}"
        "@keyframes sh{0%,100%{transform:translateX(0)}25%{transform:translateX(-8px)}"
        "75%{transform:translateX(8px)}}"
        ".prog{display:flex;gap:5px;margin:10px 0;flex-wrap:wrap;justify-content:center}"
        ".dot{width:12px;height:12px;border-radius:50%;background:rgba(168,85,247,.2);"
        "border:1px solid rgba(168,85,247,.3);transition:all .3s}"
        ".dot.dn{background:#34d399;border-color:#6ee7b7}"
        ".dot.cur{background:#fbbf24;border-color:#fcd34d;transform:scale(1.4);"
        "box-shadow:0 0 8px rgba(251,191,36,.6)}"
        ".end{position:absolute;inset:0;z-index:10;display:none;flex-direction:column;"
        "align-items:center;justify-content:center;background:rgba(10,2,33,.95);"
        "backdrop-filter:blur(20px)}"
        ".end.show{display:flex}"
        ".end h2{font-size:34px;color:#e9d5ff;margin:8px}"
        ".end p{color:#c4b5fd;font-size:18px}"
        ".rbtn{padding:14px 40px;font-size:18px;font-weight:700;border-radius:50px;"
        "border:2px solid rgba(196,181,253,.3);cursor:pointer;color:#fff;margin-top:16px;"
        "background:linear-gradient(135deg,#7c3aed,#6d28d9);"
        "box-shadow:0 0 20px rgba(124,58,237,.4);transition:all .3s}"
        ".rbtn:hover{transform:scale(1.08)}"
        "</style></head><body>"
        "<div class='w'><canvas id='cv'></canvas>"
        "<div class='ct'>"
        "<div class='hdr'><h2>\u2712\uFE0F Eksik Harf</h2></div>"
        "<div class='score' id='sc'>0 / 10</div>"
        "<div class='prog' id='pg'></div>"
        "<div class='emoji' id='em'></div>"
        "<div class='word' id='wd'></div>"
        "<div class='opts' id='op'></div>"
        "</div>"
        "<div class='end' id='ed'>"
        "<div style='font-size:80px'>&#127942;</div>"
        "<h2 id='et'></h2><p id='es'></p>"
        "<div class='rbtn' onclick='init()'>Tekrar Oyna</div>"
        "</div></div>"
        "<script>"
        "try{window.speechSynthesis.cancel()}catch(e){}"
        "var W=" + all_w + ";"
        "var pool,qi,pts,cur;"
        "function shuf(a){for(var i=a.length-1;i>0;i--){var j=Math.floor(Math.random()*(i+1));"
        "var t=a[i];a[i]=a[j];a[j]=t;}return a;}"
        "var _bV=null;function fBV(){if(_bV)return _bV;var vs=speechSynthesis.getVoices();"
        "var pr=['Google UK English Female','Google US English','Microsoft Zira','Microsoft Jenny','Samantha','Karen','Daniel','Moira'];"
        "for(var p=0;p<pr.length;p++){for(var i=0;i<vs.length;i++){if(vs[i].name.indexOf(pr[p])>=0&&vs[i].lang.indexOf('en')===0){_bV=vs[i];return _bV}}}"
        "for(var i=0;i<vs.length;i++){if(vs[i].lang.indexOf('en')===0){_bV=vs[i];return _bV}}return null}"
        "function spk(t){if(!window._uc){if(!window._ucL){window._ucL=1;document.addEventListener('click',function(){window._uc=1});document.addEventListener('touchstart',function(){window._uc=1})}return;}try{var u=new SpeechSynthesisUtterance(t);u.lang='en-US';"
        "u.rate=0.8;u.pitch=1.1;var bv=fBV();if(bv)u.voice=bv;speechSynthesis.cancel();speechSynthesis.speak(u);}catch(e){}}"
        "function init(){"
        "document.getElementById('ed').classList.remove('show');"
        "pool=shuf(W.slice()).slice(0,10);qi=0;pts=0;"
        "var pg=document.getElementById('pg');pg.innerHTML='';"
        "for(var i=0;i<10;i++){var d=document.createElement('div');"
        "d.className='dot';d.id='d'+i;pg.appendChild(d);}"
        "show();}"
        "function show(){"
        "if(qi>=10){endG();return;}"
        "cur=pool[qi];var w=cur[1];var bi=Math.floor(Math.random()*w.length);"
        "var ml=w[bi].toUpperCase();"
        "document.getElementById('em').textContent=String.fromCodePoint(cur[0]);"
        "var ds='';for(var i=0;i<w.length;i++){"
        "if(i===bi)ds+='<span class=\"blank\">_</span>';else ds+=w[i].toUpperCase();}"
        "document.getElementById('wd').innerHTML=ds;"
        "document.getElementById('sc').textContent=pts+' / 10';"
        "for(var i=0;i<10;i++){var d=document.getElementById('d'+i);"
        "d.className='dot';if(i<qi)d.classList.add('dn');"
        "if(i===qi)d.classList.add('cur');}"
        "var letters=[ml];var abc='ABCDEFGHIJKLMNOPQRSTUVWXYZ';"
        "while(letters.length<4){var r=abc[Math.floor(Math.random()*26)];"
        "if(letters.indexOf(r)<0)letters.push(r);}"
        "shuf(letters);"
        "var op=document.getElementById('op');op.innerHTML='';"
        "letters.forEach(function(l){"
        "var b=document.createElement('div');b.className='opt';b.textContent=l;"
        "b.onclick=function(){pick(l,ml,b);};op.appendChild(b);});}"
        "function pick(l,ml,el){"
        "if(el.classList.contains('ok')||el.classList.contains('no'))return;"
        "if(l===ml){el.classList.add('ok');pts++;spk(cur[1]);"
        "setTimeout(function(){qi++;show();},1200);"
        "}else{el.classList.add('no');}}"
        "function endG(){"
        "document.getElementById('et').textContent="
        "pts>=8?'Harika! '+String.fromCodePoint(0x1F929):"
        "pts>=5?'Iyi! '+String.fromCodePoint(0x1F60A):"
        "'Tekrar Dene! '+String.fromCodePoint(0x1F4AA);"
        "document.getElementById('es').textContent=pts+' / 10 dogru';"
        "document.getElementById('ed').classList.add('show');}"
        "var cv=document.getElementById('cv'),cx=cv.getContext('2d');"
        "function rsz(){cv.width=cv.offsetWidth;cv.height=cv.offsetHeight;}rsz();"
        "window.addEventListener('resize',rsz);"
        "var ps=[];for(var i=0;i<30;i++)ps.push({x:Math.random()*cv.width,"
        "y:Math.random()*cv.height,r:Math.random()*2+.8,"
        "dx:(Math.random()-.5)*.4,dy:(Math.random()-.5)*.4,"
        "a:Math.random()*.4+.1});"
        "function drw(){cx.clearRect(0,0,cv.width,cv.height);"
        "ps.forEach(function(p){p.x+=p.dx;p.y+=p.dy;"
        "if(p.x<0)p.x=cv.width;if(p.x>cv.width)p.x=0;"
        "if(p.y<0)p.y=cv.height;if(p.y>cv.height)p.y=0;"
        "cx.beginPath();cx.arc(p.x,p.y,p.r,0,Math.PI*2);"
        "cx.fillStyle='rgba(168,85,247,'+p.a+')';cx.fill();});"
        "requestAnimationFrame(drw);}drw();"
        "init();"
        "</script></body></html>"
    )


def _build_pk_spell_html():
    """Harf Sirala oyunu — harfleri dogru sirada tiklayarak kelimeyi yaz."""
    all_w = _ps_all_words()
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'>"
        "<style>"
        "*{margin:0;padding:0;box-sizing:border-box}"
        "html,body{height:100%;overflow:hidden}"
        "body{background:linear-gradient(135deg,#1a0533,#0d0221,#150530);"
        "font-family:'Segoe UI',system-ui,sans-serif;display:flex;justify-content:center}"
        ".w{width:100%;max-width:820px;height:100vh;position:relative;overflow:hidden;"
        "background:linear-gradient(180deg,rgba(30,10,60,.95),rgba(10,5,30,.98));"
        "border-left:2px solid rgba(168,85,247,.3);border-right:2px solid rgba(168,85,247,.3)}"
        "canvas{position:absolute;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:0}"
        ".ct{position:relative;z-index:1;width:100%;height:100%;display:flex;flex-direction:column;"
        "align-items:center}"
        ".hdr{text-align:center;padding:12px 0 8px;"
        "background:linear-gradient(180deg,rgba(124,58,237,.25),transparent);"
        "border-bottom:1px solid rgba(168,85,247,.2);width:100%}"
        ".hdr h2{font-size:18px;color:#e9d5ff;font-weight:800;"
        "text-shadow:0 0 20px rgba(168,85,247,.6)}"
        ".score{color:#c4b5fd;font-size:14px;margin:6px 0;font-weight:600;"
        "background:rgba(124,58,237,.15);padding:4px 18px;border-radius:20px;"
        "border:1px solid rgba(168,85,247,.25)}"
        ".emoji{font-size:80px;margin:12px 0;"
        "filter:drop-shadow(0 0 25px rgba(168,85,247,.5));"
        "animation:ef 3s ease-in-out infinite}"
        "@keyframes ef{0%,100%{transform:translateY(0) scale(1)}"
        "50%{transform:translateY(-10px) scale(1.05)}}"
        ".slots{display:flex;gap:8px;margin:10px 0;justify-content:center}"
        ".slot{width:44px;height:52px;border-radius:12px;border:2px dashed rgba(168,85,247,.5);"
        "background:rgba(124,58,237,.1);display:flex;align-items:center;justify-content:center;"
        "font-size:28px;font-weight:800;color:#fbbf24;transition:all .3s}"
        ".slot.filled{border-style:solid;border-color:#34d399;"
        "background:rgba(52,211,153,.15);color:#6ee7b7}"
        ".ltrs{display:flex;gap:8px;margin:16px 0;flex-wrap:wrap;justify-content:center;"
        "max-width:400px;padding:0 16px}"
        ".ltr{width:50px;height:54px;border-radius:14px;"
        "border:2px solid rgba(168,85,247,.4);"
        "background:linear-gradient(145deg,rgba(40,20,80,.6),rgba(20,10,50,.8));"
        "cursor:pointer;font-size:26px;font-weight:700;color:#e9d5ff;"
        "display:flex;align-items:center;justify-content:center;"
        "transition:all .3s cubic-bezier(.34,1.56,.64,1);"
        "box-shadow:0 4px 15px rgba(0,0,0,.3)}"
        ".ltr:hover{transform:scale(1.1);border-color:rgba(168,85,247,.8)}"
        ".ltr.used{opacity:.2;pointer-events:none;transform:scale(.8)}"
        ".ltr.wrong{border-color:#f87171;animation:sh .4s ease}"
        "@keyframes sh{0%,100%{transform:translateX(0)}25%{transform:translateX(-8px)}"
        "75%{transform:translateX(8px)}}"
        ".prog{display:flex;gap:5px;margin:8px 0;flex-wrap:wrap;justify-content:center}"
        ".dot{width:12px;height:12px;border-radius:50%;background:rgba(168,85,247,.2);"
        "border:1px solid rgba(168,85,247,.3);transition:all .3s}"
        ".dot.dn{background:#34d399;border-color:#6ee7b7}"
        ".dot.cur{background:#fbbf24;border-color:#fcd34d;transform:scale(1.4)}"
        ".end{position:absolute;inset:0;z-index:10;display:none;flex-direction:column;"
        "align-items:center;justify-content:center;background:rgba(10,2,33,.95);"
        "backdrop-filter:blur(20px)}"
        ".end.show{display:flex}"
        ".end h2{font-size:34px;color:#e9d5ff;margin:8px}"
        ".end p{color:#c4b5fd;font-size:18px}"
        ".rbtn{padding:14px 40px;font-size:18px;font-weight:700;border-radius:50px;"
        "border:2px solid rgba(196,181,253,.3);cursor:pointer;color:#fff;margin-top:16px;"
        "background:linear-gradient(135deg,#7c3aed,#6d28d9);"
        "box-shadow:0 0 20px rgba(124,58,237,.4);transition:all .3s}"
        ".rbtn:hover{transform:scale(1.08)}"
        "</style></head><body>"
        "<div class='w'><canvas id='cv'></canvas>"
        "<div class='ct'>"
        "<div class='hdr'><h2>\U0001F520 Harf S\u0131rala</h2></div>"
        "<div class='score' id='sc'>0 / 8</div>"
        "<div class='prog' id='pg'></div>"
        "<div class='emoji' id='em'></div>"
        "<div class='slots' id='sl'></div>"
        "<div class='ltrs' id='lt'></div>"
        "</div>"
        "<div class='end' id='ed'>"
        "<div style='font-size:80px'>&#127942;</div>"
        "<h2 id='et'></h2><p id='es'></p>"
        "<div class='rbtn' onclick='init()'>Tekrar Oyna</div>"
        "</div></div>"
        "<script>"
        "try{window.speechSynthesis.cancel()}catch(e){}"
        "var W=" + all_w + ";"
        "var pool,qi,pts,cur,typed;"
        "function shuf(a){for(var i=a.length-1;i>0;i--){var j=Math.floor(Math.random()*(i+1));"
        "var t=a[i];a[i]=a[j];a[j]=t;}return a;}"
        "var _bV=null;function fBV(){if(_bV)return _bV;var vs=speechSynthesis.getVoices();"
        "var pr=['Google UK English Female','Google US English','Microsoft Zira','Microsoft Jenny','Samantha','Karen','Daniel','Moira'];"
        "for(var p=0;p<pr.length;p++){for(var i=0;i<vs.length;i++){if(vs[i].name.indexOf(pr[p])>=0&&vs[i].lang.indexOf('en')===0){_bV=vs[i];return _bV}}}"
        "for(var i=0;i<vs.length;i++){if(vs[i].lang.indexOf('en')===0){_bV=vs[i];return _bV}}return null}"
        "function spk(t){if(!window._uc){if(!window._ucL){window._ucL=1;document.addEventListener('click',function(){window._uc=1});document.addEventListener('touchstart',function(){window._uc=1})}return;}try{var u=new SpeechSynthesisUtterance(t);u.lang='en-US';"
        "u.rate=0.8;u.pitch=1.1;var bv=fBV();if(bv)u.voice=bv;speechSynthesis.cancel();speechSynthesis.speak(u);}catch(e){}}"
        "function init(){"
        "document.getElementById('ed').classList.remove('show');"
        "var short=W.filter(function(x){return x[1].length<=7&&x[1].indexOf(' ')<0;});"
        "pool=shuf(short).slice(0,8);qi=0;pts=0;show();}"
        "function show(){"
        "if(qi>=8){endG();return;}"
        "cur=pool[qi];typed='';"
        "document.getElementById('em').textContent=String.fromCodePoint(cur[0]);"
        "document.getElementById('sc').textContent=pts+' / 8';"
        "var pg=document.getElementById('pg');pg.innerHTML='';"
        "for(var i=0;i<8;i++){var d=document.createElement('div');"
        "d.className='dot';if(i<qi)d.classList.add('dn');"
        "if(i===qi)d.classList.add('cur');pg.appendChild(d);}"
        "var w=cur[1].toUpperCase();"
        "var sl=document.getElementById('sl');sl.innerHTML='';"
        "for(var i=0;i<w.length;i++){var s=document.createElement('div');"
        "s.className='slot';s.id='s'+i;sl.appendChild(s);}"
        "var letters=shuf(w.split(''));"
        "var lt=document.getElementById('lt');lt.innerHTML='';"
        "letters.forEach(function(l,i){"
        "var b=document.createElement('div');b.className='ltr';b.textContent=l;b.id='l'+i;"
        "b.onclick=function(){pickL(l,i,b);};lt.appendChild(b);});}"
        "function pickL(l,i,el){"
        "var w=cur[1].toUpperCase();"
        "if(w[typed.length]===l){"
        "el.classList.add('used');typed+=l;"
        "document.getElementById('s'+(typed.length-1)).textContent=l;"
        "document.getElementById('s'+(typed.length-1)).classList.add('filled');"
        "if(typed.length===w.length){pts++;spk(cur[1]);"
        "setTimeout(function(){qi++;show();},1200);}"
        "}else{el.classList.add('wrong');"
        "setTimeout(function(){el.classList.remove('wrong');},400);}}"
        "function endG(){"
        "document.getElementById('et').textContent="
        "pts>=7?'Muhtesem! '+String.fromCodePoint(0x1F929):"
        "pts>=4?'Guzel! '+String.fromCodePoint(0x1F60A):"
        "'Tekrar Dene! '+String.fromCodePoint(0x1F4AA);"
        "document.getElementById('es').textContent=pts+' / 8 dogru';"
        "document.getElementById('ed').classList.add('show');}"
        "var cv=document.getElementById('cv'),cx=cv.getContext('2d');"
        "function rsz(){cv.width=cv.offsetWidth;cv.height=cv.offsetHeight;}rsz();"
        "window.addEventListener('resize',rsz);"
        "var ps=[];for(var i=0;i<30;i++)ps.push({x:Math.random()*cv.width,"
        "y:Math.random()*cv.height,r:Math.random()*2+.8,"
        "dx:(Math.random()-.5)*.4,dy:(Math.random()-.5)*.4,"
        "a:Math.random()*.4+.1});"
        "function drw(){cx.clearRect(0,0,cv.width,cv.height);"
        "ps.forEach(function(p){p.x+=p.dx;p.y+=p.dy;"
        "if(p.x<0)p.x=cv.width;if(p.x>cv.width)p.x=0;"
        "if(p.y<0)p.y=cv.height;if(p.y>cv.height)p.y=0;"
        "cx.beginPath();cx.arc(p.x,p.y,p.r,0,Math.PI*2);"
        "cx.fillStyle='rgba(168,85,247,'+p.a+')';cx.fill();});"
        "requestAnimationFrame(drw);}drw();"
        "init();"
        "</script></body></html>"
    )


