        "[0x1F347,'Grape'],[0x1F353,'Strawberry'],[0x1F349,'Watermelon'],"
        "[0x1F351,'Peach'],[0x1F352,'Cherry'],[0x1F34D,'Pineapple']]},"
        "{name:'Vehicles',items:[[0x1F697,'Car'],[0x1F68C,'Bus'],[0x1F682,'Train'],"
        "[0x2708,'Airplane'],[0x1F6A2,'Ship'],[0x1F6B2,'Bicycle'],"
        "[0x1F680,'Rocket'],[0x1F695,'Taxi'],[0x1F691,'Ambulance']]},"
        "{name:'Foods',items:[[0x1F355,'Pizza'],[0x1F354,'Hamburger'],[0x1F95A,'Egg'],"
        "[0x1F9C0,'Cheese'],[0x1F35E,'Bread'],[0x1F95B,'Milk'],"
        "[0x1F955,'Carrot'],[0x1F36B,'Chocolate'],[0x1F33D,'Corn']]},"
        "{name:'Nature',items:[[0x1F333,'Tree'],[0x1F33B,'Flower'],[0x2B50,'Star'],"
        "[0x26F0,'Mountain'],[0x1F30A,'Wave'],[0x1F331,'Plant'],"
        "[0x1F344,'Mushroom'],[0x1F343,'Leaf'],[0x1F41A,'Shell']]},"
        "{name:'Music',items:[[0x1F3B8,'Guitar'],[0x1F3B9,'Piano'],[0x1F941,'Drum'],"
        "[0x1F3BA,'Trumpet'],[0x1F3BB,'Violin'],[0x1F3A4,'Microphone'],"
        "[0x1F3B7,'Saxophone'],[0x1F514,'Bell'],[0x1F50A,'Speaker']]}"
        "];"
        "var c0,c1,items,qi,pts;"
        "function shuf(a){for(var i=a.length-1;i>0;i--){var j=Math.floor(Math.random()*(i+1));"
        "var t=a[i];a[i]=a[j];a[j]=t;}return a;}"
        "var _bV=null;function fBV(){if(_bV)return _bV;var vs=speechSynthesis.getVoices();"
        "var pr=['Google UK English Female','Google US English','Microsoft Zira','Microsoft Jenny','Samantha','Karen','Daniel','Moira'];"
        "for(var p=0;p<pr.length;p++){for(var i=0;i<vs.length;i++){if(vs[i].name.indexOf(pr[p])>=0&&vs[i].lang.indexOf('en')===0){_bV=vs[i];return _bV}}}"
        "for(var i=0;i<vs.length;i++){if(vs[i].lang.indexOf('en')===0){_bV=vs[i];return _bV}}return null}"
        "function spk(t){if(!window._uc){if(!window._ucL){window._ucL=1;document.addEventListener('click',function(){window._uc=1});document.addEventListener('touchstart',function(){window._uc=1})}return;}try{var u=new SpeechSynthesisUtterance(t);u.lang='en-US';"
        "u.rate=0.8;u.pitch=1.1;var bv=fBV();if(bv)u.voice=bv;speechSynthesis.cancel();speechSynthesis.speak(u);}catch(e){}}"
        "function init(){"
        "document.getElementById('ed').classList.remove('show');"
        "var pairs=shuf(CATS.slice());c0=pairs[0];c1=pairs[1];"
        "items=shuf(c0.items.slice(0,5).map(function(x){return{cp:x[0],w:x[1],cat:0};})"
        ".concat(c1.items.slice(0,5).map(function(x){return{cp:x[0],w:x[1],cat:1};})));"
        "qi=0;pts=0;"
        "document.getElementById('ct0').textContent=c0.name;"
        "document.getElementById('ct1').textContent=c1.name;"
        "document.getElementById('ci0').innerHTML='';"
        "document.getElementById('ci1').innerHTML='';"
        "show();}"
        "function show(){"
        "if(qi>=10){endG();return;}"
        "var it=items[qi];"
        "document.getElementById('it').textContent=String.fromCodePoint(it.cp);"
        "document.getElementById('iw').textContent=it.w;"
        "document.getElementById('sc').textContent=pts+' / 10';"
        "document.getElementById('c0').classList.remove('ok','no');"
        "document.getElementById('c1').classList.remove('ok','no');"
        "var pg=document.getElementById('pg');pg.innerHTML='';"
        "for(var i=0;i<10;i++){var d=document.createElement('div');"
        "d.className='dot';if(i<qi)d.classList.add('dn');"
        "if(i===qi)d.classList.add('cur');pg.appendChild(d);}}"
        "function pick(ci){"
        "var it=items[qi];"
