# -- 3. Sinif Oyunlar --

def _build_pk3_sentence_builder_html():
    """Cumle Kur oyunu — karisik kelimeleri dogru sirada tap ederek cumle olustur."""
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'>"
        "<style>"
        "*{margin:0;padding:0;box-sizing:border-box}"
        "html,body{height:100%;overflow:hidden}"
        "body{background:linear-gradient(135deg,#1a0533 0%,#0d0221 50%,#150530 100%);"
        "font-family:'Segoe UI',system-ui,sans-serif;display:flex;justify-content:center}"
        ".w{width:100%;max-width:820px;height:100vh;position:relative;overflow:hidden;"
        "background:linear-gradient(180deg,rgba(30,10,60,.95),rgba(10,5,30,.98));"
        "border-left:2px solid rgba(168,85,247,.3);border-right:2px solid rgba(168,85,247,.3)}"
        "canvas{position:absolute;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:0}"
        ".ct{position:relative;z-index:1;width:100%;height:100%;display:flex;flex-direction:column;"
        "align-items:center}"
        ".hdr{text-align:center;padding:12px 0 8px;"
        "background:linear-gradient(180deg,rgba(124,58,237,.25),transparent);"
        "border-bottom:1px solid rgba(168,85,247,.2);width:100%}"
        ".hdr h2{font-size:18px;color:#e9d5ff;font-weight:800;"
        "text-shadow:0 0 20px rgba(168,85,247,.6)}"
        ".score{color:#c4b5fd;font-size:14px;margin:4px 0;font-weight:600;"
        "background:rgba(124,58,237,.15);padding:4px 18px;border-radius:20px;"
        "border:1px solid rgba(168,85,247,.25)}"
        ".hint-emoji{font-size:70px;margin:10px 0;"
        "filter:drop-shadow(0 0 25px rgba(168,85,247,.5));"
        "animation:ef 3s ease-in-out infinite}"
        "@keyframes ef{0%,100%{transform:translateY(0) scale(1)}"
        "50%{transform:translateY(-8px) scale(1.05)}}"
        ".slots{display:flex;gap:8px;flex-wrap:wrap;justify-content:center;"
        "max-width:700px;margin:8px auto;padding:0 16px;min-height:50px;align-items:center}"
        ".slot{padding:8px 14px;border-radius:12px;border:2px dashed rgba(168,85,247,.4);"
        "background:rgba(124,58,237,.1);font-size:17px;font-weight:700;color:#fbbf24;"
        "min-width:50px;text-align:center;transition:all .3s;min-height:42px;"
        "display:flex;align-items:center;justify-content:center}"
        ".slot.filled{border-style:solid;border-color:#34d399;"
        "background:rgba(52,211,153,.15);color:#6ee7b7;"
        "animation:pop .3s ease}"
        "@keyframes pop{0%{transform:scale(1)}50%{transform:scale(1.15)}100%{transform:scale(1)}}"
        ".words{display:flex;gap:8px;flex-wrap:wrap;justify-content:center;"
        "max-width:700px;margin:12px auto;padding:0 16px}"
        ".word-btn{padding:10px 16px;border-radius:14px;"
        "border:2px solid rgba(168,85,247,.4);"
        "background:linear-gradient(145deg,rgba(40,20,80,.6),rgba(20,10,50,.8));"
        "cursor:pointer;font-size:16px;font-weight:700;color:#e9d5ff;"
        "transition:all .3s cubic-bezier(.34,1.56,.64,1);"
        "box-shadow:0 4px 15px rgba(0,0,0,.3)}"
        ".word-btn:hover{transform:scale(1.1);border-color:rgba(168,85,247,.8);"
        "box-shadow:0 6px 25px rgba(124,58,237,.5)}"
        ".word-btn.used{opacity:.15;pointer-events:none;transform:scale(.8)}"
        ".word-btn.wrong{border-color:#f87171;animation:sh .4s ease}"
        "@keyframes sh{0%,100%{transform:translateX(0)}25%{transform:translateX(-8px)}"
        "75%{transform:translateX(8px)}}"
        ".fb{text-align:center;font-size:16px;font-weight:700;min-height:26px;margin:4px 0}"
        ".fb.ok{color:#34d399;text-shadow:0 0 12px rgba(52,211,153,.5)}"
        ".fb.no{color:#f87171}"
        ".prog{display:flex;gap:5px;margin:6px 0;flex-wrap:wrap;justify-content:center}"
        ".dot{width:12px;height:12px;border-radius:50%;background:rgba(168,85,247,.2);"
        "border:1px solid rgba(168,85,247,.3);transition:all .3s}"
        ".dot.dn{background:#34d399;border-color:#6ee7b7}"
        ".dot.cur{background:#fbbf24;border-color:#fcd34d;transform:scale(1.4);"
        "box-shadow:0 0 8px rgba(251,191,36,.6)}"
        ".end{position:absolute;inset:0;z-index:10;display:none;flex-direction:column;"
        "align-items:center;justify-content:center;background:rgba(10,2,33,.95);"
        "backdrop-filter:blur(20px)}"
        ".end.show{display:flex}"
        ".end h2{font-size:34px;color:#e9d5ff;margin:8px}"
        ".end p{color:#c4b5fd;font-size:18px}"
        ".rbtn{padding:14px 40px;font-size:18px;font-weight:700;border-radius:50px;"
        "border:2px solid rgba(196,181,253,.3);cursor:pointer;color:#fff;margin-top:16px;"
        "background:linear-gradient(135deg,#7c3aed,#6d28d9);"
        "box-shadow:0 0 20px rgba(124,58,237,.4);transition:all .3s}"
        ".rbtn:hover{transform:scale(1.08)}"
        "</style></head><body>"
        "<div class='w'><canvas id='cv'></canvas>"
        "<div class='ct'>"
        "<div class='hdr'><h2>\U0001F4DD Cumle Kur — Sentence Builder</h2></div>"
        "<div class='score' id='sc'>0 / 10</div>"
        "<div class='prog' id='pg'></div>"
        "<div class='hint-emoji' id='em'></div>"
        "<div class='slots' id='sl'></div>"
        "<div class='words' id='wr'></div>"
        "<div class='fb' id='fb'></div>"
        "</div>"
        "<div class='end' id='ed'>"
        "<div style='font-size:80px'>&#127942;</div>"
        "<h2 id='et'></h2><p id='es'></p>"
        "<div class='rbtn' onclick='init()'>Play Again</div>"
        "</div></div>"
        "<script>"
        "try{window.speechSynthesis.cancel()}catch(e){}"
        "var SENTS=["
        "{s:'I have a big dog',e:0x1F415},"
        "{s:'The cat is sleeping',e:0x1F408},"
        "{s:'She likes red apples',e:0x1F34E},"
        "{s:'We go to school',e:0x1F3EB},"
        "{s:'He can run fast',e:0x1F3C3},"
        "{s:'The bird is singing',e:0x1F426},"
        "{s:'I drink cold water',e:0x1F4A7},"
        "{s:'They play in the park',e:0x1F3DE},"
        "{s:'My mother is kind',e:0x1F469},"
        "{s:'The sun is very hot',e:0x2600},"
        "{s:'I read a good book',e:0x1F4D6},"
        "{s:'The fish swims fast',e:0x1F41F}"
        "];"
        "var pool,qi,pts,cur,typed;"
        "function shuf(a){for(var i=a.length-1;i>0;i--){var j=Math.floor(Math.random()*(i+1));"
        "var t=a[i];a[i]=a[j];a[j]=t;}return a;}"
        "var _bV=null;function fBV(){if(_bV)return _bV;var vs=speechSynthesis.getVoices();"
        "var pr=['Google UK English Female','Google US English','Microsoft Zira','Microsoft Jenny','Samantha','Karen','Daniel','Moira'];"
        "for(var p=0;p<pr.length;p++){for(var i=0;i<vs.length;i++){if(vs[i].name.indexOf(pr[p])>=0&&vs[i].lang.indexOf('en')===0){_bV=vs[i];return _bV}}}"
        "for(var i=0;i<vs.length;i++){if(vs[i].lang.indexOf('en')===0){_bV=vs[i];return _bV}}return null}"
        "function spk(t){if(!window._uc){if(!window._ucL){window._ucL=1;document.addEventListener('click',function(){window._uc=1});document.addEventListener('touchstart',function(){window._uc=1})}return;}try{var u=new SpeechSynthesisUtterance(t);u.lang='en-US';"
        "u.rate=0.8;u.pitch=1.1;var bv=fBV();if(bv)u.voice=bv;speechSynthesis.cancel();speechSynthesis.speak(u);}catch(e){}}"
        "function init(){"
        "document.getElementById('ed').classList.remove('show');"
        "pool=shuf(SENTS.slice()).slice(0,10);qi=0;pts=0;show();}"
        "function show(){"
        "if(qi>=10){endG();return;}"
        "cur=pool[qi];typed=0;"
        "document.getElementById('em').textContent=String.fromCodePoint(cur.e);"
        "document.getElementById('sc').textContent=pts+' / 10';"
        "document.getElementById('fb').textContent='';document.getElementById('fb').className='fb';"
        "var pg=document.getElementById('pg');pg.innerHTML='';"
        "for(var i=0;i<10;i++){var d=document.createElement('div');"
        "d.className='dot';if(i<qi)d.classList.add('dn');"
        "if(i===qi)d.classList.add('cur');pg.appendChild(d);}"
        "var words=cur.s.split(' ');"
        "var sl=document.getElementById('sl');sl.innerHTML='';"
        "for(var i=0;i<words.length;i++){"
        "var s=document.createElement('div');"
        "s.className='slot';s.id='sl'+i;sl.appendChild(s);}"
        "var shuffled=shuf(words.slice());"
        "var wr=document.getElementById('wr');wr.innerHTML='';"
        "shuffled.forEach(function(w,i){"
        "var b=document.createElement('div');b.className='word-btn';"
        "b.textContent=w;b.id='wb'+i;"
        "b.onclick=function(){pickW(w,i,b);};wr.appendChild(b);});}"
        "function pickW(w,i,el){"
        "if(el.classList.contains('used')||el.classList.contains('wrong'))return;"
        "var words=cur.s.split(' ');"
        "if(w===words[typed]){"
        "el.classList.add('used');"
        "var sl=document.getElementById('sl'+typed);"
        "sl.textContent=w;sl.classList.add('filled');"
        "typed++;"
        "if(typed===words.length){"
        "pts++;spk(cur.s);"
        "document.getElementById('fb').textContent='\u2705 Correct!';"
        "document.getElementById('fb').className='fb ok';"
        "setTimeout(function(){qi++;show();},1400);"
        "}"
        "}else{"
        "el.classList.add('wrong');"
        "document.getElementById('fb').textContent='\u274C Try again!';"
        "document.getElementById('fb').className='fb no';"
        "setTimeout(function(){"
        "el.classList.remove('wrong');"
        "document.getElementById('fb').textContent='';"
        "document.getElementById('fb').className='fb';"
        "},500);}}"
        "function endG(){"
        "document.getElementById('et').textContent="
        "pts>=9?'Excellent! '+String.fromCodePoint(0x1F929):"
        "pts>=7?'Great! '+String.fromCodePoint(0x1F60A):"
        "pts>=5?'Good! '+String.fromCodePoint(0x1F44D):"
        "'Keep Trying! '+String.fromCodePoint(0x1F4AA);"
        "document.getElementById('es').textContent=pts+' / 10 correct';"
        "document.getElementById('ed').classList.add('show');}"
        "var cv=document.getElementById('cv'),cx=cv.getContext('2d');"
        "function rsz(){cv.width=cv.offsetWidth;cv.height=cv.offsetHeight;}rsz();"
        "window.addEventListener('resize',rsz);"
        "var ps=[];for(var i=0;i<30;i++)ps.push({x:Math.random()*cv.width,"
        "y:Math.random()*cv.height,r:Math.random()*2+.8,"
        "dx:(Math.random()-.5)*.4,dy:(Math.random()-.5)*.4,"
        "a:Math.random()*.4+.1});"
        "function drw(){cx.clearRect(0,0,cv.width,cv.height);"
        "ps.forEach(function(p){p.x+=p.dx;p.y+=p.dy;"
        "if(p.x<0)p.x=cv.width;if(p.x>cv.width)p.x=0;"
        "if(p.y<0)p.y=cv.height;if(p.y>cv.height)p.y=0;"
        "cx.beginPath();cx.arc(p.x,p.y,p.r,0,Math.PI*2);"
        "cx.fillStyle='rgba(168,85,247,'+p.a+')';cx.fill();});"
        "requestAnimationFrame(drw);}drw();"
        "init();"
        "</script></body></html>"
    )


def _build_pk3_spelling_bee_html():
    """Spelling Bee oyunu — emoji goster, TTS soyle, harfleri tek tek yaz."""
    all_w = _ps_all_words()
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'>"
        "<style>"
        "*{margin:0;padding:0;box-sizing:border-box}"
        "html,body{height:100%;overflow:hidden}"
        "body{background:linear-gradient(135deg,#1a0533 0%,#0d0221 50%,#150530 100%);"
        "font-family:'Segoe UI',system-ui,sans-serif;display:flex;justify-content:center}"
        ".w{width:100%;max-width:820px;height:100vh;position:relative;overflow:hidden;"
        "background:linear-gradient(180deg,rgba(30,10,60,.95),rgba(10,5,30,.98));"
        "border-left:2px solid rgba(168,85,247,.3);border-right:2px solid rgba(168,85,247,.3)}"
        "canvas{position:absolute;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:0}"
        ".ct{position:relative;z-index:1;width:100%;height:100%;display:flex;flex-direction:column;"
        "align-items:center}"
        ".hdr{text-align:center;padding:12px 0 8px;"
        "background:linear-gradient(180deg,rgba(124,58,237,.25),transparent);"
        "border-bottom:1px solid rgba(168,85,247,.2);width:100%}"
        ".hdr h2{font-size:18px;color:#e9d5ff;font-weight:800;"
        "text-shadow:0 0 20px rgba(168,85,247,.6)}"
        ".score{color:#c4b5fd;font-size:14px;margin:4px 0;font-weight:600;"
        "background:rgba(124,58,237,.15);padding:4px 18px;border-radius:20px;"
        "border:1px solid rgba(168,85,247,.25)}"
        ".emoji{font-size:80px;margin:10px 0;"
        "filter:drop-shadow(0 0 25px rgba(168,85,247,.5));"
        "animation:ef 3s ease-in-out infinite}"
        "@keyframes ef{0%,100%{transform:translateY(0) scale(1)}"
        "50%{transform:translateY(-8px) scale(1.05)}}"
        ".listen-btn{margin:6px 0;padding:8px 22px;border-radius:22px;cursor:pointer;"
        "background:linear-gradient(135deg,#7c3aed,#6d28d9);"
        "border:2px solid rgba(196,181,253,.3);"
        "color:#e9d5ff;font-size:14px;font-weight:700;transition:all .3s;"
        "box-shadow:0 4px 15px rgba(124,58,237,.4)}"
        ".listen-btn:hover{transform:scale(1.08);box-shadow:0 6px 25px rgba(124,58,237,.6)}"
        ".boxes{display:flex;gap:8px;margin:10px 0;justify-content:center;flex-wrap:wrap;"
        "max-width:600px;padding:0 16px}"
        ".lbox{width:46px;height:54px;border-radius:12px;border:2px solid rgba(168,85,247,.4);"
        "background:rgba(124,58,237,.1);display:flex;align-items:center;justify-content:center;"
        "font-size:26px;font-weight:800;color:#fbbf24;transition:all .3s}"
        ".lbox.ok{border-color:#34d399;background:rgba(52,211,153,.15);color:#6ee7b7;"
        "box-shadow:0 0 15px rgba(52,211,153,.3)}"
        ".lbox.current{border-color:#a855f7;box-shadow:0 0 12px rgba(168,85,247,.6);"
        "background:rgba(124,58,237,.25)}"
        ".lbox.wrong{border-color:#f87171;background:rgba(248,113,113,.1);"
        "animation:sh .4s ease}"
        "@keyframes sh{0%,100%{transform:translateX(0)}25%{transform:translateX(-8px)}"
        "75%{transform:translateX(8px)}}"
        ".inp-wrap{position:relative}"
        "#hinput{position:absolute;opacity:0;pointer-events:none;width:1px;height:1px}"
        ".fb{text-align:center;font-size:16px;font-weight:700;min-height:26px;margin:4px 0}"
        ".fb.ok{color:#34d399;text-shadow:0 0 12px rgba(52,211,153,.5)}"
        ".fb.no{color:#f87171}"
        ".prog{display:flex;gap:5px;margin:6px 0;flex-wrap:wrap;justify-content:center}"
        ".dot{width:12px;height:12px;border-radius:50%;background:rgba(168,85,247,.2);"
        "border:1px solid rgba(168,85,247,.3);transition:all .3s}"
        ".dot.dn{background:#34d399;border-color:#6ee7b7}"
        ".dot.cur{background:#fbbf24;border-color:#fcd34d;transform:scale(1.4);"
        "box-shadow:0 0 8px rgba(251,191,36,.6)}"
        ".end{position:absolute;inset:0;z-index:10;display:none;flex-direction:column;"
        "align-items:center;justify-content:center;background:rgba(10,2,33,.95);"
        "backdrop-filter:blur(20px)}"
        ".end.show{display:flex}"
        ".end h2{font-size:34px;color:#e9d5ff;margin:8px}"
        ".end p{color:#c4b5fd;font-size:18px}"
        ".rbtn{padding:14px 40px;font-size:18px;font-weight:700;border-radius:50px;"
        "border:2px solid rgba(196,181,253,.3);cursor:pointer;color:#fff;margin-top:16px;"
        "background:linear-gradient(135deg,#7c3aed,#6d28d9);"
        "box-shadow:0 0 20px rgba(124,58,237,.4);transition:all .3s}"
        ".rbtn:hover{transform:scale(1.08)}"
        "</style></head><body>"
        "<div class='w'><canvas id='cv'></canvas>"
        "<div class='ct'>"
        "<div class='hdr'><h2>\U0001F41D Spelling Bee</h2></div>"
        "<div class='score' id='sc'>0 / 10</div>"
        "<div class='prog' id='pg'></div>"
        "<div class='emoji' id='em'></div>"
        "<button class='listen-btn' onclick='spk(cur[1])' id='lbtn'>\U0001F50A Listen Again</button>"
        "<div class='boxes' id='bx'></div>"
        "<div class='inp-wrap'><input id='hinput' autocomplete='off' autocorrect='off'"
        " autocapitalize='off' spellcheck='false'/></div>"
        "<div class='fb' id='fb'></div>"
        "</div>"
        "<div class='end' id='ed'>"
        "<div style='font-size:80px'>&#127942;</div>"
        "<h2 id='et'></h2><p id='es'></p>"
        "<div class='rbtn' onclick='init()'>Play Again</div>"
        "</div></div>"
        "<script>"
        "try{window.speechSynthesis.cancel()}catch(e){}"
        "var W=" + all_w + ";"
        "var pool,qi,pts,cur,typed,locked;"
        "function shuf(a){for(var i=a.length-1;i>0;i--){var j=Math.floor(Math.random()*(i+1));"
        "var t=a[i];a[i]=a[j];a[j]=t;}return a;}"
        "var _bV=null;function fBV(){if(_bV)return _bV;var vs=speechSynthesis.getVoices();"
        "var pr=['Google UK English Female','Google US English','Microsoft Zira','Microsoft Jenny','Samantha','Karen','Daniel','Moira'];"
        "for(var p=0;p<pr.length;p++){for(var i=0;i<vs.length;i++){if(vs[i].name.indexOf(pr[p])>=0&&vs[i].lang.indexOf('en')===0){_bV=vs[i];return _bV}}}"
        "for(var i=0;i<vs.length;i++){if(vs[i].lang.indexOf('en')===0){_bV=vs[i];return _bV}}return null}"
        "function spk(t){if(!window._uc){if(!window._ucL){window._ucL=1;document.addEventListener('click',function(){window._uc=1});document.addEventListener('touchstart',function(){window._uc=1})}return;}try{var u=new SpeechSynthesisUtterance(t);u.lang='en-US';"
        "u.rate=0.8;u.pitch=1.1;var bv=fBV();if(bv)u.voice=bv;speechSynthesis.cancel();speechSynthesis.speak(u);}catch(e){}}"
        "function init(){"
        "document.getElementById('ed').classList.remove('show');"
        "var short=W.filter(function(x){return x[1].length<=8&&x[1].indexOf(' ')<0;});"
        "pool=shuf(short).slice(0,10);qi=0;pts=0;show();}"
        "function show(){"
        "if(qi>=10){endG();return;}"
        "cur=pool[qi];typed='';locked=false;"
        "document.getElementById('em').textContent=String.fromCodePoint(cur[0]);"
        "document.getElementById('sc').textContent=pts+' / 10';"
        "document.getElementById('fb').textContent='';document.getElementById('fb').className='fb';"
        "var pg=document.getElementById('pg');pg.innerHTML='';"
        "for(var i=0;i<10;i++){var d=document.createElement('div');"
        "d.className='dot';if(i<qi)d.classList.add('dn');"
        "if(i===qi)d.classList.add('cur');pg.appendChild(d);}"
        "renderBoxes();"
        "setTimeout(function(){spk(cur[1]);},300);"
        "var h=document.getElementById('hinput');h.value='';h.focus();}"
        "function renderBoxes(){"
        "var bx=document.getElementById('bx');bx.innerHTML='';"
        "var w=cur[1];var tlen=typed.length;"
        "for(var i=0;i<w.length;i++){"
        "var d=document.createElement('div');d.className='lbox';"
        "if(i<tlen){d.textContent=typed[i].toUpperCase();d.classList.add('ok');}"
        "else if(i===tlen){d.classList.add('current');}"
        "bx.appendChild(d);}}"
        "document.getElementById('hinput').addEventListener('input',function(ev){"
        "if(locked)return;"
        "var h=this;var val=h.value.replace(/[^a-zA-Z]/g,'');"
        "if(!val){h.value='';return;}"
        "var ch=val[val.length-1].toUpperCase();"
        "h.value='';"
        "var w=cur[1].toUpperCase();"
        "if(ch===w[typed.length]){"
        "typed+=ch;"
        "renderBoxes();"
        "if(typed.length===w.length){"
        "locked=true;pts++;spk(cur[1]);"
        "document.getElementById('fb').textContent='\u2705 Correct!';"
        "document.getElementById('fb').className='fb ok';"
        "setTimeout(function(){qi++;show();},1500);}"
        "}else{"
        "var bx=document.getElementById('bx');"
        "var boxes=bx.getElementsByClassName('lbox');"
        "if(boxes[typed.length]){boxes[typed.length].classList.add('wrong');"
        "setTimeout(function(){if(boxes[typed.length])boxes[typed.length].classList.remove('wrong');},400);}"
        "document.getElementById('fb').textContent='\u274C Wrong letter!';"
        "document.getElementById('fb').className='fb no';"
        "setTimeout(function(){document.getElementById('fb').textContent='';"
        "document.getElementById('fb').className='fb';},600);}});"
        "document.addEventListener('click',function(e){"
        "if(!document.getElementById('ed').classList.contains('show')){"
        "document.getElementById('hinput').focus();}});"
        "function endG(){"
        "document.getElementById('et').textContent="
        "pts>=9?'Excellent! '+String.fromCodePoint(0x1F929):"
        "pts>=7?'Great! '+String.fromCodePoint(0x1F60A):"
        "pts>=5?'Good! '+String.fromCodePoint(0x1F44D):"
        "'Keep Trying! '+String.fromCodePoint(0x1F4AA);"
        "document.getElementById('es').textContent=pts+' / 10 correct';"
        "document.getElementById('ed').classList.add('show');}"
        "var cv=document.getElementById('cv'),cx=cv.getContext('2d');"
        "function rsz(){cv.width=cv.offsetWidth;cv.height=cv.offsetHeight;}rsz();"
        "window.addEventListener('resize',rsz);"
        "var ps=[];for(var i=0;i<30;i++)ps.push({x:Math.random()*cv.width,"
        "y:Math.random()*cv.height,r:Math.random()*2+.8,"
        "dx:(Math.random()-.5)*.4,dy:(Math.random()-.5)*.4,"
        "a:Math.random()*.4+.1});"
        "function drw(){cx.clearRect(0,0,cv.width,cv.height);"
        "ps.forEach(function(p){p.x+=p.dx;p.y+=p.dy;"
        "if(p.x<0)p.x=cv.width;if(p.x>cv.width)p.x=0;"
        "if(p.y<0)p.y=cv.height;if(p.y>cv.height)p.y=0;"
        "cx.beginPath();cx.arc(p.x,p.y,p.r,0,Math.PI*2);"
        "cx.fillStyle='rgba(168,85,247,'+p.a+')';cx.fill();});"
        "requestAnimationFrame(drw);}drw();"
        "init();"
        "</script></body></html>"
    )


def _build_pk3_memory_match_html():
    """Memory Match oyunu — 4x3 kart grid, emoji-kelime cift eslestirme."""
    all_w = _ps_all_words()
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'>"
        "<style>"
        "*{margin:0;padding:0;box-sizing:border-box}"
        "html,body{height:100%;overflow:hidden}"
        "body{background:linear-gradient(135deg,#1a0533 0%,#0d0221 50%,#150530 100%);"
        "font-family:'Segoe UI',system-ui,sans-serif;display:flex;justify-content:center}"
        ".w{width:100%;max-width:820px;height:100vh;position:relative;overflow:hidden;"
        "background:linear-gradient(180deg,rgba(30,10,60,.95),rgba(10,5,30,.98));"
        "border-left:2px solid rgba(168,85,247,.3);border-right:2px solid rgba(168,85,247,.3)}"
        "canvas{position:absolute;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:0}"
        ".ct{position:relative;z-index:1;width:100%;height:100%;display:flex;flex-direction:column;"
        "align-items:center}"
        ".hdr{text-align:center;padding:12px 0 8px;"
        "background:linear-gradient(180deg,rgba(124,58,237,.25),transparent);"
        "border-bottom:1px solid rgba(168,85,247,.2);width:100%}"
        ".hdr h2{font-size:18px;color:#e9d5ff;font-weight:800;"
        "text-shadow:0 0 20px rgba(168,85,247,.6)}"
        ".stats{display:flex;gap:16px;margin:6px 0;justify-content:center;flex-wrap:wrap}"
        ".stat{color:#c4b5fd;font-size:13px;font-weight:600;"
        "background:rgba(124,58,237,.15);padding:4px 14px;border-radius:20px;"
        "border:1px solid rgba(168,85,247,.25)}"
        ".grid{display:grid;grid-template-columns:repeat(4,1fr);"
        "gap:10px;padding:12px 18px;max-width:520px;margin:6px auto;width:100%}"
        ".card{aspect-ratio:.9;border-radius:14px;cursor:pointer;"
        "perspective:600px;position:relative;transition:transform .05s}"
        ".card:hover .card-inner{box-shadow:0 6px 25px rgba(124,58,237,.55)}"
        ".card-inner{width:100%;height:100%;position:relative;"
        "transform-style:preserve-3d;transition:transform .5s cubic-bezier(.4,0,.2,1);"
        "border-radius:14px;box-shadow:0 4px 15px rgba(88,28,135,.4)}"
        ".card.flipped .card-inner{transform:rotateY(180deg)}"
        ".card-front,.card-back{position:absolute;width:100%;height:100%;"
        "border-radius:14px;backface-visibility:hidden;"
        "display:flex;align-items:center;justify-content:center}"
        ".card-front{background:linear-gradient(145deg,rgba(124,58,237,.4),rgba(88,28,135,.6));"
        "border:2px solid rgba(168,85,247,.3);"
        "font-size:28px;color:rgba(168,85,247,.6);font-weight:800}"
        ".card-back{background:linear-gradient(145deg,rgba(30,10,60,.9),rgba(20,5,40,.95));"
        "border:2px solid rgba(168,85,247,.5);"
        "transform:rotateY(180deg)}"
        ".card-back.is-emoji{font-size:38px}"
        ".card-back.is-word{font-size:14px;font-weight:800;color:#e9d5ff;"
        "text-align:center;padding:4px;word-break:break-word}"
        ".card.matched .card-inner{box-shadow:0 0 20px rgba(52,211,153,.5)}"
        ".card.matched .card-back{border-color:#34d399;"
        "background:linear-gradient(145deg,rgba(34,197,94,.25),rgba(22,163,74,.35))}"
        "@keyframes matchPop{0%{transform:scale(1)}40%{transform:scale(1.15)}100%{transform:scale(1)}}"
        ".card.matched{animation:matchPop .4s ease}"
        ".end{position:absolute;inset:0;z-index:10;display:none;flex-direction:column;"
        "align-items:center;justify-content:center;background:rgba(10,2,33,.95);"
        "backdrop-filter:blur(20px)}"
        ".end.show{display:flex}"
        ".end h2{font-size:34px;color:#e9d5ff;margin:8px}"
        ".end p{color:#c4b5fd;font-size:18px}"
        ".rbtn{padding:14px 40px;font-size:18px;font-weight:700;border-radius:50px;"
        "border:2px solid rgba(196,181,253,.3);cursor:pointer;color:#fff;margin-top:16px;"
        "background:linear-gradient(135deg,#7c3aed,#6d28d9);"
        "box-shadow:0 0 20px rgba(124,58,237,.4);transition:all .3s}"
        ".rbtn:hover{transform:scale(1.08)}"
        "</style></head><body>"
        "<div class='w'><canvas id='cv'></canvas>"
        "<div class='ct'>"
        "<div class='hdr'><h2>\U0001F9E0 Memory Match</h2></div>"
        "<div class='stats'>"
        "<span class='stat' id='sMoves'>Moves: 0</span>"
        "<span class='stat' id='sPairs'>Pairs: 0 / 6</span>"
        "</div>"
        "<div class='grid' id='gr'></div>"
        "</div>"
        "<div class='end' id='ed'>"
        "<div style='font-size:70px'>&#127881;</div>"
        "<h2>Well done!</h2><p id='es'></p>"
        "<div class='rbtn' onclick='init()'>Play Again</div>"
        "</div></div>"
        "<script>"
        "try{window.speechSynthesis.cancel()}catch(e){}"
        "var W=" + all_w + ";"
        "var flipped,matched,moves,busy;"
        "function shuf(a){for(var i=a.length-1;i>0;i--){var j=Math.floor(Math.random()*(i+1));"
        "var t=a[i];a[i]=a[j];a[j]=t;}return a;}"
        "var _bV=null;function fBV(){if(_bV)return _bV;var vs=speechSynthesis.getVoices();"
        "var pr=['Google UK English Female','Google US English','Microsoft Zira','Microsoft Jenny','Samantha','Karen','Daniel','Moira'];"
        "for(var p=0;p<pr.length;p++){for(var i=0;i<vs.length;i++){if(vs[i].name.indexOf(pr[p])>=0&&vs[i].lang.indexOf('en')===0){_bV=vs[i];return _bV}}}"
        "for(var i=0;i<vs.length;i++){if(vs[i].lang.indexOf('en')===0){_bV=vs[i];return _bV}}return null}"
        "function spk(t){if(!window._uc){if(!window._ucL){window._ucL=1;document.addEventListener('click',function(){window._uc=1});document.addEventListener('touchstart',function(){window._uc=1})}return;}try{var u=new SpeechSynthesisUtterance(t);u.lang='en-US';"
        "u.rate=0.8;u.pitch=1.1;var bv=fBV();if(bv)u.voice=bv;speechSynthesis.cancel();speechSynthesis.speak(u);}catch(e){}}"
        "function init(){"
        "document.getElementById('ed').classList.remove('show');"
        "flipped=[];matched=0;moves=0;busy=false;"
        "document.getElementById('sMoves').textContent='Moves: 0';"
        "document.getElementById('sPairs').textContent='Pairs: 0 / 6';"
        "var pick=shuf(W.slice()).slice(0,6);"
        "var cards=[];"
        "pick.forEach(function(p,i){"
        "cards.push({id:'e'+i,type:'emoji',cp:p[0],word:p[1],pair:i});"
        "cards.push({id:'w'+i,type:'word',cp:p[0],word:p[1],pair:i});});"
        "shuf(cards);"
        "var gr=document.getElementById('gr');gr.innerHTML='';"
        "cards.forEach(function(c){"
        "var outer=document.createElement('div');outer.className='card';"
        "outer.id='c'+c.id;"
        "var inner=document.createElement('div');inner.className='card-inner';"
        "var front=document.createElement('div');front.className='card-front';"
        "front.textContent='?';"
        "var back=document.createElement('div');"
        "if(c.type==='emoji'){"
        "back.className='card-back is-emoji';"
        "back.textContent=String.fromCodePoint(c.cp);"
        "}else{"
        "back.className='card-back is-word';"
        "back.textContent=c.word;}"
        "inner.appendChild(front);inner.appendChild(back);"
        "outer.appendChild(inner);"
        "outer.dataset.pair=c.pair;outer.dataset.word=c.word;"
        "outer.onclick=function(){flipCard(outer);};"
        "gr.appendChild(outer);});}"
        "function flipCard(el){"
        "if(busy||el.classList.contains('flipped')||el.classList.contains('matched'))return;"
        "el.classList.add('flipped');"
        "flipped.push(el);"
        "if(flipped.length===2){"
        "moves++;"
        "document.getElementById('sMoves').textContent='Moves: '+moves;"
        "busy=true;"
        "if(flipped[0].dataset.pair===flipped[1].dataset.pair){"
        "flipped[0].classList.add('matched');"
        "flipped[1].classList.add('matched');"
        "spk(flipped[0].dataset.word);"
        "matched++;"
        "document.getElementById('sPairs').textContent='Pairs: '+matched+' / 6';"
        "flipped=[];busy=false;"
        "if(matched>=6){"
        "setTimeout(function(){"
        "document.getElementById('es').textContent='You did it in '+moves+' moves!';"
        "document.getElementById('ed').classList.add('show');},600);"
        "}"
        "}else{"
        "var a=flipped[0],b=flipped[1];"
        "setTimeout(function(){"
        "a.classList.remove('flipped');"
        "b.classList.remove('flipped');"
        "flipped=[];busy=false;},1000);}}}"
        "var cv=document.getElementById('cv'),cx=cv.getContext('2d');"
        "function rsz(){cv.width=cv.offsetWidth;cv.height=cv.offsetHeight;}rsz();"
        "window.addEventListener('resize',rsz);"
        "var ps=[];for(var i=0;i<30;i++)ps.push({x:Math.random()*cv.width,"
        "y:Math.random()*cv.height,r:Math.random()*2+.8,"
        "dx:(Math.random()-.5)*.4,dy:(Math.random()-.5)*.4,"
        "a:Math.random()*.4+.1});"
        "function drw(){cx.clearRect(0,0,cv.width,cv.height);"
        "ps.forEach(function(p){p.x+=p.dx;p.y+=p.dy;"
        "if(p.x<0)p.x=cv.width;if(p.x>cv.width)p.x=0;"
        "if(p.y<0)p.y=cv.height;if(p.y>cv.height)p.y=0;"
        "cx.beginPath();cx.arc(p.x,p.y,p.r,0,Math.PI*2);"
        "cx.fillStyle='rgba(168,85,247,'+p.a+')';cx.fill();});"
        "requestAnimationFrame(drw);}drw();"
        "init();"
        "</script></body></html>"
    )


