# -- 4. Sinif Oyunlar --

def _build_pk4_crossword_html():
    """Mini Crossword — 4-5 kelimelik basit bulmaca."""
    all_w = _ps_all_words()
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'>"
        "<style>"
        "*{margin:0;padding:0;box-sizing:border-box}"
        "html,body{height:100%;overflow:hidden}"
        "body{background:linear-gradient(135deg,#1a0533,#0d0221,#150530);"
        "font-family:'Segoe UI',system-ui,sans-serif;display:flex;justify-content:center}"
        ".w{width:100%;max-width:820px;height:100vh;position:relative;overflow:hidden;"
        "background:linear-gradient(180deg,rgba(30,10,60,.95),rgba(10,5,30,.98));"
        "border-left:2px solid rgba(168,85,247,.3);border-right:2px solid rgba(168,85,247,.3)}"
        "canvas{position:absolute;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:0}"
        ".ct{position:relative;z-index:1;width:100%;height:100%;display:flex;flex-direction:column;"
        "align-items:center;overflow-y:auto}"
        ".hdr{text-align:center;padding:12px 0 8px;"
        "background:linear-gradient(180deg,rgba(124,58,237,.25),transparent);"
        "border-bottom:1px solid rgba(168,85,247,.2);width:100%}"
        ".hdr h2{font-size:18px;color:#e9d5ff;font-weight:800;"
        "text-shadow:0 0 20px rgba(168,85,247,.6)}"
        ".clues{display:flex;flex-wrap:wrap;gap:10px;justify-content:center;"
        "margin:12px 16px;max-width:600px}"
        ".clue{background:rgba(124,58,237,.12);border:1px solid rgba(168,85,247,.25);"
        "border-radius:14px;padding:8px 14px;display:flex;align-items:center;gap:8px}"
        ".clue .num{color:#c4b5fd;font-weight:800;font-size:14px}"
        ".clue .em{font-size:28px}"
        ".grid{display:inline-grid;gap:3px;margin:10px auto;padding:10px}"
        ".cell{width:38px;height:38px;border-radius:8px;text-align:center;font-size:18px;"
        "font-weight:700;text-transform:uppercase;outline:none;transition:all .3s;"
        "border:2px solid rgba(168,85,247,.3);background:rgba(124,58,237,.1);color:#e9d5ff}"
        ".cell:focus{border-color:#a78bfa;box-shadow:0 0 12px rgba(168,85,247,.5)}"
        ".cell.ok{background:rgba(52,211,153,.15);border-color:#34d399;color:#6ee7b7}"
        ".cell.blk{background:transparent;border-color:transparent;pointer-events:none}"
        ".fb{text-align:center;font-size:16px;font-weight:700;min-height:24px;margin:8px 0;color:#c4b5fd}"
        ".btn{padding:10px 30px;font-size:16px;font-weight:700;border-radius:50px;"
        "border:2px solid rgba(196,181,253,.3);cursor:pointer;color:#fff;margin:8px;"
        "background:linear-gradient(135deg,#7c3aed,#6d28d9);"
        "box-shadow:0 0 15px rgba(124,58,237,.4);transition:all .3s}"
        ".btn:hover{transform:scale(1.06)}"
        "</style></head><body>"
        "<div class='w'><canvas id='cv'></canvas>"
        "<div class='ct'>"
        "<div class='hdr'><h2>&#128221; Crossword Puzzle</h2></div>"
        "<div id='cluesDiv' class='clues'></div>"
        "<div id='gridDiv'></div>"
        "<div class='fb' id='fb'></div>"
        "<button class='btn' onclick='checkAll()'>&#9989; Check Answers</button>"
        "<button class='btn' onclick='init()'>&#128260; New Puzzle</button>"
        "</div></div>"
        "<script>"
        "var W=" + all_w + ";"
        "function shuf(a){for(var i=a.length-1;i>0;i--){var j=Math.floor(Math.random()*(i+1));"
        "var t=a[i];a[i]=a[j];a[j]=t}return a}"
        "var gData,gRows,gCols;"
        "function init(){"
        "var short=W.filter(function(x){return x[1].length>=3&&x[1].length<=6&&x[1].indexOf(' ')<0});"
        "var picks=shuf(short).slice(0,5);"
        "var words=picks.map(function(p){return{cp:p[0],w:p[1].toUpperCase()}});"
        "words.sort(function(a,b){return b.w.length-a.w.length});"
        "gRows=12;gCols=12;var grid=[];"
        "for(var r=0;r<gRows;r++){grid[r]=[];for(var c=0;c<gCols;c++)grid[r][c]='';}"
        "var placed=[];"
        "var sr=1,sc=Math.floor((gCols-words[0].w.length)/2);"
        "for(var i=0;i<words[0].w.length;i++)grid[sr][sc+i]=words[0].w[i];"
        "placed.push({w:words[0],r:sr,c:sc,dir:'H',num:1});"
        "for(var wi=1;wi<words.length;wi++){"
        "var wd=words[wi],done=false;"
        "for(var pi=0;pi<placed.length&&!done;pi++){"
        "var pw=placed[pi];"
        "for(var ci=0;ci<wd.w.length&&!done;ci++){"
        "for(var pci=0;pci<pw.w.w.length&&!done;pci++){"
        "if(wd.w[ci]===pw.w.w[pci]){"
        "var nr,nc,dir;"
        "if(pw.dir==='H'){dir='V';nr=pw.r-ci;nc=pw.c+pci}"
        "else{dir='H';nr=pw.r+pci;nc=pw.c-ci}"
        "if(nr<0||nc<0||nr+((dir==='V')?wd.w.length:1)>gRows||nc+((dir==='H')?wd.w.length:1)>gCols)continue;"
        "var ok=true;"
        "for(var k=0;k<wd.w.length&&ok;k++){"
        "var tr=nr+(dir==='V'?k:0),tc=nc+(dir==='H'?k:0);"
        "if(grid[tr][tc]!==''&&grid[tr][tc]!==wd.w[k])ok=false}"
        "if(ok){for(var k=0;k<wd.w.length;k++){"
        "var tr=nr+(dir==='V'?k:0),tc=nc+(dir==='H'?k:0);"
        "grid[tr][tc]=wd.w[k]}"
        "placed.push({w:wd,r:nr,c:nc,dir:dir,num:placed.length+1});done=true}"
        "}}}}"
        "if(!done){var rr=placed[0].r+2+wi,rcc=1;"
        "if(rr<gRows-1){for(var k=0;k<wd.w.length&&rcc+k<gCols;k++)grid[rr][rcc+k]=wd.w[k];"
        "placed.push({w:wd,r:rr,c:rcc,dir:'H',num:placed.length+1})}}}"
        "gData={grid:grid,placed:placed};"
        "render()}"
        "function render(){"
        "var cl=document.getElementById('cluesDiv');cl.innerHTML='';"
        "gData.placed.forEach(function(p){"
        "var d=document.createElement('div');d.className='clue';"
        "d.innerHTML='<span class=\"num\">'+p.num+(p.dir==='H'?'\\u2192':'\\u2193')+"
        "'</span><span class=\"em\">'+String.fromCodePoint(p.w.cp)+'</span>';cl.appendChild(d)});"
        "var gd=document.getElementById('gridDiv');"
        "var usedCells={};"
        "gData.placed.forEach(function(p){"
        "for(var k=0;k<p.w.w.length;k++){"
        "var r=p.r+(p.dir==='V'?k:0),c=p.c+(p.dir==='H'?k:0);"
        "usedCells[r+','+c]=true}});"
        "var minR=gRows,maxR=0,minC=gCols,maxC=0;"
        "for(var key in usedCells){var rc=key.split(',');var r=+rc[0],c=+rc[1];"
        "if(r<minR)minR=r;if(r>maxR)maxR=r;if(c<minC)minC=c;if(c>maxC)maxC=c}"
        "var rows=maxR-minR+1,cols=maxC-minC+1;"
        "gd.innerHTML='';var g=document.createElement('div');g.className='grid';"
        "g.style.gridTemplateColumns='repeat('+cols+',38px)';"
        "for(var r=minR;r<=maxR;r++){for(var c=minC;c<=maxC;c++){"
        "if(usedCells[r+','+c]){"
        "var inp=document.createElement('input');inp.className='cell';inp.maxLength=1;"
        "inp.dataset.r=r;inp.dataset.c=c;"
        "var nm='';gData.placed.forEach(function(p){if(p.r===r&&p.c===c)"
        "nm=p.num+(p.dir==='H'?'\\u2192':'\\u2193')});"
        "if(nm)inp.placeholder=nm;"
        "g.appendChild(inp)"
        "}else{var bl=document.createElement('div');bl.className='cell blk';g.appendChild(bl)}}}"
        "gd.appendChild(g);"
        "document.getElementById('fb').textContent=''}"
        "function checkAll(){"
        "var cells=document.querySelectorAll('.cell:not(.blk)');"
        "var all=true;"
        "cells.forEach(function(c){"
        "var r=+c.dataset.r,col=+c.dataset.c,v=c.value.toUpperCase();"
        "if(v===gData.grid[r][col]){c.classList.add('ok');c.classList.remove('cell');"
        "c.className='cell ok'}else{all=false;c.classList.remove('ok');"
        "if(v)c.style.borderColor='#f87171'}});"
        "document.getElementById('fb').textContent=all?'\\u2705 Perfect!':'\\u274C Some letters are wrong';"
        "document.getElementById('fb').style.color=all?'#34d399':'#f87171'}"
        "var cv=document.getElementById('cv'),cx=cv.getContext('2d');"
        "function rsz(){cv.width=cv.offsetWidth;cv.height=cv.offsetHeight}rsz();"
        "window.addEventListener('resize',rsz);"
        "var ps=[];for(var i=0;i<30;i++)ps.push({x:Math.random()*cv.width,"
        "y:Math.random()*cv.height,r:Math.random()*2+.8,"
        "dx:(Math.random()-.5)*.4,dy:(Math.random()-.5)*.4,"
        "a:Math.random()*.4+.1});"
        "function drw(){cx.clearRect(0,0,cv.width,cv.height);"
        "ps.forEach(function(p){p.x+=p.dx;p.y+=p.dy;"
        "if(p.x<0)p.x=cv.width;if(p.x>cv.width)p.x=0;"
        "if(p.y<0)p.y=cv.height;if(p.y>cv.height)p.y=0;"
        "cx.beginPath();cx.arc(p.x,p.y,p.r,0,Math.PI*2);"
        "cx.fillStyle='rgba(168,85,247,'+p.a+')';cx.fill()});"
        "requestAnimationFrame(drw)}drw();"
        "init();"
        "</script></body></html>"
    )


def _build_pk4_word_chain_html():
    """Word Chain — bir onceki kelimenin son harfi ile baslayan kelime sec."""
    all_w = _ps_all_words()
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'>"
        "<style>"
        "*{margin:0;padding:0;box-sizing:border-box}"
        "html,body{height:100%;overflow:hidden}"
        "body{background:linear-gradient(135deg,#1a0533,#0d0221,#150530);"
        "font-family:'Segoe UI',system-ui,sans-serif;display:flex;justify-content:center}"
        ".w{width:100%;max-width:820px;height:100vh;position:relative;overflow:hidden;"
        "background:linear-gradient(180deg,rgba(30,10,60,.95),rgba(10,5,30,.98));"
        "border-left:2px solid rgba(168,85,247,.3);border-right:2px solid rgba(168,85,247,.3)}"
        "canvas{position:absolute;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:0}"
        ".ct{position:relative;z-index:1;width:100%;height:100%;display:flex;flex-direction:column;"
        "align-items:center}"
        ".hdr{text-align:center;padding:12px 0 8px;"
        "background:linear-gradient(180deg,rgba(124,58,237,.25),transparent);"
        "border-bottom:1px solid rgba(168,85,247,.2);width:100%}"
        ".hdr h2{font-size:18px;color:#e9d5ff;font-weight:800;"
        "text-shadow:0 0 20px rgba(168,85,247,.6)}"
        ".score{color:#c4b5fd;font-size:14px;margin:6px 0;font-weight:600;"
        "background:rgba(124,58,237,.15);padding:4px 18px;border-radius:20px;"
        "border:1px solid rgba(168,85,247,.25)}"
        ".chain{display:flex;flex-wrap:wrap;gap:6px;justify-content:center;"
        "margin:8px 16px;max-width:700px;min-height:40px}"
        ".chip{padding:6px 12px;border-radius:20px;font-size:14px;font-weight:600;"
        "background:rgba(52,211,153,.15);border:1px solid #34d399;color:#6ee7b7}"
        ".prompt{font-size:18px;color:#e9d5ff;margin:8px 0;font-weight:700}"
        ".letter{font-size:48px;color:#fbbf24;font-weight:900;margin:4px 0;"
        "text-shadow:0 0 20px rgba(251,191,36,.5)}"
        ".opts{display:flex;flex-wrap:wrap;gap:10px;justify-content:center;"
        "margin:12px 16px;max-width:600px}"
        ".opt{padding:10px 18px;border-radius:16px;cursor:pointer;font-size:16px;"
        "font-weight:600;border:2px solid rgba(168,85,247,.4);"
        "background:linear-gradient(145deg,rgba(40,20,80,.6),rgba(20,10,50,.8));"
        "color:#e9d5ff;transition:all .3s;display:flex;align-items:center;gap:8px}"
        ".opt:hover{transform:scale(1.06);border-color:#a78bfa}"
        ".opt.ok{border-color:#34d399;background:rgba(52,211,153,.15);color:#6ee7b7}"
        ".opt.no{border-color:#f87171;animation:sh .4s ease}"
        "@keyframes sh{0%,100%{transform:translateX(0)}25%{transform:translateX(-6px)}75%{transform:translateX(6px)}}"
        ".fb{text-align:center;font-size:16px;font-weight:700;min-height:24px;margin:4px 0}"
        ".end{position:absolute;inset:0;z-index:10;display:none;flex-direction:column;"
        "align-items:center;justify-content:center;background:rgba(10,2,33,.95)}"
        ".end.show{display:flex}"
        ".end h2{font-size:30px;color:#e9d5ff;margin:8px}"
        ".end p{color:#c4b5fd;font-size:18px}"
        ".rbtn{padding:12px 36px;font-size:16px;font-weight:700;border-radius:50px;"
        "border:2px solid rgba(196,181,253,.3);cursor:pointer;color:#fff;margin-top:14px;"
        "background:linear-gradient(135deg,#7c3aed,#6d28d9);transition:all .3s}"
        ".rbtn:hover{transform:scale(1.06)}"
        "</style></head><body>"
        "<div class='w'><canvas id='cv'></canvas>"
        "<div class='ct'>"
        "<div class='hdr'><h2>&#128279; Word Chain</h2></div>"
        "<div class='score' id='sc'>Chain: 0</div>"
        "<div class='chain' id='ch'></div>"
        "<div class='prompt'>Next word starts with:</div>"
        "<div class='letter' id='lt'></div>"
        "<div class='fb' id='fb'></div>"
        "<div class='opts' id='opts'></div>"
        "</div>"
        "<div class='end' id='ed'>"
        "<div style='font-size:80px'>&#128279;</div>"
        "<h2 id='et'></h2><p id='es'></p>"
        "<div class='rbtn' onclick='init()'>Play Again</div>"
        "</div></div>"
        "<script>"
        "var W=" + all_w + ";"
        "function shuf(a){for(var i=a.length-1;i>0;i--){var j=Math.floor(Math.random()*(i+1));"
        "var t=a[i];a[i]=a[j];a[j]=t}return a}"
        "function spk(t){if(!window._uc){if(!window._ucL){window._ucL=1;document.addEventListener('click',function(){window._uc=1});document.addEventListener('touchstart',function(){window._uc=1})}return;}try{var u=new SpeechSynthesisUtterance(t);u.lang='en-US';"
        "u.rate=0.85;speechSynthesis.cancel();speechSynthesis.speak(u)}catch(e){}}"
        "var pool,chainArr,curLetter,round,maxRound=10,locking;"
        "function init(){"
        "document.getElementById('ed').classList.remove('show');"
        "pool=shuf(W.filter(function(x){return x[1].length<=8&&x[1].indexOf(' ')<0})).slice(0,60);"
        "chainArr=[];round=0;locking=false;"
        "var first=pool.splice(0,1)[0];"
        "chainArr.push(first);curLetter=first[1].slice(-1).toUpperCase();"
        "renderChain();showOpts()}"
        "function renderChain(){"
        "var ch=document.getElementById('ch');ch.innerHTML='';"
        "chainArr.forEach(function(w){var d=document.createElement('div');d.className='chip';"
        "d.textContent=String.fromCodePoint(w[0])+' '+w[1];ch.appendChild(d)});"
        "document.getElementById('sc').textContent='Chain: '+chainArr.length;"
        "document.getElementById('lt').textContent=curLetter;"
        "document.getElementById('fb').textContent=''}"
        "function showOpts(){"
        "if(round>=maxRound){endG();return}"
        "var correct=pool.filter(function(x){return x[1][0].toUpperCase()===curLetter});"
        "if(!correct.length){endG();return}"
        "var ans=correct[0];"
        "pool=pool.filter(function(x){return x!==ans});"
        "var wrong=shuf(pool.filter(function(x){return x[1][0].toUpperCase()!==curLetter})).slice(0,3);"
        "var opts=shuf([ans].concat(wrong));"
        "var od=document.getElementById('opts');od.innerHTML='';"
        "opts.forEach(function(o){"
        "var b=document.createElement('div');b.className='opt';"
        "b.innerHTML='<span style=\"font-size:24px\">'+String.fromCodePoint(o[0])+'</span> '+o[1];"
        "b.onclick=function(){pick(o,ans,b)};od.appendChild(b)})}"
        "function pick(sel,ans,el){"
        "if(locking)return;locking=true;"
        "if(sel===ans){el.classList.add('ok');spk(sel[1]);"
        "chainArr.push(sel);curLetter=sel[1].slice(-1).toUpperCase();round++;"
        "setTimeout(function(){renderChain();locking=false;showOpts()},800)"
        "}else{el.classList.add('no');"
        "document.getElementById('fb').textContent='Try: '+ans[1];document.getElementById('fb').style.color='#f87171';"
        "setTimeout(function(){chainArr.push(ans);curLetter=ans[1].slice(-1).toUpperCase();round++;"
        "renderChain();locking=false;showOpts()},1200)}}"
        "function endG(){"
        "var n=chainArr.length;"
        "document.getElementById('et').textContent="
        "n>=10?'Amazing Chain! \\u2728':n>=7?'Great! \\U0001F60A':'Good Try! \\U0001F4AA';"
        "document.getElementById('es').textContent=n+' words chained!';"
        "document.getElementById('ed').classList.add('show')}"
        "var cv=document.getElementById('cv'),cx=cv.getContext('2d');"
        "function rsz(){cv.width=cv.offsetWidth;cv.height=cv.offsetHeight}rsz();"
        "window.addEventListener('resize',rsz);"
        "var ps=[];for(var i=0;i<30;i++)ps.push({x:Math.random()*cv.width,"
        "y:Math.random()*cv.height,r:Math.random()*2+.8,"
        "dx:(Math.random()-.5)*.4,dy:(Math.random()-.5)*.4,"
        "a:Math.random()*.4+.1});"
        "function drw(){cx.clearRect(0,0,cv.width,cv.height);"
        "ps.forEach(function(p){p.x+=p.dx;p.y+=p.dy;"
        "if(p.x<0)p.x=cv.width;if(p.x>cv.width)p.x=0;"
        "if(p.y<0)p.y=cv.height;if(p.y>cv.height)p.y=0;"
        "cx.beginPath();cx.arc(p.x,p.y,p.r,0,Math.PI*2);"
        "cx.fillStyle='rgba(168,85,247,'+p.a+')';cx.fill()});"
        "requestAnimationFrame(drw)}drw();"
        "init();"
        "</script></body></html>"
    )


