        "</style></head><body>"
        "<div class='w'><canvas id='cv'></canvas>"
        "<div class='ct'>"
        "<div class='hdr'><h2>\u26A1 Kart Yar\u0131\u015F\u0131</h2></div>"
        "<div class='stats'><span class='stat' id='sc'>0 / 12</span>"
        "<span class='stat' id='tm'>30s</span></div>"
        "<div class='timer-bar'><div class='timer-fill' id='tf' style='width:100%'></div></div>"
        "<div class='card'><span class='em' id='em'></span></div>"
        "<div class='opts' id='op'></div>"
        "</div>"
        "<div class='end' id='ed'>"
        "<div style='font-size:80px'>&#9889;</div>"
