## ── Grammar Practice Template & Builders ─────────────────────────────────────


def _ps_grammar_template(title, emoji_cp, rule_html_js, exercises_js):
    """Grammar Practice sablonu — Diamond Premium.
    title: kural adi, emoji_cp: hex int string,
    rule_html_js: JS string (HTML iceren kural kutusu),
    exercises_js: [{q:'...',opts:['a','b','c'],ans:0}, ...]
    """
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'>"
        "<style>"
        "*{margin:0;padding:0;box-sizing:border-box}"
        "html,body{height:100%;overflow:hidden}"
        "body{background:linear-gradient(135deg,#1a0533 0%,#0d0221 50%,#150530 100%);"
        "font-family:'Segoe UI',system-ui,sans-serif;display:flex;flex-direction:column;"
        "align-items:center}"
        ".gw{width:100%;max-width:820px;height:100vh;position:relative;overflow:hidden;"
        "background:linear-gradient(180deg,rgba(30,10,60,.95),rgba(10,5,30,.98));"
        "border-left:2px solid rgba(168,85,247,.3);border-right:2px solid rgba(168,85,247,.3)}"
        "canvas{position:absolute;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:0}"
        ".gc{position:relative;z-index:1;width:100%;height:100%;display:flex;flex-direction:column}"
        ".gh{text-align:center;padding:10px 0 6px;"
        "background:linear-gradient(180deg,rgba(124,58,237,.25),transparent);"
        "border-bottom:1px solid rgba(168,85,247,.2)}"
        ".gh-e{font-size:30px;display:block;margin-bottom:1px;"
        "filter:drop-shadow(0 0 12px rgba(168,85,247,.8))}"
        ".gh-t{font-size:17px;font-weight:800;color:#e9d5ff;"
        "text-shadow:0 0 20px rgba(168,85,247,.6);letter-spacing:1.5px}"
        ".gr{margin:6px 16px;padding:10px 14px;border-radius:14px;"
        "background:linear-gradient(135deg,rgba(124,58,237,.12),rgba(88,28,135,.18));"
        "border:1.5px solid rgba(168,85,247,.3);"
        "max-height:170px;overflow-y:auto}"
        ".gr::-webkit-scrollbar{width:4px}"
        ".gr::-webkit-scrollbar-thumb{background:rgba(168,85,247,.3);border-radius:2px}"
        ".gr table{width:100%;border-collapse:collapse}"
        ".gr td{padding:4px 10px;color:#e9d5ff;font-size:14px;font-weight:600;"
        "border-bottom:1px solid rgba(168,85,247,.12)}"
        ".gr td:first-child{color:#c4b5fd;font-weight:700;width:40%}"
        ".gr td:last-child{color:#fbbf24;font-weight:800}"
        ".gr .rl{font-size:13px;color:#c4b5fd;text-align:center;margin-bottom:6px;font-weight:700}"
        ".gq{flex:1;display:flex;flex-direction:column;align-items:center;"
        "justify-content:center;padding:0 20px}"
        ".gq-s{font-size:22px;font-weight:700;color:#e9d5ff;text-align:center;"
        "text-shadow:0 0 15px rgba(168,85,247,.4);margin-bottom:16px;line-height:1.4}"
        ".gq-blank{display:inline-block;min-width:60px;border-bottom:3px solid #a78bfa;"
        "margin:0 4px;text-align:center;color:#fbbf24;font-weight:800}"
        ".gq-opts{display:flex;gap:10px;flex-wrap:wrap;justify-content:center}"
        ".gq-opt{padding:12px 28px;border-radius:30px;font-size:17px;font-weight:700;"
        "cursor:pointer;border:2px solid rgba(168,85,247,.4);"
        "background:linear-gradient(145deg,rgba(40,20,80,.6),rgba(20,10,50,.8));"
        "color:#e9d5ff;transition:all .25s;min-width:80px;text-align:center;"
        "user-select:none}"
        ".gq-opt:hover{transform:scale(1.08);border-color:#a78bfa;"
        "box-shadow:0 0 18px rgba(168,85,247,.4)}"
        ".gq-opt.ok{border-color:#34d399;background:rgba(52,211,153,.2);color:#6ee7b7;"
        "box-shadow:0 0 22px rgba(52,211,153,.5);pointer-events:none}"
        ".gq-opt.no{border-color:#f87171;background:rgba(248,113,113,.15);color:#fca5a5;"
        "animation:gSh .45s ease}"
        "@keyframes gSh{0%,100%{transform:translateX(0)}"
        "20%{transform:translateX(-8px)}40%{transform:translateX(8px)}"
        "60%{transform:translateX(-5px)}80%{transform:translateX(5px)}}"
        ".gp{display:flex;align-items:center;justify-content:center;gap:12px;"
        "padding:8px 16px;flex-wrap:wrap}"
        ".gp-txt{color:#c4b5fd;font-size:14px;font-weight:700}"
        ".gp-dots{display:flex;gap:5px}"
        ".gp-dot{width:10px;height:10px;border-radius:50%;"
        "background:rgba(168,85,247,.2);border:1px solid rgba(168,85,247,.3);transition:all .3s}"
        ".gp-dot.done{background:#34d399;border-color:#6ee7b7}"
        ".gp-dot.cur{background:#fbbf24;border-color:#fcd34d;transform:scale(1.4);"
        "box-shadow:0 0 8px rgba(251,191,36,.6)}"
        ".gp-score{color:#fbbf24;font-size:14px;font-weight:800;"
        "background:rgba(124,58,237,.15);padding:3px 14px;border-radius:16px;"
        "border:1px solid rgba(168,85,247,.25)}"
        ".ge{position:absolute;inset:0;z-index:10;display:none;flex-direction:column;"
        "align-items:center;justify-content:center;background:rgba(10,2,33,.96)}"
        ".ge.show{display:flex}"
        ".ge-em{font-size:70px;margin-bottom:8px}"
        ".ge-t{font-size:26px;font-weight:800;color:#e9d5ff;margin-bottom:4px}"
        ".ge-s{font-size:18px;color:#c4b5fd;margin-bottom:16px}"
        ".ge-btn{padding:12px 36px;font-size:16px;font-weight:700;border-radius:50px;"
        "border:2px solid rgba(196,181,253,.3);cursor:pointer;color:#fff;"
        "background:linear-gradient(135deg,#7c3aed,#6d28d9);transition:all .3s}"
        ".ge-btn:hover{transform:scale(1.08);box-shadow:0 0 25px rgba(124,58,237,.6)}"
        "</style></head><body>"
        "<div class='gw'><canvas id='gCv'></canvas>"
        "<div class='gc'>"
        "<div class='gh'>"
        "<span class='gh-e' id='gHE'></span>"
        "<div class='gh-t' id='gHT'></div></div>"
        "<div class='gr' id='gRule'></div>"
        "<div class='gq' id='gQ'>"
        "<div class='gq-s' id='gSen'></div>"
        "<div class='gq-opts' id='gOpts'></div></div>"
        "<div class='gp'>"
        "<span class='gp-txt' id='gPTxt'></span>"
        "<div class='gp-dots' id='gDots'></div>"
        "<span class='gp-score' id='gSc'></span></div>"
        "</div>"
        "<div class='ge' id='gEnd'>"
        "<div class='ge-em' id='gEE'></div>"
        "<div class='ge-t' id='gET'></div>"
        "<div class='ge-s' id='gES'></div>"
        "<div class='ge-btn' onclick='gRestart()'>Play Again</div>"
        "</div></div>"
        "<script>"
        "var GT='" + title.replace("'", "\\'") + "',"
        "GE=" + emoji_cp + ","
        "GR=" + rule_html_js + ","
        "GX=" + exercises_js + ";"
        "var gi=0,gscore=0,glocked=false;"
        "function gInit(){"
        "document.getElementById('gHE').textContent=String.fromCodePoint(GE);"
        "document.getElementById('gHT').textContent=GT;"
        "document.getElementById('gRule').innerHTML=GR;"
        "var dts=document.getElementById('gDots');dts.innerHTML='';"
        "for(var i=0;i<GX.length;i++){"
        "var d=document.createElement('span');d.className='gp-dot';d.id='gD'+i;"
        "dts.appendChild(d)}"
        "gi=0;gscore=0;glocked=false;"
        "document.getElementById('gEnd').classList.remove('show');"
        "gShowQ()}"
        "function gShowQ(){"
        "if(gi>=GX.length){gFinish();return}"
        "var ex=GX[gi];"
        "var parts=ex.q.split('___');"
        "var html='';"
        "for(var p=0;p<parts.length;p++){"
        "html+=parts[p].replace(/</g,'&lt;');"
        "if(p<parts.length-1)html+='<span class=\"gq-blank\" id=\"gBlank\">?</span>'}"
        "document.getElementById('gSen').innerHTML=html;"
        "var od=document.getElementById('gOpts');od.innerHTML='';"
        "ex.opts.forEach(function(o,oi){"
        "var b=document.createElement('div');b.className='gq-opt';"
        "b.textContent=o;b.onclick=function(){gPick(oi,b)};od.appendChild(b)});"
        "document.getElementById('gPTxt').textContent='Soru '+(gi+1)+'/'+GX.length;"
        "document.getElementById('gSc').textContent=String.fromCodePoint(0x2B50)+' '+gscore;"
        "for(var j=0;j<GX.length;j++){"
        "var dt=document.getElementById('gD'+j);"
        "dt.classList.remove('done','cur');"
        "if(j<gi)dt.classList.add('done');"
        "else if(j===gi)dt.classList.add('cur')}}"
        "function gPick(oi,el){"
        "if(glocked)return;glocked=true;"
        "var ex=GX[gi];"
        "if(oi===ex.ans){"
        "el.classList.add('ok');"
        "var bl=document.getElementById('gBlank');"
        "if(bl){bl.textContent=ex.opts[oi];bl.style.color='#34d399';bl.style.borderColor='#34d399'}"
        "gscore++;"
        "document.getElementById('gSc').textContent=String.fromCodePoint(0x2B50)+' '+gscore;"
        "setTimeout(function(){gi++;glocked=false;gShowQ()},900)"
        "}else{"
        "el.classList.add('no');"
        "setTimeout(function(){el.classList.remove('no');glocked=false},500)}}"
        "function gFinish(){"
        "var pct=Math.round(gscore/GX.length*100);"
        "var em,tt;"
        "if(pct>=100){em=String.fromCodePoint(0x1F3C6);tt='Perfect!'}"
        "else if(pct>=75){em=String.fromCodePoint(0x1F31F);tt='Great Job!'}"
        "else if(pct>=50){em=String.fromCodePoint(0x1F44D);tt='Good Try!'}"
        "else{em=String.fromCodePoint(0x1F4AA);tt='Keep Practicing!'}"
        "document.getElementById('gEE').textContent=em;"
        "document.getElementById('gET').textContent=tt;"
        "document.getElementById('gES').textContent=gscore+' / '+GX.length+' correct ('+pct+'%)';"
        "document.getElementById('gEnd').classList.add('show')}"
        "function gRestart(){gInit()}"
        "var cv=document.getElementById('gCv'),cx=cv.getContext('2d');"
        "function rsz(){cv.width=cv.offsetWidth;cv.height=cv.offsetHeight}rsz();"
        "window.addEventListener('resize',rsz);"
        "var pts=[];for(var i=0;i<30;i++)pts.push({x:Math.random()*cv.width,"
        "y:Math.random()*cv.height,r:Math.random()*2+.8,"
        "dx:(Math.random()-.5)*.4,dy:(Math.random()-.5)*.4,"
        "a:Math.random()*.35+.1});"
        "function drw(){cx.clearRect(0,0,cv.width,cv.height);"
        "pts.forEach(function(p){p.x+=p.dx;p.y+=p.dy;"
        "if(p.x<0)p.x=cv.width;if(p.x>cv.width)p.x=0;"
        "if(p.y<0)p.y=cv.height;if(p.y>cv.height)p.y=0;"
        "cx.beginPath();cx.arc(p.x,p.y,p.r,0,Math.PI*2);"
        "cx.fillStyle='rgba(168,85,247,'+p.a+')';cx.fill()});"
        "requestAnimationFrame(drw)}drw();"
        "gInit();"
        "</script></body></html>"
    )


