        "<tr><td>He / She / It</td><td>is</td></tr>"
        "</table>'",
        "[{q:'I ___ happy.',opts:['am','is','are'],ans:0},"
        "{q:'She ___ a student.',opts:['am','is','are'],ans:1},"
        "{q:'They ___ friends.',opts:['am','is','are'],ans:2},"
        "{q:'He ___ tall.',opts:['am','is','are'],ans:1},"
