## ── Reading Comprehension Template & Builders ────────────────────────────────

def _ps_reading_template(title, emoji_cp, passage_js, questions_js):
    """Reading comprehension template — Diamond Premium.
    title: string, emoji_cp: hex string e.g. '0x1F408',
    passage_js: JS array of sentence strings,
    questions_js: JS array of {q,opts,ans} objects.
    """
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'>"
        "<style>"
        "*{margin:0;padding:0;box-sizing:border-box;}"
        "html,body{height:100%;overflow:hidden;}"
        "body{background:linear-gradient(135deg,#1a0533 0%,#0d0221 50%,#150530 100%);"
        "font-family:'Segoe UI Emoji','Apple Color Emoji','Noto Color Emoji','Segoe UI',system-ui,sans-serif;display:flex;flex-direction:column;"
        "align-items:center;}"
        ".rd-wrap{width:100%;max-width:820px;height:100vh;position:relative;overflow:hidden;"
        "background:linear-gradient(180deg,rgba(30,10,60,0.95),rgba(10,5,30,0.98));"
        "border-left:2px solid rgba(168,85,247,0.3);border-right:2px solid rgba(168,85,247,0.3);}"
        ".rd-header{text-align:center;padding:12px 0 8px;"
        "background:linear-gradient(180deg,rgba(124,58,237,0.25),transparent);"
        "border-bottom:1px solid rgba(168,85,247,0.2);}"
        ".rd-header-emoji{font-size:34px;display:block;margin-bottom:2px;"
        "filter:drop-shadow(0 0 12px rgba(168,85,247,0.8));}"
        ".rd-header-text{font-size:18px;font-weight:800;color:#e9d5ff;"
        "text-shadow:0 0 20px rgba(168,85,247,0.6);letter-spacing:1.5px;}"
        ".rd-body{flex:1;overflow-y:auto;padding:10px 16px;display:flex;"
        "flex-direction:column;gap:10px;scroll-behavior:smooth;}"
        ".rd-body::-webkit-scrollbar{width:6px;}"
        ".rd-body::-webkit-scrollbar-thumb{background:rgba(168,85,247,0.3);border-radius:3px;}"
        ".rd-passage{background:linear-gradient(135deg,rgba(124,58,237,0.15),rgba(99,45,200,0.1));"
        "border:1.5px solid rgba(168,85,247,0.3);border-radius:16px;"
        "padding:14px 18px;line-height:1.7;color:#e2d6f8;font-size:15px;"
        "font-weight:500;position:relative;}"
        ".rd-passage-title{font-size:11px;font-weight:700;color:#a78bfa;"
        "text-transform:uppercase;letter-spacing:1.5px;margin-bottom:6px;"
        "display:flex;align-items:center;gap:6px;}"
        ".rd-passage-title::before{content:'';display:inline-block;width:14px;height:2px;"
        "background:#a78bfa;border-radius:1px;}"
        ".rd-passage span{transition:background 0.3s;border-radius:4px;padding:0 2px;cursor:pointer;}"
        ".rd-passage span:hover{background:rgba(168,85,247,0.25);}"
        ".rd-passage span.highlight{background:rgba(168,85,247,0.35);"
        "box-shadow:0 0 8px rgba(168,85,247,0.3);}"
        ".rd-speak-btn{position:absolute;top:10px;right:12px;width:32px;height:32px;"
        "border-radius:50%;background:linear-gradient(135deg,#7c3aed,#6d28d9);"
        "border:1.5px solid rgba(196,181,253,0.3);cursor:pointer;font-size:16px;"
        "color:#fff;display:flex;align-items:center;justify-content:center;"
        "box-shadow:0 0 12px rgba(124,58,237,0.4);transition:all 0.3s;}"
        ".rd-speak-btn:hover{transform:scale(1.15);box-shadow:0 0 20px rgba(124,58,237,0.7);}"
        ".rd-qsection{margin-top:4px;}"
        ".rd-qlabel{font-size:11px;font-weight:700;color:#a78bfa;"
        "text-transform:uppercase;letter-spacing:1.5px;margin-bottom:6px;"
        "display:flex;align-items:center;gap:6px;}"
        ".rd-qlabel::before{content:'';display:inline-block;width:14px;height:2px;"
        "background:#a78bfa;border-radius:1px;}"
        ".rd-score{text-align:center;padding:6px;font-size:14px;font-weight:700;"
        "color:#c4b5fd;text-shadow:0 0 10px rgba(168,85,247,0.4);}"
        ".rd-qcard{background:linear-gradient(145deg,rgba(40,20,80,0.5),rgba(20,10,50,0.7));"
        "border:1.5px solid rgba(168,85,247,0.25);border-radius:14px;"
        "padding:12px 14px;margin-bottom:8px;transition:all 0.3s;}"
        ".rd-qtext{font-size:14px;font-weight:600;color:#e9d5ff;margin-bottom:8px;}"
        ".rd-qnum{display:inline-block;background:linear-gradient(135deg,#7c3aed,#6d28d9);"
        "color:#fff;font-size:11px;font-weight:800;padding:2px 8px;border-radius:10px;"
        "margin-right:6px;}"
        ".rd-opts{display:flex;flex-direction:column;gap:6px;}"
        ".rd-opt{padding:9px 14px;border-radius:12px;"
        "border:2px solid rgba(168,85,247,0.3);"
        "background:linear-gradient(145deg,rgba(40,20,80,0.4),rgba(20,10,50,0.6));"
        "cursor:pointer;font-size:13px;font-weight:600;color:#d4c6f0;"
        "transition:all 0.3s cubic-bezier(0.34,1.56,0.64,1);"
        "display:flex;align-items:center;gap:8px;}"
        ".rd-opt:hover{transform:translateX(4px);border-color:rgba(168,85,247,0.6);"
        "background:linear-gradient(145deg,rgba(60,30,100,0.5),rgba(30,15,60,0.7));}"
        ".rd-opt .rd-opt-letter{display:inline-flex;align-items:center;justify-content:center;"
        "width:24px;height:24px;border-radius:50%;font-size:11px;font-weight:800;"
        "background:rgba(168,85,247,0.25);color:#c4b5fd;flex-shrink:0;}"
        ".rd-opt.correct{background:linear-gradient(145deg,rgba(16,185,129,0.35),rgba(5,150,105,0.5));"
        "border-color:#34d399;color:#a7f3d0;"
        "box-shadow:0 0 20px rgba(52,211,153,0.4);animation:rdCorrect 0.5s ease;}"
        ".rd-opt.correct .rd-opt-letter{background:rgba(52,211,153,0.4);color:#a7f3d0;}"
        "@keyframes rdCorrect{0%{transform:scale(1)}30%{transform:scale(1.05)}"
        "60%{transform:scale(0.98)}100%{transform:scale(1)}}"
        ".rd-opt.wrong{background:linear-gradient(145deg,rgba(239,68,68,0.25),rgba(220,38,38,0.35));"
        "border-color:#f87171;color:#fca5a5;animation:rdWrong 0.4s ease;}"
        ".rd-opt.wrong .rd-opt-letter{background:rgba(239,68,68,0.4);color:#fca5a5;}"
        "@keyframes rdWrong{0%,100%{transform:translateX(0)}"
        "20%{transform:translateX(-8px)}40%{transform:translateX(8px)}"
        "60%{transform:translateX(-4px)}80%{transform:translateX(4px)}}"
        ".rd-opt.disabled{pointer-events:none;opacity:0.5;}"
        ".rd-done{text-align:center;padding:16px;}"
        ".rd-done-emoji{font-size:60px;margin-bottom:6px;"
        "animation:rdFloat 2s ease-in-out infinite;}"
        "@keyframes rdFloat{0%,100%{transform:translateY(0)}50%{transform:translateY(-8px)}}"
        ".rd-done-text{font-size:22px;font-weight:800;color:#e9d5ff;"
        "text-shadow:0 0 15px rgba(168,85,247,0.5);margin-bottom:4px;}"
        ".rd-done-score{font-size:16px;color:#c4b5fd;margin-bottom:12px;}"
        ".rd-done-stars{font-size:40px;margin-bottom:10px;"
        "filter:drop-shadow(0 0 10px rgba(251,191,36,0.6));}"
        ".rd-replay{padding:12px 36px;font-size:16px;font-weight:700;"
        "border-radius:50px;border:2px solid rgba(196,181,253,0.3);cursor:pointer;"
        "color:#fff;background:linear-gradient(135deg,#7c3aed,#6d28d9);"
        "box-shadow:0 0 20px rgba(124,58,237,0.4);transition:all 0.3s;"
        "letter-spacing:1px;}"
        ".rd-replay:hover{transform:scale(1.08);box-shadow:0 0 30px rgba(124,58,237,0.7);}"
        "#rdCv{position:absolute;top:0;left:0;width:100%;height:100%;"
        "pointer-events:none;z-index:0;}"
        "#rdCt{position:relative;z-index:1;width:100%;height:100%;"
        "display:flex;flex-direction:column;}"
        "</style></head><body>"
        "<div class='rd-wrap'><canvas id='rdCv'></canvas>"
        "<div id='rdCt'>"
        "<div class='rd-header'>"
        "<span class='rd-header-emoji' id='rdHE'></span>"
        "<div class='rd-header-text' id='rdHT'></div></div>"
        "<div class='rd-body' id='rdBody'></div>"
        "</div></div>"
        "<script>"
        "var RD_TITLE='" + title.replace("'", "\\'") + "';"
        "var RD_EMOJI=" + emoji_cp + ";"
        "var RD_PASSAGE=" + passage_js + ";"
        "var RD_QUESTIONS=" + questions_js + ";"
        "var rdScore=0,rdAnswered=0,rdTotal=RD_QUESTIONS.length;"
        ""
        "document.getElementById('rdHE').textContent=String.fromCodePoint(RD_EMOJI);"
        "document.getElementById('rdHT').textContent=RD_TITLE;"
        ""
        "function speak(txt){"
        "if(!window._uc){if(!window._ucL){window._ucL=1;document.addEventListener('click',function(){window._uc=1});document.addEventListener('touchstart',function(){window._uc=1})}return;}"
        "try{speechSynthesis.cancel();"
        "var u=new SpeechSynthesisUtterance(txt);"
        "u.lang='en-US';u.rate=0.75;u.pitch=1.1;"
        "var vs=speechSynthesis.getVoices();"
        "for(var i=0;i<vs.length;i++){if(vs[i].lang.indexOf('en')===0){u.voice=vs[i];break;}}"
        "speechSynthesis.speak(u);}catch(e){}}"
        "speechSynthesis.getVoices();"
        ""
        "function playMelody(notes){"
        "if(!window._uc)return;"
        "try{var ac=new(window.AudioContext||window.webkitAudioContext)();"
        "var t=ac.currentTime;"
        "for(var i=0;i<notes.length;i++){var o=ac.createOscillator();var g=ac.createGain();"
        "o.type='sine';o.frequency.value=notes[i][0];"
        "g.gain.setValueAtTime(0.12,t);g.gain.exponentialRampToValueAtTime(0.001,t+notes[i][1]);"
        "o.connect(g);g.connect(ac.destination);"
        "o.start(t);o.stop(t+notes[i][1]);t+=notes[i][1]*0.7;}"
        "}catch(e){}}"
        "function playCorrect(){playMelody([[523,0.12],[659,0.12],[784,0.12],[1047,0.25]]);}"
        "function playWrong(){playMelody([[300,0.15],[200,0.3]]);}"
        "function playFinish(){playMelody([[523,0.15],[659,0.15],[784,0.15],[1047,0.15],[1319,0.3]]);}"
        ""
        "function spawnConfetti(n){"
        "var colors=['#fbbf24','#34d399','#60a5fa','#f472b6','#a78bfa','#fb923c','#e879f9'];"
        "for(var i=0;i<n;i++){var el=document.createElement('div');"
        "el.style.cssText='position:fixed;pointer-events:none;z-index:9999;"
        "width:'+(Math.random()*8+5)+'px;height:'+(Math.random()*8+5)+'px;"
        "background:'+colors[Math.floor(Math.random()*colors.length)]+"
        "';border-radius:'+(Math.random()>0.5?'50%':'2px')+"
        "';left:'+Math.random()*100+'%;top:-10px;"
        "animation:confDrop '+(Math.random()*1.5+1)+'s ease-out '+(Math.random()*0.4)+'s forwards;';"
        "document.body.appendChild(el);"
        "setTimeout(function(){el.remove();},3500);}}"
        "var cSt=document.createElement('style');"
        "cSt.textContent='@keyframes confDrop{0%{transform:translateY(0) rotate(0);opacity:1}"
        "100%{transform:translateY('+window.innerHeight+'px) rotate(720deg);opacity:0}}';"
        "document.head.appendChild(cSt);"
        ""
        "function renderAll(){"
        "rdScore=0;rdAnswered=0;"
        "var bd=document.getElementById('rdBody');"
        "var h='';"
        "h+='<div class=\"rd-passage\">';"
        "h+='<div class=\"rd-passage-title\">Reading Passage</div>';"
        "h+='<button class=\"rd-speak-btn\" id=\"rdSpk\">&#x1F50A;</button>';"
        "for(var i=0;i<RD_PASSAGE.length;i++){"
        "h+='<span onclick=\"speak(this.textContent)\">'+RD_PASSAGE[i]+' </span>';}"
        "h+='</div>';"
        "h+='<div class=\"rd-qsection\">';"
        "h+='<div class=\"rd-qlabel\">Questions</div>';"
        "h+='<div class=\"rd-score\" id=\"rdScoreBox\">0 / '+rdTotal+' Do\\u011Fru</div>';"
        "for(var q=0;q<RD_QUESTIONS.length;q++){"
        "var item=RD_QUESTIONS[q];"
        "h+='<div class=\"rd-qcard\" id=\"rdQ'+q+'\">';"
        "h+='<div class=\"rd-qtext\"><span class=\"rd-qnum\">'+(q+1)+'</span>'+item.q+'</div>';"
        "h+='<div class=\"rd-opts\">';"
        "var letters=['A','B','C','D','E','F'];"
        "for(var o=0;o<item.opts.length;o++){"
        "h+='<div class=\"rd-opt\" data-q=\"'+q+'\" data-o=\"'+o+'\">';"
        "h+='<span class=\"rd-opt-letter\">'+letters[o]+'</span>';"
        "h+=item.opts[o]+'</div>';}"
        "h+='</div></div>';}"
        "h+='</div>';"
        "h+='<div class=\"rd-done\" id=\"rdDone\" style=\"display:none\"></div>';"
        "bd.innerHTML=h;"
        "document.getElementById('rdSpk').onclick=function(){"
        "speak(RD_PASSAGE.join(' '));};"
        "var opts=document.querySelectorAll('.rd-opt');"
        "for(var i=0;i<opts.length;i++){(function(el){"
        "el.onclick=function(){handleOpt(el);};"
        "})(opts[i]);}}"
        ""
        "function handleOpt(el){"
        "var qi=parseInt(el.getAttribute('data-q'));"
        "var oi=parseInt(el.getAttribute('data-o'));"
        "var card=document.getElementById('rdQ'+qi);"
        "if(card.getAttribute('data-done'))return;"
        "card.setAttribute('data-done','1');"
        "var isCorrect=oi===RD_QUESTIONS[qi].ans;"
        "if(isCorrect){el.classList.add('correct');rdScore++;playCorrect();spawnConfetti(12);}"
        "else{el.classList.add('wrong');playWrong();"
        "var siblings=card.querySelectorAll('.rd-opt');"
        "for(var j=0;j<siblings.length;j++){"
        "if(parseInt(siblings[j].getAttribute('data-o'))===RD_QUESTIONS[qi].ans){"
        "siblings[j].classList.add('correct');}}}"
        "var allOpts=card.querySelectorAll('.rd-opt');"
        "for(var k=0;k<allOpts.length;k++){allOpts[k].classList.add('disabled');}"
        "rdAnswered++;"
        "document.getElementById('rdScoreBox').textContent=rdScore+' / '+rdTotal+' Do\\u011Fru!';"
        "if(rdAnswered>=rdTotal){setTimeout(showDone,800);}}"
        ""
        "function showDone(){"
        "playFinish();spawnConfetti(40);"
        "var pct=Math.round(rdScore*100/rdTotal);"
        "var stars=pct>=90?3:pct>=60?2:1;"
        "var sStr='';for(var i=0;i<3;i++){sStr+=i<stars?'\\u2B50':'\\u2606';}"
        "var emoji=stars===3?String.fromCodePoint(0x1F389):"
        "stars===2?String.fromCodePoint(0x1F60A):String.fromCodePoint(0x1F4AA);"
        "var d=document.getElementById('rdDone');"
        "d.style.display='block';"
        "d.innerHTML='<div class=\"rd-done-emoji\">'+emoji+'</div>'"
        "+'<div class=\"rd-done-text\">'+(stars===3?'Excellent!':stars===2?'Good Job!':'Keep Trying!')+'</div>'"
        "+'<div class=\"rd-done-stars\">'+sStr+'</div>'"
        "+'<div class=\"rd-done-score\">'+rdScore+' / '+rdTotal+' Do\\u011Fru</div>'"
        "+'<button class=\"rd-replay\" onclick=\"renderAll()\">\\u21BB Tekrar</button>';}"
        ""
        "var cv=document.getElementById('rdCv'),cx=cv.getContext('2d');"
        "function rsz(){cv.width=cv.offsetWidth;cv.height=cv.offsetHeight;}rsz();"
        "window.addEventListener('resize',rsz);"
        "var pts=[];for(var i=0;i<30;i++)pts.push({x:Math.random()*cv.width,"
        "y:Math.random()*cv.height,r:Math.random()*2+0.8,"
        "dx:(Math.random()-0.5)*0.4,dy:(Math.random()-0.5)*0.4,"
        "a:Math.random()*0.4+0.1});"
        "function drw(){cx.clearRect(0,0,cv.width,cv.height);"
        "pts.forEach(function(p){p.x+=p.dx;p.y+=p.dy;"
        "if(p.x<0)p.x=cv.width;if(p.x>cv.width)p.x=0;"
        "if(p.y<0)p.y=cv.height;if(p.y>cv.height)p.y=0;"
        "cx.beginPath();cx.arc(p.x,p.y,p.r,0,Math.PI*2);"
        "cx.fillStyle='rgba(168,85,247,'+p.a+')';cx.fill();});"
        "requestAnimationFrame(drw);}drw();"
        "window.addEventListener('beforeunload',function(){speechSynthesis.cancel();});"
        "document.addEventListener('visibilitychange',function(){"
        "if(document.hidden){speechSynthesis.cancel();}});"
        "renderAll();"
        "</script></body></html>"
    )


