        ".wr-wrap{width:100%;max-width:820px;height:100vh;position:relative;overflow:hidden;"
        "background:linear-gradient(180deg,rgba(30,10,60,0.95),rgba(10,5,30,0.98));"
        "border-left:2px solid rgba(168,85,247,0.3);border-right:2px solid rgba(168,85,247,0.3)}"
        "#wrCv{position:absolute;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:0}"
        "#wrCt{position:relative;z-index:1;width:100%;height:100%;display:flex;flex-direction:column}"
        ".wr-hdr{text-align:center;padding:10px 0 6px;"
        "background:linear-gradient(180deg,rgba(124,58,237,0.25),transparent);"
        "border-bottom:1px solid rgba(168,85,247,0.2)}"
        ".wr-hdr-e{font-size:32px;display:block;margin-bottom:2px;"
        "filter:drop-shadow(0 0 12px rgba(168,85,247,0.8))}"
        ".wr-hdr-t{font-size:17px;font-weight:800;color:#e9d5ff;"
        "text-shadow:0 0 20px rgba(168,85,247,0.6);letter-spacing:1.5px}"
        ".wr-score{text-align:center;color:#c4b5fd;font-size:13px;font-weight:600;"
        "padding:6px 0;background:rgba(124,58,237,0.1);"
        "border-bottom:1px solid rgba(168,85,247,0.12)}"
        ".wr-score span{color:#fbbf24;font-weight:800}"
        ".wr-body{flex:1;overflow-y:auto;padding:10px 16px;display:flex;"
        "flex-direction:column;gap:10px}"
        ".wr-body::-webkit-scrollbar{width:6px}"
        ".wr-body::-webkit-scrollbar-thumb{background:rgba(168,85,247,0.3);border-radius:3px}"
        ".cp-model{text-align:center;font-size:28px;font-weight:800;color:#fbbf24;"
        "letter-spacing:3px;padding:8px 12px;margin-bottom:4px;"
        "background:rgba(251,191,36,0.08);border-radius:14px;"
        "border:1.5px dashed rgba(251,191,36,0.3);"
        "text-shadow:0 0 14px rgba(251,191,36,0.3)}"
        ".cp-built{min-height:38px;padding:6px 12px;margin-bottom:6px;text-align:center;"
        "font-size:24px;font-weight:700;color:#a855f7;letter-spacing:2px;"
        "background:rgba(168,85,247,0.08);border-radius:12px;"
        "border:1.5px solid rgba(168,85,247,0.25)}"
        ".cp-letters{display:flex;flex-wrap:wrap;gap:6px;justify-content:center;padding:4px 0}"
        ".cp-lbtn{width:40px;height:42px;border-radius:10px;border:2px solid rgba(196,181,253,0.3);"
        "background:linear-gradient(145deg,rgba(124,58,237,0.3),rgba(88,28,135,0.5));"
        "color:#e9d5ff;font-size:20px;font-weight:800;cursor:pointer;display:flex;"
        "align-items:center;justify-content:center;transition:all 0.2s;"
        "box-shadow:0 2px 8px rgba(88,28,135,0.3)}"
