## ── Phonics / Sounds — Diamond Premium Template ────────────────────────────


def _ps_phonics_template(title, emoji_cp, mode, data_js):
    """Phonics / Sounds sablonu — 5 mod destekler.
    mode: 'letter_sound' | 'cvc_build' | 'minimal_pairs' | 'rhyme' | 'syllable'
    data_js: moda uygun JS array string
    """
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'>"
        "<style>"
        "*{margin:0;padding:0;box-sizing:border-box}"
        "html,body{height:100%;overflow:hidden}"
        "body{background:linear-gradient(135deg,#1a0533 0%,#0d0221 50%,#150530 100%);"
        "font-family:'Segoe UI',system-ui,sans-serif;display:flex;justify-content:center}"
        ".ph-wrap{width:100%;max-width:820px;height:100vh;position:relative;overflow:hidden;"
        "background:linear-gradient(180deg,rgba(30,10,60,.95),rgba(10,5,30,.98));"
        "border-left:2px solid rgba(168,85,247,.3);border-right:2px solid rgba(168,85,247,.3)}"
        "canvas{position:absolute;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:0}"
        ".ph-ct{position:relative;z-index:1;width:100%;height:100%;display:flex;flex-direction:column;"
        "align-items:center;overflow:hidden}"
        ".ph-hdr{text-align:center;padding:10px 0 6px;"
        "background:linear-gradient(180deg,rgba(124,58,237,.25),transparent);"
        "border-bottom:1px solid rgba(168,85,247,.2);width:100%}"
        ".ph-hdr-em{font-size:30px;display:block;margin-bottom:2px;"
        "filter:drop-shadow(0 0 12px rgba(168,85,247,.8))}"
        ".ph-hdr-t{font-size:16px;font-weight:800;color:#e9d5ff;"
        "text-shadow:0 0 20px rgba(168,85,247,.6);letter-spacing:1.5px}"
        ".ph-score{color:#c4b5fd;font-size:13px;margin:4px 0;font-weight:600;"
        "background:rgba(124,58,237,.15);padding:3px 16px;border-radius:20px;"
        "border:1px solid rgba(168,85,247,.25)}"
        ".ph-prog{display:flex;justify-content:center;gap:4px;padding:4px 8px;flex-wrap:wrap}"
        ".ph-dot{width:9px;height:9px;border-radius:50%;"
        "background:rgba(168,85,247,.2);border:1px solid rgba(168,85,247,.3);transition:all .3s}"
        ".ph-dot.done{background:#34d399;border-color:#6ee7b7}"
        ".ph-dot.cur{background:#fbbf24;border-color:#fcd34d;transform:scale(1.4);"
        "box-shadow:0 0 8px rgba(251,191,36,.6)}"
        ".ph-area{flex:1;display:flex;flex-direction:column;align-items:center;"
        "justify-content:center;width:100%;padding:4px 12px;gap:6px;overflow-y:auto}"
        ".ph-big{font-size:90px;font-weight:900;color:#e9d5ff;cursor:pointer;"
        "text-shadow:0 0 30px rgba(168,85,247,.7);transition:all .3s;"
        "user-select:none;line-height:1}"
        ".ph-big:hover{transform:scale(1.1);text-shadow:0 0 50px rgba(168,85,247,1)}"
        ".ph-big:active{transform:scale(.95)}"
        ".ph-sub{font-size:14px;color:#c4b5fd;font-weight:600;margin-top:2px}"
        ".ph-cards{display:flex;flex-wrap:wrap;gap:10px;justify-content:center;max-width:700px}"
        ".ph-card{padding:10px 18px;border-radius:14px;"
        "background:linear-gradient(135deg,rgba(124,58,237,.2),rgba(99,45,200,.12));"
        "border:2px solid rgba(168,85,247,.3);color:#e9d5ff;font-size:16px;font-weight:700;"
        "cursor:pointer;transition:all .3s;display:flex;align-items:center;gap:8px;"
        "user-select:none;min-width:90px;justify-content:center}"
        ".ph-card:hover{transform:translateY(-3px);border-color:rgba(168,85,247,.7);"
        "box-shadow:0 4px 20px rgba(168,85,247,.3)}"
        ".ph-card.correct{border-color:#34d399;background:rgba(52,211,153,.2);"
        "box-shadow:0 0 20px rgba(52,211,153,.5);animation:phPop .4s ease}"
        ".ph-card.wrong{border-color:#ef4444;background:rgba(239,68,68,.15);"
        "animation:phShake .5s ease}"
        ".ph-card.selected{border-color:#fbbf24;background:rgba(251,191,36,.15);"
        "box-shadow:0 0 15px rgba(251,191,36,.3)}"
        ".ph-card.disabled{opacity:.5;pointer-events:none}"
        "@keyframes phPop{0%{transform:scale(1)}50%{transform:scale(1.15)}100%{transform:scale(1)}}"
        "@keyframes phShake{0%,100%{transform:translateX(0)}20%{transform:translateX(-8px)}"
        "40%{transform:translateX(8px)}60%{transform:translateX(-5px)}80%{transform:translateX(5px)}}"
        ".ph-slots{display:flex;gap:8px;justify-content:center;margin:8px 0}"
        ".ph-slot{width:52px;height:56px;border-radius:12px;"
        "border:2.5px dashed rgba(168,85,247,.5);background:rgba(124,58,237,.08);"
        "display:flex;align-items:center;justify-content:center;font-size:28px;"
        "font-weight:900;color:#fbbf24;transition:all .3s;cursor:pointer}"
        ".ph-slot.filled{border-style:solid;border-color:#34d399;"
        "background:rgba(52,211,153,.12);animation:phPop .3s ease}"
        ".ph-slot.error{border-color:#ef4444;animation:phShake .5s ease}"
        ".ph-letters{display:flex;flex-wrap:wrap;gap:6px;justify-content:center;"
        "max-width:500px;margin:6px 0}"
        ".ph-lbtn{width:42px;height:42px;border-radius:10px;"
        "background:linear-gradient(135deg,rgba(124,58,237,.3),rgba(99,45,200,.2));"
        "border:2px solid rgba(168,85,247,.3);color:#e9d5ff;font-size:20px;font-weight:800;"
        "cursor:pointer;transition:all .3s;display:flex;align-items:center;justify-content:center}"
        ".ph-lbtn:hover{transform:scale(1.12);border-color:rgba(168,85,247,.8);"
        "box-shadow:0 0 15px rgba(168,85,247,.4)}"
        ".ph-lbtn.used{opacity:.3;pointer-events:none}"
        ".ph-spk{width:44px;height:44px;border-radius:50%;border:2px solid rgba(196,181,253,.3);"
        "cursor:pointer;font-size:20px;color:#fff;"
        "background:linear-gradient(135deg,#7c3aed,#6d28d9);"
        "box-shadow:0 0 15px rgba(124,58,237,.4);transition:all .3s;"
        "display:flex;align-items:center;justify-content:center}"
        ".ph-spk:hover{transform:scale(1.15);box-shadow:0 0 25px rgba(124,58,237,.7)}"
        ".ph-pair{display:flex;gap:20px;align-items:center;justify-content:center}"
        ".ph-pw{display:flex;flex-direction:column;align-items:center;gap:6px}"
        ".ph-pw-t{font-size:30px;font-weight:800;color:#e9d5ff;"
        "text-shadow:0 0 15px rgba(168,85,247,.5)}"
        ".ph-q{font-size:18px;font-weight:700;color:#fbbf24;text-align:center;"
        "margin:8px 0;text-shadow:0 0 10px rgba(251,191,36,.3)}"
        ".ph-cbx{display:flex;align-items:center;gap:8px;padding:8px 16px;border-radius:12px;"
        "background:linear-gradient(135deg,rgba(124,58,237,.15),rgba(99,45,200,.08));"
        "border:2px solid rgba(168,85,247,.25);cursor:pointer;transition:all .3s;"
        "color:#e9d5ff;font-size:15px;font-weight:600;user-select:none}"
        ".ph-cbx:hover{border-color:rgba(168,85,247,.6)}"
        ".ph-cbx.checked{border-color:#34d399;background:rgba(52,211,153,.15)}"
        ".ph-cbx .tick{width:20px;height:20px;border-radius:6px;"
        "border:2px solid rgba(168,85,247,.4);display:flex;align-items:center;"
        "justify-content:center;font-size:14px;transition:all .3s}"
        ".ph-cbx.checked .tick{border-color:#34d399;background:#34d399;color:#064e3b}"
        ".ph-syl-btns{display:flex;gap:10px;justify-content:center;margin:8px 0}"
        ".ph-syl{width:48px;height:48px;border-radius:12px;"
        "background:linear-gradient(135deg,rgba(124,58,237,.25),rgba(99,45,200,.15));"
        "border:2px solid rgba(168,85,247,.3);color:#e9d5ff;font-size:22px;font-weight:800;"
        "cursor:pointer;transition:all .3s;display:flex;align-items:center;justify-content:center}"
        ".ph-syl:hover{transform:scale(1.1);border-color:rgba(168,85,247,.8)}"
        ".ph-syl.correct{border-color:#34d399;background:rgba(52,211,153,.25);"
        "box-shadow:0 0 15px rgba(52,211,153,.5)}"
        ".ph-syl.wrong{border-color:#ef4444;background:rgba(239,68,68,.15);"
        "animation:phShake .5s ease}"
        ".ph-next{padding:8px 28px;border-radius:25px;border:2px solid rgba(168,85,247,.4);"
        "background:linear-gradient(135deg,#7c3aed,#6d28d9);color:#fff;font-size:15px;"
        "font-weight:700;cursor:pointer;transition:all .3s;margin-top:6px}"
        ".ph-next:hover{transform:scale(1.08);box-shadow:0 0 20px rgba(124,58,237,.6)}"
        ".ph-emoji{font-size:56px;filter:drop-shadow(0 0 15px rgba(168,85,247,.4));"
        "animation:phFloat 3s ease-in-out infinite}"
        "@keyframes phFloat{0%,100%{transform:translateY(0)}50%{transform:translateY(-6px)}}"
        ".ph-check{padding:8px 24px;border-radius:25px;border:2px solid rgba(52,211,153,.4);"
        "background:linear-gradient(135deg,#059669,#047857);color:#fff;font-size:14px;"
        "font-weight:700;cursor:pointer;transition:all .3s;margin-top:4px}"
        ".ph-check:hover{transform:scale(1.08);box-shadow:0 0 20px rgba(52,211,153,.6)}"
        ".ph-fb{font-size:15px;font-weight:700;padding:6px 16px;border-radius:12px;margin:4px 0}"
        ".ph-fb.ok{color:#6ee7b7;background:rgba(52,211,153,.15);border:1px solid rgba(52,211,153,.3)}"
        ".ph-fb.no{color:#fca5a5;background:rgba(239,68,68,.12);border:1px solid rgba(239,68,68,.3)}"
        ".ph-complete{font-size:20px;font-weight:800;color:#fbbf24;"
        "text-shadow:0 0 20px rgba(251,191,36,.5);text-align:center;padding:20px}"
        "</style></head><body>"
        "<div class='ph-wrap'><canvas id='phCv'></canvas>"
        "<div class='ph-ct'>"
        "<div class='ph-hdr'>"
        "<span class='ph-hdr-em' id='phHE'></span>"
        "<div class='ph-hdr-t' id='phHT'></div></div>"
        "<div class='ph-score' id='phSc'>0 / 0</div>"
        "<div class='ph-prog' id='phPg'></div>"
        "<div class='ph-area' id='phArea'></div>"
        "</div></div>"
        "<script>"
        "try{window.speechSynthesis.cancel()}catch(e){}"
        "var PH_T='" + title.replace("'", "\\'") + "',PH_E=" + str(emoji_cp) + ","
        "PH_M='" + mode + "',"
        "PH_D=" + data_js + ";"
        "var phi=0,phOk=0,phTot=0,phDone=false;"
        "function phSpk(txt,cb){"
        "try{speechSynthesis.cancel()}catch(e){}"
        "var u=new SpeechSynthesisUtterance(txt);"
        "u.lang='en-US';u.rate=0.8;u.pitch=1.1;"
        "var vs=speechSynthesis.getVoices();"
        "var pr=['Google UK English Female','Google US English','Microsoft Zira','Microsoft Jenny','Samantha','Karen','Daniel','Moira'];"
        "var bv=null;for(var p=0;p<pr.length&&!bv;p++){for(var vi=0;vi<vs.length;vi++){if(vs[vi].name.indexOf(pr[p])>=0&&vs[vi].lang.indexOf('en')===0){bv=vs[vi];break;}}}"
        "if(!bv){for(var vi=0;vi<vs.length;vi++){if(vs[vi].lang.indexOf('en')===0){bv=vs[vi];break;}}}"
        "if(bv)u.voice=bv;"
        "if(cb)u.onend=cb;"
        "speechSynthesis.speak(u)}"
        "function phInit(){"
        "document.getElementById('phHE').textContent=String.fromCodePoint(PH_E);"
        "document.getElementById('phHT').textContent=PH_T;"
        "phTot=PH_D.length;phOk=0;phi=0;phDone=false;"
        "var pg=document.getElementById('phPg');pg.innerHTML='';"
        "PH_D.forEach(function(_,i){"
        "var d=document.createElement('div');d.className='ph-dot';d.id='phD'+i;"
        "pg.appendChild(d)});"
        "phUpSc();phRound()}"
        "function phUpSc(){document.getElementById('phSc').textContent=phOk+' / '+phTot}"
        "function phUpDots(){"
        "PH_D.forEach(function(_,i){"
        "var d=document.getElementById('phD'+i);"
        "d.classList.remove('done','cur');"
        "if(i<phi)d.classList.add('done');"
        "else if(i===phi)d.classList.add('cur')})}"
        "function phRound(){"
        "if(phi>=PH_D.length){phComplete();return}"
        "phUpDots();"
        "var a=document.getElementById('phArea');a.innerHTML='';"
        "switch(PH_M){"
        "case 'letter_sound':phLetterSound();break;"
        "case 'cvc_build':phCvcBuild();break;"
        "case 'minimal_pairs':phMinPairs();break;"
        "case 'rhyme':phRhyme();break;"
        "case 'syllable':phSyllable();break}}"
        "function phComplete(){"
        "phDone=true;phUpDots();"
        "var a=document.getElementById('phArea');a.innerHTML='';"
        "var pct=Math.round(phOk/phTot*100);"
        "var st=pct>=80?'Excellent! \\u2B50':pct>=50?'Good job! \\u{1F44D}':'Keep practicing! \\u{1F4AA}';"
        "a.innerHTML='<div class=\"ph-complete\">"
        "\\u{1F389} Complete!<br>'+phOk+' / '+phTot+' correct ('+pct+'%)<br>'+st+'</div>'}"
        ""
        "function phLetterSound(){"
        "var d=PH_D[phi],a=document.getElementById('phArea');"
        "var big=document.createElement('div');big.className='ph-big';"
        "big.textContent=d.letter;big.onclick=function(){phSpk(d.letter)};a.appendChild(big);"
        "var sub=document.createElement('div');sub.className='ph-sub';"
        "sub.textContent='Tap the letter to hear its sound';a.appendChild(sub);"
        "var sub2=document.createElement('div');sub2.className='ph-sub';"
        "sub2.textContent='Select words that START with this sound:';a.appendChild(sub2);"
        "var cc=document.createElement('div');cc.className='ph-cards';"
        "var answered=0,total=d.words.filter(function(w){return w.match}).length;"
        "d.words.forEach(function(w){"
        "var c=document.createElement('div');c.className='ph-card';"
        "c.innerHTML=String.fromCodePoint(w.cp)+' '+w.w;"
        "c.onclick=function(){"
        "if(c.classList.contains('correct')||c.classList.contains('wrong'))return;"
        "if(w.match){c.classList.add('correct');phSpk(w.w);answered++;"
        "if(answered>=total){phOk++;phUpSc();"
        "setTimeout(function(){phi++;phRound()},900)}}"
        "else{c.classList.add('wrong');setTimeout(function(){c.classList.remove('wrong')},600)}};cc.appendChild(c)});"
        "a.appendChild(cc);"
        "setTimeout(function(){phSpk(d.letter)},300)}"
        ""
        "function phCvcBuild(){"
        "var d=PH_D[phi],a=document.getElementById('phArea');"
        "var em=document.createElement('div');em.className='ph-emoji';"
        "em.textContent=String.fromCodePoint(d.cp);a.appendChild(em);"
        "var row=document.createElement('div');row.style.cssText='display:flex;align-items:center;gap:10px';"
        "var spk=document.createElement('div');spk.className='ph-spk';"
        "spk.innerHTML='\\u{1F50A}';spk.onclick=function(){phSpk(d.word)};row.appendChild(spk);"
        "var hint=document.createElement('div');hint.className='ph-sub';"
        "hint.textContent='Build the word!';row.appendChild(hint);a.appendChild(row);"
        "var slots=document.createElement('div');slots.className='ph-slots';"
        "var filled=[];"
        "var ltrs=d.letters.split('');"
        "ltrs.forEach(function(_,i){"
        "var s=document.createElement('div');s.className='ph-slot';s.id='phS'+i;"
        "s.onclick=function(){if(filled[i]!==undefined){"
        "var li=filled[i];filled[i]=undefined;s.textContent='';s.classList.remove('filled');"
        "var lb=document.getElementById('phL'+li);if(lb)lb.classList.remove('used')}};slots.appendChild(s)});"
        "a.appendChild(slots);"
        "var avail='abcdefghijklmnopqrstuvwxyz'.split('');"
        "var pool=ltrs.slice();"
        "while(pool.length<Math.min(ltrs.length+6,14)){"
        "var r=avail[Math.floor(Math.random()*avail.length)];"
        "if(pool.indexOf(r)<0)pool.push(r)}"
        "pool.sort(function(){return Math.random()-0.5});"
        "var lc=document.createElement('div');lc.className='ph-letters';"
        "pool.forEach(function(ch,li){"
        "var b=document.createElement('div');b.className='ph-lbtn';b.id='phL'+li;"
        "b.textContent=ch;"
        "b.onclick=function(){"
        "if(b.classList.contains('used'))return;"
        "var si=-1;for(var j=0;j<ltrs.length;j++){if(filled[j]===undefined){si=j;break}}"
        "if(si<0)return;"
        "filled[si]=li;b.classList.add('used');"
        "var sl=document.getElementById('phS'+si);sl.textContent=ch;sl.classList.add('filled');"
        "var allFilled=true;for(var j=0;j<ltrs.length;j++){if(filled[j]===undefined){allFilled=false;break}}"
        "if(allFilled){"
        "var built='';for(var j=0;j<ltrs.length;j++){built+=document.getElementById('phS'+j).textContent}"
        "if(built===d.letters){"
        "phOk++;phUpSc();phSpk(d.word);"
        "setTimeout(function(){phi++;phRound()},1200)}"
        "else{"
        "for(var j=0;j<ltrs.length;j++){document.getElementById('phS'+j).classList.add('error')}"
        "setTimeout(function(){"
        "for(var j=0;j<ltrs.length;j++){"
        "document.getElementById('phS'+j).classList.remove('error','filled');"
        "document.getElementById('phS'+j).textContent='';filled[j]=undefined}"
        "pool.forEach(function(_,k){document.getElementById('phL'+k).classList.remove('used')})},800)}}};lc.appendChild(b)});"
        "a.appendChild(lc);"
        "setTimeout(function(){phSpk(d.word)},300)}"
        ""
        "function phMinPairs(){"
        "var d=PH_D[phi],a=document.getElementById('phArea');"
        "var pr=document.createElement('div');pr.className='ph-pair';"
        "var mkW=function(txt){"
        "var pw=document.createElement('div');pw.className='ph-pw';"
        "var t=document.createElement('div');t.className='ph-pw-t';t.textContent=txt;pw.appendChild(t);"
        "var s=document.createElement('div');s.className='ph-spk';s.innerHTML='\\u{1F50A}';"
        "s.onclick=function(){phSpk(txt)};pw.appendChild(s);return pw};"
        "pr.appendChild(mkW(d.w1));"
        "var vs=document.createElement('div');vs.style.cssText='font-size:20px;color:#c4b5fd;font-weight:800';"
        "vs.textContent='vs';pr.appendChild(vs);"
        "pr.appendChild(mkW(d.w2));a.appendChild(pr);"
        "var q=document.createElement('div');q.className='ph-q';q.textContent=d.q;a.appendChild(q);"
        "var cc=document.createElement('div');cc.className='ph-cards';"
        "var opts=[d.w1,d.w2];"
        "opts.forEach(function(w,i){"
        "var c=document.createElement('div');c.className='ph-card';"
        "c.textContent=w;c.style.minWidth='120px';"
        "c.onclick=function(){"
        "if(c.classList.contains('correct')||c.classList.contains('disabled'))return;"
        "if(i===d.ans){c.classList.add('correct');phOk++;phUpSc();phSpk(w);"
        "cc.querySelectorAll('.ph-card').forEach(function(x){x.classList.add('disabled')});"
        "setTimeout(function(){phi++;phRound()},1000)}"
        "else{c.classList.add('wrong');setTimeout(function(){c.classList.remove('wrong')},600)}};cc.appendChild(c)});"
        "a.appendChild(cc);"
        "setTimeout(function(){phSpk(d.w1,function(){setTimeout(function(){phSpk(d.w2)},500)})},300)}"
        ""
        "function phRhyme(){"
        "var d=PH_D[phi],a=document.getElementById('phArea');"
        "var tw=document.createElement('div');tw.className='ph-big';tw.style.fontSize='50px';"
        "tw.textContent=d.target;tw.onclick=function(){phSpk(d.target)};a.appendChild(tw);"
        "var sub=document.createElement('div');sub.className='ph-sub';"
        "sub.textContent='Select ALL words that rhyme with \"'+d.target+'\":';a.appendChild(sub);"
        "var cc=document.createElement('div');cc.className='ph-cards';cc.style.flexDirection='column';"
        "cc.style.maxWidth='400px';"
        "var sel={};"
        "d.words.forEach(function(w,i){"
        "var c=document.createElement('div');c.className='ph-cbx';c.id='phR'+i;"
        "c.innerHTML='<span class=\"tick\"></span> '+w.w;"
        "sel[i]=false;"
        "c.onclick=function(){"
        "sel[i]=!sel[i];c.classList.toggle('checked');phSpk(w.w)};cc.appendChild(c)});"
        "a.appendChild(cc);"
        "var btn=document.createElement('div');btn.className='ph-check';btn.textContent='Check Answers';"
        "btn.onclick=function(){"
        "var ok=true;"
        "d.words.forEach(function(w,i){"
        "var c=document.getElementById('phR'+i);"
        "if(w.match&&!sel[i]){ok=false;c.style.borderColor='#ef4444'}"
        "else if(!w.match&&sel[i]){ok=false;c.style.borderColor='#ef4444'}"
        "else if(w.match&&sel[i]){c.classList.add('checked');c.style.borderColor='#34d399'}"
        "});"
        "if(ok){phOk++;phUpSc()}"
        "var fb=document.createElement('div');fb.className='ph-fb '+(ok?'ok':'no');"
        "fb.textContent=ok?'Correct! Well done!':'Not quite. The rhyming words are highlighted.';"
        "a.appendChild(fb);"
        "setTimeout(function(){phi++;phRound()},1500)};a.appendChild(btn);"
        "setTimeout(function(){phSpk(d.target)},300)}"
        ""
        "function phSyllable(){"
        "var d=PH_D[phi],a=document.getElementById('phArea');"
        "var tw=document.createElement('div');tw.className='ph-big';tw.style.fontSize='44px';"
        "tw.textContent=d.word;tw.onclick=function(){phSpk(d.word)};a.appendChild(tw);"
        "var spk=document.createElement('div');spk.className='ph-spk';spk.innerHTML='\\u{1F50A}';"
        "spk.onclick=function(){phSpk(d.word)};a.appendChild(spk);"
        "var sub=document.createElement('div');sub.className='ph-q';"
        "sub.textContent='How many syllables?';a.appendChild(sub);"
        "var btns=document.createElement('div');btns.className='ph-syl-btns';"
        "for(var n=1;n<=5;n++){(function(num){"
        "var b=document.createElement('div');b.className='ph-syl';b.textContent=num;"
        "b.onclick=function(){"
        "if(b.classList.contains('correct')||b.classList.contains('wrong'))return;"
        "btns.querySelectorAll('.ph-syl').forEach(function(x){x.classList.remove('wrong')});"
        "if(num===d.count){b.classList.add('correct');phOk++;phUpSc();phSpk(d.word);"
        "setTimeout(function(){phi++;phRound()},1000)}"
        "else{b.classList.add('wrong');setTimeout(function(){b.classList.remove('wrong')},600)}};btns.appendChild(b)})(n)}"
        "a.appendChild(btns);"
        "setTimeout(function(){phSpk(d.word)},300)}"
        ""
        "var cv=document.getElementById('phCv'),cx=cv.getContext('2d');"
        "function rsz(){cv.width=cv.offsetWidth;cv.height=cv.offsetHeight}rsz();"
        "window.addEventListener('resize',rsz);"
        "var pts=[];for(var i=0;i<35;i++)pts.push({x:Math.random()*cv.width,"
        "y:Math.random()*cv.height,r:Math.random()*2+0.8,"
        "dx:(Math.random()-0.5)*0.4,dy:(Math.random()-0.5)*0.4,"
        "a:Math.random()*0.4+0.1});"
        "function drw(){cx.clearRect(0,0,cv.width,cv.height);"
        "pts.forEach(function(p){p.x+=p.dx;p.y+=p.dy;"
        "if(p.x<0)p.x=cv.width;if(p.x>cv.width)p.x=0;"
        "if(p.y<0)p.y=cv.height;if(p.y>cv.height)p.y=0;"
        "cx.beginPath();cx.arc(p.x,p.y,p.r,0,Math.PI*2);"
        "cx.fillStyle='rgba(168,85,247,'+p.a+')';cx.fill()});"
        "requestAnimationFrame(drw)}drw();"
        "window.addEventListener('beforeunload',function(){try{speechSynthesis.cancel()}catch(e){}});"
        "document.addEventListener('visibilitychange',function(){"
        "if(document.hidden){try{speechSynthesis.cancel()}catch(e){}}});"
        "phInit();"
        "</script></body></html>"
    )


