def _build_word_emoji_map():
    """Tum kelime havuzlarindan lowercase_word -> (emoji, OriginalWord) dict."""
    m = {}
    for pool in [_ACT_WORDS_PRESCHOOL, _ACT_WORDS_GRADE1, _ACT_WORDS_GRADE2,
                 _ACT_WORDS_GRADE3, _ACT_WORDS_GRADE4, _ACT_WORDS_GRADE5,
                 _ACT_WORDS_GRADE6, _ACT_WORDS_GRADE7, _ACT_WORDS_GRADE8,
                 _ACT_WORDS_GRADE10, _ACT_WORDS_GRADE12]:
        for items in pool.values():
            for emoji, word in items:
                m[word.lower()] = (emoji, word)
    return m

_WORD_TO_EMOJI = _build_word_emoji_map()

