# ══════════════════════════════════════════════════════════════════════════════
# LISTENING COMPREHENSION (Dinleme Anlama) — Template + Builders
# ══════════════════════════════════════════════════════════════════════════════


def _ps_listening_template(title, emoji_cp, mode, data_js):
    """Listening comprehension sablonu — 3 mod destekler.
    mode: 'listen_choose' | 'listen_order' | 'listen_fill'
    data_js: moda uygun JS array string

    listen_choose data: [{q:"...",audio:"word",opts:["a","b","c"],ans:0}, ...]
      (legacy: {sentence:"...",opts:[...],ans:N} — audio/q otomatik fallback)
    listen_order data: [{audio:"I like apples",words:["I","like","apples"],order:[0,1,2]}, ...]
      (legacy: {sentence:"...",words:[...]} — audio fallback, order=identity)
    listen_fill data: [{audio:"The cat is big",sentence:"The ___ is big",opts:["cat","dog"],ans:0}, ...]
      (legacy: {sentence:"...",missing:"word",hint:"h__t"} — text-input mode)
    """
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'>"
        "<style>"
        "*{margin:0;padding:0;box-sizing:border-box}"
        "html,body{height:100%;overflow:hidden}"
        "body{background:linear-gradient(135deg,#1a0533 0%,#0d0221 50%,#150530 100%);"
        "font-family:'Segoe UI',system-ui,sans-serif;display:flex;justify-content:center}"
        ".ls-wrap{width:100%;max-width:820px;height:100vh;position:relative;overflow:hidden;"
        "background:linear-gradient(180deg,rgba(30,10,60,.95),rgba(10,5,30,.98));"
        "border-left:2px solid rgba(168,85,247,.3);border-right:2px solid rgba(168,85,247,.3)}"
        "canvas{position:absolute;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:0}"
        ".ls-ct{position:relative;z-index:1;width:100%;height:100%;display:flex;flex-direction:column;"
        "align-items:center;overflow:hidden}"
        ".ls-hdr{text-align:center;padding:10px 0 6px;"
        "background:linear-gradient(180deg,rgba(124,58,237,.25),transparent);"
        "border-bottom:1px solid rgba(168,85,247,.2);width:100%;"
        "display:flex;flex-direction:column;align-items:center}"
        ".ls-hdr-em{font-size:30px;display:block;margin-bottom:2px;"
        "filter:drop-shadow(0 0 12px rgba(168,85,247,.8))}"
        ".ls-hdr-t{font-size:16px;font-weight:800;color:#e9d5ff;"
        "text-shadow:0 0 20px rgba(168,85,247,.6);letter-spacing:1.5px}"
        ".ls-score{color:#c4b5fd;font-size:13px;margin:4px 0;font-weight:600;"
        "background:rgba(124,58,237,.15);padding:3px 16px;border-radius:20px;"
        "border:1px solid rgba(168,85,247,.25)}"
        ".ls-prog{display:flex;justify-content:center;gap:4px;padding:4px 8px;flex-wrap:wrap}"
        ".ls-dot{width:9px;height:9px;border-radius:50%;"
        "background:rgba(168,85,247,.2);border:1px solid rgba(168,85,247,.3);transition:all .3s}"
        ".ls-dot.done{background:#34d399;border-color:#6ee7b7}"
        ".ls-dot.cur{background:#fbbf24;border-color:#fcd34d;transform:scale(1.4);"
        "box-shadow:0 0 8px rgba(251,191,36,.6)}"
        ".ls-area{flex:1;display:flex;flex-direction:column;align-items:center;"
        "justify-content:center;width:100%;padding:8px 16px;gap:8px;overflow-y:auto}"
        ".ls-area::-webkit-scrollbar{width:6px}"
        ".ls-area::-webkit-scrollbar-thumb{background:rgba(168,85,247,.3);border-radius:3px}"
        ".ls-spk-big{width:72px;height:72px;border-radius:50%;"
        "background:linear-gradient(135deg,#7c3aed,#6d28d9);"
        "border:3px solid rgba(196,181,253,.3);cursor:pointer;font-size:34px;"
        "color:#fff;display:flex;align-items:center;justify-content:center;"
        "box-shadow:0 0 25px rgba(124,58,237,.5);transition:all .3s;"
        "animation:lsPulse 2s ease-in-out infinite}"
        ".ls-spk-big:hover{transform:scale(1.12);box-shadow:0 0 35px rgba(124,58,237,.8)}"
        ".ls-spk-big:active{transform:scale(.95)}"
        "@keyframes lsPulse{0%,100%{box-shadow:0 0 25px rgba(124,58,237,.5)}"
        "50%{box-shadow:0 0 40px rgba(124,58,237,.8),0 0 60px rgba(168,85,247,.3)}}"
        ".ls-hint{font-size:13px;color:#a78bfa;font-weight:600;margin-top:2px}"
        ".ls-q{font-size:18px;font-weight:700;color:#fbbf24;text-align:center;"
        "margin:4px 0;text-shadow:0 0 10px rgba(251,191,36,.3)}"
        ".ls-sent{font-size:22px;font-weight:800;color:#e9d5ff;text-align:center;"
        "text-shadow:0 0 15px rgba(168,85,247,.5);letter-spacing:1px}"
        ".ls-blank{color:#fbbf24;border-bottom:3px dashed rgba(251,191,36,.5);padding:0 8px}"
        ".ls-opts{display:flex;flex-direction:column;gap:8px;width:100%;max-width:500px;margin-top:8px}"
        ".ls-opt{padding:11px 16px;border-radius:14px;"
        "border:2px solid rgba(168,85,247,.3);"
        "background:linear-gradient(145deg,rgba(40,20,80,.4),rgba(20,10,50,.6));"
        "cursor:pointer;font-size:14px;font-weight:600;color:#d4c6f0;"
        "transition:all .3s cubic-bezier(.34,1.56,.64,1);"
        "display:flex;align-items:center;gap:10px}"
        ".ls-opt:hover{transform:translateX(4px);border-color:rgba(168,85,247,.6);"
        "background:linear-gradient(145deg,rgba(60,30,100,.5),rgba(30,15,60,.7))}"
        ".ls-opt .ls-ltr{display:inline-flex;align-items:center;justify-content:center;"
        "width:26px;height:26px;border-radius:50%;font-size:12px;font-weight:800;"
        "background:rgba(168,85,247,.25);color:#c4b5fd;flex-shrink:0}"
        ".ls-opt.correct{background:linear-gradient(145deg,rgba(16,185,129,.35),rgba(5,150,105,.5));"
        "border-color:#34d399;color:#a7f3d0;"
        "box-shadow:0 0 20px rgba(52,211,153,.4);animation:lsCorrect .5s ease}"
        ".ls-opt.correct .ls-ltr{background:rgba(52,211,153,.4);color:#a7f3d0}"
        "@keyframes lsCorrect{0%{transform:scale(1)}30%{transform:scale(1.05)}"
        "60%{transform:scale(.98)}100%{transform:scale(1)}}"
        ".ls-opt.wrong{background:linear-gradient(145deg,rgba(239,68,68,.25),rgba(220,38,38,.35));"
        "border-color:#f87171;color:#fca5a5;animation:lsWrong .4s ease}"
        ".ls-opt.wrong .ls-ltr{background:rgba(239,68,68,.4);color:#fca5a5}"
        "@keyframes lsWrong{0%,100%{transform:translateX(0)}"
        "20%{transform:translateX(-8px)}40%{transform:translateX(8px)}"
        "60%{transform:translateX(-4px)}80%{transform:translateX(4px)}}"
        ".ls-opt.disabled{pointer-events:none;opacity:.5}"
        ".ls-cards{display:flex;flex-wrap:wrap;gap:10px;justify-content:center;max-width:700px}"
        ".ls-card{padding:12px 22px;border-radius:14px;"
        "background:linear-gradient(135deg,rgba(124,58,237,.2),rgba(99,45,200,.12));"
        "border:2px solid rgba(168,85,247,.3);color:#e9d5ff;font-size:17px;font-weight:700;"
        "cursor:pointer;transition:all .3s;display:flex;align-items:center;gap:8px;"
        "user-select:none;min-width:100px;justify-content:center}"
        ".ls-card:hover{transform:translateY(-3px);border-color:rgba(168,85,247,.7);"
        "box-shadow:0 4px 20px rgba(168,85,247,.3)}"
        ".ls-card.correct{border-color:#34d399;background:rgba(52,211,153,.2);"
        "box-shadow:0 0 20px rgba(52,211,153,.5);animation:lsPop .4s ease}"
        ".ls-card.wrong{border-color:#ef4444;background:rgba(239,68,68,.15);"
        "animation:lsShake .5s ease}"
        ".ls-card.selected{border-color:#fbbf24;background:rgba(251,191,36,.15);"
        "box-shadow:0 0 15px rgba(251,191,36,.3)}"
        ".ls-card.disabled{opacity:.5;pointer-events:none}"
        ".ls-card.placed{border-color:#a78bfa;background:rgba(167,139,250,.15)}"
        "@keyframes lsPop{0%{transform:scale(1)}50%{transform:scale(1.15)}100%{transform:scale(1)}}"
        "@keyframes lsShake{0%,100%{transform:translateX(0)}20%{transform:translateX(-8px)}"
        "40%{transform:translateX(8px)}60%{transform:translateX(-5px)}80%{transform:translateX(5px)}}"
        ".ls-words{display:flex;flex-wrap:wrap;gap:8px;justify-content:center;"
        "max-width:600px;margin:8px 0}"
        ".ls-wcard{padding:10px 18px;border-radius:14px;"
        "background:linear-gradient(135deg,rgba(124,58,237,.2),rgba(99,45,200,.12));"
        "border:2px solid rgba(168,85,247,.3);color:#e9d5ff;font-size:16px;font-weight:700;"
        "cursor:pointer;transition:all .3s;user-select:none;min-width:60px;text-align:center}"
        ".ls-wcard:hover{transform:translateY(-3px);border-color:rgba(168,85,247,.7);"
        "box-shadow:0 4px 20px rgba(168,85,247,.3)}"
        ".ls-wcard.used{opacity:.3;pointer-events:none}"
        ".ls-wcard.correct{border-color:#34d399;background:rgba(52,211,153,.2);"
        "box-shadow:0 0 15px rgba(52,211,153,.4)}"
        ".ls-wcard.wrong{border-color:#ef4444;background:rgba(239,68,68,.15);"
        "animation:lsWrong .5s ease}"
        ".ls-slots{display:flex;flex-wrap:wrap;gap:6px;justify-content:center;"
        "margin:8px 0;min-height:44px;padding:8px 12px;border-radius:14px;"
        "background:rgba(124,58,237,.08);border:2px dashed rgba(168,85,247,.25);"
        "max-width:600px;width:100%}"
        ".ls-slot{padding:6px 14px;border-radius:10px;"
        "background:linear-gradient(135deg,rgba(52,211,153,.15),rgba(52,211,153,.08));"
        "border:1.5px solid rgba(52,211,153,.3);color:#a7f3d0;font-size:15px;"
        "font-weight:600;cursor:pointer;transition:all .3s}"
        ".ls-slot:hover{background:rgba(239,68,68,.15);border-color:#f87171}"
        ".ls-inp-wrap{display:flex;gap:10px;align-items:center;margin:8px 0}"
        ".ls-inp{padding:10px 16px;border-radius:12px;font-size:16px;font-weight:600;"
        "border:2px solid rgba(168,85,247,.4);background:rgba(30,15,60,.6);color:#e9d5ff;"
        "outline:none;width:180px;text-align:center;transition:border-color .3s}"
        ".ls-inp:focus{border-color:#a855f7;box-shadow:0 0 15px rgba(168,85,247,.3)}"
        ".ls-inp.correct{border-color:#34d399;background:rgba(52,211,153,.1);color:#a7f3d0}"
        ".ls-inp.wrong{border-color:#ef4444;background:rgba(239,68,68,.08);color:#fca5a5}"
        ".ls-sentence{font-size:16px;font-weight:600;color:#e2d6f8;text-align:center;"
        "line-height:1.6;padding:8px 16px;border-radius:14px;"
        "background:linear-gradient(135deg,rgba(124,58,237,.12),rgba(99,45,200,.08));"
        "border:1.5px solid rgba(168,85,247,.2);max-width:560px}"
        ".ls-sentence .blank{display:inline-block;min-width:60px;border-bottom:2.5px dashed #a855f7;"
        "color:#fbbf24;font-weight:700;margin:0 2px;padding:0 4px}"
        ".ls-hint-text{font-size:12px;color:#a78bfa;font-style:italic;margin-top:2px}"
        ".ls-check{padding:8px 24px;border-radius:25px;border:2px solid rgba(52,211,153,.4);"
        "background:linear-gradient(135deg,#059669,#047857);color:#fff;font-size:14px;"
        "font-weight:700;cursor:pointer;transition:all .3s;margin-top:4px}"
        ".ls-check:hover{transform:scale(1.08);box-shadow:0 0 20px rgba(52,211,153,.6)}"
        ".ls-next{padding:8px 28px;border-radius:25px;border:2px solid rgba(168,85,247,.4);"
        "background:linear-gradient(135deg,#7c3aed,#6d28d9);color:#fff;font-size:15px;"
        "font-weight:700;cursor:pointer;transition:all .3s;margin-top:6px}"
        ".ls-next:hover{transform:scale(1.08);box-shadow:0 0 20px rgba(124,58,237,.6)}"
        ".ls-fb{font-size:14px;font-weight:700;padding:5px 14px;border-radius:12px;margin:4px 0;"
        "text-align:center}"
        ".ls-fb.ok{color:#6ee7b7;background:rgba(52,211,153,.15);border:1px solid rgba(52,211,153,.3)}"
        ".ls-fb.no{color:#fca5a5;background:rgba(239,68,68,.12);border:1px solid rgba(239,68,68,.3)}"
        ".ls-complete{text-align:center;padding:16px}"
        ".ls-comp-emoji{font-size:60px;margin-bottom:6px;"
        "animation:lsFloat 2s ease-in-out infinite}"
        "@keyframes lsFloat{0%,100%{transform:translateY(0)}50%{transform:translateY(-8px)}}"
        ".ls-comp-title{font-size:22px;font-weight:800;color:#e9d5ff;"
        "text-shadow:0 0 15px rgba(168,85,247,.5);margin-bottom:4px}"
        ".ls-comp-score{font-size:16px;color:#c4b5fd;margin-bottom:4px}"
        ".ls-comp-stars{font-size:40px;margin-bottom:10px;"
        "filter:drop-shadow(0 0 10px rgba(251,191,36,.6))}"
        ".ls-replay{padding:12px 36px;font-size:16px;font-weight:700;"
        "border-radius:50px;border:2px solid rgba(196,181,253,.3);cursor:pointer;"
        "color:#fff;background:linear-gradient(135deg,#7c3aed,#6d28d9);"
        "box-shadow:0 0 20px rgba(124,58,237,.4);transition:all .3s;"
        "letter-spacing:1px}"
        ".ls-replay:hover{transform:scale(1.08);box-shadow:0 0 30px rgba(124,58,237,.7)}"
        "</style></head><body>"
        "<div class='ls-wrap'><canvas id='lsCv'></canvas>"
        "<div class='ls-ct'>"
        "<div class='ls-hdr'>"
        "<span class='ls-hdr-em' id='lsHE'></span>"
        "<div class='ls-hdr-t' id='lsHT'></div></div>"
        "<div class='ls-score' id='lsSc'>0 / 0</div>"
        "<div class='ls-prog' id='lsPg'></div>"
        "<div class='ls-area' id='lsArea'></div>"
        "</div></div>"
        "<script>"
        "try{window.speechSynthesis.cancel()}catch(e){}"
        "var LS_T='" + title.replace("'", "\\'") + "',LS_E=" + str(emoji_cp) + ","
        "LS_M='" + mode + "',"
        "LS_D=" + data_js + ";"
        "var lsi=0,lsOk=0,lsTot=0,lsDone=false;"

        "function lstSpk(text,cb){"
        "try{speechSynthesis.cancel()}catch(e){}"
        "var u=new SpeechSynthesisUtterance(text);"
        "u.lang='en-US';u.rate=0.85;u.pitch=1.1;"
        "var vs=speechSynthesis.getVoices();"
        "var pr=['Google UK English Female','Google US English','Microsoft Zira','Microsoft Jenny','Samantha','Karen','Daniel','Moira'];"
        "var bv=null;for(var p=0;p<pr.length&&!bv;p++){for(var vi=0;vi<vs.length;vi++){if(vs[vi].name.indexOf(pr[p])>=0&&vs[vi].lang.indexOf('en')===0){bv=vs[vi];break;}}}"
        "if(!bv){for(var vi=0;vi<vs.length;vi++){if(vs[vi].lang.indexOf('en')===0){bv=vs[vi];break;}}}"
        "if(bv)u.voice=bv;"
        "if(cb)u.onend=cb;"
        "speechSynthesis.speak(u)}"
        "speechSynthesis.getVoices();"

        "function playMelody(notes){"
        "if(!window._uc)return;"
        "try{var ac=new(window.AudioContext||window.webkitAudioContext)();"
        "var t=ac.currentTime;"
        "for(var i=0;i<notes.length;i++){var o=ac.createOscillator();var g=ac.createGain();"
        "o.type='sine';o.frequency.value=notes[i][0];"
        "g.gain.setValueAtTime(0.12,t);g.gain.exponentialRampToValueAtTime(0.001,t+notes[i][1]);"
        "o.connect(g);g.connect(ac.destination);"
        "o.start(t);o.stop(t+notes[i][1]);t+=notes[i][1]*0.7;}"
        "}catch(e){}}"
        "function playCorrect(){playMelody([[523,0.12],[659,0.12],[784,0.12],[1047,0.25]]);}"
        "function playWrong(){playMelody([[300,0.15],[200,0.3]]);}"
        "function playFinish(){playMelody([[523,0.15],[659,0.15],[784,0.15],[1047,0.15],[1319,0.3]]);}"

        "function spawnConfetti(n){"
        "var colors=['#fbbf24','#34d399','#60a5fa','#f472b6','#a78bfa','#fb923c','#e879f9'];"
        "for(var i=0;i<n;i++){var el=document.createElement('div');"
        "el.style.cssText='position:fixed;pointer-events:none;z-index:9999;"
        "width:'+(Math.random()*8+5)+'px;height:'+(Math.random()*8+5)+'px;"
        "background:'+colors[Math.floor(Math.random()*colors.length)]+"
        "';border-radius:'+(Math.random()>0.5?'50%':'2px')+"
        "';left:'+Math.random()*100+'%;top:-10px;"
        "animation:confDrop '+(Math.random()*1.5+1)+'s ease-out '+(Math.random()*0.4)+'s forwards;';"
        "document.body.appendChild(el);"
        "setTimeout(function(){el.remove();},3500);}}"
        "var cSt=document.createElement('style');"
        "cSt.textContent='@keyframes confDrop{0%{transform:translateY(0) rotate(0);opacity:1}"
        "100%{transform:translateY('+window.innerHeight+'px) rotate(720deg);opacity:0}}';"
        "document.head.appendChild(cSt);"

        "function lsInit(){"
        "document.getElementById('lsHE').textContent=String.fromCodePoint(LS_E);"
        "document.getElementById('lsHT').textContent=LS_T;"
        "lsTot=LS_D.length;lsOk=0;lsi=0;lsDone=false;"
        "var pg=document.getElementById('lsPg');pg.innerHTML='';"
        "LS_D.forEach(function(_,i){"
        "var d=document.createElement('div');d.className='ls-dot';d.id='lsD'+i;"
        "pg.appendChild(d)});"
        "lsUpSc();lsRound()}"
        "function lsUpSc(){document.getElementById('lsSc').textContent=lsOk+' / '+lsTot}"
        "function lsUpDots(){"
        "LS_D.forEach(function(_,i){"
        "var d=document.getElementById('lsD'+i);"
        "d.classList.remove('done','cur');"
        "if(i<lsi)d.classList.add('done');"
        "else if(i===lsi)d.classList.add('cur')})}"

        "function lsRound(){"
        "if(lsi>=LS_D.length){lsComplete();return}"
        "lsUpDots();"
        "var a=document.getElementById('lsArea');a.innerHTML='';"
        "switch(LS_M){"
        "case 'listen_choose':lsChoose();break;"
        "case 'listen_order':lsOrder();break;"
        "case 'listen_fill':lsFill();break}}"

        "function lsComplete(){"
        "lsDone=true;lsUpDots();playFinish();spawnConfetti(40);"
        "var a=document.getElementById('lsArea');a.innerHTML='';"
        "var pct=Math.round(lsOk/lsTot*100);"
        "var stars=pct>=90?3:pct>=60?2:1;"
        "var sStr='';for(var i=0;i<3;i++){sStr+=i<stars?'\\u2B50':'\\u2606';}"
        "var emoji=stars===3?String.fromCodePoint(0x1F389):"
        "stars===2?String.fromCodePoint(0x1F60A):String.fromCodePoint(0x1F4AA);"
        "a.innerHTML='<div class=\"ls-complete\">"
        "<div class=\"ls-comp-emoji\">'+emoji+'</div>"
        "<div class=\"ls-comp-title\">'+(stars===3?'Excellent!':stars===2?'Good Job!':'Keep Trying!')+'</div>"
        "<div class=\"ls-comp-stars\">'+sStr+'</div>"
        "<div class=\"ls-comp-score\">'+lsOk+' / '+lsTot+' Correct ('+pct+'%)</div>"
        "<button class=\"ls-replay\" onclick=\"lsInit()\">\\u21BB Try Again</button>"
        "</div>';}"

        "function lsChoose(){"
        "var d=LS_D[lsi],a=document.getElementById('lsArea');"
        "var ttsText=d.audio||d.sentence;"
        "var spk=document.createElement('button');spk.className='ls-spk-big';"
        "spk.innerHTML='&#x1F50A;';spk.onclick=function(){lstSpk(ttsText)};a.appendChild(spk);"
        "var h=document.createElement('div');h.className='ls-hint';"
        "h.textContent='Tap the speaker, then choose the correct answer';a.appendChild(h);"
        "if(d.q){var qEl=document.createElement('div');qEl.className='ls-q';qEl.textContent=d.q;a.appendChild(qEl);}"
        "var opts=document.createElement('div');opts.className='ls-opts';"
        "var letters=['A','B','C','D'];"
        "d.opts.forEach(function(txt,oi){"
        "var o=document.createElement('div');o.className='ls-opt';"
        "o.innerHTML='<span class=\"ls-ltr\">'+letters[oi]+'</span>'+txt;"
        "o.onclick=function(){"
        "if(o.classList.contains('disabled'))return;"
        "var all=opts.querySelectorAll('.ls-opt');"
        "for(var k=0;k<all.length;k++)all[k].classList.add('disabled');"
        "if(oi===d.ans){o.classList.add('correct');lsOk++;playCorrect();spawnConfetti(12);"
        "lstSpk(ttsText);}"
        "else{o.classList.add('wrong');playWrong();"
        "all[d.ans].classList.add('correct');}"
        "lsUpSc();"
        "setTimeout(function(){lsi++;lsRound()},1000);};"
        "opts.appendChild(o)});"
        "a.appendChild(opts);"
        "lstSpk(ttsText);}"

        "function lsOrder(){"
        "var d=LS_D[lsi],a=document.getElementById('lsArea');"
        "var ttsText=d.audio||d.sentence;"
        "var correctOrder=d.order?d.order:null;"
        "var spk=document.createElement('button');spk.className='ls-spk-big';"
        "spk.innerHTML='&#x1F50A;';spk.onclick=function(){lstSpk(ttsText)};a.appendChild(spk);"
        "var h=document.createElement('div');h.className='ls-hint';"
        "h.textContent='Listen and put the words in order';a.appendChild(h);"
        "var chosen=[];"
        "var slotsDiv=document.createElement('div');slotsDiv.className='ls-slots';"
        "a.appendChild(slotsDiv);"
        "var shuffled=d.words.slice();"
        "for(var i=shuffled.length-1;i>0;i--){var j=Math.floor(Math.random()*(i+1));"
        "var tmp=shuffled[i];shuffled[i]=shuffled[j];shuffled[j]=tmp;}"
        "var cardsDiv=document.createElement('div');cardsDiv.className='ls-words';"
        "var cardEls=[];"
        "shuffled.forEach(function(w,wi){"
        "var c=document.createElement('div');c.className='ls-wcard';"
        "c.textContent=w;c.setAttribute('data-word',w);"
        "c.onclick=function(){"
        "if(c.classList.contains('used'))return;"
        "c.classList.add('used');chosen.push(w);"
        "var sl=document.createElement('div');sl.className='ls-slot';"
        "sl.textContent=w;sl.onclick=function(){"
        "var idx=chosen.indexOf(w);if(idx>-1)chosen.splice(idx,1);"
        "sl.remove();c.classList.remove('used')};"
        "slotsDiv.appendChild(sl);"
        "if(chosen.length===d.words.length){"
        "var target=[];if(correctOrder){for(var k=0;k<correctOrder.length;k++)target.push(d.words[correctOrder[k]]);}"
        "else{target=d.words;}"
        "var ok=true;for(var k=0;k<target.length;k++){if(chosen[k]!==target[k]){ok=false;break;}}"
        "if(ok){lsOk++;playCorrect();spawnConfetti(12);lsUpSc();lstSpk(ttsText);"
        "setTimeout(function(){lsi++;lsRound()},1200);}"
        "else{"
        "playWrong();"
        "setTimeout(function(){"
        "chosen=[];slotsDiv.innerHTML='';"
        "cardEls.forEach(function(ce){ce.classList.remove('used')});},900);}}};"
        "cardEls.push(c);cardsDiv.appendChild(c)});"
        "a.appendChild(cardsDiv);"
        "lstSpk(ttsText);}"

        "function lsFill(){"
        "var d=LS_D[lsi],a=document.getElementById('lsArea');"
        "var isNewFmt=d.opts!==undefined&&d.ans!==undefined;"
        "var ttsText=d.audio||(d.sentence?d.sentence.replace('___',d.missing||''):'');"
        "var spk=document.createElement('button');spk.className='ls-spk-big';"
        "spk.innerHTML='&#x1F50A;';spk.onclick=function(){lstSpk(ttsText)};a.appendChild(spk);"
        "var h=document.createElement('div');h.className='ls-hint';"
        "h.textContent='Listen and fill in the blank';a.appendChild(h);"
        "if(isNewFmt){"
        "var sDiv=document.createElement('div');sDiv.className='ls-sent';"
        "var parts=(d.sentence||'').split('___');"
        "sDiv.innerHTML=parts[0]+'<span class=\"ls-blank\" id=\"lsBlank\">???</span>'+(parts[1]||'');"
        "a.appendChild(sDiv);"
        "var cc=document.createElement('div');cc.className='ls-cards';"
        "d.opts.forEach(function(opt,i){"
        "var c=document.createElement('div');c.className='ls-card';"
        "c.textContent=opt;"
        "c.onclick=function(){"
        "if(c.classList.contains('correct')||c.classList.contains('disabled'))return;"
        "var bl=document.getElementById('lsBlank');"
        "if(i===d.ans){c.classList.add('correct');bl.textContent=opt;bl.style.color='#6ee7b7';"
        "bl.style.borderColor='#34d399';lsOk++;lsUpSc();"
        "cc.querySelectorAll('.ls-card').forEach(function(x){x.classList.add('disabled')});"
        "playCorrect();spawnConfetti(12);lstSpk(ttsText);"
        "setTimeout(function(){lsi++;lsRound()},1000)}"
        "else{c.classList.add('wrong');playWrong();"
        "setTimeout(function(){c.classList.remove('wrong')},600)}};cc.appendChild(c)});"
        "a.appendChild(cc);}"
        "else{"
        "var sDiv=document.createElement('div');sDiv.className='ls-sentence';"
        "sDiv.innerHTML=d.sentence.replace('___','<span class=\"blank\">?</span>');"
        "a.appendChild(sDiv);"
        "if(d.hint){var ht=document.createElement('div');ht.className='ls-hint-text';"
        "ht.textContent='Hint: '+d.hint;a.appendChild(ht);}"
        "var iw=document.createElement('div');iw.className='ls-inp-wrap';"
        "var inp=document.createElement('input');inp.className='ls-inp';inp.type='text';"
        "inp.placeholder='Type the word...';inp.autocomplete='off';"
        "iw.appendChild(inp);"
        "var chk=document.createElement('button');chk.className='ls-check';"
        "chk.textContent='\\u2714 Check';iw.appendChild(chk);a.appendChild(iw);"
        "var fbDiv=document.createElement('div');fbDiv.className='ls-fb';a.appendChild(fbDiv);"
        "chk.onclick=function(){"
        "var val=inp.value.trim().toLowerCase();"
        "if(!val){fbDiv.className='ls-fb no';fbDiv.textContent='Type a word first!';return;}"
        "inp.disabled=true;chk.style.display='none';"
        "if(val===d.missing.toLowerCase()){inp.classList.add('correct');"
        "fbDiv.className='ls-fb ok';fbDiv.textContent='\\u2714 Correct!';"
        "lsOk++;playCorrect();spawnConfetti(12);"
        "sDiv.querySelector('.blank').textContent=d.missing;}"
        "else{inp.classList.add('wrong');"
        "fbDiv.className='ls-fb no';"
        "fbDiv.textContent='\\u2718 Answer: '+d.missing;playWrong();"
        "sDiv.querySelector('.blank').textContent=d.missing;}"
        "lsUpSc();"
        "setTimeout(function(){lsi++;lsRound()},1200);};"
        "inp.addEventListener('keydown',function(e){if(e.key==='Enter')chk.click()});}"
        "lstSpk(ttsText);}"

        "var cv=document.getElementById('lsCv'),cx=cv.getContext('2d');"
        "function rsz(){cv.width=cv.offsetWidth;cv.height=cv.offsetHeight;}rsz();"
        "window.addEventListener('resize',rsz);"
        "var pts=[];for(var i=0;i<35;i++)pts.push({x:Math.random()*cv.width,"
        "y:Math.random()*cv.height,r:Math.random()*2+0.8,"
        "dx:(Math.random()-0.5)*0.4,dy:(Math.random()-0.5)*0.4,"
        "a:Math.random()*0.4+0.1});"
        "function drw(){cx.clearRect(0,0,cv.width,cv.height);"
        "pts.forEach(function(p){p.x+=p.dx;p.y+=p.dy;"
        "if(p.x<0)p.x=cv.width;if(p.x>cv.width)p.x=0;"
        "if(p.y<0)p.y=cv.height;if(p.y>cv.height)p.y=0;"
        "cx.beginPath();cx.arc(p.x,p.y,p.r,0,Math.PI*2);"
        "cx.fillStyle='rgba(168,85,247,'+p.a+')';cx.fill();});"
        "requestAnimationFrame(drw);}drw();"
        "window.addEventListener('beforeunload',function(){try{speechSynthesis.cancel()}catch(e){}});"
        "document.addEventListener('visibilitychange',function(){"
        "if(document.hidden){try{speechSynthesis.cancel()}catch(e){}}});"
        "lsInit();"
        "</script></body></html>"
    )


