def _act_pdf(data):
    """Etkinlik verisinden A4 PDF calisma kagidi uret (ReportLab)."""
    from io import BytesIO
    try:
        from reportlab.lib.pagesizes import A4
        from reportlab.pdfgen import canvas as pdf_canvas
        from reportlab.lib.units import cm
        from utils.shared_data import ensure_turkish_pdf_fonts
    except ImportError:
        return b""

    font_name, font_bold = ensure_turkish_pdf_fonts()
    buf = BytesIO()
    w, h = A4
    c = pdf_canvas.Canvas(buf, pagesize=A4)
    y = h - 1.5 * cm

    lvl = data["level_label"]
    age = data["age"]
    diff_txt = {"easy": "Kolay", "medium": "Orta", "hard": "Zor"}.get(data["difficulty"], "")

    c.setFillColor("#7c3aed")
    c.roundRect(1.5 * cm, y - 30, w - 3 * cm, 40, 8, fill=1, stroke=0)
    c.setFillColor("#ffffff")
    c.setFont(font_bold, 15)
    c.drawCentredString(w / 2, y - 20, f"{lvl} Ingilizce Etkinlik Calisma Kagidi")
    # Hafta/gun bilgisi
    week_num = data.get("week_num")
    theme_tr = data.get("theme_tr", "")
    theme = data.get("theme", "")
    day_label = data.get("day_label", "")
    if week_num and day_label:
        sub_line = f"Hafta {week_num} - {theme_tr} ({theme}) - {day_label}"
    elif week_num:
        sub_line = f"Hafta {week_num} - {theme_tr} ({theme})"
    else:
        sub_line = f"English Activity Worksheet - Age {age} - {diff_txt}"

    c.setFont(font_name, 9)
    c.drawCentredString(w / 2, y - 30, sub_line)
    y -= 50

    c.setFillColor("#000000")
    c.setFont(font_name, 10)
    c.drawString(1.8 * cm, y, f"Tarih: {data['date']}    Seviye: {diff_txt}")
    c.drawRightString(w - 1.8 * cm, y, "Ad Soyad: ____________________________")
    y -= 6
    c.setStrokeColor("#e0e0e0")
    c.line(1.5 * cm, y, w - 1.5 * cm, y)
    y -= 16

    # Gunluk plan bilgisi (varsa)
    day_activities = data.get("day_activities", [])
    if day_activities:
        c.setFillColor("#0d9488")
        c.roundRect(1.5 * cm, y - 4, w - 3 * cm, 18, 4, fill=1, stroke=0)
        c.setFillColor("#ffffff")
        c.setFont(font_bold, 11)
        plan_title = f"Gunluk Plan - Hafta {week_num}: {theme_tr}"
        if day_label:
            plan_title += f" - {day_label}"
        c.drawString(2 * cm, y, plan_title)
        c.setFillColor("#000000")
        y -= 22
        c.setFont(font_name, 9)
        for act in day_activities:
            c.drawString(2.2 * cm, y, f"  > {act}")
            y -= 13
        y -= 6

    def section_header(txt, color):
        nonlocal y
        c.setFillColor(color)
        c.roundRect(1.5 * cm, y - 4, w - 3 * cm, 18, 4, fill=1, stroke=0)
        c.setFillColor("#ffffff")
        c.setFont(font_bold, 11)
        c.drawString(2 * cm, y, txt)
        c.setFillColor("#000000")
        y -= 22

    section_header("1) Eslestir (Match the Picture)", "#7c3aed")
    c.setFont(font_name, 11)
    shuffled_w = [w2 for _, w2 in data["match"]]
    random.shuffle(shuffled_w)
    for (emoji, word), sw in zip(data["match"], shuffled_w):
        c.drawString(2.2 * cm, y, f"  [{word}]")
        c.drawString(w / 2 + 1 * cm, y, f"____  {sw}")
        y -= 16
    y -= 6

    section_header("2) Eksik Harfi Yaz (Fill the Letter)", "#2563eb")
    c.setFont(font_name, 11)
    for emoji, word, blanked, letter in data["missing"]:
        c.drawString(2.2 * cm, y, f"  [{word[:1]}...]   {blanked}   ->  ___")
        y -= 16
    y -= 6

    section_header(f"3) Sarkiyi Tamamla - {data['song_title']}", "#059669")
    c.setFont(font_name, 10)
    for i, (line, removed) in enumerate(data["song_fill"], 1):
        c.drawString(2.2 * cm, y, f"  {i}. {line}")
        y -= 14
    y -= 6

    section_header(f"4) Diyalogu Sirala - {data['dlg_title']}", "#d97706")
    c.setFont(font_name, 10)
    n = len(data["dlg_shuffled"])
    c.drawString(2.2 * cm, y, f"  Dogru sirayi parantezlere yazin (1-{n})")
    y -= 14
    for speaker, text in data["dlg_shuffled"]:
        c.drawString(2.2 * cm, y, f"  (  )  {speaker}: {text}")
        y -= 14
    y -= 6

    section_header("5) Dogru / Yanlis (True or False)", "#dc2626")
    c.setFont(font_name, 10)
    for emoji, word, cat, is_true in data["truefalse"]:
        c.drawString(2.2 * cm, y, f"  {word} is a {cat} word.    ( True / False )")
        y -= 14

    # 6) Cumleni Kur
    sentences = data.get("sentences", [])
    if sentences:
        y -= 6
        section_header("6) Cumleni Kur (Build the Sentence)", "#7c3aed")
        c.setFont(font_name, 9)
        c.setFillColor("#666666")
        c.drawString(2.2 * cm, y, "Kelimeleri dogru siraya dizin ve cizgiye yazin.")
        y -= 14
        c.setFont(font_name, 10)
        c.setFillColor("#1a1a2e")
        for i, s in enumerate(sentences, 1):
            if y < 3 * cm:
                c.showPage()
                y = h - 2 * cm
            c.drawString(2.2 * cm, y, f"  {i}. {s['hint']}  [ {' | '.join(s['shuffled'])} ]")
            y -= 14
            c.setFont(font_name, 9)
            c.setFillColor("#c4b5fd")
            c.drawString(2.2 * cm, y, "   ________________________________________")
            y -= 16
            c.setFont(font_name, 10)
            c.setFillColor("#1a1a2e")

    y -= 12
    c.setFont(font_name, 8)
    c.setFillColor("#999999")
    c.drawCentredString(w / 2, max(y, 1 * cm), "SmartCampusAI - Dijital Kutuphane 2026")

    c.save()
    buf.seek(0)
    return buf.getvalue()


