def _academic_week_dates(week_num: int) -> tuple:
    """Hafta numarasından (Pzt, Cum) tarihlerini hesapla.
    Akademik yıl: Eylül 2. Pazartesi başlangıç, 18. hafta sonrası 2 hafta yarıyıl tatili.
    Returns: (monday_date, friday_date) veya (None, None)."""
    from datetime import date, timedelta
    today = date.today()
    # Akademik yıl başlangıç yılı: Eyl-Ara → bu yıl, Oca-Ağu → önceki yıl
    yr = today.year if today.month >= 9 else today.year - 1
    # Eylül'ün 2. Pazartesi'sini bul
    sep1 = date(yr, 9, 1)
    # İlk Pazartesi
    days_to_mon = (7 - sep1.weekday()) % 7
    first_mon = sep1 + timedelta(days=days_to_mon) if sep1.weekday() != 0 else sep1
    # 2. Pazartesi (okul başlangıcı)
    start = first_mon + timedelta(weeks=1)
    if week_num < 1 or week_num > 36:
        return (None, None)
    # Yarıyıl tatili: 18. hafta sonrası 2 hafta ara
    if week_num <= 18:
        monday = start + timedelta(weeks=week_num - 1)
    else:
        monday = start + timedelta(weeks=week_num - 1 + 2)  # +2 hafta tatil
    friday = monday + timedelta(days=4)
    return (monday, friday)


def _get_today_plan_info():
    """Bugunun akademik hafta, gun ve plan bilgisini dondurur.
    Returns dict: week_num, day_key, day_name, date_str, week_data(grade->plan), is_school_day"""
    from datetime import date, timedelta
    today = date.today()
    yr = today.year if today.month >= 9 else today.year - 1
    sep1 = date(yr, 9, 1)
    days_to_mon = (7 - sep1.weekday()) % 7
    first_mon = sep1 + timedelta(days=days_to_mon) if sep1.weekday() != 0 else sep1
    start = first_mon + timedelta(weeks=1)  # 2. Pazartesi
    # Bugunun haftasini ve gununu hesapla
    delta = (today - start).days
    _day_keys = ["mon", "tue", "wed", "thu", "fri", "sat", "sun"]
    _day_names = ["Pazartesi", "Sali", "Carsamba", "Persembe", "Cuma", "Cumartesi", "Pazar"]
    dow = today.weekday()  # 0=Mon
    is_school = dow < 5
    day_key = _day_keys[dow] if dow < 5 else None
    day_name = _day_names[dow]
    # Hafta hesabi (yariyil tatili dahil)
    if delta < 0:
        week_num = 1
    else:
        raw_week = delta // 7 + 1
        # 18. haftadan sonra 2 hafta tatil
        sem1_end = start + timedelta(weeks=18)
        sem2_start = sem1_end + timedelta(weeks=2)
        if today < sem1_end:
            week_num = raw_week
        elif today < sem2_start:
            week_num = 18  # tatil — 18. hafta goster
            is_school = False
        else:
            week_num = (today - sem2_start).days // 7 + 19
        week_num = max(1, min(36, week_num))
    # weekly_plans.json yukle
    _wp_cache_key = "_yd_weekly_plans_cache"
    if _wp_cache_key not in st.session_state:
        try:
            with open(_WP_PATH, "r", encoding="utf-8") as _f:
                st.session_state[_wp_cache_key] = _json.load(_f)
        except Exception:
            st.session_state[_wp_cache_key] = {}
    _wp = st.session_state[_wp_cache_key]
    return {
        "week_num": week_num,
        "day_key": day_key,
        "day_name": day_name,
        "date_str": today.strftime("%d.%m.%Y"),
        "is_school_day": is_school,
        "all_plans": _wp,
    }


def _render_daily_plan_panel(grade_key, plan_info=None):
    """Belirli bir sinif icin bugunun gunluk planini ve etkinliklerini gosterir.
    grade_key: '1','2',...'12','preschool'"""
    if plan_info is None:
        plan_info = _get_today_plan_info()
    _wn = plan_info["week_num"]
    _dk = plan_info["day_key"]
    _dn = plan_info["day_name"]
    _ds = plan_info["date_str"]
    _is_school = plan_info["is_school_day"]
    _wp = plan_info["all_plans"]
    # Bu sinifin plan verisi
    _grade_weeks = _wp.get(str(grade_key), [])
    _week_data = None
    for w in _grade_weeks:
        if w.get("week") == _wn:
            _week_data = w
            break
    # Tema adi (iki format: unit_theme veya theme)
    _theme_name = ""
    _theme_tr = ""
    if _week_data:
        _theme_name = _week_data.get("unit_theme") or _week_data.get("theme", "")
        _theme_tr = _week_data.get("unit_theme_tr") or _week_data.get("theme_tr", "")
    # Baslik
    _mon, _fri = _academic_week_dates(_wn)
    _date_range = ""
    if _mon and _fri:
        _date_range = f" ({_mon.strftime('%d.%m')} - {_fri.strftime('%d.%m')})"
    _theme_display = _theme_name
    if _theme_tr:
        _theme_display = f"{_theme_name} ({_theme_tr})" if _theme_name else _theme_tr
    st.markdown(
        f'<div style="background:linear-gradient(135deg,#111827,#eef2ff);'
        f'border:1.5px solid #c7d2fe;border-radius:14px;padding:16px 20px;margin:14px 0;'
        f'box-shadow:0 2px 8px rgba(0,0,0,.04);">'
        f'<div style="display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;">'
        f'<div>'
        f'<div style="font-size:1.1rem;font-weight:800;color:#4f46e5;">'
        f'&#x1F4C5; Gunluk Plan &mdash; {_dn}, {_ds}</div>'
        f'<div style="font-size:.8rem;color:#6366f1;margin-top:2px;">'
        f'Hafta {_wn}/36{_date_range}</div></div>'
        f'<div style="font-size:.75rem;color:#64748b;text-align:right;">'
        f'{_theme_display}'
        f'{"" if _is_school else " &mdash; <span style=color:#f87171;font-weight:700>Okul Disi Gun</span>"}'
        f'</div></div></div>',
        unsafe_allow_html=True,
    )
    if not _week_data:
        st.markdown(
            '<div style="text-align:center;padding:16px;color:#64748b;font-size:.88rem;">'
            '&#x1F4AD; Bu sinif icin henuz haftalik plan olusturulmamis. '
            'Plan & Etkinlik Olusturma aracindan plan olusturabilirsiniz.</div>',
            unsafe_allow_html=True,
        )
        return
    if not _is_school or not _dk:
        st.markdown(
            '<div style="text-align:center;padding:16px;color:#7dd3fc;font-size:.88rem;">'
            '&#x1F31F; Hafta sonu / tatil gunu &mdash; Hafta plani asagida goruntulenebilir.</div>',
            unsafe_allow_html=True,
        )
    # Gunun dersleri
    _day_raw = _week_data.get("days", {}).get(_dk, {}) if _dk else {}
    # Iki format var: dict{"day_name","hours":[...]} veya list["etkinlik1","etkinlik2"]
    if isinstance(_day_raw, list):
        # Basit liste formati (preschool, lise) — her ogesi bir etkinlik stringi
        if _day_raw:
            for _si, _s_item in enumerate(_day_raw):
                st.markdown(
                    f'<div style="background:linear-gradient(135deg,#0B0F1908,#94A3B805);'
                    f'border:1px solid #0ea5e925;border-left:4px solid #38bdf8;'
                    f'border-radius:10px;padding:12px 16px;margin:6px 0;">'
                    f'<div style="display:flex;align-items:center;gap:10px;">'
                    f'<div style="font-size:1.1rem;color:#0ea5e940;font-weight:800;">{_si+1}</div>'
                    f'<div style="font-size:.88rem;font-weight:600;color:#38bdf8;">{_s_item}</div>'
                    f'</div></div>',
                    unsafe_allow_html=True,
                )
        elif _is_school and _dk:
            st.markdown(
                '<div style="text-align:center;padding:12px;color:#64748b;font-size:.85rem;">'
                '&#x1F4CB; Bu gun icin detayli ders plani bulunmuyor.</div>',
                unsafe_allow_html=True,
            )
        _day_data = {}
        _hours = []
    else:
        _day_data = _day_raw
        _hours = _day_data.get("hours", [])
    if _hours:
        _slot_colors = {
            "green": ("#38bdf8", "#0B0F19"), "purple": ("#0ea5e9", "#0B0F19"),
            "blue": ("#7dd3fc", "#0B0F19"), "orange": ("#64748b", "#0B0F19"),
            "red": ("#f87171", "#0B0F19"),
        }
        def _format_focus_with_badges(focus_text):
            """Focus icindeki [E5.1.L1, E5.1.S2] kazanim kodlarini renkli badge'lere cevirir."""
            import re as _fre
            _badge_colors = {"L": "#7c3aed", "S": "#059669", "R": "#2563eb", "W": "#dc2626"}
            def _badge_repl(m):
                codes_str = m.group(1)
                codes = [c.strip() for c in codes_str.split(",")]
                badges = ""
                for c in codes:
                    parts = c.rsplit(".", 1)
                    skill = parts[-1][0] if parts and parts[-1] else "L"
                    color = _badge_colors.get(skill, "#6b7280")
                    badges += (
                        f'<span style="background:{color};color:#fff;padding:1px 6px;border-radius:5px;'
                        f'font-size:.6rem;font-weight:700;font-family:monospace;margin-left:3px;'
                        f'letter-spacing:.3px;">{c}</span>'
                    )
                return badges
            # Hem [...] hem (...) icindeki kodlari yakala
            result = _fre.sub(r'\[([^\]]+)\]', _badge_repl, focus_text)
            result = _fre.sub(r'\(([E][P0-9][^\)]*)\)', _badge_repl, result)
            return result

        for _h in _hours:
            _sc = _slot_colors.get(_h.get("slot_color", "green"), ("#38bdf8", "#0B0F19"))
            _mats = _h.get("materials", [])
            _acts = _h.get("activity", [])
            _mat_html = ""
            if _mats:
                _mat_html = '<div style="margin-top:6px;padding-top:6px;border-top:1px solid #0ea5e920;">'
                for _m in _mats:
                    _mat_html += (
                        f'<span style="display:inline-block;background:#0ea5e915;border:1px solid #0ea5e930;'
                        f'border-radius:6px;padding:2px 8px;font-size:.72rem;color:#38bdf8;'
                        f'margin:2px 4px 2px 0;">&#x1F4E6; {_m}</span>'
                    )
                _mat_html += '</div>'
            _act_html = ""
            if _acts:
                _act_html = '<div style="margin-top:6px;">'
                for _ai, _a in enumerate(_acts):
                    _a_fmt = _format_focus_with_badges(_a)
                    _act_html += (
                        f'<div style="font-size:.75rem;color:#64748b;padding:1px 0;">'
                        f'<span style="color:#0ea5e9;font-weight:600;">{_ai+1}.</span> {_a_fmt}</div>'
                    )
                _act_html += '</div>'
            st.markdown(
                f'<div style="background:linear-gradient(135deg,#0B0F1908,#94A3B805);'
                f'border:1px solid #0ea5e925;border-left:4px solid {_sc[0]};'
                f'border-radius:10px;padding:12px 16px;margin:6px 0;">'
                f'<div style="display:flex;justify-content:space-between;align-items:center;">'
                f'<div>'
                f'<span style="font-size:.7rem;color:{_sc[0]};font-weight:800;'
                f'text-transform:uppercase;letter-spacing:.5px;">'
                f'{_h.get("slot", "DERS")} &mdash; {_h.get("duration", "40 dk")}</span>'
                f'<div style="font-size:.88rem;font-weight:700;color:#38bdf8;margin-top:2px;">'
                f'{_format_focus_with_badges(_h.get("focus", ""))}</div></div>'
                f'<div style="font-size:1.3rem;color:#0ea5e940;">{_h.get("hour", "")}</div></div>'
                f'{_act_html}{_mat_html}</div>',
                unsafe_allow_html=True,
            )
    elif _is_school and _dk:
        st.markdown(
            '<div style="text-align:center;padding:12px;color:#64748b;font-size:.85rem;">'
            '&#x1F4CB; Bu gun icin detayli ders plani bulunmuyor.</div>',
            unsafe_allow_html=True,
        )
    # Hafta ozeti (acilir-kapanir)
    _exp_title = f"&#x1F4D6; Hafta {_wn} Ozeti"
    if _theme_display:
        _exp_title += f" — {_theme_display}"
    with st.expander(_exp_title, expanded=False):
        _summary = _week_data.get("summary", "")
        if _summary:
            st.markdown(f'<div style="font-size:.85rem;color:#7dd3fc;">{_summary}</div>', unsafe_allow_html=True)
        _unit_num = _week_data.get("unit", "")
        _grammar = _week_data.get("grammar_focus", "")
        _phase = _week_data.get("phase", "")
        _phase_en = _week_data.get("phase_en", "")
        _info_parts = []
        if _theme_name:
            _info_parts.append(f'<b style="color:#38bdf8;">Tema:</b> {str(_unit_num) + " &mdash; " if _unit_num else ""}{_theme_name}')
        if _theme_tr:
            _info_parts.append(f'<b style="color:#38bdf8;">Tema (TR):</b> {_theme_tr}')
        if _grammar:
            _info_parts.append(f'<b style="color:#38bdf8;">Dilbilgisi:</b> {_grammar}')
        if _phase:
            _info_parts.append(f'<b style="color:#38bdf8;">Asama:</b> {_phase}{" (" + _phase_en + ")" if _phase_en else ""}')
        if _info_parts:
            st.markdown(
                f'<div style="font-size:.82rem;color:#64748b;margin-top:6px;">'
                + '<br>'.join(_info_parts)
                + '</div>', unsafe_allow_html=True,
            )


def _build_content_registry(cat_names, game_names, song_names, dlg_names,
                            reading_names=None, writing_names=None,
                            grammar_names=None, phonics_names=None,
                            listening_names=None):
    """İçerik adı -> (tab_type, selectbox_index) eşleme dict'i oluşturur.
    Curriculum linked_content isimleriyle eşleştirmek için emoji prefix strip edilir."""
    registry = {}

    def _strip(name):
        parts = name.split(" ", 1)
        if len(parts) == 2 and len(parts[0]) <= 3:
            return parts[1]
        return name

    _map = [
        ("cat", cat_names), ("game", game_names),
        ("song", song_names), ("dlg", dlg_names),
    ]
    if reading_names:
        _map.append(("reading", reading_names))
    if writing_names:
        _map.append(("writing", writing_names))
    if grammar_names:
        _map.append(("grammar", grammar_names))
    if phonics_names:
        _map.append(("phonics", phonics_names))
    if listening_names:
        _map.append(("listening", listening_names))

    for tab_type, names in _map:
        for i, n in enumerate(names):
            clean = _strip(n)
            registry[clean] = (tab_type, i)
            # Kısa isim eşleştirme (ör: "Hello & Greeting" -> "Hello")
            if " & " in clean:
                registry[clean.split(" & ")[0]] = (tab_type, i)
    return registry


def _split_activity_to_steps(activity_text, template, wk):
    """Düz metin aktiviteyi zaman adımlarına böler.
    Aktivite metnindeki ':' ile ayrılmış parçaları template adımlarına dağıtır.
    Eksik adımlar için tema bilgisiyle varsayılan içerik üretir."""
    parts = [p.strip() for p in activity_text.split(",") if p.strip()] if activity_text else []
    # Ayrıca ';' veya '+' ile de ayrılmış olabilir
    if len(parts) <= 1 and activity_text:
        parts = [p.strip() for p in activity_text.replace("+", ";").split(";") if p.strip()]
    # Her template adımı için bir açıklama oluştur
    result = []
    theme = wk.get("theme_tr", wk.get("theme", ""))
    vocab = wk.get("vocab", [])
    vocab_str = ", ".join(vocab[:5]) if vocab else ""
    for i, (stime, slabel, stype) in enumerate(template):
        if i < len(parts):
            result.append(parts[i])
        else:
            # Varsayılan adım açıklamaları
            _defaults = {
                "warm_up": f"Isınma: Haftanın teması ({theme}) hatırlama",
                "presentation": f"Kelime tanıtımı: {vocab_str}" if vocab_str else f"Yeni kelime sunumu",
                "practice": f"Uygulama: Öğrenilen kelimeleri tekrar",
                "production": f"Eşli çalışma: Kalıp pratiği",
                "wrap_up": f"Kapanış: Günün özeti + bir sonraki derse bağlantı",
                "main_activity": f"Ana etkinlik: {theme} temalı interaktif çalışma",
                "reinforcement": f"Pekiştirme: Oyun veya şarkı ile tekrar",
                "assessment": f"Değerlendirme: Çalışma kağıdı veya sözlü kontrol",
            }
            result.append(_defaults.get(stype, slabel))
    return result


def _parse_activity_links(text, registry, _sorted_names=None):
    """Günlük plan metin satırındaki içerik referanslarını bulur.
    _sorted_names: önceden sıralanmış isim listesi (performans için dışarıdan ver).
    Returns: [(matched_name, tab_type, sel_idx), ...]"""
    links = []
    if not registry or not text:
        return links
    text_lower = text.lower()
    if _sorted_names is None:
        _sorted_names = sorted(registry.keys(), key=len, reverse=True)
    matched_spans = []
    for name in _sorted_names:
        name_lower = name.lower()
        pos = text_lower.find(name_lower)
        if pos >= 0:
            end = pos + len(name_lower)
            overlap = False
            for ms, me in matched_spans:
                if pos < me and end > ms:
                    overlap = True
                    break
            if not overlap:
                tab_type, idx = registry[name]
                links.append((name, tab_type, idx))
                matched_spans.append((pos, end))
    return links


def _curriculum_auto_week():
    """Takvime göre otomatik hafta seçimi (Eylül-Haziran). Hafta sonu ise son aktif haftayı döndür."""
    from datetime import date
    today = date.today()
    # Hafta sonu kontrolü (5=Cumartesi, 6=Pazar)
    if today.weekday() >= 5:
        return st.session_state.get("_eng_last_auto_week", 1)
    m, d = today.month, today.day
    # Eylül 2. hafta başlangıç
    if m >= 9:
        week = ((m - 9) * 4) + (d // 7) + 1
    elif m <= 6:
        week = 16 + ((m - 1) * 4) + (d // 7) + 1
    else:
        week = 36
    week = max(1, min(36, week))
    st.session_state["_eng_last_auto_week"] = week
    return week


def _get_today_day_key():
    """Bugünün gün anahtarını döndür (mon/tue/wed/thu/fri veya None)."""
    from datetime import date
    _day_map = {0: "mon", 1: "tue", 2: "wed", 3: "thu", 4: "fri"}
    return _day_map.get(date.today().weekday())


@st.cache_data(show_spinner=False, ttl=3600)
def _cached_curriculum_pdf(level: str, week_num: int):
    """Cache'li PDF uretici — ayni (level, week) icin tekrar uretmez."""
    weeks = _CURRICULUM.get(level, [])
    if not weeks or week_num < 1 or week_num > len(weeks):
        return b""
    return _curriculum_pdf(weeks[week_num - 1], level)


def _curriculum_pdf(week_data, level):
    """Haftalik plan PDF ciktisi — detayli 40+40dk ders plani formati."""
    from views.yd_tools import _generate_detailed_daily_plan
    from io import BytesIO
    try:
        from reportlab.lib.pagesizes import A4
        from reportlab.pdfgen import canvas as pdf_canvas
        from reportlab.lib.units import cm
        from utils.shared_data import ensure_turkish_pdf_fonts
    except ImportError:
        return b""

    font_name, font_bold = ensure_turkish_pdf_fonts()
    buf = BytesIO()
    w, h = A4
    c = pdf_canvas.Canvas(buf, pagesize=A4)
    lm = 1.5 * cm  # left margin
    bw = w - 3 * cm  # box width

    def _new_page():
        c.showPage()
        return h - 1.5 * cm

    def _check_space(yy, need=2 * cm):
        return _new_page() if yy < need else yy

    def _section_bar(yy, text, color="#1e40af"):
        c.setFillColor(color)
        c.roundRect(lm, yy - 4, bw, 18, 4, fill=1, stroke=0)
        c.setFillColor("#ffffff")
        c.setFont(font_bold, 10)
        c.drawString(lm + 0.3 * cm, yy, text)
        return yy - 22

    def _draw_text(yy, text, indent=2 * cm, font=font_name, size=8, max_w=95):
        c.setFont(font, size)
        c.setFillColor("#000000")
        for ln in [text[i:i + max_w] for i in range(0, max(len(text), 1), max_w)]:
            c.drawString(indent, yy, ln)
            yy -= size + 3
        return yy

    lvl_label = _CURRICULUM_LEVEL_LABELS.get(level, level)
    cefr = _CURRICULUM_CEFR.get(level, "")
    wk_num = week_data["week"]
    theme = week_data["theme"]
    theme_tr = week_data["theme_tr"]
    y = h - 1.5 * cm

    # ── Header ──
    c.setFillColor("#1e40af")
    c.roundRect(lm, y - 35, bw, 45, 8, fill=1, stroke=0)
    c.setFillColor("#ffffff")
    c.setFont(font_bold, 13)
    c.drawCentredString(w / 2, y - 12, f"{lvl_label} Ingilizce Haftalik Ders Plani ({cefr})")
    c.setFont(font_name, 10)
    c.drawCentredString(w / 2, y - 28, f"Hafta {wk_num}: {theme} - {theme_tr}")
    y -= 50

    # ── Kelime Odak ──
    y = _section_bar(y, "Kelime Odak", "#2563eb")
    vocab = week_data.get("vocab", [])
    y = _draw_text(y, ", ".join(vocab) if vocab else "Tekrar haftasi", size=9)
    y -= 4

    # ── Dil Yapisi ──
    y = _section_bar(y, "Dil Yapisi / Kalip", "#059669")
    y = _draw_text(y, week_data.get("structure", ""), size=9)
    y -= 4

    # ── Kazanimlar ──
    y = _check_space(y, 3 * cm)
    y = _section_bar(y, "Kazanimlar", "#7c3aed")
    skills = week_data.get("skills", {})
    _sk_labels = {"listening": "Dinleme", "speaking": "Konusma", "reading": "Okuma",
                  "writing": "Yazma", "pre_reading": "On-Okuma", "pre_writing": "On-Yazma"}
    for sk, sv in skills.items():
        if sv and sv != "\u2014":
            lbl = _sk_labels.get(sk, sk)
            c.setFont(font_bold, 8)
            c.setFillColor("#000000")
            c.drawString(2 * cm, y, f"{lbl}:")
            c.setFont(font_name, 8)
            sv_s = sv if len(sv) < 80 else sv[:77] + "..."
            c.drawString(4.5 * cm, y, sv_s)
            y -= 11
    y -= 4

    # ── Gunluk Ders Planlari (yeni _DAILY_PATTERNS sistemi) ──
    _step_hex = {"warm_up": "#f59e0b", "present": "#2563eb", "practice": "#059669",
                 "assess": "#dc2626", "wrap_up": "#64748b"}

    for day_key in ["mon", "tue", "wed", "thu", "fri"]:
        day_label, _ = _DAY_LABELS.get(day_key, (day_key, ""))
        plan = _generate_detailed_daily_plan(level, week_data, day_key)
        if not plan:
            continue

        y = _check_space(y, 5 * cm)
        # Gun basligi
        c.setFillColor("#94A3B8")
        c.roundRect(lm, y - 4, bw, 20, 4, fill=1, stroke=0)
        c.setFillColor("#ffffff")
        c.setFont(font_bold, 10)
        c.drawString(lm + 0.3 * cm, y, f"{day_label}  |  Ders: Ingilizce  |  Konu: {theme}  |  Sure: 40+40 dk")
        y -= 26

        for lesson_num, ders_color, ders_label in [
            (1, "#dc2626" if day_key == "fri" else "#2563eb",
             "1. DERS (40 dakika) — " + ("Native Speaker" if day_key == "fri" else "Main Course")),
            (2, "#b91c1c" if day_key == "fri" else "#059669",
             "2. DERS (40 dakika) — " + ("Native Speaker" if day_key == "fri" else "Skills Lab")),
        ]:
            y = _check_space(y, 2.5 * cm)
            c.setFillColor(ders_color)
            c.roundRect(lm + 0.3 * cm, y - 2, bw - 0.6 * cm, 14, 3, fill=1, stroke=0)
            c.setFillColor("#ffffff")
            c.setFont(font_bold, 8)
            c.drawString(lm + 0.5 * cm, y, ders_label)
            y -= 18

            acts = plan.get(f"lesson_{lesson_num}", [])
            cum = 0
            for act in acts:
                y = _check_space(y, 1.5 * cm)
                end_min = cum + act["min"]
                time_str = f"{cum}-{end_min}dk"
                icon = act.get("icon", "")
                title = act.get("title", "")
                marker = "[*]" if act.get("btn_type") else "[ ]"

                c.setFillColor("#000000")
                c.setFont(font_bold, 7)
                c.drawString(lm + 0.5 * cm, y, marker)
                step_color = _step_hex.get(act.get("step", ""), "#475569")
                c.setFillColor(step_color)
                c.setFont(font_name, 7)
                c.drawString(lm + 1.2 * cm, y, time_str)
                c.setFillColor("#000000")
                c.setFont(font_name, 7)
                detail_s = f"{icon} {title}"
                if len(detail_s) > 85:
                    detail_s = detail_s[:82] + "..."
                c.drawString(lm + 2.4 * cm, y, detail_s)
                y -= 10
                cum = end_min
            y -= 4
        y -= 6

    # ── Degerlendirme ──
    y = _check_space(y, 2 * cm)
    y = _section_bar(y, "Hafta Sonu Degerlendirme", "#dc2626")
    y = _draw_text(y, week_data.get("assessment", ""), size=9)

    # ── Baglantili Icerik ──
    linked = week_data.get("linked_content", {})
    _lc_keys = ["categories", "songs", "games", "dialogues", "readings", "writings", "phonics", "listening"]
    _lc_active = [(k, linked.get(k, [])) for k in _lc_keys if linked.get(k)]
    if _lc_active:
        y = _check_space(y, 2 * cm)
        y -= 4
        y = _section_bar(y, "Baglantili Icerik", "#475569")
        _lc_names = {
            "categories": "Kategoriler", "songs": "Sarkilar", "games": "Oyunlar",
            "dialogues": "Diyaloglar", "readings": "Okuma", "writings": "Yazma",
            "phonics": "Sesler", "listening": "Dinleme",
        }
        for lk, items in _lc_active:
            lbl = _lc_names.get(lk, lk)
            c.setFont(font_bold, 7)
            c.setFillColor("#000000")
            c.drawString(2 * cm, y, f"{lbl}:")
            c.setFont(font_name, 7)
            c.drawString(4 * cm, y, ", ".join(items))
            y -= 10
            y = _check_space(y, 1.5 * cm)

    # ── Footer ──
    c.setFont(font_name, 7)
    c.setFillColor("#999999")
    c.drawCentredString(w / 2, 1 * cm, f"SmartCampusAI - Dijital Kutuphane | {lvl_label} Hafta {wk_num} | 2026")

    c.save()
    buf.seek(0)
    return buf.getvalue()


@st.cache_data(show_spinner="Tum planlar PDF olusturuluyor...", ttl=3600)
def _cached_all_weeks_pdf(level: str):
    """Tum haftalik planlari tek PDF olarak uretir."""
    from io import BytesIO
    try:
        from PyPDF2 import PdfMerger
    except ImportError:
        try:
            from pypdf import PdfMerger
        except ImportError:
            return b""
    weeks = _CURRICULUM.get(level, [])
    if not weeks:
        return b""
    merger = PdfMerger()
    for wk_data in weeks:
        pdf_bytes = _curriculum_pdf(wk_data, level)
        if pdf_bytes:
            merger.append(BytesIO(pdf_bytes))
    buf = BytesIO()
    merger.write(buf)
    merger.close()
    buf.seek(0)
    return buf.getvalue()


