def _get_content_bank_data_for_pdf(grade_num: int) -> dict:
    """PDF icin content bank verilerini toplu yukler. Returns {bank_key: {unit: data}}"""
    result = {}
    _bank_attrs = [
        ("STORY_BANK", "story"), ("CULTURE_CORNER_BANK", "culture"),
        ("TURKEY_CORNER_BANK", "turkey"), ("COMIC_STRIP_BANK", "comic"),
        ("MISSION_BANK", "mission"), ("ESCAPE_ROOM_BANK", "escape"),
        ("FAMILY_CORNER_BANK", "family"), ("SEL_BANK", "sel"),
        ("STEAM_BANK", "steam"), ("PODCAST_BANK", "podcast"),
        ("PROJECT_BANK", "project"), ("FUN_FACTS_BANK", "funfacts"),
        ("PROGRESS_CHECK_BANK", "progress"), ("MODEL_WRITING_BANK", "writing"),
        ("WORKBOOK_BANK", "workbook"), ("PRONUNCIATION_BANK", "pronunciation"),
    ]
    try:
        if grade_num == 5:
            from views.textbook_grade5 import (
                _STORY_BANK, _CULTURE_CORNER_BANK, _TURKEY_CORNER_BANK,
                _COMIC_STRIP_BANK, _MISSION_BANK, _ESCAPE_ROOM_BANK,
                _FAMILY_CORNER_BANK, _SEL_BANK, _STEAM_BANK, _PODCAST_BANK,
                _PROJECT_BANK, _FUN_FACTS_BANK, _PROGRESS_CHECK_BANK,
                _MODEL_WRITING_BANK, _WORKBOOK_BANK, _PRONUNCIATION_BANK,
            )
            _bmap = {"story": _STORY_BANK, "culture": _CULTURE_CORNER_BANK,
                     "turkey": _TURKEY_CORNER_BANK, "comic": _COMIC_STRIP_BANK,
                     "mission": _MISSION_BANK, "escape": _ESCAPE_ROOM_BANK,
                     "family": _FAMILY_CORNER_BANK, "sel": _SEL_BANK,
                     "steam": _STEAM_BANK, "podcast": _PODCAST_BANK,
                     "project": _PROJECT_BANK, "funfacts": _FUN_FACTS_BANK,
                     "progress": _PROGRESS_CHECK_BANK, "writing": _MODEL_WRITING_BANK,
                     "workbook": _WORKBOOK_BANK, "pronunciation": _PRONUNCIATION_BANK}
        else:
            mod = __import__(f"views.content_banks.grade{grade_num}", fromlist=["__all__"])
            _bmap = {}
            for attr_name, key in _bank_attrs:
                bank = getattr(mod, attr_name, None)
                if bank and isinstance(bank, dict):
                    _bmap[key] = bank
        for key, bank in _bmap.items():
            grade_data = bank.get(grade_num, bank)
            if isinstance(grade_data, dict) and any(isinstance(k, int) for k in grade_data.keys()):
                result[key] = grade_data
    except Exception:
        pass
    return result


_PP_DAY_CB_MAP = {
    "mon": ["story", "culture", "pronunciation"],
    "tue": ["podcast", "comic", "turkey"],
    "wed": ["writing", "workbook", "steam"],
    "thu": ["project", "sel", "family"],
    "fri": ["escape", "funfacts", "progress", "mission"],
}

_PP_CB_TR = {
    "story": "Hikaye", "culture": "Kultur Kosesi", "turkey": "Turkiye Kosesi",
    "comic": "Cizgi Roman", "mission": "Gorev", "escape": "Kacis Odasi",
    "family": "Aile Kosesi", "sel": "SEL", "steam": "STEAM",
    "podcast": "Podcast", "project": "Proje", "funfacts": "Ilginc Bilgiler",
    "progress": "Ilerleme", "writing": "Yazma Modeli", "workbook": "Calisma Kitabi",
    "pronunciation": "Telaffuz",
}


def _premium_plan_pdf(level: str, start_week: int, end_week: int, day_filter: str | None = None) -> bytes:
    """Premium ders planı PDF üretici — kurumsal kapak + detaylı günlük planlar."""
    from views.yd_tools import _generate_detailed_daily_plan, _week_to_unit
    from io import BytesIO
    from datetime import datetime
    try:
        from reportlab.lib.pagesizes import A4
        from reportlab.lib import colors as rl_colors
        from reportlab.lib.units import cm
        from reportlab.lib.styles import ParagraphStyle, getSampleStyleSheet
        from reportlab.platypus import (SimpleDocTemplate, Paragraph, Spacer,
                                         Table, TableStyle, PageBreak, Image)
        from utils.shared_data import ensure_turkish_pdf_fonts
        from utils.report_utils import get_institution_info
    except ImportError:
        return b""

    font_name, font_bold = ensure_turkish_pdf_fonts()
    font_ok = font_name != "Helvetica"

    def _t(text):
        if font_ok:
            return str(text)
        _map = str.maketrans("ıİğĞüÜşŞöÖçÇ", "iIgGuUsSoOcC")
        return str(text).translate(_map)

    weeks_data = _CURRICULUM.get(level, [])
    if not weeks_data:
        return b""
    start_week = max(1, min(start_week, len(weeks_data)))
    end_week = max(start_week, min(end_week, len(weeks_data)))

    # Content bank loader
    _grade_num_map = {"preschool": 0, "grade1": 1, "grade2": 2, "grade3": 3,
                      "grade4": 4, "grade5": 5, "grade6": 6, "grade7": 7,
                      "grade8": 8, "grade9": 9, "grade10": 10, "grade11": 11, "grade12": 12}
    _pp_grade = _grade_num_map.get(level, 5)
    _pp_cb_data = _get_content_bank_data_for_pdf(_pp_grade)

    lvl_label = _CURRICULUM_LEVEL_LABELS.get(level, level)
    cefr = _CURRICULUM_CEFR.get(level, "")
    info = get_institution_info()
    now_str = datetime.now().strftime("%d.%m.%Y")

    # — Renkler —
    C_HEADER = rl_colors.HexColor("#0B0F19")
    C_ACCENT = rl_colors.HexColor("#0ea5e9")
    C_BLUE = rl_colors.HexColor("#1e40af")
    C_GREEN = rl_colors.HexColor("#059669")
    C_PURPLE = rl_colors.HexColor("#7c3aed")
    C_ORANGE = rl_colors.HexColor("#f59e0b")
    C_RED = rl_colors.HexColor("#dc2626")
    C_SLATE = rl_colors.HexColor("#475569")
    C_LIGHT = rl_colors.HexColor("#111827")
    C_WHITE = rl_colors.white
    C_TEXT = rl_colors.HexColor("#94A3B8")
    C_SUB = rl_colors.HexColor("#64748b")
    C_BORDER = rl_colors.HexColor("#e2e8f0")

    _DAY_COLORS = {
        "mon": C_BLUE, "tue": C_GREEN, "wed": C_PURPLE,
        "thu": C_ORANGE, "fri": C_RED,
    }

    # — Stiller —
    styles = getSampleStyleSheet()
    s_title = ParagraphStyle("PPTitle", fontName=font_name, fontSize=22,
                              leading=28, alignment=1, textColor=C_WHITE, spaceAfter=4)
    s_subtitle = ParagraphStyle("PPSub", fontName=font_name, fontSize=12,
                                 leading=16, alignment=1, textColor=rl_colors.HexColor("#94A3B8"), spaceAfter=2)
    s_cover_info = ParagraphStyle("PPCover", fontName=font_name, fontSize=10,
                                   leading=14, alignment=1, textColor=rl_colors.HexColor("#CBD5E1"))
    s_h1 = ParagraphStyle("PPH1", fontName=font_name, fontSize=14,
                           leading=18, textColor=C_WHITE, alignment=0)
    s_h2 = ParagraphStyle("PPH2", fontName=font_name, fontSize=11,
                           leading=14, textColor=C_WHITE, alignment=0)
    s_body = ParagraphStyle("PPBody", fontName=font_name, fontSize=8.5,
                             leading=11, textColor=C_TEXT)
    s_body_sm = ParagraphStyle("PPBodySm", fontName=font_name, fontSize=7.5,
                                leading=10, textColor=C_TEXT)
    s_bold = ParagraphStyle("PPBold", fontName=font_name, fontSize=8.5,
                             leading=11, textColor=C_TEXT)
    s_label = ParagraphStyle("PPLabel", fontName=font_name, fontSize=8,
                              leading=10, textColor=C_SUB)
    s_cell_w = ParagraphStyle("PPCellW", fontName=font_name, fontSize=7.5,
                               leading=10, textColor=C_WHITE, alignment=0)
    s_link = ParagraphStyle("PPLink", fontName=font_name, fontSize=7.5,
                             leading=10, textColor=C_SLATE)

    pw = A4[0] - 4 * cm  # available width

    elements = []

    # ══════════════════════════════════════════════════════════════════
    # KAPAK SAYFASI
    # ══════════════════════════════════════════════════════════════════
    elements.append(Spacer(1, 3 * cm))

    # Kurum logo + isim
    cover_rows = []
    logo_cell = ""
    if info.get("logo_path") and os.path.exists(info["logo_path"]):
        try:
            logo_cell = Image(info["logo_path"], width=3 * cm, height=3 * cm)
        except Exception as _exc:
            _logger.debug('Suppressed: %s', _exc)

    kurum_adi = info.get("name", "")
    kurum_text = []
    if kurum_adi:
        kurum_text.append(Paragraph(_t(kurum_adi), ParagraphStyle(
            "PPKurum", fontName=font_name, fontSize=16, leading=20,
            textColor=C_WHITE, alignment=1)))

    # Kapak başlık bandı
    cover_title_data = [[Paragraph(_t("İNGİLİZCE DERS PLANI"), s_title)]]
    cover_title_tbl = Table(cover_title_data, colWidths=[pw], rowHeights=[40])
    cover_title_tbl.setStyle(TableStyle([
        ("BACKGROUND", (0, 0), (-1, -1), C_HEADER),
        ("ALIGN", (0, 0), (-1, -1), "CENTER"),
        ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
        ("TOPPADDING", (0, 0), (-1, -1), 10),
        ("BOTTOMPADDING", (0, 0), (-1, -1), 10),
        ("ROUNDEDCORNERS", [10, 10, 0, 0]),
    ]))
    elements.append(cover_title_tbl)

    # Altın accent çizgi
    accent_tbl = Table([[""]], colWidths=[pw], rowHeights=[4])
    accent_tbl.setStyle(TableStyle([
        ("BACKGROUND", (0, 0), (0, 0), C_ACCENT),
        ("LEFTPADDING", (0, 0), (0, 0), 0), ("RIGHTPADDING", (0, 0), (0, 0), 0),
        ("TOPPADDING", (0, 0), (0, 0), 0), ("BOTTOMPADDING", (0, 0), (0, 0), 0),
    ]))
    elements.append(accent_tbl)

    # Alt bilgi bandı — tarih aralığı
    _cover_start_mon, _ = _academic_week_dates(start_week)
    _, _cover_end_fri = _academic_week_dates(end_week)
    if start_week == end_week:
        range_txt = f"Hafta {start_week}"
    else:
        range_txt = f"Hafta {start_week} - {end_week}"
    if day_filter:
        day_name = _DAY_LABELS.get(day_filter, (day_filter, ""))[0]
        range_txt += f" | {day_name}"
    # Kapak tarih aralığı
    _cover_date_range = ""
    if _cover_start_mon and _cover_end_fri:
        _cover_date_range = f"  |  {_cover_start_mon.strftime('%d.%m.%Y')} - {_cover_end_fri.strftime('%d.%m.%Y')}"

    cover_info_items = [
        [Paragraph(_t(f"{lvl_label} | CEFR {cefr}"), s_subtitle)],
        [Paragraph(_t(f"{range_txt}{_cover_date_range}"), s_cover_info)],
        [Paragraph(_t(f"2x40 dakika | 5 gun/hafta | 10 ders saati/hafta"), s_cover_info)],
    ]
    cover_info_tbl = Table(cover_info_items, colWidths=[pw], rowHeights=[22, 18, 18])
    cover_info_tbl.setStyle(TableStyle([
        ("BACKGROUND", (0, 0), (-1, -1), rl_colors.HexColor("#94A3B8")),
        ("ALIGN", (0, 0), (-1, -1), "CENTER"),
        ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
        ("TOPPADDING", (0, 0), (-1, -1), 2),
        ("BOTTOMPADDING", (0, 0), (-1, -1), 2),
        ("ROUNDEDCORNERS", [0, 0, 10, 10]),
    ]))
    elements.append(cover_info_tbl)

    elements.append(Spacer(1, 1.5 * cm))

    # Kurum bilgileri kartı
    if kurum_adi or logo_cell:
        _inst_parts = []
        if logo_cell:
            _inst_parts.append(logo_cell)
        inst_texts = []
        if kurum_adi:
            inst_texts.append(Paragraph(_t(kurum_adi), ParagraphStyle(
                "PPInst", fontName=font_name, fontSize=14, leading=18,
                textColor=C_TEXT, alignment=1)))
        if info.get("address"):
            inst_texts.append(Paragraph(_t(info["address"]), ParagraphStyle(
                "PPAddr", fontName=font_name, fontSize=9, leading=12,
                textColor=C_SUB, alignment=1)))
        contact_parts = []
        if info.get("phone"):
            contact_parts.append(f"Tel: {info['phone']}")
        if info.get("web"):
            contact_parts.append(info["web"])
        if contact_parts:
            inst_texts.append(Paragraph(_t(" | ".join(contact_parts)), ParagraphStyle(
                "PPContact", fontName=font_name, fontSize=8, leading=11,
                textColor=C_SUB, alignment=1)))

        if logo_cell:
            inst_data = [[logo_cell, inst_texts]]
            inst_cols = [3.5 * cm, pw - 3.5 * cm]
        else:
            inst_data = [[inst_texts]]
            inst_cols = [pw]

        inst_tbl = Table(inst_data, colWidths=inst_cols, rowHeights=[3.5 * cm])
        inst_tbl.setStyle(TableStyle([
            ("BACKGROUND", (0, 0), (-1, -1), C_LIGHT),
            ("ALIGN", (0, 0), (-1, -1), "CENTER"),
            ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
            ("BOX", (0, 0), (-1, -1), 0.5, C_BORDER),
            ("ROUNDEDCORNERS", [8, 8, 8, 8]),
            ("TOPPADDING", (0, 0), (-1, -1), 10),
            ("BOTTOMPADDING", (0, 0), (-1, -1), 10),
            ("LEFTPADDING", (0, 0), (-1, -1), 12),
            ("RIGHTPADDING", (0, 0), (-1, -1), 12),
        ]))
        elements.append(inst_tbl)

    elements.append(Spacer(1, 2 * cm))

    # Tarih
    elements.append(Paragraph(_t(f"Olusturma Tarihi: {now_str}"), ParagraphStyle(
        "PPDate", fontName=font_name, fontSize=9, leading=12,
        textColor=C_SUB, alignment=1)))

    elements.append(PageBreak())

    # ══════════════════════════════════════════════════════════════════
    # HAFTA İÇERİKLERİ
    # ══════════════════════════════════════════════════════════════════

    _sk_labels = {"listening": "Dinleme", "speaking": "Konusma", "reading": "Okuma",
                  "writing": "Yazma", "pre_reading": "On-Okuma", "pre_writing": "On-Yazma"}
    _lc_names = {
        "categories": "Kategoriler", "songs": "Sarkilar", "games": "Oyunlar",
        "dialogues": "Diyaloglar", "readings": "Okuma", "writings": "Yazma",
        "phonics": "Sesler", "listening": "Dinleme",
    }

    day_keys = [day_filter] if day_filter else ["mon", "tue", "wed", "thu", "fri"]

    from datetime import timedelta as _td

    for wi in range(start_week - 1, end_week):
        wk = weeks_data[wi]
        wk_num = wk["week"]
        theme = wk["theme"]
        theme_tr = wk["theme_tr"]
        vocab = wk.get("vocab", [])
        structure = wk.get("structure", "")

        # Hafta tarihleri
        _wk_mon, _wk_fri = _academic_week_dates(wk_num)
        _wk_date_str = ""
        if _wk_mon and _wk_fri:
            _wk_date_str = f"  ({_wk_mon.strftime('%d.%m')} - {_wk_fri.strftime('%d.%m.%Y')})"

        # — Hafta Başlık Bandı —
        wk_header_data = [[
            Paragraph(_t(f"HAFTA {wk_num}"), ParagraphStyle(
                "PPWkNum", fontName=font_name, fontSize=16, leading=20, textColor=C_WHITE)),
            Paragraph(_t(f"{theme} — {theme_tr}{_wk_date_str}"), ParagraphStyle(
                "PPWkTheme", fontName=font_name, fontSize=11, leading=14, textColor=rl_colors.HexColor("#93c5fd"))),
        ]]
        wk_header_tbl = Table(wk_header_data, colWidths=[pw * 0.3, pw * 0.7], rowHeights=[32])
        wk_header_tbl.setStyle(TableStyle([
            ("BACKGROUND", (0, 0), (-1, -1), C_BLUE),
            ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
            ("LEFTPADDING", (0, 0), (0, 0), 14),
            ("LEFTPADDING", (1, 0), (1, 0), 8),
            ("TOPPADDING", (0, 0), (-1, -1), 6),
            ("BOTTOMPADDING", (0, 0), (-1, -1), 6),
            ("ROUNDEDCORNERS", [8, 8, 0, 0]),
        ]))
        elements.append(wk_header_tbl)

        # — Bilgi Satırı —
        vocab_count = len(vocab)
        info_text = f"Kelime: {vocab_count} | Yapi: {structure}" if structure else f"Kelime: {vocab_count}"
        info_row = [[Paragraph(_t(info_text), ParagraphStyle(
            "PPInfo", fontName=font_name, fontSize=8, leading=11, textColor=C_SUB))]]
        info_tbl = Table(info_row, colWidths=[pw], rowHeights=[16])
        info_tbl.setStyle(TableStyle([
            ("BACKGROUND", (0, 0), (-1, -1), rl_colors.HexColor("#eff6ff")),
            ("LEFTPADDING", (0, 0), (-1, -1), 14),
            ("TOPPADDING", (0, 0), (-1, -1), 2),
            ("BOTTOMPADDING", (0, 0), (-1, -1), 2),
            ("ROUNDEDCORNERS", [0, 0, 8, 8]),
        ]))
        elements.append(info_tbl)
        elements.append(Spacer(1, 0.25 * cm))

        # — Kelime Listesi —
        if vocab:
            vocab_text = ", ".join(vocab)
            elements.append(Paragraph(
                _t(f"<b>Kelime Odak:</b> {vocab_text}"), s_body))
            elements.append(Spacer(1, 0.15 * cm))

        # — Kazanımlar —
        skills = wk.get("skills", {})
        skill_rows = []
        for sk, sv in skills.items():
            if sv and sv != "\u2014":
                lbl = _sk_labels.get(sk, sk)
                skill_rows.append([
                    Paragraph(_t(f"<b>{lbl}</b>"), s_body_sm),
                    Paragraph(_t(sv), s_body_sm),
                ])
        if skill_rows:
            sk_tbl = Table(skill_rows, colWidths=[pw * 0.18, pw * 0.82])
            sk_style = [
                ("VALIGN", (0, 0), (-1, -1), "TOP"),
                ("LEFTPADDING", (0, 0), (-1, -1), 6),
                ("RIGHTPADDING", (0, 0), (-1, -1), 6),
                ("TOPPADDING", (0, 0), (-1, -1), 3),
                ("BOTTOMPADDING", (0, 0), (-1, -1), 3),
                ("GRID", (0, 0), (-1, -1), 0.3, C_BORDER),
                ("BACKGROUND", (0, 0), (0, -1), rl_colors.HexColor("#f5f3ff")),
            ]
            for ri in range(len(skill_rows)):
                if ri % 2 == 1:
                    sk_style.append(("BACKGROUND", (1, ri), (1, ri), C_LIGHT))
            sk_tbl.setStyle(TableStyle(sk_style))
            # Section header
            sk_sec = Table(
                [["", Paragraph(_t("<b>Kazanimlar</b>"), ParagraphStyle(
                    "PPSkSec", fontName=font_name, fontSize=9, leading=12, textColor=C_TEXT))]],
                colWidths=[4, pw - 4], rowHeights=[20])
            sk_sec.setStyle(TableStyle([
                ("BACKGROUND", (0, 0), (0, 0), C_PURPLE),
                ("BACKGROUND", (1, 0), (1, 0), rl_colors.HexColor("#7c3aed0D")),
                ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
                ("LEFTPADDING", (1, 0), (1, 0), 10),
                ("ROUNDEDCORNERS", [0, 6, 6, 0]),
            ]))
            elements.append(sk_sec)
            elements.append(Spacer(1, 0.1 * cm))
            elements.append(sk_tbl)
            elements.append(Spacer(1, 0.25 * cm))

        # — Günlük Planlar (yeni _DAILY_PATTERNS sistemi) —
        _day_offsets = {"mon": 0, "tue": 1, "wed": 2, "thu": 3, "fri": 4}
        _step_pdf_colors = {
            "warm_up": rl_colors.HexColor("#f59e0b"),
            "present": rl_colors.HexColor("#2563eb"),
            "practice": rl_colors.HexColor("#059669"),
            "assess": rl_colors.HexColor("#dc2626"),
            "wrap_up": rl_colors.HexColor("#64748b"),
        }
        for dk in day_keys:
            plan = _generate_detailed_daily_plan(level, wk, dk)
            if not plan:
                continue
            day_label, _ = _DAY_LABELS.get(dk, (dk, ""))
            day_color = _DAY_COLORS.get(dk, C_BLUE)

            # Gün tarihi
            _day_date_str = ""
            if _wk_mon:
                _day_date = _wk_mon + _td(days=_day_offsets.get(dk, 0))
                _day_date_str = f"  ({_day_date.strftime('%d.%m.%Y')})"

            # Gün başlık bandı
            day_header_data = [[Paragraph(
                _t(f"{day_label}{_day_date_str}  |  Ders: Ingilizce  |  Konu: {theme}  |  Sure: 40+40 dk"), s_h2)]]
            day_header_tbl = Table(day_header_data, colWidths=[pw], rowHeights=[24])
            day_header_tbl.setStyle(TableStyle([
                ("BACKGROUND", (0, 0), (-1, -1), day_color),
                ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
                ("LEFTPADDING", (0, 0), (-1, -1), 12),
                ("TOPPADDING", (0, 0), (-1, -1), 4),
                ("BOTTOMPADDING", (0, 0), (-1, -1), 4),
                ("ROUNDEDCORNERS", [6, 6, 0, 0]),
            ]))
            elements.append(day_header_tbl)

            # Her ders icin (1. ve 2.)
            for lesson_num, ders_color_hex, ders_label in [
                (1, "#dc2626" if dk == "fri" else "#2563eb",
                 "1. DERS (40 dk) \u2014 " + ("Native Speaker" if dk == "fri" else "Main Course")),
                (2, "#b91c1c" if dk == "fri" else "#059669",
                 "2. DERS (40 dk) \u2014 " + ("Native Speaker" if dk == "fri" else "Skills Lab")),
            ]:
                acts = plan.get(f"lesson_{lesson_num}", [])
                ders_header = [[Paragraph(_t(ders_label), s_cell_w)]]
                ders_h_tbl = Table(ders_header, colWidths=[pw - 0.4 * cm], rowHeights=[16])
                ders_h_tbl.setStyle(TableStyle([
                    ("BACKGROUND", (0, 0), (-1, -1), rl_colors.HexColor(ders_color_hex)),
                    ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
                    ("LEFTPADDING", (0, 0), (-1, -1), 10),
                    ("TOPPADDING", (0, 0), (-1, -1), 2),
                    ("BOTTOMPADDING", (0, 0), (-1, -1), 2),
                    ("ROUNDEDCORNERS", [4, 4, 4, 4]),
                ]))
                elements.append(ders_h_tbl)

                # Etkinlik satirlari
                step_rows = []
                cum = 0
                for act in acts:
                    end_min = cum + act["min"]
                    time_str = f"{cum}-{end_min}dk"
                    icon = act.get("icon", "")
                    title = act.get("title", "")
                    interactive = "[*]" if act.get("btn_type") else "[ ]"
                    step_rows.append([
                        Paragraph(_t(interactive), s_body_sm),
                        Paragraph(_t(time_str), ParagraphStyle(
                            "PPTimeN", fontName=font_name, fontSize=7.5, leading=10,
                            textColor=_step_pdf_colors.get(act.get("step", ""), C_BLUE))),
                        Paragraph(_t(f"{icon} {title}"), s_body_sm),
                    ])
                    cum = end_min

                if step_rows:
                    st_tbl = Table(step_rows, colWidths=[0.8 * cm, 1.4 * cm, pw - 2.6 * cm])
                    st_style = [
                        ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
                        ("LEFTPADDING", (0, 0), (-1, -1), 4),
                        ("TOPPADDING", (0, 0), (-1, -1), 2),
                        ("BOTTOMPADDING", (0, 0), (-1, -1), 2),
                        ("LINEBELOW", (0, 0), (-1, -2), 0.3, C_BORDER),
                    ]
                    for ri in range(len(step_rows)):
                        if ri % 2 == 0:
                            st_style.append(("BACKGROUND", (0, ri), (-1, ri), C_LIGHT))
                    st_tbl.setStyle(TableStyle(st_style))
                    elements.append(st_tbl)
                elements.append(Spacer(1, 0.15 * cm))

            # ── Content Bank Etkinlikleri (gun sonu) ──
            _pp_unit = _week_to_unit(wk_num)
            _pp_day_banks = _PP_DAY_CB_MAP.get(dk, [])
            _pp_cb_rows = []
            for _bk in _pp_day_banks:
                _bdata = _pp_cb_data.get(_bk, {}).get(_pp_unit)
                if _bdata and isinstance(_bdata, dict):
                    _btitle = str(_bdata.get("title", _bdata.get("topic", _bdata.get("mission", ""))))[:50]
                    _blabel = _PP_CB_TR.get(_bk, _bk)
                    _pp_cb_rows.append([
                        Paragraph(_t(f"<b>{_blabel}</b>"), ParagraphStyle(
                            f"PPcbl{wk_num}{dk}{_bk}", fontName=font_name, fontSize=7,
                            leading=9.5, textColor=rl_colors.HexColor("#0F766E"))),
                        Paragraph(_t(_btitle), ParagraphStyle(
                            f"PPcbt{wk_num}{dk}{_bk}", fontName=font_name, fontSize=7,
                            leading=9.5, textColor=C_TEXT)),
                    ])
            if _pp_cb_rows:
                _pp_cb_sec = Table(
                    [["", Paragraph(_t("<b>Icerik Bankasi Etkinlikleri</b>"), ParagraphStyle(
                        f"PPCbSec{wk_num}{dk}", fontName=font_name, fontSize=8,
                        leading=11, textColor=C_TEXT))]],
                    colWidths=[4, pw - 4], rowHeights=[18])
                _pp_cb_sec.setStyle(TableStyle([
                    ("BACKGROUND", (0, 0), (0, 0), rl_colors.HexColor("#0F766E")),
                    ("BACKGROUND", (1, 0), (1, 0), rl_colors.HexColor("#ECFDF5")),
                    ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
                    ("LEFTPADDING", (1, 0), (1, 0), 10),
                    ("ROUNDEDCORNERS", [0, 4, 4, 0]),
                ]))
                elements.append(_pp_cb_sec)
                elements.append(Spacer(1, 0.05 * cm))
                _pp_cbt = Table(_pp_cb_rows, colWidths=[pw * 0.25, pw * 0.75])
                _pp_cbt_s = [
                    ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
                    ("LEFTPADDING", (0, 0), (-1, -1), 5),
                    ("TOPPADDING", (0, 0), (-1, -1), 2),
                    ("BOTTOMPADDING", (0, 0), (-1, -1), 2),
                    ("LINEBELOW", (0, 0), (-1, -2), 0.2, C_BORDER),
                ]
                for _ri in range(len(_pp_cb_rows)):
                    if _ri % 2 == 0:
                        _pp_cbt_s.append(("BACKGROUND", (0, _ri), (-1, _ri), C_LIGHT))
                _pp_cbt.setStyle(TableStyle(_pp_cbt_s))
                elements.append(_pp_cbt)

            elements.append(Spacer(1, 0.15 * cm))

        # — Değerlendirme —
        assessment = wk.get("assessment", "")
        if assessment:
            ass_sec = Table(
                [["", Paragraph(_t("<b>Hafta Sonu Degerlendirme</b>"), ParagraphStyle(
                    "PPAsSec", fontName=font_name, fontSize=9, leading=12, textColor=C_TEXT))]],
                colWidths=[4, pw - 4], rowHeights=[20])
            ass_sec.setStyle(TableStyle([
                ("BACKGROUND", (0, 0), (0, 0), C_RED),
                ("BACKGROUND", (1, 0), (1, 0), rl_colors.HexColor("#dc26260D")),
                ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
                ("LEFTPADDING", (1, 0), (1, 0), 10),
                ("ROUNDEDCORNERS", [0, 6, 6, 0]),
            ]))
            elements.append(ass_sec)
            elements.append(Spacer(1, 0.1 * cm))
            elements.append(Paragraph(_t(assessment), s_body))
            elements.append(Spacer(1, 0.2 * cm))

        # — Bağlantılı İçerik —
        linked = wk.get("linked_content", {})
        _lc_keys = ["categories", "songs", "games", "dialogues", "readings", "writings", "phonics", "listening"]
        _lc_active = [(k, linked.get(k, [])) for k in _lc_keys if linked.get(k)]
        if _lc_active:
            lc_sec = Table(
                [["", Paragraph(_t("<b>Baglantili Icerik</b>"), ParagraphStyle(
                    "PPLcSec", fontName=font_name, fontSize=9, leading=12, textColor=C_TEXT))]],
                colWidths=[4, pw - 4], rowHeights=[20])
            lc_sec.setStyle(TableStyle([
                ("BACKGROUND", (0, 0), (0, 0), C_SLATE),
                ("BACKGROUND", (1, 0), (1, 0), rl_colors.HexColor("#4755690D")),
                ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
                ("LEFTPADDING", (1, 0), (1, 0), 10),
                ("ROUNDEDCORNERS", [0, 6, 6, 0]),
            ]))
            elements.append(lc_sec)
            elements.append(Spacer(1, 0.1 * cm))
            for lk, items in _lc_active:
                lbl = _lc_names.get(lk, lk)
                elements.append(Paragraph(_t(f"<b>{lbl}:</b> {', '.join(items)}"), s_link))
            elements.append(Spacer(1, 0.15 * cm))

        # Sayfa sonu (son hafta hariç)
        if wi < end_week - 1:
            elements.append(PageBreak())

    # ══════════════════════════════════════════════════════════════════
    # PDF Oluştur
    # ══════════════════════════════════════════════════════════════════
    buf = BytesIO()
    doc = SimpleDocTemplate(
        buf, pagesize=A4,
        topMargin=1.2 * cm, bottomMargin=2 * cm,
        leftMargin=2 * cm, rightMargin=2 * cm,
    )

    _footer_level = _t(lvl_label)

    def _footer(canvas, doc):
        canvas.saveState()
        _pw, _ph = A4
        _y = 1 * cm
        canvas.setStrokeColor(rl_colors.HexColor("#e2e8f0"))
        canvas.setLineWidth(0.5)
        canvas.line(2 * cm, _y + 14, _pw - 2 * cm, _y + 14)
        canvas.setFont(font_name, 7)
        canvas.setFillColor(rl_colors.HexColor("#94A3B8"))
        canvas.drawString(2 * cm, _y + 2, f"SmartCampus AI — Dijital Kutuphane | {_footer_level}")
        canvas.drawRightString(_pw - 2 * cm, _y + 2, f"Sayfa {doc.page}")
        canvas.restoreState()

    doc.build(elements, onFirstPage=_footer, onLaterPages=_footer)
    buf.seek(0)
    return buf.getvalue()


@st.cache_data(show_spinner="Premium PDF olusturuluyor...", ttl=3600)
def _cached_premium_pdf(level: str, start_week: int, end_week: int, day_filter: str | None = None):
    """Cache'li premium PDF uretici."""
    return _premium_plan_pdf(level, start_week, end_week, day_filter)


