# Oyun ismi → dinamik builder tipi eşleştirmesi
_GAME_TYPE_MAP = {
    "Hafıza Kartları": "memory",
    "Memory Match": "memory",
    "Doğru / Yanlış": "quiz",
    "Fill the Blank": "quiz",
    "Bul ve Dokun": "flashcard",
    "Balon Patlat": "balloon",
    "Sıralı Dinle": "flashcard",
    "Kategori Ayır": "wordsearch",
    "Sentence Builder": "flashcard",
    "Spelling Bee": "quiz",
    "Antonym Match": "memory",
    "Crossword": "flashcard",
    "Word Chain": "flashcard",
    "Eşleştirme": "memory",
}


def _build_week_game_html(vocab_pairs, theme_tr, game_type="memory"):
    """Hafta bazlı dinamik oyun HTML builder.
    vocab_pairs: [(en, tr), ...] kelime çiftleri
    theme_tr: haftanın Türkçe teması
    game_type: 'memory' | 'quiz' | 'balloon' | 'wordsearch' | 'flashcard'
    """
    if not vocab_pairs:
        return ""
    if game_type == "memory":
        return _week_memory_html(vocab_pairs, theme_tr)
    elif game_type == "quiz":
        return _week_quiz_html(vocab_pairs, theme_tr)
    elif game_type == "balloon":
        return _week_balloon_html(vocab_pairs, theme_tr)
    elif game_type == "wordsearch":
        return _week_wordsearch_html(vocab_pairs, theme_tr)
    return _week_flashcard_html(vocab_pairs, theme_tr)


def _week_memory_html(pairs, theme):
    """Hafıza kartları — EN↔TR eşleştirme oyunu."""
    import json as _j
    cards_data = _j.dumps([(e, t) for e, t in pairs[:8]], ensure_ascii=False)
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'><style>"
        "*{margin:0;padding:0;box-sizing:border-box;}"
        "body{font-family:'Segoe UI',system-ui,sans-serif;background:linear-gradient(135deg,#0B0F19,#94A3B8);min-height:100vh;display:flex;flex-direction:column;align-items:center;padding:12px;}"
        ".header{text-align:center;margin-bottom:12px;}"
        ".header h2{color:#fff;font-size:18px;margin-bottom:4px;}"
        ".header p{color:#94a3b8;font-size:13px;}"
        ".stats{display:flex;gap:16px;justify-content:center;margin-bottom:12px;}"
        ".stat{background:rgba(255,255,255,.08);border-radius:10px;padding:6px 16px;color:#e2e8f0;font-size:13px;}"
        ".stat b{color:#60a5fa;}"
        ".grid{display:grid;grid-template-columns:repeat(4,1fr);gap:8px;max-width:520px;width:100%;}"
        ".card{position:relative;aspect-ratio:1;cursor:pointer;perspective:800px;}"
        ".card-inner{position:relative;width:100%;height:100%;transition:transform .5s;transform-style:preserve-3d;}"
        ".card.flipped .card-inner{transform:rotateY(180deg);}"
        ".card.matched .card-inner{transform:rotateY(180deg);}"
        ".card-front,.card-back{position:absolute;width:100%;height:100%;backface-visibility:hidden;border-radius:12px;display:flex;align-items:center;justify-content:center;font-weight:700;text-align:center;padding:6px;}"
        ".card-front{background:linear-gradient(135deg,#2563eb,#1e40af);color:rgba(255,255,255,.3);font-size:28px;border:2px solid rgba(255,255,255,.1);}"
        ".card-back{transform:rotateY(180deg);font-size:14px;border:2px solid transparent;}"
        ".card-back.en{background:linear-gradient(135deg,#059669,#047857);color:#fff;}"
        ".card-back.tr{background:linear-gradient(135deg,#7c3aed,#6d28d9);color:#fff;}"
        ".card.matched .card-front{opacity:0;}"
        ".card.matched .card-back{border-color:#fbbf24;box-shadow:0 0 12px rgba(251,191,36,.3);}"
        ".win{display:none;position:fixed;inset:0;background:rgba(0,0,0,.7);z-index:10;align-items:center;justify-content:center;}"
        ".win.show{display:flex;}"
        ".win-box{background:linear-gradient(135deg,#1e40af,#7c3aed);border-radius:20px;padding:32px;text-align:center;color:#fff;max-width:320px;}"
        ".win-box h2{font-size:24px;margin-bottom:8px;}"
        ".win-box p{font-size:15px;opacity:.9;}"
        ".win-box button{margin-top:16px;padding:10px 28px;border:none;border-radius:10px;background:#fff;color:#1e40af;font-size:15px;font-weight:700;cursor:pointer;}"
        "</style></head><body>"
        f"<div class='header'><h2>🧠 Hafıza Kartları</h2><p>{theme}</p></div>"
        "<div class='stats'>"
        "<div class='stat'>Hamle: <b id='moves'>0</b></div>"
        "<div class='stat'>Eşleşme: <b id='matches'>0</b>/<b id='total'>0</b></div>"
        "</div>"
        "<div class='grid' id='grid'></div>"
        "<div class='win' id='win'><div class='win-box'>"
        "<h2>🎉 Tebrikler!</h2><p id='winMsg'></p>"
        "<button onclick='initGame()'>Tekrar Oyna</button></div></div>"
        "<script>"
        f"const PAIRS={cards_data};"
        "let cards=[],flipped=[],matched=0,moves=0,lock=false;"
        "function shuffle(a){for(let i=a.length-1;i>0;i--){let j=Math.floor(Math.random()*(i+1));[a[i],a[j]]=[a[j],a[i]];}return a;}"
        "function initGame(){"
        "  flipped=[];matched=0;moves=0;"
        "  document.getElementById('moves').textContent='0';"
        "  document.getElementById('matches').textContent='0';"
        "  document.getElementById('total').textContent=PAIRS.length;"
        "  document.getElementById('win').classList.remove('show');"
        "  cards=[];"
        "  PAIRS.forEach((p,i)=>{cards.push({id:i*2,pairId:i,text:p[0],type:'en'});cards.push({id:i*2+1,pairId:i,text:p[1],type:'tr'});});"
        "  shuffle(cards);"
        "  const g=document.getElementById('grid');"
        "  g.innerHTML='';"
        "  cards.forEach(c=>{"
        "    const d=document.createElement('div');d.className='card';d.dataset.id=c.id;d.dataset.pair=c.pairId;"
        "    d.innerHTML=`<div class='card-inner'><div class='card-front'>?</div><div class='card-back ${c.type}'>${c.text}</div></div>`;"
        "    d.onclick=()=>flipCard(d,c);"
        "    g.appendChild(d);"
        "  });"
        "}"
        "function flipCard(el,c){"
        "  if(lock||el.classList.contains('flipped')||el.classList.contains('matched'))return;"
        "  el.classList.add('flipped');flipped.push({el,c});"
        "  if(flipped.length===2){"
        "    moves++;document.getElementById('moves').textContent=moves;"
        "    lock=true;"
        "    const[a,b]=flipped;"
        "    if(a.c.pairId===b.c.pairId&&a.c.id!==b.c.id){"
        "      a.el.classList.add('matched');b.el.classList.add('matched');"
        "      matched++;document.getElementById('matches').textContent=matched;"
        "      flipped=[];lock=false;"
        "      if(matched===PAIRS.length){"
        "        setTimeout(()=>{document.getElementById('winMsg').textContent=`${moves} hamlede ${PAIRS.length} eşleşmeyi buldunuz!`;document.getElementById('win').classList.add('show');},500);"
        "      }"
        "    }else{"
        "      setTimeout(()=>{a.el.classList.remove('flipped');b.el.classList.remove('flipped');flipped=[];lock=false;},800);"
        "    }"
        "  }"
        "}"
        "initGame();"
        "</script></body></html>"
    )


def _week_quiz_html(pairs, theme):
    """Doğru/Yanlış quiz — hafta kelimelerinden sorular."""
    import json as _j
    quiz_data = _j.dumps([(e, t) for e, t in pairs], ensure_ascii=False)
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'><style>"
        "*{margin:0;padding:0;box-sizing:border-box;}"
        "body{font-family:'Segoe UI',system-ui,sans-serif;background:linear-gradient(135deg,#0B0F19,#94A3B8);min-height:100vh;display:flex;flex-direction:column;align-items:center;padding:16px;color:#fff;}"
        ".header{text-align:center;margin-bottom:16px;}"
        ".header h2{font-size:18px;margin-bottom:4px;}"
        ".header p{color:#94a3b8;font-size:13px;}"
        ".progress{width:100%;max-width:400px;height:6px;background:rgba(255,255,255,.1);border-radius:3px;margin-bottom:16px;}"
        ".progress-bar{height:100%;background:linear-gradient(90deg,#2563eb,#7c3aed);border-radius:3px;transition:width .3s;}"
        ".card{background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.1);border-radius:16px;padding:28px;max-width:400px;width:100%;text-align:center;}"
        ".q-num{font-size:12px;color:#64748b;margin-bottom:8px;}"
        ".q-word{font-size:28px;font-weight:800;margin-bottom:6px;color:#60a5fa;}"
        ".q-eq{font-size:16px;color:#94a3b8;margin-bottom:2px;}"
        ".q-trans{font-size:22px;font-weight:700;margin-bottom:20px;color:#e2e8f0;}"
        ".btns{display:flex;gap:12px;justify-content:center;}"
        ".btn{flex:1;padding:14px;border:none;border-radius:12px;font-size:16px;font-weight:700;cursor:pointer;transition:all .2s;}"
        ".btn-true{background:linear-gradient(135deg,#059669,#047857);color:#fff;}"
        ".btn-false{background:linear-gradient(135deg,#dc2626,#b91c1c);color:#fff;}"
        ".btn:hover{transform:scale(1.04);}"
        ".btn:disabled{opacity:.5;cursor:default;transform:none;}"
        ".feedback{margin-top:16px;padding:12px;border-radius:10px;font-size:14px;font-weight:600;display:none;}"
        ".feedback.correct{display:block;background:rgba(5,150,105,.2);border:1px solid #059669;color:#6ee7b7;}"
        ".feedback.wrong{display:block;background:rgba(220,38,38,.2);border:1px solid #dc2626;color:#fca5a5;}"
        ".result{display:none;text-align:center;}"
        ".result.show{display:block;}"
        ".result h2{font-size:22px;margin-bottom:8px;}"
        ".result .score{font-size:48px;font-weight:800;background:linear-gradient(135deg,#60a5fa,#a78bfa);-webkit-background-clip:text;-webkit-text-fill-color:transparent;}"
        ".result button{margin-top:16px;padding:10px 28px;border:none;border-radius:10px;background:#2563eb;color:#fff;font-size:15px;font-weight:700;cursor:pointer;}"
        ".stats-row{display:flex;gap:12px;justify-content:center;margin:12px 0;}"
        ".stat-box{background:rgba(255,255,255,.06);border-radius:10px;padding:8px 16px;font-size:13px;}"
        ".stat-box b{color:#60a5fa;}"
        "</style></head><body>"
        f"<div class='header'><h2>✅ Doğru / Yanlış</h2><p>{theme}</p></div>"
        "<div class='progress'><div class='progress-bar' id='pbar'></div></div>"
        "<div class='card' id='quizCard'>"
        "<div class='q-num' id='qnum'></div>"
        "<div class='q-word' id='qword'></div>"
        "<div class='q-eq'>=</div>"
        "<div class='q-trans' id='qtrans'></div>"
        "<div class='btns'>"
        "<button class='btn btn-true' id='btnT' onclick='answer(true)'>✓ Doğru</button>"
        "<button class='btn btn-false' id='btnF' onclick='answer(false)'>✗ Yanlış</button>"
        "</div>"
        "<div class='feedback' id='fb'></div></div>"
        "<div class='result' id='res'>"
        "<h2>🏆 Sonuç</h2><div class='score' id='finalScore'></div>"
        "<div class='stats-row'><div class='stat-box'>Doğru: <b id='rc'>0</b></div>"
        "<div class='stat-box'>Yanlış: <b id='wc'>0</b></div></div>"
        "<button onclick='startQuiz()'>Tekrar Dene</button></div>"
        "<script>"
        f"const PAIRS={quiz_data};"
        "let questions=[],qi=0,correct=0,wrong=0;"
        "function shuffle(a){for(let i=a.length-1;i>0;i--){let j=Math.floor(Math.random()*(i+1));[a[i],a[j]]=[a[j],a[i]];}return a;}"
        "function startQuiz(){"
        "  questions=[];qi=0;correct=0;wrong=0;"
        "  document.getElementById('res').classList.remove('show');"
        "  document.getElementById('quizCard').style.display='block';"
        "  PAIRS.forEach(p=>{"
        "    questions.push({word:p[0],shown:p[1],isCorrect:true});"
        "    let others=PAIRS.filter(x=>x[0]!==p[0]);"
        "    if(others.length>0){"
        "      let rnd=others[Math.floor(Math.random()*others.length)];"
        "      questions.push({word:p[0],shown:rnd[1],isCorrect:false});"
        "    }"
        "  });"
        "  shuffle(questions);"
        "  if(questions.length>12)questions=questions.slice(0,12);"
        "  showQ();"
        "}"
        "function showQ(){"
        "  if(qi>=questions.length){endQuiz();return;}"
        "  let q=questions[qi];"
        "  document.getElementById('qnum').textContent=`Soru ${qi+1}/${questions.length}`;"
        "  document.getElementById('qword').textContent=q.word;"
        "  document.getElementById('qtrans').textContent=q.shown;"
        "  document.getElementById('fb').className='feedback';"
        "  document.getElementById('btnT').disabled=false;"
        "  document.getElementById('btnF').disabled=false;"
        "  document.getElementById('pbar').style.width=((qi/questions.length)*100)+'%';"
        "}"
        "function answer(val){"
        "  let q=questions[qi],fb=document.getElementById('fb');"
        "  document.getElementById('btnT').disabled=true;"
        "  document.getElementById('btnF').disabled=true;"
        "  if(val===q.isCorrect){correct++;fb.className='feedback correct';fb.textContent='✓ Doğru! Harika!';}"
        "  else{wrong++;fb.className='feedback wrong';"
        "    let cp=PAIRS.find(p=>p[0]===q.word);"
        "    fb.textContent='✗ Yanlış! Doğrusu: '+q.word+' = '+(cp?cp[1]:'?');}"
        "  setTimeout(()=>{qi++;showQ();},1200);"
        "}"
        "function endQuiz(){"
        "  document.getElementById('quizCard').style.display='none';"
        "  document.getElementById('pbar').style.width='100%';"
        "  document.getElementById('finalScore').textContent=Math.round((correct/questions.length)*100)+'%';"
        "  document.getElementById('rc').textContent=correct;"
        "  document.getElementById('wc').textContent=wrong;"
        "  document.getElementById('res').classList.add('show');"
        "}"
        "startQuiz();"
        "</script></body></html>"
    )


def _week_balloon_html(pairs, theme):
    """Balon patlatma — doğru çeviriyi bul."""
    import json as _j
    data = _j.dumps([(e, t) for e, t in pairs[:8]], ensure_ascii=False)
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'><style>"
        "*{margin:0;padding:0;box-sizing:border-box;}"
        "body{font-family:'Segoe UI',system-ui,sans-serif;background:linear-gradient(135deg,#0B0F19,#94A3B8);min-height:100vh;display:flex;flex-direction:column;align-items:center;padding:16px;color:#fff;overflow:hidden;}"
        ".header{text-align:center;margin-bottom:12px;z-index:2;}"
        ".header h2{font-size:18px;}"
        ".header p{color:#94a3b8;font-size:13px;}"
        ".prompt{font-size:22px;font-weight:800;color:#60a5fa;margin:12px 0;text-align:center;z-index:2;}"
        ".prompt span{color:#fbbf24;}"
        ".balloons{display:flex;flex-wrap:wrap;gap:12px;justify-content:center;max-width:480px;z-index:2;margin-top:8px;}"
        ".bln{width:100px;height:120px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:14px;font-weight:700;cursor:pointer;transition:all .3s;position:relative;text-align:center;padding:8px;color:#fff;}"
        ".bln:hover{transform:scale(1.12);}"
        ".bln.pop{animation:pop .4s forwards;pointer-events:none;}"
        "@keyframes pop{0%{transform:scale(1);}50%{transform:scale(1.4);opacity:.5;}100%{transform:scale(0);opacity:0;}}"
        ".bln.correct-pop{animation:correctPop .5s forwards;}"
        "@keyframes correctPop{0%{transform:scale(1);}50%{transform:scale(1.3);box-shadow:0 0 30px #22c55e;}100%{transform:scale(1.1);box-shadow:0 0 20px #22c55e;}}"
        ".score-bar{display:flex;gap:16px;margin:12px 0;z-index:2;}"
        ".sc{background:rgba(255,255,255,.08);border-radius:8px;padding:6px 14px;font-size:13px;}"
        ".sc b{color:#60a5fa;}"
        ".msg{font-size:16px;font-weight:700;margin-top:8px;min-height:24px;z-index:2;}"
        ".colors-0{background:radial-gradient(circle at 30% 30%,#ef4444,#b91c1c);}"
        ".colors-1{background:radial-gradient(circle at 30% 30%,#3b82f6,#1d4ed8);}"
        ".colors-2{background:radial-gradient(circle at 30% 30%,#22c55e,#15803d);}"
        ".colors-3{background:radial-gradient(circle at 30% 30%,#f59e0b,#d97706);}"
        ".colors-4{background:radial-gradient(circle at 30% 30%,#a855f7,#7e22ce);}"
        ".colors-5{background:radial-gradient(circle at 30% 30%,#ec4899,#be185d);}"
        ".result{display:none;text-align:center;z-index:2;}"
        ".result.show{display:block;}"
        ".result h2{font-size:22px;margin-bottom:8px;}"
        ".result .big{font-size:48px;font-weight:800;color:#60a5fa;}"
        ".result button{margin-top:12px;padding:10px 24px;border:none;border-radius:10px;background:#2563eb;color:#fff;font-weight:700;cursor:pointer;font-size:15px;}"
        "</style></head><body>"
        f"<div class='header'><h2>🎈 Balon Patlatma</h2><p>{theme}</p></div>"
        "<div class='score-bar'><div class='sc'>Skor: <b id='sc'>0</b></div><div class='sc'>Kalan: <b id='rem'>0</b></div></div>"
        "<div class='prompt' id='prompt'></div>"
        "<div class='balloons' id='area'></div>"
        "<div class='msg' id='msg'></div>"
        "<div class='result' id='res'><h2>🎉 Oyun Bitti!</h2><div class='big' id='fs'></div>"
        "<button onclick='initGame()'>Tekrar Oyna</button></div>"
        "<script>"
        f"const PAIRS={data};"
        "let qi=0,score=0,order=[];"
        "function shuffle(a){for(let i=a.length-1;i>0;i--){let j=Math.floor(Math.random()*(i+1));[a[i],a[j]]=[a[j],a[i]];}return a;}"
        "function initGame(){"
        "  qi=0;score=0;order=shuffle([...Array(PAIRS.length).keys()]);"
        "  document.getElementById('res').classList.remove('show');"
        "  document.getElementById('sc').textContent='0';"
        "  showRound();"
        "}"
        "function showRound(){"
        "  if(qi>=order.length){endGame();return;}"
        "  document.getElementById('rem').textContent=(order.length-qi);"
        "  document.getElementById('msg').textContent='';"
        "  let idx=order[qi],target=PAIRS[idx];"
        "  document.getElementById('prompt').innerHTML=`<span>${target[0]}</span> kelimesini bul!`;"
        "  let opts=[target[1]];"
        "  let others=PAIRS.filter((_,i)=>i!==idx).map(p=>p[1]);"
        "  shuffle(others);"
        "  opts.push(...others.slice(0,3));"
        "  shuffle(opts);"
        "  let area=document.getElementById('area');area.innerHTML='';"
        "  opts.forEach((txt,i)=>{"
        "    let b=document.createElement('div');"
        "    b.className=`bln colors-${i%6}`;"
        "    b.textContent=txt;"
        "    b.onclick=()=>pickBalloon(b,txt,target[1]);"
        "    area.appendChild(b);"
        "  });"
        "}"
        "function pickBalloon(el,picked,correct){"
        "  if(picked===correct){"
        "    score++;document.getElementById('sc').textContent=score;"
        "    el.classList.add('correct-pop');"
        "    document.getElementById('msg').innerHTML='<span style=\"color:#22c55e\">✓ Doğru!</span>';"
        "  }else{"
        "    el.classList.add('pop');"
        "    document.getElementById('msg').innerHTML=`<span style=\"color:#f87171\">✗ Doğrusu: ${correct}</span>`;"
        "  }"
        "  document.querySelectorAll('.bln').forEach(b=>b.style.pointerEvents='none');"
        "  setTimeout(()=>{qi++;showRound();},1000);"
        "}"
        "function endGame(){"
        "  document.getElementById('area').innerHTML='';"
        "  document.getElementById('prompt').innerHTML='';"
        "  document.getElementById('fs').textContent=`${score}/${order.length}`;"
        "  document.getElementById('res').classList.add('show');"
        "}"
        "initGame();"
        "</script></body></html>"
    )


def _week_wordsearch_html(pairs, theme):
    """Kelime avı — İngilizce kelimeyi Türkçe ipucuyla bul."""
    import json as _j
    data = _j.dumps([(e, t) for e, t in pairs[:6]], ensure_ascii=False)
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'><style>"
        "*{margin:0;padding:0;box-sizing:border-box;}"
        "body{font-family:'Segoe UI',system-ui,sans-serif;background:linear-gradient(135deg,#0B0F19,#94A3B8);min-height:100vh;display:flex;flex-direction:column;align-items:center;padding:16px;color:#fff;}"
        ".header{text-align:center;margin-bottom:10px;}"
        ".header h2{font-size:18px;}"
        ".header p{color:#94a3b8;font-size:13px;}"
        ".clues{display:flex;flex-wrap:wrap;gap:6px;justify-content:center;margin-bottom:12px;max-width:460px;}"
        ".clue{background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.1);border-radius:8px;padding:4px 10px;font-size:12px;transition:all .3s;}"
        ".clue.found{background:rgba(34,197,94,.15);border-color:#22c55e;text-decoration:line-through;color:#86efac;}"
        ".grid-wrap{display:inline-grid;gap:3px;margin:0 auto;}"
        ".cell{width:36px;height:36px;display:flex;align-items:center;justify-content:center;font-size:15px;font-weight:700;border-radius:6px;cursor:pointer;user-select:none;background:rgba(255,255,255,.05);border:1px solid rgba(255,255,255,.08);transition:all .15s;text-transform:uppercase;}"
        ".cell:hover{background:rgba(96,165,250,.2);}"
        ".cell.selected{background:rgba(37,99,235,.5);border-color:#60a5fa;}"
        ".cell.found{background:rgba(34,197,94,.25);border-color:#22c55e;color:#86efac;}"
        ".info{margin-top:10px;font-size:13px;color:#94a3b8;}"
        ".win{display:none;text-align:center;margin-top:16px;}"
        ".win.show{display:block;}"
        ".win h2{color:#22c55e;font-size:20px;}"
        ".win button{margin-top:10px;padding:8px 24px;border:none;border-radius:8px;background:#2563eb;color:#fff;font-weight:700;cursor:pointer;}"
        "</style></head><body>"
        f"<div class='header'><h2>🔍 Kelime Avı</h2><p>{theme}</p></div>"
        "<div class='clues' id='clues'></div>"
        "<div class='grid-wrap' id='grid'></div>"
        "<div class='info'>İpucu: Türkçe anlamlardan İngilizce kelimeyi bul! Harflere tıkla.</div>"
        "<div class='win' id='win'><h2>🎉 Hepsini buldun!</h2><button onclick='initGame()'>Tekrar Oyna</button></div>"
        "<script>"
        f"const PAIRS={data};"
        "const GRID_SIZE=10;let grid=[],foundWords=new Set(),selCells=[];"
        "const DIRS=[[0,1],[1,0],[1,1],[0,-1],[-1,0]];"
        "function rndChar(){return 'ABCDEFGHIJKLMNOPQRSTUVWXYZ'[Math.floor(Math.random()*26)];}"
        "function initGame(){"
        "  foundWords=new Set();selCells=[];"
        "  document.getElementById('win').classList.remove('show');"
        "  grid=Array.from({length:GRID_SIZE},()=>Array.from({length:GRID_SIZE},()=>({ch:rndChar(),wordIdx:-1})));"
        "  PAIRS.forEach((p,wi)=>{"
        "    let w=p[0].toUpperCase().replace(/\\s/g,''),placed=false;"
        "    for(let att=0;att<100&&!placed;att++){"
        "      let d=DIRS[Math.floor(Math.random()*DIRS.length)];"
        "      let r=Math.floor(Math.random()*GRID_SIZE),c=Math.floor(Math.random()*GRID_SIZE);"
        "      let ok=true;"
        "      for(let k=0;k<w.length;k++){"
        "        let nr=r+d[0]*k,nc=c+d[1]*k;"
        "        if(nr<0||nr>=GRID_SIZE||nc<0||nc>=GRID_SIZE){ok=false;break;}"
        "        if(grid[nr][nc].wordIdx>=0&&grid[nr][nc].ch!==w[k]){ok=false;break;}"
        "      }"
        "      if(ok){"
        "        for(let k=0;k<w.length;k++){let nr=r+d[0]*k,nc=c+d[1]*k;grid[nr][nc]={ch:w[k],wordIdx:wi};}"
        "        placed=true;"
        "      }"
        "    }"
        "  });"
        "  renderGrid();renderClues();"
        "}"
        "function renderGrid(){"
        "  let g=document.getElementById('grid');"
        "  g.style.gridTemplateColumns=`repeat(${GRID_SIZE},36px)`;"
        "  g.innerHTML='';"
        "  for(let r=0;r<GRID_SIZE;r++)for(let c=0;c<GRID_SIZE;c++){"
        "    let d=document.createElement('div');d.className='cell';"
        "    d.textContent=grid[r][c].ch;d.dataset.r=r;d.dataset.c=c;"
        "    d.onclick=()=>toggleCell(d,r,c);"
        "    g.appendChild(d);"
        "  }"
        "}"
        "function renderClues(){"
        "  let cl=document.getElementById('clues');cl.innerHTML='';"
        "  PAIRS.forEach((p,i)=>{"
        "    let d=document.createElement('div');d.className='clue';d.id='clue_'+i;"
        "    d.textContent=`${p[1]} (${p[0].length} harf)`;"
        "    if(foundWords.has(i))d.classList.add('found');"
        "    cl.appendChild(d);"
        "  });"
        "}"
        "function toggleCell(el,r,c){"
        "  if(el.classList.contains('found'))return;"
        "  if(el.classList.contains('selected')){el.classList.remove('selected');selCells=selCells.filter(x=>!(x.r===r&&x.c===c));}else{el.classList.add('selected');selCells.push({r,c,ch:grid[r][c].ch});}"
        "  checkWord();"
        "}"
        "function checkWord(){"
        "  let sel=selCells.map(s=>s.ch).join('');"
        "  PAIRS.forEach((p,i)=>{"
        "    if(foundWords.has(i))return;"
        "    let w=p[0].toUpperCase().replace(/\\s/g,'');"
        "    if(sel===w||sel===w.split('').reverse().join('')){"
        "      foundWords.add(i);"
        "      selCells.forEach(s=>{let el=document.querySelector(`.cell[data-r='${s.r}'][data-c='${s.c}']`);if(el){el.classList.remove('selected');el.classList.add('found');}});"
        "      selCells=[];document.getElementById('clue_'+i).classList.add('found');"
        "      if(foundWords.size===PAIRS.length)setTimeout(()=>document.getElementById('win').classList.add('show'),500);"
        "    }"
        "  });"
        "}"
        "initGame();"
        "</script></body></html>"
    )


def _week_flashcard_html(pairs, theme):
    """Flashcard — kelime kartları çevir & öğren."""
    import json as _j
    data = _j.dumps([(e, t) for e, t in pairs], ensure_ascii=False)
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'><style>"
        "*{margin:0;padding:0;box-sizing:border-box;}"
        "body{font-family:'Segoe UI',system-ui,sans-serif;background:linear-gradient(135deg,#0B0F19,#94A3B8);min-height:100vh;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:16px;color:#fff;}"
        ".header{text-align:center;margin-bottom:16px;}"
        ".header h2{font-size:18px;}"
        ".header p{color:#94a3b8;font-size:13px;}"
        ".counter{font-size:14px;color:#94a3b8;margin-bottom:12px;}"
        ".card-container{perspective:1000px;width:300px;height:200px;cursor:pointer;margin-bottom:16px;}"
        ".card-flip{position:relative;width:100%;height:100%;transition:transform .6s;transform-style:preserve-3d;}"
        ".card-container.flipped .card-flip{transform:rotateY(180deg);}"
        ".card-face{position:absolute;width:100%;height:100%;backface-visibility:hidden;border-radius:16px;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:20px;}"
        ".face-front{background:linear-gradient(135deg,#2563eb,#1e40af);border:2px solid rgba(255,255,255,.15);}"
        ".face-back{background:linear-gradient(135deg,#7c3aed,#6d28d9);border:2px solid rgba(255,255,255,.15);transform:rotateY(180deg);}"
        ".card-word{font-size:28px;font-weight:800;}"
        ".card-label{font-size:12px;opacity:.6;margin-top:8px;}"
        ".nav{display:flex;gap:12px;}"
        ".nav button{padding:10px 24px;border:none;border-radius:10px;font-size:14px;font-weight:700;cursor:pointer;transition:all .2s;}"
        ".nav button:hover{transform:scale(1.05);}"
        ".btn-prev{background:rgba(255,255,255,.1);color:#fff;}"
        ".btn-next{background:#2563eb;color:#fff;}"
        ".btn-prev:disabled,.btn-next:disabled{opacity:.3;cursor:default;transform:none;}"
        ".tip{margin-top:16px;font-size:12px;color:#64748b;}"
        ".dots{display:flex;gap:6px;margin-bottom:12px;}"
        ".dot{width:8px;height:8px;border-radius:50%;background:rgba(255,255,255,.15);transition:all .3s;}"
        ".dot.active{background:#60a5fa;transform:scale(1.3);}"
        ".dot.seen{background:rgba(96,165,250,.4);}"
        "</style></head><body>"
        f"<div class='header'><h2>📖 Kelime Kartları</h2><p>{theme}</p></div>"
        "<div class='dots' id='dots'></div>"
        "<div class='counter' id='cnt'></div>"
        "<div class='card-container' id='cc' onclick='flipCard()'>"
        "<div class='card-flip' id='cf'>"
        "<div class='card-face face-front'><div class='card-word' id='fw'></div><div class='card-label'>İngilizce — tıkla çevir</div></div>"
        "<div class='card-face face-back'><div class='card-word' id='bw'></div><div class='card-label'>Türkçe</div></div>"
        "</div></div>"
        "<div class='nav'>"
        "<button class='btn-prev' id='bp' onclick='prev()'>← Önceki</button>"
        "<button class='btn-next' id='bn' onclick='next()'>Sonraki →</button>"
        "</div>"
        "<div class='tip'>Kartı çevirmek için tıklayın</div>"
        "<script>"
        f"const PAIRS={data};"
        "let idx=0,seen=new Set();"
        "function show(){"
        "  document.getElementById('cc').classList.remove('flipped');"
        "  document.getElementById('fw').textContent=PAIRS[idx][0];"
        "  document.getElementById('bw').textContent=PAIRS[idx][1];"
        "  document.getElementById('cnt').textContent=`${idx+1} / ${PAIRS.length}`;"
        "  document.getElementById('bp').disabled=(idx===0);"
        "  document.getElementById('bn').disabled=(idx===PAIRS.length-1);"
        "  seen.add(idx);renderDots();"
        "}"
        "function renderDots(){"
        "  let d=document.getElementById('dots');d.innerHTML='';"
        "  PAIRS.forEach((_,i)=>{"
        "    let dot=document.createElement('div');dot.className='dot';"
        "    if(i===idx)dot.classList.add('active');"
        "    else if(seen.has(i))dot.classList.add('seen');"
        "    dot.onclick=()=>{idx=i;show();};"
        "    d.appendChild(dot);"
        "  });"
        "}"
        "function flipCard(){document.getElementById('cc').classList.toggle('flipped');}"
        "function prev(){if(idx>0){idx--;show();}}"
        "function next(){if(idx<PAIRS.length-1){idx++;show();}}"
        "show();"
        "</script></body></html>"
    )


def _get_week_vocab_pairs(week_data):
    """Haftanın vocab listesinden (en, tr) çiftleri oluştur."""
    vocab = week_data.get("vocab", [])
    pairs = []
    for w in vocab:
        w_lower = w.lower().strip()
        tr = _VOCAB_TR.get(w_lower)
        if tr:
            pairs.append((w, tr))
    return pairs


# ── İçerik Tipi Dinamik Builder'lar ──

def _week_vocabulary_html(pairs, theme):
    """Kelime Öğren — interaktif kelime kartları (progress tracking)."""
    import json as _j
    data = _j.dumps([(e, t) for e, t in pairs], ensure_ascii=False)
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'><style>"
        "*{margin:0;padding:0;box-sizing:border-box;}"
        "body{font-family:'Segoe UI',system-ui,sans-serif;background:linear-gradient(135deg,#0B0F19,#94A3B8);min-height:100vh;padding:16px;color:#fff;}"
        ".header{text-align:center;margin-bottom:16px;}"
        ".header h2{font-size:18px;margin-bottom:4px;}"
        ".header p{color:#94a3b8;font-size:13px;}"
        ".progress{display:flex;align-items:center;gap:8px;justify-content:center;margin-bottom:16px;}"
        ".pbar{flex:1;max-width:300px;height:8px;background:rgba(255,255,255,.1);border-radius:4px;}"
        ".pfill{height:100%;background:linear-gradient(90deg,#22c55e,#16a34a);border-radius:4px;transition:width .4s;}"
        ".ptxt{font-size:13px;color:#94a3b8;}"
        ".cards{display:grid;grid-template-columns:repeat(auto-fill,minmax(140px,1fr));gap:10px;max-width:600px;margin:0 auto;}"
        ".wcard{background:rgba(255,255,255,.05);border:2px solid rgba(255,255,255,.1);border-radius:14px;padding:16px 12px;text-align:center;cursor:pointer;transition:all .3s;}"
        ".wcard:hover{border-color:#60a5fa;transform:translateY(-2px);}"
        ".wcard.learned{border-color:#22c55e;background:rgba(34,197,94,.1);}"
        ".wcard .en{font-size:18px;font-weight:800;color:#60a5fa;margin-bottom:4px;}"
        ".wcard.learned .en{color:#86efac;}"
        ".wcard .tr{font-size:13px;color:#94a3b8;opacity:0;transition:opacity .3s;}"
        ".wcard.show .tr,.wcard.learned .tr{opacity:1;}"
        ".wcard .check{font-size:11px;margin-top:6px;color:#64748b;}"
        ".wcard.learned .check{color:#22c55e;}"
        ".tip{text-align:center;margin-top:14px;font-size:12px;color:#64748b;}"
        ".btn-row{text-align:center;margin-top:12px;}"
        ".rbtn{padding:8px 20px;border:none;border-radius:8px;background:#2563eb;color:#fff;font-weight:700;cursor:pointer;font-size:13px;}"
        "</style></head><body>"
        f"<div class='header'><h2>📖 Kelime Öğren</h2><p>{theme}</p></div>"
        "<div class='progress'><div class='pbar'><div class='pfill' id='pf' style='width:0%'></div></div>"
        "<div class='ptxt' id='pt'>0/0 öğrenildi</div></div>"
        "<div class='cards' id='cards'></div>"
        "<div class='tip'>Kartlara tıklayarak Türkçe anlamını gör, tekrar tıklayarak öğrenildi işaretle</div>"
        "<div class='btn-row'><button class='rbtn' onclick='resetAll()'>Sıfırla</button></div>"
        "<script>"
        f"const W={data};"
        "let learned=new Set();"
        "function render(){"
        "  const c=document.getElementById('cards');c.innerHTML='';"
        "  W.forEach((p,i)=>{"
        "    const d=document.createElement('div');d.className='wcard'+(learned.has(i)?' learned':'');"
        "    d.innerHTML=`<div class='en'>${p[0]}</div><div class='tr'>${p[1]}</div>`"
        "      +`<div class='check'>${learned.has(i)?'✓ Öğrenildi':'Tıkla → göster'}</div>`;"
        "    d.onclick=()=>{if(!d.classList.contains('show')&&!learned.has(i)){d.classList.add('show');d.querySelector('.check').textContent='Tekrar tıkla → öğrenildi';}"
        "      else{learned.add(i);render();}};"
        "    c.appendChild(d);"
        "  });"
        "  document.getElementById('pf').style.width=(learned.size/W.length*100)+'%';"
        "  document.getElementById('pt').textContent=`${learned.size}/${W.length} öğrenildi`;"
        "}"
        "function resetAll(){learned=new Set();render();}"
        "render();"
        "</script></body></html>"
    )


def _week_singalong_html(pairs, theme):
    """Şarkı ile Öğren — kelimeler müzikal animasyonla."""
    import json as _j
    data = _j.dumps([(e, t) for e, t in pairs], ensure_ascii=False)
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'><style>"
        "*{margin:0;padding:0;box-sizing:border-box;}"
        "body{font-family:'Segoe UI',system-ui,sans-serif;background:linear-gradient(135deg,#1e1b4b,#312e81,#4c1d95);min-height:100vh;padding:16px;color:#fff;overflow:hidden;}"
        ".header{text-align:center;margin-bottom:12px;}"
        ".header h2{font-size:18px;}"
        ".header p{color:#c4b5fd;font-size:13px;}"
        ".stage{position:relative;max-width:500px;margin:0 auto;min-height:400px;}"
        ".word-bubble{position:absolute;padding:12px 20px;border-radius:20px;font-weight:700;text-align:center;cursor:pointer;transition:all .3s;opacity:0;transform:scale(0);}"
        ".word-bubble.show{opacity:1;transform:scale(1);}"
        ".word-bubble:hover{transform:scale(1.15)!important;z-index:10;}"
        ".word-bubble .en{font-size:18px;display:block;}"
        ".word-bubble .tr{font-size:12px;display:block;opacity:0;transition:opacity .3s;}"
        ".word-bubble.reveal .tr{opacity:1;}"
        ".controls{text-align:center;margin-top:12px;}"
        ".cbtn{padding:10px 24px;border:none;border-radius:12px;font-size:14px;font-weight:700;cursor:pointer;margin:0 6px;transition:all .2s;}"
        ".cbtn:hover{transform:scale(1.08);}"
        ".play-btn{background:linear-gradient(135deg,#f59e0b,#d97706);color:#fff;font-size:16px;}"
        ".reveal-btn{background:rgba(255,255,255,.15);color:#fff;}"
        ".notes{position:fixed;pointer-events:none;}"
        ".note{position:absolute;font-size:20px;animation:float 3s ease-out forwards;opacity:0;}"
        "@keyframes float{0%{opacity:1;transform:translateY(0) rotate(0deg);}100%{opacity:0;transform:translateY(-200px) rotate(20deg);}}"
        "@keyframes bounce{0%,100%{transform:scale(1);}50%{transform:scale(1.1);}}"
        "@keyframes pulse{0%{box-shadow:0 0 0 0 rgba(251,191,36,.4);}70%{box-shadow:0 0 0 15px rgba(251,191,36,0);}100%{box-shadow:0 0 0 0 rgba(251,191,36,0);}}"
        ".word-bubble.active{animation:bounce .5s ease,pulse 1s ease infinite;}"
        ".colors{display:flex;flex-wrap:wrap;gap:4px;justify-content:center;position:absolute;bottom:0;width:100%;}"
        "</style></head><body>"
        f"<div class='header'><h2>🎵 Şarkı ile Öğren</h2><p>{theme}</p></div>"
        "<div class='stage' id='stage'></div>"
        "<div class='controls'>"
        "<button class='cbtn play-btn' id='playBtn' onclick='playSequence()'>▶ Başlat</button>"
        "<button class='cbtn reveal-btn' onclick='revealAll()'>👁 Tümünü Göster</button>"
        "</div>"
        "<div class='notes' id='notes'></div>"
        "<script>"
        f"const W={data};"
        "const COLORS=['#ef4444','#f59e0b','#22c55e','#3b82f6','#a855f7','#ec4899','#14b8a6','#f97316','#6366f1'];"
        "let bubbles=[],playing=false,revealed=false;"
        "function init(){"
        "  const s=document.getElementById('stage');"
        "  s.innerHTML='';"
        "  bubbles=[];"
        "  W.forEach((p,i)=>{"
        "    const d=document.createElement('div');"
        "    d.className='word-bubble';"
        "    const c=COLORS[i%COLORS.length];"
        "    const x=10+Math.random()*60,y=10+(i/W.length)*75;"
        "    d.style.cssText=`left:${x}%;top:${y}%;background:${c};`;"
        "    d.innerHTML=`<span class='en'>${p[0]}</span><span class='tr'>${p[1]}</span>`;"
        "    d.onclick=()=>{d.classList.toggle('reveal');spawnNote(d);};"
        "    s.appendChild(d);"
        "    bubbles.push(d);"
        "    setTimeout(()=>d.classList.add('show'),100+i*150);"
        "  });"
        "}"
        "function spawnNote(el){"
        "  const n=document.createElement('div');n.className='note';"
        "  n.textContent=['🎵','🎶','🎼','♪','♫'][Math.floor(Math.random()*5)];"
        "  const r=el.getBoundingClientRect();"
        "  n.style.left=r.left+'px';n.style.top=r.top+'px';"
        "  document.getElementById('notes').appendChild(n);"
        "  setTimeout(()=>n.remove(),3000);"
        "}"
        "function playSequence(){"
        "  if(playing)return;playing=true;"
        "  document.getElementById('playBtn').textContent='🎵 Çalıyor...';"
        "  bubbles.forEach(b=>b.classList.remove('active','reveal'));"
        "  let i=0;"
        "  const iv=setInterval(()=>{"
        "    if(i>0)bubbles[i-1].classList.remove('active');"
        "    if(i>=bubbles.length){clearInterval(iv);playing=false;"
        "      document.getElementById('playBtn').textContent='▶ Tekrar';return;}"
        "    bubbles[i].classList.add('active','reveal');"
        "    spawnNote(bubbles[i]);i++;"
        "  },800);"
        "}"
        "function revealAll(){"
        "  revealed=!revealed;"
        "  bubbles.forEach(b=>{if(revealed)b.classList.add('reveal');else b.classList.remove('reveal');});"
        "}"
        "init();"
        "</script></body></html>"
    )


def _week_dialogue_html(pairs, structure, theme):
    """Diyalog Pratik — hafta kalıbıyla interaktif diyalog."""
    import json as _j
    data = _j.dumps([(e, t) for e, t in pairs], ensure_ascii=False)
    struct_js = _j.dumps(structure, ensure_ascii=False)
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'><style>"
        "*{margin:0;padding:0;box-sizing:border-box;}"
        "body{font-family:'Segoe UI',system-ui,sans-serif;background:linear-gradient(135deg,#0B0F19,#94A3B8);min-height:100vh;padding:16px;color:#fff;}"
        ".header{text-align:center;margin-bottom:12px;}"
        ".header h2{font-size:18px;}"
        ".header p{color:#94a3b8;font-size:13px;}"
        ".struct{background:rgba(37,99,235,.15);border:1px solid #2563eb;border-radius:10px;padding:10px 16px;text-align:center;margin-bottom:16px;max-width:480px;margin-left:auto;margin-right:auto;}"
        ".struct-label{font-size:11px;color:#60a5fa;font-weight:600;margin-bottom:4px;}"
        ".struct-text{font-size:16px;font-weight:700;color:#e2e8f0;}"
        ".chat{max-width:480px;margin:0 auto;display:flex;flex-direction:column;gap:10px;}"
        ".bubble{max-width:80%;padding:12px 16px;border-radius:16px;font-size:14px;line-height:1.5;animation:fadeIn .4s ease;}"
        "@keyframes fadeIn{from{opacity:0;transform:translateY(10px);}to{opacity:1;transform:translateY(0);}}"
        ".bubble-a{align-self:flex-start;background:linear-gradient(135deg,#2563eb,#1e40af);border-bottom-left-radius:4px;}"
        ".bubble-b{align-self:flex-end;background:linear-gradient(135deg,#7c3aed,#6d28d9);border-bottom-right-radius:4px;}"
        ".bubble .name{font-size:11px;opacity:.7;margin-bottom:2px;}"
        ".bubble .tr{font-size:12px;opacity:.6;font-style:italic;margin-top:4px;}"
        ".blank{display:inline-block;min-width:60px;border-bottom:2px dashed #fbbf24;color:#fbbf24;font-weight:700;cursor:pointer;padding:0 4px;}"
        ".blank.filled{border-color:#22c55e;color:#86efac;}"
        ".word-bank{max-width:480px;margin:16px auto 0;display:flex;flex-wrap:wrap;gap:6px;justify-content:center;}"
        ".wbtn{padding:6px 14px;border-radius:20px;border:1px solid rgba(255,255,255,.2);background:rgba(255,255,255,.06);color:#e2e8f0;font-size:13px;cursor:pointer;transition:all .2s;}"
        ".wbtn:hover{background:rgba(37,99,235,.3);border-color:#2563eb;}"
        ".wbtn.used{opacity:.3;pointer-events:none;text-decoration:line-through;}"
        ".result{text-align:center;margin-top:16px;font-size:15px;font-weight:700;min-height:24px;}"
        ".reset-btn{display:block;margin:12px auto 0;padding:8px 20px;border:none;border-radius:8px;background:#2563eb;color:#fff;font-weight:700;cursor:pointer;font-size:13px;}"
        "</style></head><body>"
        f"<div class='header'><h2>💬 Diyalog Pratik</h2><p>{theme}</p></div>"
        f"<div class='struct'><div class='struct-label'>Bu haftanın kalıbı</div>"
        f"<div class='struct-text' id='struct'></div></div>"
        "<div class='chat' id='chat'></div>"
        "<div class='word-bank' id='bank'></div>"
        "<div class='result' id='res'></div>"
        "<button class='reset-btn' onclick='init()'>Yeni Diyalog</button>"
        "<script>"
        f"const W={data},STRUCT={struct_js};"
        "document.getElementById('struct').textContent=STRUCT;"
        "const TEMPLATES=["
        "  [{r:'a',t:'Hello! {w}?'},{r:'b',t:'Hi! {w}!'},{r:'a',t:'Do you know {w}?'},{r:'b',t:'Yes, {w}!'}],"
        "  [{r:'a',t:'What is {w}?'},{r:'b',t:'{w} means {tr}.'},{r:'a',t:'Can you say {w}?'},{r:'b',t:'{w}! Easy!'}],"
        "  [{r:'a',t:'I like {w}.'},{r:'b',t:'Me too! {w} is great.'},{r:'a',t:'Do you have {w}?'},{r:'b',t:'Yes, I have {w}.'}],"
        "];"
        "let blanks=[],answers=[],bankWords=[];"
        "function shuffle(a){for(let i=a.length-1;i>0;i--){let j=Math.floor(Math.random()*(i+1));[a[i],a[j]]=[a[j],a[i]];}return a;}"
        "function init(){"
        "  const tmpl=TEMPLATES[Math.floor(Math.random()*TEMPLATES.length)];"
        "  const picks=shuffle([...W]).slice(0,Math.min(4,W.length));"
        "  blanks=[];answers=[];bankWords=[];"
        "  const chat=document.getElementById('chat');chat.innerHTML='';"
        "  document.getElementById('res').textContent='';"
        "  tmpl.forEach((line,li)=>{"
        "    const p=picks[li%picks.length];"
        "    let text=line.t.replace('{w}',`<span class='blank' data-idx='${li}'>${'_'.repeat(p[0].length)}</span>`);"
        "    text=text.replace('{tr}',p[1]);"
        "    answers.push(p[0]);"
        "    bankWords.push(p[0]);"
        "    const d=document.createElement('div');"
        "    d.className='bubble bubble-'+line.r;"
        "    d.innerHTML=`<div class='name'>${line.r==='a'?'👩 Öğretmen':'👦 Öğrenci'}</div>${text}`;"
        "    chat.appendChild(d);"
        "  });"
        "  shuffle(bankWords);"
        "  const bank=document.getElementById('bank');bank.innerHTML='';"
        "  bankWords.forEach((w,i)=>{"
        "    const b=document.createElement('span');b.className='wbtn';b.textContent=w;b.dataset.idx=i;"
        "    b.onclick=()=>fillNext(w,b);"
        "    bank.appendChild(b);"
        "  });"
        "}"
        "function fillNext(word,btn){"
        "  const bl=document.querySelector('.blank:not(.filled)');"
        "  if(!bl)return;"
        "  const idx=parseInt(bl.dataset.idx);"
        "  bl.textContent=word;bl.classList.add('filled');"
        "  btn.classList.add('used');"
        "  if(document.querySelectorAll('.blank:not(.filled)').length===0){"
        "    let correct=0;"
        "    document.querySelectorAll('.blank').forEach((b,i)=>{"
        "      if(b.textContent===answers[i])correct++;"
        "    });"
        "    document.getElementById('res').innerHTML=correct===answers.length"
        "      ?'<span style=\"color:#22c55e\">🎉 Mükemmel! Tüm boşluklar doğru!</span>'"
        "      :`<span style=\"color:#f59e0b\">${correct}/${answers.length} doğru — tekrar dene!</span>`;"
        "  }"
        "}"
        "init();"
        "</script></body></html>"
    )


def _week_reading_html(pairs, theme):
    """Okuma Pratiği — kelimelerle kısa metin + anlama soruları."""
    import json as _j
    data = _j.dumps([(e, t) for e, t in pairs], ensure_ascii=False)
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'><style>"
        "*{margin:0;padding:0;box-sizing:border-box;}"
        "body{font-family:'Segoe UI',system-ui,sans-serif;background:linear-gradient(135deg,#0B0F19,#94A3B8);min-height:100vh;padding:16px;color:#fff;}"
        ".header{text-align:center;margin-bottom:14px;}"
        ".header h2{font-size:18px;}"
        ".header p{color:#94a3b8;font-size:13px;}"
        ".text-box{background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.1);border-radius:14px;padding:20px;max-width:520px;margin:0 auto 16px;line-height:1.8;font-size:15px;}"
        ".hl{background:rgba(37,99,235,.3);border-radius:4px;padding:1px 4px;color:#93c5fd;cursor:pointer;font-weight:600;position:relative;}"
        ".hl:hover::after{content:attr(data-tr);position:absolute;bottom:100%;left:50%;transform:translateX(-50%);background:#1e40af;color:#fff;padding:4px 10px;border-radius:6px;font-size:12px;white-space:nowrap;z-index:10;}"
        ".quiz-section{max-width:520px;margin:0 auto;}"
        ".quiz-title{font-size:15px;font-weight:700;margin-bottom:10px;}"
        ".q-card{background:rgba(255,255,255,.05);border:1px solid rgba(255,255,255,.08);border-radius:10px;padding:14px;margin-bottom:10px;}"
        ".q-text{font-size:14px;margin-bottom:8px;}"
        ".q-opts{display:flex;flex-wrap:wrap;gap:6px;}"
        ".q-opt{padding:6px 14px;border-radius:8px;border:1px solid rgba(255,255,255,.15);background:rgba(255,255,255,.04);cursor:pointer;font-size:13px;transition:all .2s;}"
        ".q-opt:hover{border-color:#60a5fa;background:rgba(37,99,235,.15);}"
        ".q-opt.correct{border-color:#22c55e;background:rgba(34,197,94,.2);color:#86efac;}"
        ".q-opt.wrong{border-color:#ef4444;background:rgba(239,68,68,.2);color:#fca5a5;}"
        ".score{text-align:center;margin-top:14px;font-size:16px;font-weight:700;}"
        "</style></head><body>"
        f"<div class='header'><h2>📖 Okuma Pratiği</h2><p>{theme}</p></div>"
        "<div class='text-box' id='txt'></div>"
        "<div class='quiz-section'>"
        "<div class='quiz-title'>📝 Anlama Soruları</div>"
        "<div id='quiz'></div>"
        "<div class='score' id='sc'></div></div>"
        "<script>"
        f"const W={data};"
        "function shuffle(a){for(let i=a.length-1;i>0;i--){let j=Math.floor(Math.random()*(i+1));[a[i],a[j]]=[a[j],a[i]];}return a;}"
        "const SENTENCE_TEMPLATES=['I see a {w}.','The {w} is here.','I like {w}.','This is a {w}.','Look at the {w}!','I have a {w}.','Where is the {w}?','The {w} is nice.'];"
        "let sentences=[];"
        "W.forEach(p=>{"
        "  const t=SENTENCE_TEMPLATES[Math.floor(Math.random()*SENTENCE_TEMPLATES.length)];"
        "  sentences.push(t.replace('{w}',`<span class='hl' data-tr='${p[1]}'>${p[0]}</span>`));"
        "});"
        "document.getElementById('txt').innerHTML=sentences.join(' ');"
        "// Quiz"
        "const quiz=document.getElementById('quiz');"
        "let total=Math.min(W.length,5),correct=0,answered=0;"
        "const picks=shuffle([...W]).slice(0,total);"
        "picks.forEach((p,qi)=>{"
        "  const d=document.createElement('div');d.className='q-card';"
        "  d.innerHTML=`<div class='q-text'>${qi+1}. \"${p[0]}\" ne demek?</div><div class='q-opts' id='qo_${qi}'></div>`;"
        "  quiz.appendChild(d);"
        "  let opts=[p[1]];let others=W.filter(x=>x[0]!==p[0]).map(x=>x[1]);"
        "  shuffle(others);opts.push(...others.slice(0,2));shuffle(opts);"
        "  const container=document.getElementById('qo_'+qi);"
        "  opts.forEach(o=>{"
        "    const b=document.createElement('span');b.className='q-opt';b.textContent=o;"
        "    b.onclick=()=>{"
        "      if(d.dataset.done)return;d.dataset.done='1';"
        "      if(o===p[1]){b.classList.add('correct');correct++;}else{"
        "        b.classList.add('wrong');"
        "        container.querySelectorAll('.q-opt').forEach(x=>{if(x.textContent===p[1])x.classList.add('correct');});"
        "      }"
        "      answered++;"
        "      if(answered===total)document.getElementById('sc').innerHTML="
        "        `<span style='color:${correct===total?\"#22c55e\":\"#f59e0b\"}'>${correct}/${total} doğru!</span>`;"
        "    };"
        "    container.appendChild(b);"
        "  });"
        "});"
        "</script></body></html>"
    )


def _week_writing_html(pairs, theme):
    """Yazma Pratiği — kelime harf sıralama + cümle tamamlama."""
    import json as _j
    data = _j.dumps([(e, t) for e, t in pairs], ensure_ascii=False)
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'><style>"
        "*{margin:0;padding:0;box-sizing:border-box;}"
        "body{font-family:'Segoe UI',system-ui,sans-serif;background:linear-gradient(135deg,#0B0F19,#94A3B8);min-height:100vh;padding:16px;color:#fff;}"
        ".header{text-align:center;margin-bottom:14px;}"
        ".header h2{font-size:18px;}"
        ".header p{color:#94a3b8;font-size:13px;}"
        ".card{background:rgba(255,255,255,.05);border:1px solid rgba(255,255,255,.1);border-radius:14px;padding:20px;max-width:480px;margin:0 auto 12px;text-align:center;}"
        ".hint{font-size:14px;color:#94a3b8;margin-bottom:4px;}"
        ".clue{font-size:22px;font-weight:800;color:#a78bfa;margin-bottom:12px;}"
        ".scramble{display:flex;flex-wrap:wrap;gap:6px;justify-content:center;margin-bottom:12px;}"
        ".letter{width:36px;height:40px;display:flex;align-items:center;justify-content:center;border-radius:8px;font-size:18px;font-weight:700;cursor:pointer;transition:all .2s;user-select:none;}"
        ".letter.bank{background:rgba(37,99,235,.2);border:1px solid #2563eb;color:#93c5fd;}"
        ".letter.bank:hover{background:rgba(37,99,235,.4);transform:scale(1.1);}"
        ".letter.placed{background:rgba(34,197,94,.2);border:1px solid #22c55e;color:#86efac;}"
        ".letter.wrong{background:rgba(239,68,68,.2);border:1px solid #ef4444;color:#fca5a5;}"
        ".answer-row{display:flex;gap:4px;justify-content:center;min-height:44px;margin-bottom:8px;}"
        ".slot{width:36px;height:40px;border-bottom:2px solid #475569;display:flex;align-items:center;justify-content:center;font-size:18px;font-weight:700;color:#e2e8f0;}"
        ".fb{font-size:14px;font-weight:600;min-height:20px;}"
        ".nav{display:flex;gap:10px;justify-content:center;margin-top:12px;}"
        ".nbtn{padding:8px 20px;border:none;border-radius:8px;font-size:14px;font-weight:700;cursor:pointer;}"
        ".nbtn-prev{background:rgba(255,255,255,.1);color:#fff;}"
        ".nbtn-next{background:#2563eb;color:#fff;}"
        ".counter{text-align:center;font-size:13px;color:#94a3b8;margin-bottom:8px;}"
        ".score-final{text-align:center;font-size:20px;font-weight:800;color:#60a5fa;margin-top:12px;}"
        "</style></head><body>"
        f"<div class='header'><h2>✍️ Yazma Pratiği</h2><p>{theme}</p></div>"
        "<div class='counter' id='cnt'></div>"
        "<div class='card' id='area'></div>"
        "<div class='nav'>"
        "<button class='nbtn nbtn-prev' id='bp' onclick='prev()'>← Önceki</button>"
        "<button class='nbtn nbtn-next' id='bn' onclick='next()'>Sonraki →</button></div>"
        "<div class='score-final' id='sf'></div>"
        "<script>"
        f"const W={data};"
        "let idx=0,scores=Array(W.length).fill(null),placed=[];"
        "function shuffle(a){for(let i=a.length-1;i>0;i--){let j=Math.floor(Math.random()*(i+1));[a[i],a[j]]=[a[j],a[i]];}return a;}"
        "function render(){"
        "  document.getElementById('cnt').textContent=`${idx+1} / ${W.length}`;"
        "  document.getElementById('bp').disabled=(idx===0);"
        "  document.getElementById('bn').textContent=idx===W.length-1?'Bitir':'Sonraki →';"
        "  const[en,tr]=W[idx];"
        "  placed=[];const letters=shuffle(en.split(''));"
        "  const a=document.getElementById('area');"
        "  a.innerHTML=`<div class='hint'>Türkçesi: <b>${tr}</b></div>`"
        "    +`<div class='clue'>\"${en}\" kelimesini yaz</div>`"
        "    +`<div class='answer-row' id='ans'>${en.split('').map(()=>`<div class='slot'></div>`).join('')}</div>`"
        "    +`<div class='scramble' id='bank'></div>`"
        "    +`<div class='fb' id='fb'></div>`;"
        "  letters.forEach((ch,i)=>{"
        "    const d=document.createElement('div');d.className='letter bank';d.textContent=ch;d.dataset.i=i;"
        "    d.onclick=()=>placeLetter(ch,d);document.getElementById('bank').appendChild(d);"
        "  });"
        "}"
        "function placeLetter(ch,el){"
        "  const slots=document.querySelectorAll('#ans .slot');"
        "  if(placed.length>=slots.length)return;"
        "  slots[placed.length].textContent=ch;"
        "  el.style.visibility='hidden';placed.push({ch,el});"
        "  if(placed.length===slots.length){"
        "    const typed=placed.map(p=>p.ch).join('');"
        "    if(typed===W[idx][0]){scores[idx]=1;document.getElementById('fb').innerHTML='<span style=\"color:#22c55e\">✓ Doğru!</span>';}"
        "    else{scores[idx]=0;document.getElementById('fb').innerHTML=`<span style=\"color:#f87171\">✗ Doğrusu: ${W[idx][0]}</span>`;}"
        "  }"
        "}"
        "function prev(){if(idx>0){idx--;render();}}"
        "function next(){"
        "  if(idx<W.length-1){idx++;render();}"
        "  else{const c=scores.filter(s=>s===1).length;"
        "    document.getElementById('sf').textContent=`Sonuç: ${c}/${W.length} doğru`;}"
        "}"
        "render();"
        "</script></body></html>"
    )


def _week_grammar_html(pairs, structure, theme):
    """Dilbilgisi Pratiği — cümle oluşturma + kalıp alıştırması."""
    import json as _j
    data = _j.dumps([(e, t) for e, t in pairs], ensure_ascii=False)
    struct_js = _j.dumps(structure, ensure_ascii=False)
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'><style>"
        "*{margin:0;padding:0;box-sizing:border-box;}"
        "body{font-family:'Segoe UI',system-ui,sans-serif;background:linear-gradient(135deg,#0B0F19,#94A3B8);min-height:100vh;padding:16px;color:#fff;}"
        ".header{text-align:center;margin-bottom:14px;}"
        ".header h2{font-size:18px;}"
        ".header p{color:#94a3b8;font-size:13px;}"
        ".rule-box{background:linear-gradient(135deg,rgba(37,99,235,.2),rgba(124,58,237,.2));border:1px solid #4f46e5;border-radius:12px;padding:14px;max-width:480px;margin:0 auto 16px;text-align:center;}"
        ".rule-label{font-size:11px;color:#a78bfa;font-weight:600;}"
        ".rule-text{font-size:18px;font-weight:700;color:#e2e8f0;margin-top:4px;}"
        ".exercise{max-width:480px;margin:0 auto;}"
        ".ex-card{background:rgba(255,255,255,.05);border:1px solid rgba(255,255,255,.08);border-radius:12px;padding:16px;margin-bottom:10px;}"
        ".ex-num{font-size:11px;color:#64748b;margin-bottom:4px;}"
        ".ex-prompt{font-size:15px;margin-bottom:10px;}"
        ".ex-prompt .gap{display:inline-block;min-width:80px;border-bottom:2px dashed #fbbf24;text-align:center;color:#fbbf24;font-weight:700;padding:0 6px;cursor:pointer;}"
        ".ex-prompt .gap.done{border-color:#22c55e;color:#86efac;}"
        ".ex-prompt .gap.err{border-color:#ef4444;color:#fca5a5;}"
        ".opts{display:flex;flex-wrap:wrap;gap:6px;}"
        ".opt{padding:5px 12px;border-radius:8px;border:1px solid rgba(255,255,255,.15);background:rgba(255,255,255,.04);cursor:pointer;font-size:13px;transition:all .2s;}"
        ".opt:hover{border-color:#60a5fa;}"
        ".opt.used{opacity:.4;pointer-events:none;}"
        ".result{text-align:center;margin-top:16px;font-size:16px;font-weight:700;}"
        "</style></head><body>"
        f"<div class='header'><h2>📝 Dilbilgisi Pratiği</h2><p>{theme}</p></div>"
        f"<div class='rule-box'><div class='rule-label'>Bu haftanın kalıbı</div>"
        "<div class='rule-text' id='rule'></div></div>"
        "<div class='exercise' id='ex'></div>"
        "<div class='result' id='res'></div>"
        "<script>"
        f"const W={data},STRUCT={struct_js};"
        "document.getElementById('rule').textContent=STRUCT;"
        "function shuffle(a){for(let i=a.length-1;i>0;i--){let j=Math.floor(Math.random()*(i+1));[a[i],a[j]]=[a[j],a[i]];}return a;}"
        "const PATTERNS=['I ___ a {w}.','This is ___.','The ___ is nice.','I like ___.','Do you have ___?','She has a ___.'];"
        "let total=Math.min(W.length,6),correct=0,answered=0;"
        "const picks=shuffle([...W]).slice(0,total);"
        "const ex=document.getElementById('ex');"
        "picks.forEach((p,qi)=>{"
        "  const pat=PATTERNS[qi%PATTERNS.length].replace('{w}',p[0]);"
        "  const d=document.createElement('div');d.className='ex-card';"
        "  const prompt=pat.replace('___',`<span class='gap' id='g${qi}'>?</span>`);"
        "  let opts=[p[0]];let others=W.filter(x=>x[0]!==p[0]).map(x=>x[0]);"
        "  shuffle(others);opts.push(...others.slice(0,2));shuffle(opts);"
        "  d.innerHTML=`<div class='ex-num'>Soru ${qi+1}</div><div class='ex-prompt'>${prompt}</div>`"
        "    +`<div class='opts' id='oo${qi}'>${opts.map(o=>`<span class='opt' onclick=\"pick(${qi},'${o}','${p[0]}',this)\">${o}</span>`).join('')}</div>`;"
        "  ex.appendChild(d);"
        "});"
        "function pick(qi,chosen,ans,el){"
        "  const g=document.getElementById('g'+qi);"
        "  if(g.classList.contains('done')||g.classList.contains('err'))return;"
        "  g.textContent=chosen;"
        "  document.querySelectorAll('#oo'+qi+' .opt').forEach(o=>o.classList.add('used'));"
        "  if(chosen===ans){g.classList.add('done');correct++;}else{g.classList.add('err');}"
        "  answered++;"
        "  if(answered===total)document.getElementById('res').innerHTML="
        "    `<span style='color:${correct===total?\"#22c55e\":\"#f59e0b\"}'>${correct}/${total} doğru!</span>`;"
        "}"
        "</script></body></html>"
    )


def _week_phonics_html(pairs, theme):
    """Sesler Pratiği — harf-ses eşleştirme + başlangıç sesi bulma."""
    import json as _j
    data = _j.dumps([(e, t) for e, t in pairs], ensure_ascii=False)
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'><style>"
        "*{margin:0;padding:0;box-sizing:border-box;}"
        "body{font-family:'Segoe UI',system-ui,sans-serif;background:linear-gradient(135deg,#0B0F19,#94A3B8);min-height:100vh;padding:16px;color:#fff;}"
        ".header{text-align:center;margin-bottom:14px;}"
        ".header h2{font-size:18px;}"
        ".header p{color:#94a3b8;font-size:13px;}"
        ".round{max-width:460px;margin:0 auto;}"
        ".prompt{text-align:center;margin-bottom:14px;}"
        ".prompt-q{font-size:14px;color:#94a3b8;}"
        ".prompt-word{font-size:32px;font-weight:800;color:#60a5fa;margin:4px 0;letter-spacing:4px;}"
        ".prompt-first{color:#fbbf24;}"
        ".prompt-tr{font-size:13px;color:#64748b;}"
        ".letters{display:flex;flex-wrap:wrap;gap:10px;justify-content:center;margin-bottom:14px;}"
        ".lbtn{width:54px;height:54px;border-radius:12px;display:flex;align-items:center;justify-content:center;font-size:24px;font-weight:800;cursor:pointer;border:2px solid rgba(255,255,255,.15);background:rgba(255,255,255,.05);transition:all .2s;}"
        ".lbtn:hover{border-color:#60a5fa;background:rgba(37,99,235,.2);transform:scale(1.1);}"
        ".lbtn.correct{border-color:#22c55e;background:rgba(34,197,94,.2);color:#86efac;animation:pop .3s;}"
        ".lbtn.wrong{border-color:#ef4444;background:rgba(239,68,68,.2);color:#fca5a5;}"
        "@keyframes pop{50%{transform:scale(1.2);}}"
        ".fb{text-align:center;font-size:14px;font-weight:600;min-height:22px;margin-bottom:10px;}"
        ".progress{text-align:center;margin-bottom:10px;}"
        ".dots{display:flex;gap:4px;justify-content:center;}"
        ".dot{width:10px;height:10px;border-radius:50%;background:rgba(255,255,255,.15);}"
        ".dot.done{background:#22c55e;}"
        ".dot.cur{background:#60a5fa;border:2px solid #fff;}"
        ".nbtn{display:block;margin:10px auto;padding:8px 24px;border:none;border-radius:8px;background:#2563eb;color:#fff;font-weight:700;cursor:pointer;font-size:14px;}"
        ".final{text-align:center;font-size:18px;font-weight:700;margin-top:16px;}"
        "</style></head><body>"
        f"<div class='header'><h2>🔤 Sesler Pratiği</h2><p>{theme}</p></div>"
        "<div class='progress'><div class='dots' id='dots'></div></div>"
        "<div class='round' id='round'></div>"
        "<div class='fb' id='fb'></div>"
        "<button class='nbtn' id='nbtn' onclick='nextRound()' style='display:none'>Sonraki →</button>"
        "<div class='final' id='fin'></div>"
        "<script>"
        f"const W={data};"
        "let qi=0,score=0;"
        "function shuffle(a){for(let i=a.length-1;i>0;i--){let j=Math.floor(Math.random()*(i+1));[a[i],a[j]]=[a[j],a[i]];}return a;}"
        "function renderDots(){"
        "  const d=document.getElementById('dots');d.innerHTML='';"
        "  W.forEach((_,i)=>{const s=document.createElement('div');s.className='dot'+(i<qi?' done':(i===qi?' cur':''));d.appendChild(s);});"
        "}"
        "function showRound(){"
        "  if(qi>=W.length){finish();return;}"
        "  renderDots();"
        "  document.getElementById('fb').textContent='';"
        "  document.getElementById('nbtn').style.display='none';"
        "  const[en,tr]=W[qi];"
        "  const first=en[0].toUpperCase();"
        "  const rest=en.slice(1);"
        "  const r=document.getElementById('round');"
        "  r.innerHTML=`<div class='prompt'><div class='prompt-q'>Bu kelimenin başlangıç harfi nedir?</div>`"
        "    +`<div class='prompt-word'><span class='prompt-first'>?</span>${rest}</div>`"
        "    +`<div class='prompt-tr'>${tr}</div></div>`"
        "    +`<div class='letters' id='letters'></div>`;"
        "  let opts=[first];"
        "  const abc='ABCDEFGHIJKLMNOPQRSTUVWXYZ';"
        "  while(opts.length<4){let c=abc[Math.floor(Math.random()*26)];if(!opts.includes(c))opts.push(c);}"
        "  shuffle(opts);"
        "  opts.forEach(ch=>{"
        "    const b=document.createElement('div');b.className='lbtn';b.textContent=ch;"
        "    b.onclick=()=>{"
        "      document.querySelectorAll('.lbtn').forEach(x=>x.style.pointerEvents='none');"
        "      if(ch===first){b.classList.add('correct');score++;"
        "        document.getElementById('fb').innerHTML='<span style=\"color:#22c55e\">✓ Doğru!</span>';"
        "        document.querySelector('.prompt-first').textContent=first;"
        "      }else{b.classList.add('wrong');"
        "        document.getElementById('fb').innerHTML=`<span style=\"color:#f87171\">✗ Doğrusu: ${first}</span>`;"
        "        document.querySelector('.prompt-first').textContent=first;}"
        "      document.getElementById('nbtn').style.display='block';"
        "    };"
        "    document.getElementById('letters').appendChild(b);"
        "  });"
        "}"
        "function nextRound(){qi++;showRound();}"
        "function finish(){"
        "  document.getElementById('round').innerHTML='';"
        "  document.getElementById('nbtn').style.display='none';"
        "  renderDots();"
        "  document.getElementById('fin').innerHTML=`🏆 ${score}/${W.length} doğru!`;"
        "}"
        "showRound();"
        "</script></body></html>"
    )


def _week_listening_html(pairs, theme):
    """Dinleme Pratiği — kelime tanıma + eşleştirme."""
    import json as _j
    data = _j.dumps([(e, t) for e, t in pairs], ensure_ascii=False)
    return (
        "<!DOCTYPE html><html><head><meta charset='utf-8'><style>"
        "*{margin:0;padding:0;box-sizing:border-box;}"
        "body{font-family:'Segoe UI',system-ui,sans-serif;background:linear-gradient(135deg,#0B0F19,#94A3B8);min-height:100vh;padding:16px;color:#fff;}"
        ".header{text-align:center;margin-bottom:14px;}"
        ".header h2{font-size:18px;}"
        ".header p{color:#94a3b8;font-size:13px;}"
        ".stage{max-width:480px;margin:0 auto;}"
        ".q-box{text-align:center;margin-bottom:16px;}"
        ".q-label{font-size:12px;color:#64748b;}"
        ".q-word{font-size:36px;font-weight:800;color:#60a5fa;margin:6px 0;cursor:pointer;transition:all .2s;}"
        ".q-word:hover{transform:scale(1.05);color:#93c5fd;}"
        ".q-hint{font-size:12px;color:#475569;}"
        ".options{display:grid;grid-template-columns:1fr 1fr;gap:10px;}"
        ".opt-card{background:rgba(255,255,255,.05);border:2px solid rgba(255,255,255,.1);border-radius:12px;padding:16px;text-align:center;cursor:pointer;transition:all .3s;}"
        ".opt-card:hover{border-color:#60a5fa;background:rgba(37,99,235,.1);transform:translateY(-2px);}"
        ".opt-card.correct{border-color:#22c55e;background:rgba(34,197,94,.15);}"
        ".opt-card.wrong{border-color:#ef4444;background:rgba(239,68,68,.1);opacity:.5;}"
        ".opt-tr{font-size:16px;font-weight:700;}"
        ".counter{text-align:center;font-size:13px;color:#94a3b8;margin-bottom:10px;}"
        ".fb{text-align:center;font-size:14px;font-weight:600;min-height:22px;margin-top:10px;}"
        ".score-box{display:none;text-align:center;margin-top:20px;}"
        ".score-box.show{display:block;}"
        ".score-big{font-size:48px;font-weight:800;color:#60a5fa;}"
        ".score-msg{font-size:15px;color:#94a3b8;margin-top:4px;}"
        ".rbtn{margin-top:12px;padding:10px 24px;border:none;border-radius:10px;background:#2563eb;color:#fff;font-weight:700;cursor:pointer;font-size:14px;}"
        "</style></head><body>"
        f"<div class='header'><h2>🎧 Dinleme Pratiği</h2><p>{theme}</p></div>"
        "<div class='stage' id='stage'>"
        "<div class='counter' id='cnt'></div>"
        "<div class='q-box'>"
        "<div class='q-label'>Bu kelimeyi dinle ve doğru anlamını seç:</div>"
        "<div class='q-word' id='qw' onclick='speakWord()'>—</div>"
        "<div class='q-hint'>🔊 Tıkla ve sesli oku</div></div>"
        "<div class='options' id='opts'></div>"
        "<div class='fb' id='fb'></div></div>"
        "<div class='score-box' id='sbox'>"
        "<div class='score-big' id='sbig'></div>"
        "<div class='score-msg'>Doğru eşleştirme</div>"
        "<button class='rbtn' onclick='initGame()'>Tekrar Dene</button></div>"
        "<script>"
        f"const W={data};"
        "let qi=0,score=0,order=[];"
        "function shuffle(a){for(let i=a.length-1;i>0;i--){let j=Math.floor(Math.random()*(i+1));[a[i],a[j]]=[a[j],a[i]];}return a;}"
        "function speakWord(){"
        "  if('speechSynthesis' in window){const u=new SpeechSynthesisUtterance(W[order[qi]][0]);u.lang='en-US';u.rate=0.8;speechSynthesis.speak(u);}"
        "}"
        "function initGame(){"
        "  qi=0;score=0;order=shuffle([...Array(W.length).keys()]);"
        "  document.getElementById('sbox').classList.remove('show');"
        "  document.getElementById('stage').style.display='block';"
        "  showQ();"
        "}"
        "function showQ(){"
        "  if(qi>=order.length){endGame();return;}"
        "  document.getElementById('cnt').textContent=`${qi+1} / ${order.length}`;"
        "  document.getElementById('fb').textContent='';"
        "  const p=W[order[qi]];"
        "  document.getElementById('qw').textContent=p[0];"
        "  let opts=[p[1]];let others=W.filter((_,i)=>i!==order[qi]).map(x=>x[1]);"
        "  shuffle(others);opts.push(...others.slice(0,3));shuffle(opts);"
        "  const container=document.getElementById('opts');container.innerHTML='';"
        "  opts.forEach(o=>{"
        "    const d=document.createElement('div');d.className='opt-card';"
        "    d.innerHTML=`<div class='opt-tr'>${o}</div>`;"
        "    d.onclick=()=>{"
        "      container.querySelectorAll('.opt-card').forEach(x=>x.style.pointerEvents='none');"
        "      if(o===p[1]){d.classList.add('correct');score++;document.getElementById('fb').innerHTML='<span style=\"color:#22c55e\">✓ Doğru!</span>';}"
        "      else{d.classList.add('wrong');document.getElementById('fb').innerHTML=`<span style=\"color:#f87171\">✗ Doğrusu: ${p[1]}</span>`;"
        "        container.querySelectorAll('.opt-card').forEach(x=>{if(x.querySelector('.opt-tr').textContent===p[1])x.classList.add('correct');});}"
        "      setTimeout(()=>{qi++;showQ();},1000);"
        "    };"
        "    container.appendChild(d);"
        "  });"
        "  setTimeout(speakWord,300);"
        "}"
        "function endGame(){"
        "  document.getElementById('stage').style.display='none';"
        "  document.getElementById('sbig').textContent=`${score}/${order.length}`;"
        "  document.getElementById('sbox').classList.add('show');"
        "}"
        "initGame();"
        "</script></body></html>"
    )


def _build_week_content_html(wk, tab_type, content_name):
    """Merkezi dinamik içerik builder — oyun, kelime, şarkı, diyalog vb."""
    pairs = _get_week_vocab_pairs(wk)
    if not pairs:
        return ""
    theme_tr = wk.get("theme_tr", wk.get("theme", ""))
    structure = wk.get("structure", "")
    # Oyunlar — game-specific type
    game_type = _GAME_TYPE_MAP.get(content_name)
    if game_type:
        return _build_week_game_html(pairs, theme_tr, game_type)
    # İçerik tipi bazlı
    _type_builders = {
        "cat": lambda: _week_vocabulary_html(pairs, theme_tr),
        "song": lambda: _week_singalong_html(pairs, theme_tr),
        "dlg": lambda: _week_dialogue_html(pairs, structure, theme_tr),
        "reading": lambda: _week_reading_html(pairs, theme_tr),
        "writing": lambda: _week_writing_html(pairs, theme_tr),
        "grammar": lambda: _week_grammar_html(pairs, structure, theme_tr),
        "phonics": lambda: _week_phonics_html(pairs, theme_tr),
        "listening": lambda: _week_listening_html(pairs, theme_tr),
    }
    builder = _type_builders.get(tab_type)
    return builder() if builder else ""


