                f'\U0001f4c6 {_dn}</td>'
                f'<td style="padding:10px 14px;font-size:.85rem;color:#e2e8f0;'
                f'border-bottom:1px solid rgba(124,58,237,.15)">{_a2}</td>'
                f'</tr>'
