            '\U0001f7e3 2. Ders (Skills Lab)</th>'
            '</tr></thead><tbody>'
            '<tr style="border-bottom:1px solid rgba(255,255,255,.05)">'
            '<td style="padding:6px 12px;font-weight:600;color:#cbd5e1">Pazartesi</td>'
            '<td style="padding:6px 12px;text-align:center;color:#6ee7b7">\u2714</td>'
            '<td style="padding:6px 12px;text-align:center;color:#c4b5fd">\u2714</td></tr>'
            '<tr style="border-bottom:1px solid rgba(255,255,255,.05)">'
            '<td style="padding:6px 12px;font-weight:600;color:#cbd5e1">Sal\u0131</td>'
            '<td style="padding:6px 12px;text-align:center;color:#6ee7b7">\u2714</td>'
            '<td style="padding:6px 12px;text-align:center;color:#c4b5fd">\u2714</td></tr>'
            '<tr style="border-bottom:1px solid rgba(255,255,255,.05)">'
            '<td style="padding:6px 12px;font-weight:600;color:#cbd5e1">\u00c7ar\u015famba</td>'
            '<td style="padding:6px 12px;text-align:center;color:#6ee7b7">\u2714</td>'
            '<td style="padding:6px 12px;text-align:center;color:#c4b5fd">\u2714</td></tr>'
            '<tr style="border-bottom:1px solid rgba(255,255,255,.05)">'
