def _detect_btn_type_from_focus(focus_text, slot_text=""):
    """Focus ve slot metninden interaktif etkinlik btn_type'ını tespit eder."""
    _t = (focus_text + " " + slot_text).lower()
    # Öncelik sırasına göre eşleştir
    _FOCUS_BTN_MAP = [
        ("flashcard", "flashcard"), ("kelime tanitimi", "flashcard"), ("vocabulary", "flashcard"),
        ("kelime derinlest", "flashcard"), ("kelime pekist", "flashcard"),
        ("sarki", "song"), ("song", "song"), ("karaoke", "song"),
        ("diyalog", "dialog"), ("dialog", "dialog"),
        ("dinleme", "listening"), ("listening", "listening"),
        ("okuma", "reading"), ("reading", "reading"),
        ("yazma", "writing"), ("writing", "writing"),
        ("gramer", "grammar"), ("grammar", "grammar"), ("dilbilgisi", "grammar"),
        ("konusma", "speaking"), ("speaking", "speaking"), ("konuşma", "speaking"),
        ("telaffuz", "pron_word"), ("pronunciation", "pron_word"), ("telafuz", "pron_word"),
        ("fonik", "phonics"), ("phonics", "phonics"), ("sesler", "phonics"),
        ("heceleme", "spelling"), ("spelling", "spelling"),
        ("islevsel", "functional"), ("functional", "functional"),
        ("strateji", "strategies"), ("strategies", "strategies"),
    ]
    for keyword, btn in _FOCUS_BTN_MAP:
        if keyword in _t:
            return btn
    return None


def _get_curriculum_week_data(grade_key, week_num):
    """Grade key ve hafta numarasından _CURRICULUM week_data döndürür."""
    _level_key = "preschool" if grade_key == "preschool" else f"grade{grade_key}"
    _curriculum = _CURRICULUM.get(_level_key, [])
    for _cw in _curriculum:
        if _cw.get("week") == week_num:
            return _cw, _level_key
    return None, _level_key

