def _generate_daily_homework(grade_key, day_key, hours_data, theme="", week_data=None):
    """Günlük ders planı verilerinden kademe-uyumlu, ünite/konu senkronize ödev üretir.

    Ödevler 2 kategoride döner:
    - Ders İçi: İlgili sekmeye (Listening/Speaking/...) + Coursebook/Practice Book + ünite/konu referansı
    - Ders Dışı: Okuma Kütüphanesi (Graded Readers, MEB Hikaye, EBA) referansı

    week_data: Haftalık plan dict'i (unit, unit_theme, grammar_focus, phase, outcome_codes vb.)
    Returns: list of homework dicts: [{"type":"ders_ici"|"ders_disi", "text":"..."}]
    """
    _hw_list = []

    # Haftalık plan verilerinden senkronizasyon bilgilerini çıkar
    _unit_num = ""
    _unit_theme = theme
    _grammar = ""
    _phase = ""
    _oc_codes = []
    if week_data:
        _unit_num = week_data.get("unit", "")
        _unit_theme = week_data.get("unit_theme") or week_data.get("theme", theme)
        _unit_theme_tr = week_data.get("unit_theme_tr") or week_data.get("theme_tr", "")
        if _unit_theme and _unit_theme_tr:
            _unit_theme = f"{_unit_theme} ({_unit_theme_tr})"
        _grammar = week_data.get("grammar_focus", "")
        _phase = week_data.get("phase", "")
        _oc_codes = week_data.get("outcome_codes", [])

    _unit_label = f"Ünite {_unit_num} — {_unit_theme}" if _unit_num else _unit_theme
    _phase_label = f" [{_phase}]" if _phase else ""
    _grammar_label = f" (Yapı: {_grammar})" if _grammar else ""

    if grade_key == "preschool":
        _day_items = _HW_TEMPLATES_PRESCHOOL.get(day_key, _HW_TEMPLATES_PRESCHOOL.get("mon", []))
        for _item in _day_items:
            # Tema bilgisini ekle
            _text = _item
            if _unit_theme and "haftanın" in _text.lower():
                _text = _text.replace("haftanın kelimelerini", f"'{_unit_theme}' temasının kelimelerini")
                _text = _text.replace("haftanın temasına", f"'{_unit_theme}' temasına")
            _cat = "ders_disi" if "[Ders Dışı]" in _text else "ders_ici"
            _hw_list.append({"type": _cat, "text": _text})
        return _hw_list

    # 1-12. sınıf: focus alanlarından beceri türünü algıla
    _detected_skills = []
    _focus_topics = []  # Her saatin odak konusunu topla
    if isinstance(hours_data, list):
        for _h in hours_data:
            if isinstance(_h, dict):
                _focus_raw = _h.get("focus", "")
                _focus_lower = (_focus_raw + " " + _h.get("slot", "")).lower()
                # Odak konularını topla (ünite/tema ile birleştirmek için)
                if _focus_raw:
                    _focus_topics.append(_focus_raw)
                for _sk in ["listening", "speaking", "reading", "writing", "grammar",
                            "vocabulary", "pronunciation", "spelling", "functional", "strategies"]:
                    if _sk in _focus_lower and _sk not in _detected_skills:
                        _detected_skills.append(_sk)
                _tr_map = {"dinleme": "listening", "konusma": "speaking", "konuşma": "speaking",
                           "okuma": "reading", "yazma": "writing", "dilbilgisi": "grammar",
                           "kelime": "vocabulary", "telaffuz": "pronunciation", "telâffuz": "pronunciation",
                           "yazim": "spelling", "yazım": "spelling"}
                for _trk, _enk in _tr_map.items():
                    if _trk in _focus_lower and _enk not in _detected_skills:
                        _detected_skills.append(_enk)

    # Kademeye göre şablon seç
    try:
        _gnum = int(grade_key)
    except (ValueError, TypeError):
        _gnum = 0

    if 1 <= _gnum <= 4:
        _templates = _HW_TEMPLATES_ILKOKUL
    elif 5 <= _gnum <= 8:
        _templates = _HW_TEMPLATES_ORTAOKUL
    elif 9 <= _gnum <= 12:
        _templates = _HW_TEMPLATES_LISE
    else:
        _templates = _HW_TEMPLATES_ILKOKUL

    # Ders İçi ödevler: algılanan becerilerden + ünite/konu senkronizasyonu
    _ders_ici_count = 0
    if _detected_skills:
        for _sk in _detected_skills:
            _sk_items = _templates.get(_sk, [])
            if isinstance(_sk_items, list):
                for _item in _sk_items:
                    if _ders_ici_count < 3:
                        _cat = "ders_disi" if "[Ders Dışı]" in _item else "ders_ici"
                        _hw_list.append({"type": _cat, "text": _item})
                        if _cat == "ders_ici":
                            _ders_ici_count += 1

    # Ders İçi fallback: beceri algılanamadıysa default
    if _ders_ici_count == 0:
        _def_items = _templates.get("default", [])
        if isinstance(_def_items, list):
            for _item in _def_items[:2]:
                _hw_list.append({"type": "ders_ici", "text": _item})

    # Ders Dışı ödevler: Okuma Kütüphanesi
    _has_ders_disi = any(h["type"] == "ders_disi" for h in _hw_list)
    if not _has_ders_disi:
        if day_key in _DERS_DISI_READING_DAYS:
            _rd = _templates.get("_ders_disi_reading", "")
            if _rd:
                _hw_list.append({"type": "ders_disi", "text": _rd})
        elif day_key in _DERS_DISI_EBA_DAYS:
            _eb = _templates.get("_ders_disi_eba", "")
            if _eb:
                _hw_list.append({"type": "ders_disi", "text": _eb})

    return _hw_list


def _render_homework_card(hw_items, is_preschool=False, week_data=None):
    """Ödev kartını ders içi / ders dışı ayrımıyla render eder.

    hw_items: list of {"type": "ders_ici"|"ders_disi", "text": "..."}
    week_data: Haftalık plan dict'i (ünite/tema/grammar senkronizasyonu için)
    """
    if not hw_items:
        return

    _ders_ici = [h for h in hw_items if isinstance(h, dict) and h.get("type") == "ders_ici"]
    _ders_disi = [h for h in hw_items if isinstance(h, dict) and h.get("type") == "ders_disi"]

    _title = "Günün Ödevi (Veli Etkinliği)" if is_preschool else "Günün Ödevi"

    # Ünite/tema/grammar senkronizasyon bilgi satırı
    _sync_html = ""
    if week_data:
        _sync_parts = []
        _u = week_data.get("unit", "")
        _ut = week_data.get("unit_theme") or week_data.get("theme", "")
        _ut_tr = week_data.get("unit_theme_tr") or week_data.get("theme_tr", "")
        _gf = week_data.get("grammar_focus", "")
        _ph = week_data.get("phase", "")
        if _u and _ut:
            _theme_label = f"{_ut} ({_ut_tr})" if _ut_tr else _ut
            _sync_parts.append(f'<span style="background:#0ea5e915;color:#0369a1;padding:2px 8px;border-radius:6px;font-size:.7rem;font-weight:700;">📘 Ü{_u}: {_theme_label}</span>')
        elif _ut:
            _theme_label = f"{_ut} ({_ut_tr})" if _ut_tr else _ut
            _sync_parts.append(f'<span style="background:#0ea5e915;color:#0369a1;padding:2px 8px;border-radius:6px;font-size:.7rem;font-weight:700;">📘 {_theme_label}</span>')
        if _gf:
            _sync_parts.append(f'<span style="background:#7c3aed15;color:#6d28d9;padding:2px 8px;border-radius:6px;font-size:.7rem;font-weight:700;">📝 {_gf}</span>')
        if _ph:
            _sync_parts.append(f'<span style="background:#ea580c15;color:#c2410c;padding:2px 8px;border-radius:6px;font-size:.7rem;font-weight:700;">📌 {_ph}</span>')
        if _sync_parts:
            _sync_html = (
                f'<div style="margin-bottom:8px;display:flex;flex-wrap:wrap;gap:4px;align-items:center;">'
                f'<span style="font-size:.65rem;font-weight:700;color:#64748b;text-transform:uppercase;'
                f'letter-spacing:.4px;">🔗 Konu Senkronizasyonu:</span> '
                + " ".join(_sync_parts)
                + '</div>'
            )

    # Ders İçi Ödevler
    if _ders_ici:
        _di_html = "".join(
            f'<div style="display:flex;gap:8px;align-items:flex-start;margin-bottom:5px;">'
            f'<span style="background:#059669;color:#fff;padding:1px 6px;border-radius:5px;'
            f'font-size:.65rem;font-weight:700;white-space:nowrap;margin-top:2px;">DERS İÇİ</span>'
            f'<span style="font-size:.82rem;color:#1e3a5f;line-height:1.5;">'
            f'{h["text"].replace("[Ders İçi] ", "").replace("[Ders Ici] ", "").replace("[Ders İçi] ▸ ", "")}</span></div>'
            for h in _ders_ici
        )
        st.markdown(
            f'<div style="background:linear-gradient(135deg,#ecfdf5,#f0fdf4);'
            f'border:2px solid #10b981;border-radius:12px;padding:12px 16px;margin-top:10px;">'
            f'<div style="display:flex;align-items:center;gap:8px;margin-bottom:8px;">'
            f'<span style="font-size:1.1rem;">📗</span>'
            f'<span style="font-weight:800;color:#065f46;font-size:.85rem;'
            f'text-transform:uppercase;letter-spacing:.5px;">{_title} — Ders İçi</span></div>'
            f'{_sync_html}'
            f'{_di_html}</div>',
            unsafe_allow_html=True,
        )

    # Ders Dışı Ödevler (Okuma Kütüphanesi referanslı)
    if _ders_disi:
        _dd_html = "".join(
            f'<div style="display:flex;gap:8px;align-items:flex-start;margin-bottom:5px;">'
            f'<span style="background:#7c3aed;color:#fff;padding:1px 6px;border-radius:5px;'
            f'font-size:.65rem;font-weight:700;white-space:nowrap;margin-top:2px;">DERS DIŞI</span>'
            f'<span style="font-size:.82rem;color:#3b0764;line-height:1.5;">'
            f'{h["text"].replace("[Ders Dışı] ", "").replace("[Ders Disi] ", "").replace("[Ders Dışı] ▸ ", "")}</span></div>'
            for h in _ders_disi
        )
        st.markdown(
            f'<div style="background:linear-gradient(135deg,#f5f3ff,#ede9fe);'
            f'border:2px solid #8b5cf6;border-radius:12px;padding:12px 16px;margin-top:8px;">'
            f'<div style="display:flex;align-items:center;gap:8px;margin-bottom:8px;">'
            f'<span style="font-size:1.1rem;">📚</span>'
            f'<span style="font-weight:800;color:#5b21b6;font-size:.85rem;'
            f'text-transform:uppercase;letter-spacing:.5px;">Ders Dışı Ödev — Okuma Kütüphanesi</span></div>'
            f'{_dd_html}</div>',
            unsafe_allow_html=True,
        )


def _render_interactive_lesson_plan_expander(grade_key, unit_num=None):
    """Tüm kademeler için etkileşimli detaylı ders planı expander'ı."""
    from views.yd_tools import _dispatch_activity_html
    _lp_cache_key = "_yd_wp_outcomes_v4"
    if _lp_cache_key not in st.session_state:
        try:
            with open(_WP_PATH, "r", encoding="utf-8") as _f:
                st.session_state[_lp_cache_key] = _json.load(_f)
        except Exception:
            st.session_state[_lp_cache_key] = {}

    _wp_all = st.session_state[_lp_cache_key]
    _grade_weeks = _wp_all.get(str(grade_key), [])
    if not _grade_weeks:
        return

    _pi = _get_today_plan_info()
    _current_week = _pi["week_num"]

    # Ünite numarasından hafta aralığını bul
    if unit_num is None:
        unit_num = (_current_week - 1) // 4 + 1

    # Bu üniteye ait tüm haftaları topla
    _unit_weeks = []
    for _w in _grade_weeks:
        _w_unit = _w.get("unit")
        if _w_unit is not None:
            if _w_unit == unit_num:
                _unit_weeks.append(_w)
        else:
            # Ünite yoksa (preschool veya haftalık format) — sadece mevcut haftayı göster
            if _w.get("week") == _current_week:
                _unit_weeks.append(_w)

    if not _unit_weeks:
        # Fallback: mevcut haftayı göster
        for _w in _grade_weeks:
            if _w.get("week") == _current_week:
                _unit_weeks = [_w]
                break

    if not _unit_weeks:
        return

    # Tema bilgisi
    _first_w = _unit_weeks[0]
    _theme = _first_w.get("unit_theme") or _first_w.get("theme", "")
    _theme_tr = _first_w.get("unit_theme_tr") or _first_w.get("theme_tr", "")
    _theme_disp = f"{_theme} ({_theme_tr})" if _theme and _theme_tr else (_theme or _theme_tr)
    _grammar = _first_w.get("grammar_focus", "")
    _cefr = ""
    _oc = _first_w.get("outcomes", {})
    if _oc:
        _cefr = _oc.get("cefr", "")

    # Toplam ders saati hesapla
    _total_hours = 0
    _total_days = 0
    for _w in _unit_weeks:
        _days = _w.get("days", {})
        for _dk, _dv in _days.items():
            _total_days += 1
            if isinstance(_dv, dict):
                _total_hours += len(_dv.get("hours", []))
            elif isinstance(_dv, list):
                _total_hours += len(_dv)

    # Hafta listesi etiketi
    _week_nums = sorted(set(_w.get("week", 0) for _w in _unit_weeks))
    _weeks_label = ", ".join(str(wn) for wn in _week_nums)
    if len(_week_nums) > 1:
        _weeks_label = f"Hafta {_week_nums[0]}-{_week_nums[-1]}"
    else:
        _weeks_label = f"Hafta {_week_nums[0]}"

    # İsim belirleme
    if grade_key == "preschool":
        _level_name = "Okul Öncesi"
    else:
        _level_name = f"{grade_key}. Sınıf"

    _exp_label = (
        f"📋 {_level_name} Detaylı Ders Planı: {_theme_disp} "
        f"({_weeks_label} | {_total_hours} ders saati | {_total_days} gün"
        f"{f' | {_cefr}' if _cefr else ''}"
        f"{f' | 📝 {_grammar}' if _grammar else ''})"
    )

    with st.expander(_exp_label, expanded=False):
        # Üst bilgi kartı
        _info_parts = []
        if _theme_disp:
            _info_parts.append(f'<span style="font-weight:700;color:#0ea5e9;">🎯 Tema:</span> {_theme_disp}')
        if _grammar:
            _info_parts.append(f'<span style="font-weight:700;color:#7c3aed;">📝 Dilbilgisi:</span> {_grammar}')
        if _cefr:
            _info_parts.append(f'<span style="font-weight:700;color:#059669;">🏷️ CEFR:</span> {_cefr}')
        _info_parts.append(f'<span style="font-weight:700;color:#ea580c;">⏱️ Toplam:</span> {_total_hours} ders saati / {_total_days} gün')
        st.markdown(
            f'<div style="background:linear-gradient(135deg,#f0f9ff,#ede9fe);'
            f'border:1px solid #c7d2fe;border-radius:12px;padding:14px 18px;margin-bottom:14px;">'
            + " &nbsp;|&nbsp; ".join(
                f'<span style="font-size:.82rem;">{p}</span>' for p in _info_parts
            )
            + '</div>',
            unsafe_allow_html=True,
        )

        # Her hafta için günleri göster
        for _wi, _w in enumerate(_unit_weeks):
            _wnum = _w.get("week", 0)
            _w_theme = _w.get("unit_theme") or _w.get("theme", "")
            _w_phase = _w.get("phase", "")
            _w_phase_en = _w.get("phase_en", "")
            _phase_lbl = f" — {_w_phase}" if _w_phase else ""
            if _w_phase_en:
                _phase_lbl = f" — {_w_phase} ({_w_phase_en})" if _w_phase else f" — {_w_phase_en}"

            if len(_unit_weeks) > 1:
                st.markdown(
                    f'<div style="background:linear-gradient(135deg,#94A3B8,#334155);color:#fff;'
                    f'padding:10px 16px;border-radius:10px;margin:10px 0 8px 0;font-weight:700;font-size:.9rem;">'
                    f'📅 Hafta {_wnum}/36{_phase_lbl}</div>',
                    unsafe_allow_html=True,
                )

            _days = _w.get("days", {})
            for _dk in ["mon", "tue", "wed", "thu", "fri"]:
                _dv = _days.get(_dk)
                if not _dv:
                    continue

                _day_icon = _LP_DAY_ICONS.get(_dk, "⚪")
                _day_name = _LP_DAY_NAMES.get(_dk, _dk)
                _is_today = (_dk == _pi.get("day_key") and _wnum == _current_week)

                if isinstance(_dv, list):
                    # Preschool basit liste formatı
                    _act_count = len(_dv)
                    _today_badge = ' 🔥 BUGÜN' if _is_today else ''
                    with st.expander(f"{_day_icon} {_day_name} — {_act_count} etkinlik{_today_badge}", expanded=_is_today,
                    ):
                        for _ai, _act in enumerate(_dv):
                            _badge_color = ["#059669", "#7c3aed", "#2563eb", "#ea580c", "#dc2626"][_ai % 5]
                            st.markdown(
                                f'<div style="display:flex;gap:10px;align-items:flex-start;'
                                f'padding:10px 14px;margin:4px 0;background:#111827;'
                                f'border:1px solid #e2e8f0;border-left:4px solid {_badge_color};'
                                f'border-radius:10px;">'
                                f'<div style="background:{_badge_color};color:#fff;padding:2px 10px;'
                                f'border-radius:8px;font-size:.75rem;font-weight:700;white-space:nowrap;">'
                                f'{_ai + 1}</div>'
                                f'<div style="font-size:.85rem;color:#334155;line-height:1.5;">{_act}</div>'
                                f'</div>',
                                unsafe_allow_html=True,
                            )
                        # ── Ödev Satırı (Preschool) ──
                        # JSON'da homework_by_day varsa onu kullan
                        _pk_hw_json = _w.get("homework_by_day", {}).get(_dk)
                        if _pk_hw_json:
                            _hw_items = [{"type": "ders_disi" if ("[Ders Disi]" in h or "[Ders Dışı]" in h) else "ders_ici", "text": h} for h in _pk_hw_json]
                        else:
                            _hw_items = _generate_daily_homework(grade_key, _dk, _dv, _theme_disp, week_data=_w)
                        _render_homework_card(_hw_items, is_preschool=True, week_data=_w)

                elif isinstance(_dv, dict):
                    # Detaylı saat formatı (1-12. sınıf)
                    _hours = _dv.get("hours", [])
                    if not _hours:
                        continue
                    _hour_count = len(_hours)
                    _slots_summary = " → ".join(
                        h.get("slot", "")[:20] for h in _hours[:3]
                    )
                    _today_badge = ' 🔥 BUGÜN' if _is_today else ''
                    with st.expander(f"{_day_icon} {_day_name} — {_hour_count} ders saati | {_slots_summary}{_today_badge}", expanded=_is_today,
                    ):
                        for _hi, _h in enumerate(_hours):
                            _slot = _h.get("slot", "DERS")
                            _sc = _h.get("slot_color", "green")
                            _accent, _bg = _LP_SLOT_COLORS.get(_sc, ("#64748b", "#111827"))
                            _focus = _h.get("focus", "")
                            _dur = _h.get("duration", "40 dk")
                            _acts = _h.get("activity", [])
                            _mats = _h.get("materials", [])
                            _instr = _h.get("instruments", [])
                            _tips = _h.get("tips", "")
                            _hour_num = _h.get("hour", _hi + 1)

                            # Kullanılacak sekme badge'leri tespit et
                            _focus_lower = (_focus + " " + _slot).lower()
                            _TAB_DETECT = {
                                "listening": ("🎧", "Listening", "#7c3aed"),
                                "speaking": ("🗣️", "Speaking", "#059669"),
                                "reading": ("📖", "Reading", "#2563eb"),
                                "writing": ("✍️", "Writing", "#dc2626"),
                                "grammar": ("📝", "Grammar", "#ea580c"),
                                "vocabulary": ("📚", "Vocabulary", "#0891b2"),
                                "pronunciation": ("🔤", "Pronunciation", "#7c3aed"),
                                "spelling": ("✏️", "Spelling", "#64748b"),
                                "functional": ("💬", "Functional", "#0d9488"),
                            }
                            _TR_DETECT = {"dinleme": "listening", "konusma": "speaking", "konuşma": "speaking",
                                          "okuma": "reading", "yazma": "writing", "dilbilgisi": "grammar",
                                          "kelime": "vocabulary", "telaffuz": "pronunciation", "yazim": "spelling", "yazım": "spelling"}
                            _detected_tabs = []
                            for _tk, _tv in _TAB_DETECT.items():
                                if _tk in _focus_lower:
                                    _detected_tabs.append(_tv)
                            for _trk2, _enk2 in _TR_DETECT.items():
                                if _trk2 in _focus_lower and _TAB_DETECT[_enk2] not in _detected_tabs:
                                    _detected_tabs.append(_TAB_DETECT[_enk2])
                            # Materyal/etkinlik metinlerinden destek sekmesi algılama
                            _mat_lower = " ".join(m.lower() for m in _mats)
                            _act_lower = " ".join(a.lower() for a in _acts) if _acts else ""
                            _all_text = _mat_lower + " " + _act_lower + " " + _focus_lower
                            # Destek sekmeleri
                            _SUPPORT_DETECT = [
                                ("coursebook", "📕", "Coursebook", "#b45400"),
                                ("practice book", "📘", "Practice Book", "#1e40af"),
                                ("practice plus", "📘", "Practice Plus", "#1e40af"),
                                ("performance book", "📘", "Performance Book", "#1e40af"),
                                ("grammar & words lab", "🎓", "Grammar & Words Lab", "#6d28d9"),
                                ("grammar & academic", "🎓", "Grammar & Academic Words", "#6d28d9"),
                                ("reading adventures", "📖", "Reading Adventures", "#0369a1"),
                                ("reading & checkpoint", "📖", "Reading & Checkpoint", "#0369a1"),
                                ("read, write & prepare", "📖", "Read, Write & Prepare", "#0369a1"),
                                ("words & sounds", "🔊", "Words & Sounds", "#7c3aed"),
                                ("learning path", "🗺️", "Learning Path", "#059669"),
                            ]
                            _support_badges = []
                            for _sd_key, _sd_icon, _sd_name, _sd_color in _SUPPORT_DETECT:
                                if _sd_key in _all_text or _sd_key.replace(" ", "") in _all_text.replace(" ", ""):
                                    _support_badges.append((_sd_icon, _sd_name, _sd_color))
                            # Coursebook fallback: kitap/ders kitabı referansı varsa
                            if not any(sb[1].startswith("Coursebook") for sb in _support_badges):
                                if any(x in _all_text for x in ["ders kitab", "kitap"]):
                                    _support_badges.append(("📕", "Coursebook", "#b45400"))

                            _tab_badges_html = ""
                            if _detected_tabs or _support_badges:
                                _tb = "".join(
                                    f'<span style="background:{t[2]}15;color:{t[2]};border:1px solid {t[2]}33;'
                                    f'padding:2px 8px;border-radius:6px;font-size:.68rem;font-weight:700;'
                                    f'display:inline-flex;align-items:center;gap:3px;margin:2px;">'
                                    f'{t[0]} {t[1]}</span>'
                                    for t in _detected_tabs
                                )
                                # Destek sekmesi badge'leri
                                _tb += "".join(
                                    f'<span style="background:{sb[2]}15;color:{sb[2]};border:1px solid {sb[2]}33;'
                                    f'padding:2px 8px;border-radius:6px;font-size:.68rem;font-weight:700;'
                                    f'display:inline-flex;align-items:center;gap:3px;margin:2px;">'
                                    f'{sb[0]} {sb[1]}</span>'
                                    for sb in _support_badges
                                )
                                _tab_badges_html = (
                                    f'<div style="margin-bottom:8px;">'
                                    f'<span style="font-size:.65rem;font-weight:700;color:#64748b;'
                                    f'text-transform:uppercase;letter-spacing:.5px;margin-right:6px;">'
                                    f'📌 Kullanılacak Sekmeler:</span>{_tb}</div>'
                                )

                            # Saat başlığı
                            st.markdown(
                                f'<div style="background:{_bg};border:1px solid {_accent}22;'
                                f'border-left:5px solid {_accent};border-radius:12px;'
                                f'padding:14px 18px;margin:8px 0;">'
                                # Üst satır: slot + süre + odak
                                f'<div style="display:flex;justify-content:space-between;align-items:center;'
                                f'margin-bottom:10px;flex-wrap:wrap;gap:6px;">'
                                f'<div style="display:flex;align-items:center;gap:8px;">'
                                f'<span style="background:{_accent};color:#fff;padding:3px 10px;'
                                f'border-radius:8px;font-size:.75rem;font-weight:800;">'
                                f'{_hour_num}. Saat</span>'
                                f'<span style="background:{_accent}18;color:{_accent};padding:3px 10px;'
                                f'border-radius:8px;font-size:.72rem;font-weight:700;">'
                                f'{_slot}</span></div>'
                                f'<span style="font-size:.72rem;color:#64748b;font-weight:600;">'
                                f'⏱️ {_dur}</span></div>'
                                # Odak
                                f'<div style="font-size:.84rem;font-weight:700;color:{_accent};'
                                f'margin-bottom:10px;line-height:1.4;">🎯 {_focus}</div>'
                                # Sekme badge'leri
                                f'{_tab_badges_html}',
                                unsafe_allow_html=True,
                            )

                            # Etkinlikler
                            if _acts:
                                _act_html = ""
                                for _ai, _a in enumerate(_acts):
                                    _step_colors = ["#059669", "#7c3aed", "#2563eb", "#ea580c", "#dc2626"]
                                    _sc2 = _step_colors[_ai % len(_step_colors)]
                                    _act_html += (
                                        f'<div style="display:flex;gap:8px;align-items:flex-start;'
                                        f'margin-bottom:6px;">'
                                        f'<span style="background:{_sc2};color:#fff;padding:1px 7px;'
                                        f'border-radius:6px;font-size:.68rem;font-weight:700;'
                                        f'white-space:nowrap;margin-top:2px;">{_ai + 1}</span>'
                                        f'<span style="font-size:.82rem;color:#334155;line-height:1.5;">'
                                        f'{_a}</span></div>'
                                    )
                                st.markdown(
                                    f'<div style="margin-bottom:10px;">'
                                    f'<div style="font-size:.72rem;font-weight:700;color:#64748b;'
                                    f'text-transform:uppercase;letter-spacing:.5px;margin-bottom:6px;">'
                                    f'📌 Etkinlik Akışı</div>{_act_html}</div>',
                                    unsafe_allow_html=True,
                                )

                            # Materyaller + Araçlar + İpuçları
                            _bottom_cards = ""
                            if _mats:
                                _mat_items = "".join(
                                    f'<span style="background:#dbeafe;color:#1e40af;padding:2px 8px;'
                                    f'border-radius:6px;font-size:.7rem;margin:2px;display:inline-block;">'
                                    f'📦 {m}</span>' for m in _mats
                                )
                                _bottom_cards += (
                                    f'<div style="margin-bottom:6px;">'
                                    f'<span style="font-size:.7rem;font-weight:700;color:#1e40af;">'
                                    f'Materyaller:</span> {_mat_items}</div>'
                                )
                            if _instr:
                                _instr_items = "".join(
                                    f'<span style="background:#fce7f3;color:#be185d;padding:2px 8px;'
                                    f'border-radius:6px;font-size:.7rem;margin:2px;display:inline-block;">'
                                    f'🔧 {i}</span>' for i in _instr
                                )
                                _bottom_cards += (
                                    f'<div style="margin-bottom:6px;">'
                                    f'<span style="font-size:.7rem;font-weight:700;color:#be185d;">'
                                    f'Araçlar:</span> {_instr_items}</div>'
                                )
                            if _tips:
                                _bottom_cards += (
                                    f'<div style="background:#fffbeb;border:1px solid #fde68a;'
                                    f'border-radius:8px;padding:8px 12px;margin-top:6px;">'
                                    f'<span style="font-size:.72rem;font-weight:700;color:#92400e;">'
                                    f'💡 İpucu:</span> '
                                    f'<span style="font-size:.78rem;color:#78350f;">{_tips}</span></div>'
                                )

                            if _bottom_cards:
                                st.markdown(
                                    f'<div style="border-top:1px solid {_accent}15;padding-top:8px;">'
                                    f'{_bottom_cards}</div>',
                                    unsafe_allow_html=True,
                                )

                            # ── İnteraktif Etkinlik Butonu (gömülü) ──
                            _btn_type_detected = _detect_btn_type_from_focus(_focus, _slot)
                            if _btn_type_detected:
                                _cur_week_data, _cur_level_key = _get_curriculum_week_data(
                                    grade_key, _wnum)
                                if _cur_week_data:
                                    _act_key = f"_ilp_{grade_key}_{_wnum}_{_dk}_{_hour_num}"
                                    _btn_labels_map = {
                                        "flashcard": "📚 Kelime Kartları",
                                        "song": "🎵 Şarkı Karaoke",
                                        "dialog": "💬 Diyalog Pratiği",
                                        "listening": "🎧 Dinleme Etkinliği",
                                        "reading": "📖 Okuma Etkinliği",
                                        "writing": "✍️ Yazma Etkinliği",
                                        "grammar": "📝 Dilbilgisi Etkinliği",
                                        "speaking": "🗣️ Konuşma Pratiği",
                                        "pron_word": "🎤 Telaffuz Pratiği",
                                        "pron_phrase": "💬 Cümle Telaffuzu",
                                        "phonics": "🔤 Fonik/Sesler",
                                        "spelling": "✏️ Heceleme",
                                        "functional": "💬 İşlevsel Dil",
                                        "strategies": "🤝 İletişim Stratejileri",
                                    }
                                    _btn_lbl = _btn_labels_map.get(
                                        _btn_type_detected, f"▶️ {_btn_type_detected.title()}")
                                    with st.expander(f"▶️ {_btn_lbl} — Tıkla & Çalış", expanded=False,
                                    ):
                                        _act_html_result = _dispatch_activity_html(
                                            _btn_type_detected, _cur_week_data, _cur_level_key)
                                        if _act_html_result:
                                            _emb_h = 500 if _btn_type_detected == "worksheet" else 400
                                            st.components.v1.html(
                                                _act_html_result, height=_emb_h, scrolling=True)
                                        else:
                                            st.info("Bu etkinlik için içerik hazırlanamadı.")

                            # Kartı kapat
                            st.markdown('</div>', unsafe_allow_html=True)

                        # ── Ödev Satırı (1-12. Sınıf) ──
                        _hw_items = _generate_daily_homework(grade_key, _dk, _hours, _theme_disp, week_data=_w)
                        # JSON'da homework alanı varsa onu öncelikle kullan
                        _hw_from_json = _dv.get("homework") or _dv.get("odev")
                        if _hw_from_json:
                            if isinstance(_hw_from_json, str):
                                _hw_type = "ders_disi" if "[Ders Disi]" in _hw_from_json or "[Ders Dışı]" in _hw_from_json else "ders_ici"
                                _hw_items = [{"type": _hw_type, "text": _hw_from_json}]
                            elif isinstance(_hw_from_json, list):
                                _hw_items = []
                                for _hjson in _hw_from_json:
                                    if isinstance(_hjson, str):
                                        _hjt = "ders_disi" if "[Ders Disi]" in _hjson or "[Ders Dışı]" in _hjson else "ders_ici"
                                        _hw_items.append({"type": _hjt, "text": _hjson})
                                    else:
                                        _hw_items.append(_hjson)
                        _render_homework_card(_hw_items, is_preschool=False, week_data=_w)


# ── Basılı Yardımcı Kitap (Çevrimdışı Ödev) ─────────────────────────────────

def _generate_preschool_workbook_pdf(unit_num: int) -> bytes:
    """Okul oncesi icin YAZISIZ aktivite kitabi. Boyama, eslestirme, cizgi, daire icine alma."""
    from reportlab.lib.pagesizes import A4
    from reportlab.lib.units import cm, mm
    from reportlab.lib.colors import HexColor, white, black, Color
    from reportlab.pdfgen import canvas
    import io, math, random as _rnd

    _rnd.seed(unit_num * 777)
    _curriculum = _CURRICULUM.get("preschool", [])

    # Unite verisi (hafta gruplari)
    _unit_map = {1: (1, 4), 2: (5, 8), 3: (9, 12), 4: (13, 16), 5: (17, 20),
                 6: (21, 24), 7: (25, 27), 8: (28, 30), 9: (31, 33), 10: (34, 36)}
    _ws, _we = _unit_map.get(unit_num, (1, 4))
    _unit_weeks = [w for w in _curriculum if _ws <= w.get("week", 0) <= _we]
    if not _unit_weeks:
        _unit_weeks = _curriculum[:4]

    _theme = _unit_weeks[0].get("theme", "") if _unit_weeks else f"Unit {unit_num}"
    _theme_tr = _unit_weeks[0].get("theme_tr", "") if _unit_weeks else ""
    _all_vocab = []
    for wk in _unit_weeks:
        _all_vocab.extend(wk.get("vocab", []))
    _all_vocab = [v for v in dict.fromkeys(_all_vocab) if v and "all" not in v.lower()]

    # Emoji/gorsel esleme
    _EMOJI_MAP = {
        "hello": "\U0001F44B", "hi": "\U0001F44B", "bye": "\U0001F44B", "friend": "\U0001F46B",
        "name": "\U0001F4DB", "head": "\U0001F9D1", "eyes": "\U0001F440", "nose": "\U0001F443",
        "mouth": "\U0001F444", "hands": "\U0001F91A", "mummy": "\U0001F469", "daddy": "\U0001F468",
        "baby": "\U0001F476", "sister": "\U0001F467", "brother": "\U0001F466",
        "circle": "\U0001F534", "square": "\U0001F7E7", "triangle": "\U0001F53A",
        "star": "\u2B50", "heart": "\u2764\uFE0F",
        "red": "\U0001F534", "blue": "\U0001F535", "yellow": "\U0001F7E1",
        "green": "\U0001F7E2", "orange": "\U0001F7E0", "pink": "\U0001F7E3",
        "purple": "\U0001F7E3", "brown": "\U0001F7E4", "black": "\u26AB", "white": "\u26AA",
        "big": "\U0001F418", "small": "\U0001F401", "tall": "\U0001F332", "short": "\U0001F33F",
        "apple": "\U0001F34E", "banana": "\U0001F34C", "grape": "\U0001F347",
        "strawberry": "\U0001F353", "one": "1\uFE0F\u20E3", "two": "2\uFE0F\u20E3",
        "three": "3\uFE0F\u20E3", "four": "4\uFE0F\u20E3", "five": "5\uFE0F\u20E3",
        "six": "6\uFE0F\u20E3", "seven": "7\uFE0F\u20E3", "eight": "8\uFE0F\u20E3",
        "nine": "9\uFE0F\u20E3", "ten": "\U0001F51F",
        "happy": "\U0001F600", "sad": "\U0001F622", "angry": "\U0001F620",
        "scared": "\U0001F628", "sleepy": "\U0001F634",
        "sun": "\u2600\uFE0F", "rain": "\U0001F327\uFE0F", "cloud": "\u2601\uFE0F",
        "wind": "\U0001F32C\uFE0F", "snow": "\u2744\uFE0F",
        "shirt": "\U0001F455", "shoes": "\U0001F45F", "hat": "\U0001F3A9",
        "coat": "\U0001F9E5", "socks": "\U0001F9E6",
        "milk": "\U0001F95B", "water": "\U0001F4A7", "bread": "\U0001F35E",
        "cheese": "\U0001F9C0", "cake": "\U0001F382",
        "run": "\U0001F3C3", "jump": "\U0001F938", "clap": "\U0001F44F",
        "dance": "\U0001F483", "sit": "\U0001FA91",
        "ball": "\u26BD", "doll": "\U0001F9F8", "car": "\U0001F697",
        "teddy": "\U0001F9F8", "puzzle": "\U0001F9E9",
        "party": "\U0001F389", "balloon": "\U0001F388", "fun": "\U0001F973",
        "door": "\U0001F6AA", "window": "\U0001FA9F", "bed": "\U0001F6CF\uFE0F",
        "table": "\U0001FA91", "chair": "\U0001FA91",
        "cow": "\U0001F404", "sheep": "\U0001F411", "horse": "\U0001F40E",
        "chicken": "\U0001F414", "pig": "\U0001F437",
        "cat": "\U0001F431", "dog": "\U0001F436", "bird": "\U0001F426",
        "fish": "\U0001F41F", "rabbit": "\U0001F430",
        "flower": "\U0001F33B", "tree": "\U0001F333", "grass": "\U0001F33F",
        "butterfly": "\U0001F98B", "bee": "\U0001F41D",
        "bus": "\U0001F68C", "bike": "\U0001F6B2", "train": "\U0001F682", "plane": "\u2708\uFE0F",
        "spring": "\U0001F33C", "summer": "\u2600\uFE0F", "autumn": "\U0001F342", "winter": "\u2744\uFE0F",
        "sand": "\U0001F3D6\uFE0F", "sea": "\U0001F30A", "shell": "\U0001F41A",
        "bucket": "\U0001FAA3", "sunglasses": "\U0001F576\uFE0F",
        "doctor": "\U0001F469\u200D\u2695\uFE0F", "teacher": "\U0001F469\u200D\U0001F3EB",
        "police": "\U0001F46E", "fire fighter": "\U0001F468\u200D\U0001F692", "cook": "\U0001F468\u200D\U0001F373",
        "football": "\u26BD", "swimming": "\U0001F3CA", "running": "\U0001F3C3",
        "jumping": "\U0001F938", "dancing": "\U0001F483",
        "goodbye": "\U0001F44B", "favourite": "\u2B50", "love": "\u2764\uFE0F",
        "show": "\U0001F3AD", "sing": "\U0001F3A4",
    }

    buf = io.BytesIO()
    w, h = A4
    c = canvas.Canvas(buf, pagesize=A4)

    _PRIMARY = HexColor("#1e40af")
    _SECONDARY = HexColor("#7c3aed")
    _ACCENT = HexColor("#059669")
    _WARM = HexColor("#ea580c")
    _PINK = HexColor("#ec4899")
    _BG_LIGHT = HexColor("#f0f9ff")
    _BG_CREAM = HexColor("#fffbeb")
    _BG_GREEN = HexColor("#ecfdf5")
    _BG_PURPLE = HexColor("#f5f3ff")
    _BG_PINK = HexColor("#fdf2f8")
    _GRAY = HexColor("#64748b")
    _DARK = HexColor("#0B0F19")

    def _rrect(x, y, rw, rh, r, fill=None, stroke=None, sw=1):
        c.saveState()
        if fill: c.setFillColor(fill)
        if stroke: c.setStrokeColor(stroke); c.setLineWidth(sw)
        p = c.beginPath(); p.roundRect(x, y, rw, rh, r)
        if fill and stroke: c.drawPath(p, fill=1, stroke=1)
        elif fill: c.drawPath(p, fill=1, stroke=0)
        elif stroke: c.drawPath(p, fill=0, stroke=1)
        c.restoreState()

    def _draw_cartoon_face(x, y, size, color, expression="happy"):
        c.saveState()
        c.setFillColor(HexColor("#fde68a")); c.setStrokeColor(color); c.setLineWidth(2)
        c.circle(x, y, size, fill=1, stroke=1)
        c.setFillColor(_DARK)
        ey = y + size * 0.15
        c.circle(x - size * 0.25, ey, size * 0.08, fill=1, stroke=0)
        c.circle(x + size * 0.25, ey, size * 0.08, fill=1, stroke=0)
        c.setStrokeColor(_DARK); c.setLineWidth(1.5)
        if expression == "happy":
            c.arc(x - size * 0.3, y - size * 0.45, x + size * 0.3, y - size * 0.05, 200, 140)
        elif expression == "sad":
            c.arc(x - size * 0.3, y - size * 0.5, x + size * 0.3, y - size * 0.15, 20, 140)
        elif expression == "surprised":
            c.circle(x, y - size * 0.25, size * 0.12, fill=0, stroke=1)
        c.restoreState()

    def _draw_full_character(x, y, scale, gender="boy", shirt_color=None, expression="happy"):
        s = scale
        c.saveState()
        _skin = HexColor("#fde68a")
        _shirt = shirt_color or (HexColor("#3b82f6") if gender == "boy" else HexColor("#ec4899"))
        _pants = HexColor("#1e3a5f") if gender != "girl" else HexColor("#7c3aed")
        # Bacaklar
        c.setFillColor(_pants)
        c.rect(x - 8*s, y, 6*s, 20*s, fill=1, stroke=0)
        c.rect(x + 2*s, y, 6*s, 20*s, fill=1, stroke=0)
        # Ayaklar
        c.setFillColor(HexColor("#94A3B8"))
        c.roundRect(x - 10*s, y - 4*s, 10*s, 6*s, 3*s, fill=1, stroke=0)
        c.roundRect(x + 0*s, y - 4*s, 10*s, 6*s, 3*s, fill=1, stroke=0)
        # Govde
        c.setFillColor(_shirt)
        c.roundRect(x - 12*s, y + 18*s, 24*s, 28*s, 5*s, fill=1, stroke=0)
        # Kollar
        c.roundRect(x - 18*s, y + 28*s, 8*s, 16*s, 3*s, fill=1, stroke=0)
        c.roundRect(x + 10*s, y + 28*s, 8*s, 16*s, 3*s, fill=1, stroke=0)
        c.setFillColor(_skin)
        c.circle(x - 14*s, y + 27*s, 4*s, fill=1, stroke=0)
        c.circle(x + 14*s, y + 27*s, 4*s, fill=1, stroke=0)
        # Boyun + kafa
        c.setFillColor(_skin)
        c.rect(x - 4*s, y + 44*s, 8*s, 6*s, fill=1, stroke=0)
        c.setStrokeColor(HexColor("#d4a574")); c.setLineWidth(1.5)
        head_y = y + 58*s; head_r = 14*s
        c.circle(x, head_y, head_r, fill=1, stroke=1)
        # Sac
        _hair = HexColor("#4a2c0a") if gender == "boy" else HexColor("#8B4513")
        c.setFillColor(_hair)
        p = c.beginPath()
        p.arc(x - head_r - 1, head_y - head_r + 2*s, x + head_r + 1, head_y + head_r + 4*s, 0, 180)
        c.drawPath(p, fill=1, stroke=0)
        if gender == "girl":
            c.roundRect(x - head_r - 2*s, head_y - head_r, 6*s, -20*s, 3*s, fill=1, stroke=0)
            c.roundRect(x + head_r - 4*s, head_y - head_r, 6*s, -20*s, 3*s, fill=1, stroke=0)
            c.setFillColor(HexColor("#f472b6"))
            c.circle(x + head_r - 2*s, head_y + head_r - 2*s, 3*s, fill=1, stroke=0)
        # Gozler
        c.setFillColor(white)
        c.circle(x - 5*s, head_y + 2*s, 3.5*s, fill=1, stroke=0)
        c.circle(x + 5*s, head_y + 2*s, 3.5*s, fill=1, stroke=0)
        c.setFillColor(_DARK)
        c.circle(x - 5*s, head_y + 2*s, 2*s, fill=1, stroke=0)
        c.circle(x + 5*s, head_y + 2*s, 2*s, fill=1, stroke=0)
        c.setFillColor(white)
        c.circle(x - 4*s, head_y + 3*s, 0.8*s, fill=1, stroke=0)
        c.circle(x + 6*s, head_y + 3*s, 0.8*s, fill=1, stroke=0)
        # Yanaklar
        c.setFillColor(Color(1, 0.6, 0.6, 0.3))
        c.circle(x - 9*s, head_y - 2*s, 3*s, fill=1, stroke=0)
        c.circle(x + 9*s, head_y - 2*s, 3*s, fill=1, stroke=0)
        # Agiz
        c.setStrokeColor(_DARK); c.setLineWidth(1.2)
        if expression == "happy":
            c.arc(x - 5*s, head_y - 10*s, x + 5*s, head_y - 2*s, 200, 140)
        c.restoreState()

    def _draw_animal(x, y, scale, animal="cat"):
        c.saveState(); s = scale
        if animal == "cat":
            c.setFillColor(HexColor("#fb923c"))
            c.circle(x, y + 10*s, 12*s, fill=1, stroke=0)
            c.circle(x, y + 26*s, 10*s, fill=1, stroke=0)
            # Kulaklar
            p1 = c.beginPath(); p1.moveTo(x-8*s,y+32*s); p1.lineTo(x-4*s,y+42*s); p1.lineTo(x,y+32*s); p1.close()
            c.drawPath(p1, fill=1, stroke=0)
            p2 = c.beginPath(); p2.moveTo(x,y+32*s); p2.lineTo(x+4*s,y+42*s); p2.lineTo(x+8*s,y+32*s); p2.close()
            c.drawPath(p2, fill=1, stroke=0)
            c.setFillColor(white)
            c.circle(x-4*s,y+28*s,3*s,fill=1,stroke=0); c.circle(x+4*s,y+28*s,3*s,fill=1,stroke=0)
            c.setFillColor(HexColor("#065f46"))
            c.circle(x-4*s,y+28*s,1.8*s,fill=1,stroke=0); c.circle(x+4*s,y+28*s,1.8*s,fill=1,stroke=0)
            c.setFillColor(HexColor("#f472b6"))
            p3=c.beginPath(); p3.moveTo(x-1.5*s,y+24*s); p3.lineTo(x,y+22*s); p3.lineTo(x+1.5*s,y+24*s); p3.close()
            c.drawPath(p3, fill=1, stroke=0)
            c.setStrokeColor(HexColor("#9ca3af")); c.setLineWidth(0.6)
            c.line(x-10*s,y+24*s,x-3*s,y+23*s); c.line(x+3*s,y+23*s,x+10*s,y+24*s)
        elif animal == "dog":
            c.setFillColor(HexColor("#a16207"))
            c.ellipse(x-12*s,y,x+12*s,y+20*s,fill=1,stroke=0)
            c.circle(x,y+26*s,10*s,fill=1,stroke=0)
            c.setFillColor(HexColor("#78350f"))
            c.ellipse(x-14*s,y+20*s,x-6*s,y+34*s,fill=1,stroke=0)
            c.ellipse(x+6*s,y+20*s,x+14*s,y+34*s,fill=1,stroke=0)
            c.setFillColor(white)
            c.circle(x-4*s,y+28*s,3.2*s,fill=1,stroke=0); c.circle(x+4*s,y+28*s,3.2*s,fill=1,stroke=0)
            c.setFillColor(_DARK)
            c.circle(x-4*s,y+28*s,2*s,fill=1,stroke=0); c.circle(x+4*s,y+28*s,2*s,fill=1,stroke=0)
            c.setFillColor(_DARK); c.circle(x,y+23*s,2.5*s,fill=1,stroke=0)
            c.setFillColor(HexColor("#f472b6"))
            c.ellipse(x-2*s,y+17*s,x+2*s,y+22*s,fill=1,stroke=0)
        elif animal == "rabbit":
            c.setFillColor(white); c.setStrokeColor(HexColor("#d1d5db")); c.setLineWidth(0.8)
            c.circle(x,y+10*s,10*s,fill=1,stroke=1); c.circle(x,y+24*s,8*s,fill=1,stroke=1)
            c.ellipse(x-6*s,y+28*s,x-1*s,y+46*s,fill=1,stroke=1)
            c.ellipse(x+1*s,y+28*s,x+6*s,y+46*s,fill=1,stroke=1)
            c.setFillColor(HexColor("#fda4af"))
            c.ellipse(x-5*s,y+30*s,x-2*s,y+43*s,fill=1,stroke=0)
            c.ellipse(x+2*s,y+30*s,x+5*s,y+43*s,fill=1,stroke=0)
            c.setFillColor(HexColor("#be185d"))
            c.circle(x-3*s,y+26*s,1.8*s,fill=1,stroke=0); c.circle(x+3*s,y+26*s,1.8*s,fill=1,stroke=0)
            c.setFillColor(HexColor("#f472b6")); c.circle(x,y+22*s,1.5*s,fill=1,stroke=0)
        elif animal == "bird":
            c.setFillColor(HexColor("#3b82f6"))
            c.ellipse(x-8*s,y,x+8*s,y+14*s,fill=1,stroke=0)
            c.setFillColor(HexColor("#60a5fa")); c.circle(x,y+18*s,7*s,fill=1,stroke=0)
            c.setFillColor(HexColor("#f59e0b"))
            p=c.beginPath(); p.moveTo(x+6*s,y+17*s); p.lineTo(x+14*s,y+16*s); p.lineTo(x+6*s,y+14*s); p.close()
            c.drawPath(p, fill=1, stroke=0)
            c.setFillColor(white); c.circle(x+2*s,y+20*s,2.5*s,fill=1,stroke=0)
            c.setFillColor(_DARK); c.circle(x+2*s,y+20*s,1.3*s,fill=1,stroke=0)
        c.restoreState()

    def _draw_sun(x, y, size):
        c.saveState()
        c.setStrokeColor(HexColor("#fbbf24")); c.setLineWidth(2)
        for i in range(12):
            angle = i * math.pi / 6
            c.line(x+size*1.3*math.cos(angle), y+size*1.3*math.sin(angle),
                   x+size*1.8*math.cos(angle), y+size*1.8*math.sin(angle))
        c.setFillColor(HexColor("#fbbf24")); c.circle(x, y, size, fill=1, stroke=0)
        c.setFillColor(_DARK)
        c.circle(x-size*0.25, y+size*0.15, size*0.08, fill=1, stroke=0)
        c.circle(x+size*0.25, y+size*0.15, size*0.08, fill=1, stroke=0)
        c.setStrokeColor(_DARK); c.setLineWidth(1)
        c.arc(x-size*0.3, y-size*0.4, x+size*0.3, y, 200, 140)
        c.restoreState()

    def _draw_cloud(x, y, size):
        c.saveState(); c.setFillColor(Color(1,1,1,0.85))
        c.circle(x,y,size*0.6,fill=1,stroke=0); c.circle(x-size*0.5,y-size*0.1,size*0.45,fill=1,stroke=0)
        c.circle(x+size*0.5,y-size*0.05,size*0.5,fill=1,stroke=0)
        c.restoreState()

    def _draw_star(x, y, size, color):
        c.saveState(); c.setFillColor(color)
        p = c.beginPath()
        for i in range(10):
            angle = math.pi/2 + i*math.pi/5
            r = size if i%2==0 else size*0.4
            px, py = x+r*math.cos(angle), y+r*math.sin(angle)
            if i==0: p.moveTo(px,py)
            else: p.lineTo(px,py)
        p.close(); c.drawPath(p, fill=1, stroke=0); c.restoreState()

    def _draw_heart(x, y, size, color=None):
        c.saveState(); c.setFillColor(color or HexColor("#ef4444"))
        c.circle(x-size*0.3, y+size*0.2, size*0.35, fill=1, stroke=0)
        c.circle(x+size*0.3, y+size*0.2, size*0.35, fill=1, stroke=0)
        p=c.beginPath(); p.moveTo(x-size*0.6,y+size*0.1); p.lineTo(x,y-size*0.6); p.lineTo(x+size*0.6,y+size*0.1); p.close()
        c.drawPath(p, fill=1, stroke=0); c.restoreState()

    def _draw_flower(x, y, size, petal_color=None):
        c.saveState(); _pc = petal_color or HexColor("#f472b6"); c.setFillColor(_pc)
        for i in range(6):
            angle = i*math.pi/3
            c.circle(x+size*0.6*math.cos(angle), y+size*0.6*math.sin(angle), size*0.4, fill=1, stroke=0)
        c.setFillColor(HexColor("#fbbf24")); c.circle(x, y, size*0.35, fill=1, stroke=0)
        c.setFillColor(HexColor("#22c55e")); c.setLineWidth(1.5)
        c.line(x, y-size*0.4, x, y-size*1.8)
        c.restoreState()

    def _draw_rainbow(x, y, rw, rh):
        c.saveState()
        for i, clr in enumerate(["#ef4444","#f97316","#eab308","#22c55e","#3b82f6","#8b5cf6"]):
            c.setStrokeColor(HexColor(clr)); c.setLineWidth(3)
            c.arc(x, y, x+rw, y+rh-i*4, 0, 180)
        c.restoreState()

    def _draw_dotted_shape(x, y, shape, size, color):
        """Noktalı (trace) sekil cizer — cocuk uzerinden cizer."""
        c.saveState(); c.setStrokeColor(color); c.setLineWidth(1.5); c.setDash(3, 4)
        if shape == "circle":
            c.circle(x, y, size, fill=0, stroke=1)
        elif shape == "square":
            c.rect(x - size, y - size, size * 2, size * 2, fill=0, stroke=1)
        elif shape == "triangle":
            p = c.beginPath()
            p.moveTo(x, y + size); p.lineTo(x - size, y - size * 0.6); p.lineTo(x + size, y - size * 0.6); p.close()
            c.drawPath(p, fill=0, stroke=1)
        elif shape == "star":
            p = c.beginPath()
            for i in range(10):
                angle = math.pi/2 + i*math.pi/5
                r = size if i%2==0 else size*0.4
                px, py = x+r*math.cos(angle), y+r*math.sin(angle)
                if i==0: p.moveTo(px,py)
                else: p.lineTo(px,py)
            p.close(); c.drawPath(p, fill=0, stroke=1)
        elif shape == "heart":
            c.circle(x-size*0.3, y+size*0.2, size*0.35, fill=0, stroke=1)
            c.circle(x+size*0.3, y+size*0.2, size*0.35, fill=0, stroke=1)
        c.setDash(); c.restoreState()

    def _draw_dotted_line(x1, y1, x2, y2, color):
        """Noktalı cizgi — cocuk takip eder."""
        c.saveState(); c.setStrokeColor(color); c.setLineWidth(2); c.setDash(5, 5)
        c.line(x1, y1, x2, y2); c.setDash(); c.restoreState()

    def _draw_dotted_wave(x1, y1, x2, y2, color, amplitude=8):
        """Dalgali noktalı cizgi."""
        c.saveState(); c.setStrokeColor(color); c.setLineWidth(2); c.setDash(4, 4)
        steps = 20; dx = (x2-x1)/steps
        p = c.beginPath(); p.moveTo(x1, y1)
        for i in range(1, steps+1):
            nx = x1 + i*dx
            ny = y1 + amplitude * math.sin(i * math.pi / 3)
            p.lineTo(nx, ny)
        c.drawPath(p, fill=0, stroke=1); c.setDash(); c.restoreState()

    def _big_picture(x, y, size, item):
        """Buyuk boyama resmi cizer — sadece kontur (cocuk boyar)."""
        c.saveState(); c.setStrokeColor(HexColor("#6b7280")); c.setLineWidth(1.5); c.setFillColor(white)
        if item in ("cat", "dog", "rabbit", "bird"):
            _draw_animal(x, y, size / 15, item)
        elif item == "sun":
            _draw_sun(x, y + size * 0.5, size * 0.4)
        elif item == "flower":
            _draw_flower(x, y + size * 0.3, size * 0.3, HexColor("#d1d5db"))
        elif item == "star":
            _draw_star(x, y + size * 0.5, size * 0.4, HexColor("#d1d5db"))
        elif item == "heart":
            _draw_heart(x, y + size * 0.5, size * 0.4, HexColor("#d1d5db"))
        else:
            # Genel: daire kontur
            c.circle(x, y + size * 0.5, size * 0.4, fill=0, stroke=1)
        c.restoreState()

    page_num = [0]

    def _page_header(title, color=_PRIMARY):
        page_num[0] += 1
        _rrect(1.5*cm, h-2.5*cm, w-3*cm, 1.8*cm, 10, fill=color)
        c.setFont("Helvetica-Bold", 16); c.setFillColor(white)
        c.drawString(2.2*cm, h-1.6*cm, title)
        c.setFont("Helvetica", 8); c.setFillColor(_GRAY)
        c.drawRightString(w-1.5*cm, 1*cm, f"Sayfa {page_num[0]}")
        c.setStrokeColor(color); c.setLineWidth(0.5)
        c.line(1.5*cm, 1.5*cm, w-1.5*cm, 1.5*cm)

    def _section_box(y, text, color=_PRIMARY):
        _rrect(1.5*cm, y-5, w-3*cm, 22, 6, fill=color)
        c.setFont("Helvetica-Bold", 11); c.setFillColor(white)
        c.drawString(2*cm, y, text)
        return y - 32

    def _star_border():
        for ix in range(int((w-2*cm)/25)):
            _draw_star(1*cm + ix*25, h-0.8*cm, 4, HexColor("#fbbf24"))
            _draw_star(1*cm + ix*25, 0.8*cm, 4, HexColor("#fbbf24"))

    # ═══════════════════════════════════════════════════════════
    # SAYFA 1: KAPAK
    # ═══════════════════════════════════════════════════════════
    for i in range(30):
        frac = i / 30
        c.setFillColor(Color(0.95 - frac*0.1, 0.85 - frac*0.05, 1.0 - frac*0.1))
        c.rect(0, h-(i+1)*(h/30), w, h/30+1, fill=1, stroke=0)
    _star_border()
    _draw_sun(w - 3*cm, h - 2.5*cm, 20)
    _draw_cloud(3*cm, h - 2*cm, 18)
    _draw_cloud(w/2 + 2*cm, h - 1.5*cm, 14)
    _draw_rainbow(w/2 - 4*cm, h - 4*cm, 8*cm, 3*cm)
    # Baslik
    _rrect(2*cm, h-8*cm, w-4*cm, 5.5*cm, 15,
           fill=Color(1,1,1,0.95), stroke=HexColor("#fbbf24"), sw=3)
    c.setFont("Helvetica-Bold", 26); c.setFillColor(_PINK)
    c.drawCentredString(w/2, h-4*cm, "MY ENGLISH BOOK")
    c.setFont("Helvetica-Bold", 18); c.setFillColor(_SECONDARY)
    c.drawCentredString(w/2, h-5.2*cm, f"Unit {unit_num}: {_theme}")
    c.setFont("Helvetica", 12); c.setFillColor(_GRAY)
    c.drawCentredString(w/2, h-6.2*cm, _theme_tr)
    c.setFont("Helvetica-Bold", 14); c.setFillColor(_WARM)
    c.drawCentredString(w/2, h-7.2*cm, f"Okul Oncesi  |  {len(_all_vocab)} Kelime")
    # Karakterler
    _draw_full_character(3*cm, h-14*cm, 1.3, "boy", HexColor("#3b82f6"), "happy")
    _draw_full_character(w/2, h-14.5*cm, 1.4, "girl", HexColor("#ec4899"), "happy")
    _draw_full_character(w-3*cm, h-14*cm, 1.3, "boy", HexColor("#22c55e"), "happy")
    # Hayvanlar
    _draw_animal(2.5*cm, h-18*cm, 0.9, "cat")
    _draw_animal(w/2, h-18.5*cm, 0.8, "rabbit")
    _draw_animal(w-2.5*cm, h-18*cm, 0.8, "dog")
    _draw_animal(w/2-3*cm, h-17*cm, 0.7, "bird")
    # Cicekler, yildizlar
    _draw_flower(5*cm, h-17*cm, 7, HexColor("#f472b6"))
    _draw_flower(w-5*cm, h-16.5*cm, 6, HexColor("#a78bfa"))
    for sx,sy in [(2*cm,h-15.5*cm),(w-2*cm,h-15*cm),(4*cm,h-16*cm)]:
        _draw_star(sx, sy, 10, HexColor("#fbbf24"))
    _draw_heart(w/2+5*cm, h-12*cm, 10, HexColor("#ef4444"))
    _draw_heart(w/2-5*cm, h-13*cm, 8, HexColor("#f472b6"))
    # Alt
    _rrect(2*cm, 2*cm, w-4*cm, 3*cm, 10, fill=_BG_CREAM, stroke=HexColor("#fbbf24"), sw=1.5)
    c.setFont("Helvetica-Bold", 10); c.setFillColor(_PRIMARY)
    c.drawCentredString(w/2, 3.8*cm, "SmartCampus AI - Okul Oncesi Calisma Kitabi")
    c.setFont("Helvetica", 8); c.setFillColor(_GRAY)
    c.drawCentredString(w/2, 2.8*cm, f"Kelimeler: {', '.join(_all_vocab[:8])}")

    # ═══════════════════════════════════════════════════════════
    # SAYFA 2: GORSELLER — Bak ve Goster
    # ═══════════════════════════════════════════════════════════
    c.showPage(); _star_border()
    _page_header(f"BAK VE GOSTER  -  {_theme}", _PRIMARY)
    y = h - 3.5*cm
    y = _section_box(y, "Resimlere Bak! (Look at the Pictures!)", _PRIMARY)
    # Buyuk gorsel kartlar (3x2 veya 2x3)
    _cw = (w - 4*cm) / 3; _ch = 3.5*cm
    for vi, vw in enumerate(_all_vocab[:6]):
        col, row = vi % 3, vi // 3
        bx = 1.8*cm + col*_cw; by = y - row*(_ch + 0.3*cm)
        _rrect(bx, by - _ch, _cw - 0.3*cm, _ch, 10,
              fill=[_BG_LIGHT, _BG_CREAM, _BG_GREEN, _BG_PURPLE, _BG_PINK, _BG_LIGHT][vi%6],
              stroke=[_PRIMARY, HexColor("#f59e0b"), _ACCENT, _SECONDARY, _PINK, _PRIMARY][vi%6], sw=1.5)
        # Hayvan/nesne cizdiriyoruz
        _item_animals = {"cat":"cat","dog":"dog","rabbit":"rabbit","bird":"bird",
                        "cow":"cat","sheep":"rabbit","horse":"dog","chicken":"bird",
                        "fish":"bird","pig":"cat","butterfly":"bird","bee":"bird"}
        _anim = _item_animals.get(vw, "cat" if vi%2==0 else "rabbit")
        _draw_animal(bx + (_cw-0.3*cm)/2, by - _ch + 0.5*cm, (_ch-1.5*cm)/30, _anim)
        # Kelime altta buyuk font
        c.setFont("Helvetica-Bold", 14)
        c.setFillColor([_PRIMARY, HexColor("#f59e0b"), _ACCENT, _SECONDARY, _PINK, _PRIMARY][vi%6])
        c.drawCentredString(bx + (_cw-0.3*cm)/2, by - _ch + 0.3*cm, vw.upper())
    # Kalan kelimeler icin ikinci satir
    if len(_all_vocab) > 6:
        y2 = y - 2*(_ch + 0.3*cm) - 0.5*cm
        y2 = _section_box(y2, "Daha Fazla! (More!)", _ACCENT)
        for vi2, vw2 in enumerate(_all_vocab[6:12]):
            col2, row2 = vi2 % 3, vi2 // 3
            bx2 = 1.8*cm + col2*_cw; by2 = y2 - row2*(_ch + 0.3*cm)
            if by2 - _ch < 2*cm: break
            _rrect(bx2, by2 - _ch, _cw - 0.3*cm, _ch, 10,
                  fill=_BG_GREEN, stroke=_ACCENT, sw=1)
            _draw_animal(bx2 + (_cw-0.3*cm)/2, by2 - _ch + 0.5*cm, (_ch-1.5*cm)/30,
                        ["cat","dog","rabbit","bird"][vi2%4])
            c.setFont("Helvetica-Bold", 14); c.setFillColor(_ACCENT)
            c.drawCentredString(bx2 + (_cw-0.3*cm)/2, by2 - _ch + 0.3*cm, vw2.upper())
    _draw_full_character(w-2*cm, 3*cm, 0.6, "girl", _PINK, "happy")

    # ═══════════════════════════════════════════════════════════
    # SAYFA 3: BOYAMA — Boya ve Ogren
    # ═══════════════════════════════════════════════════════════
    c.showPage(); _star_border()
    _page_header(f"BOYA!  -  {_theme}", HexColor("#e11d48"))
    y = h - 3.5*cm
    y = _section_box(y, "Resimleri Boya! (Colour the Pictures!)", HexColor("#e11d48"))
    # 6 buyuk boyama alani (2x3)
    _bw = (w - 4*cm) / 2; _bh = (y - 3*cm) / 3
    _coloring_items = _all_vocab[:6] if len(_all_vocab) >= 6 else _all_vocab + ["cat","dog","star","heart","flower","sun"]
    for bi in range(min(6, len(_coloring_items))):
        col, row = bi%2, bi//2
        bx = 2*cm + col*_bw; by = y - (row+1)*_bh
        _rrect(bx, by, _bw - 0.5*cm, _bh - 0.3*cm, 12,
              fill=white, stroke=HexColor("#d1d5db"), sw=1.5)
        # Kontur resim
        _big_picture(bx + (_bw-0.5*cm)/2, by + 0.3*cm, (_bh-1*cm), _coloring_items[bi])
        # Kelime altta
        c.setFont("Helvetica-Bold", 12); c.setFillColor(HexColor("#6b7280"))
        c.drawCentredString(bx + (_bw-0.5*cm)/2, by + 0.2*cm, _coloring_items[bi].upper())
    # Boya paleti sag alt
    _palette = ["#ef4444","#f97316","#eab308","#22c55e","#3b82f6","#8b5cf6","#ec4899"]
    for pi, pc in enumerate(_palette):
        c.setFillColor(HexColor(pc))
        c.circle(w - 2*cm, 2.5*cm + pi*0.7*cm, 5, fill=1, stroke=0)

    # ═══════════════════════════════════════════════════════════
    # SAYFA 4: ESLESTIRME — Esle
    # ═══════════════════════════════════════════════════════════
    c.showPage(); _star_border()
    _page_header(f"ESLE!  -  {_theme}", _ACCENT)
    y = h - 3.5*cm
    y = _section_box(y, "Resimleri Esle! (Match!)", _ACCENT)
    # Sol: resimler, Sag: resimler (karisik) — cizgi cek
    _match_count = min(5, len(_all_vocab))
    _left = _all_vocab[:_match_count]
    _right = list(_left); _rnd.shuffle(_right)
    _item_h = (y - 4*cm) / _match_count
    for mi in range(_match_count):
        ly = y - mi*_item_h - _item_h/2
        # Sol: karikatür
        _rrect(2*cm, ly - _item_h*0.35, 3.5*cm, _item_h*0.7, 8,
              fill=_BG_LIGHT, stroke=_PRIMARY, sw=1)
        _draw_animal(3.75*cm, ly - _item_h*0.25, _item_h*0.015,
                    ["cat","dog","rabbit","bird"][mi%4])
        c.setFont("Helvetica-Bold", 11); c.setFillColor(_PRIMARY)
        c.drawCentredString(3.75*cm, ly - _item_h*0.3, _left[mi].upper())
        # Sag: karikatür
        _rrect(w-5.5*cm, ly - _item_h*0.35, 3.5*cm, _item_h*0.7, 8,
              fill=_BG_CREAM, stroke=_WARM, sw=1)
        _draw_animal(w-3.75*cm, ly - _item_h*0.25, _item_h*0.015,
                    ["dog","cat","bird","rabbit"][mi%4])
        c.setFont("Helvetica-Bold", 11); c.setFillColor(_WARM)
        c.drawCentredString(w-3.75*cm, ly - _item_h*0.3, _right[mi].upper())
        # Noktalar (cizgi alanı)
        c.setStrokeColor(HexColor("#cbd5e1")); c.setDash(3,5); c.setLineWidth(1)
        c.circle(5.7*cm, ly, 4, fill=0, stroke=1)
        c.circle(w-5.7*cm, ly, 4, fill=0, stroke=1)
        c.setDash()
    _draw_full_character(w-1.5*cm, 2*cm, 0.5, "boy", _ACCENT, "happy")

    # ═══════════════════════════════════════════════════════════
    # SAYFA 5: CIZGI CEKME — Takip Et
    # ═══════════════════════════════════════════════════════════
    c.showPage(); _star_border()
    _page_header(f"CIZGI CEK!  -  {_theme}", _SECONDARY)
    y = h - 3.5*cm
    y = _section_box(y, "Cizgiyi Takip Et! (Trace the Line!)", _SECONDARY)
    # 6 satır çizgi çekme
    _line_h = (y - 3*cm) / 6
    _line_types = ["straight", "wave", "zigzag", "curve", "straight", "wave"]
    _line_colors = [_PRIMARY, _PINK, _ACCENT, _WARM, _SECONDARY, HexColor("#e11d48")]
    for li in range(6):
        ly = y - li*_line_h - _line_h*0.5
        # Sol: karikatür
        _draw_animal(2.5*cm, ly - 10, 0.5, ["cat","dog","rabbit","bird","cat","dog"][li])
        # Sag: hedef (yildiz/kalp/cicek)
        if li % 3 == 0: _draw_star(w-2.5*cm, ly, 10, HexColor("#fbbf24"))
        elif li % 3 == 1: _draw_heart(w-2.5*cm, ly, 10, HexColor("#ef4444"))
        else: _draw_flower(w-2.5*cm, ly, 8, HexColor("#f472b6"))
        # Noktali cizgi
        if _line_types[li] == "straight":
            _draw_dotted_line(4*cm, ly, w-4*cm, ly, _line_colors[li])
        elif _line_types[li] == "wave":
            _draw_dotted_wave(4*cm, ly, w-4*cm, ly, _line_colors[li])
        else:
            # Zigzag
            c.saveState(); c.setStrokeColor(_line_colors[li]); c.setLineWidth(2); c.setDash(4,4)
            p = c.beginPath(); p.moveTo(4*cm, ly)
            for zi in range(8):
                nx = 4*cm + (zi+1)*(w-8*cm)/8
                ny = ly + (10 if zi%2==0 else -10)
                p.lineTo(nx, ny)
            c.drawPath(p, fill=0, stroke=1); c.setDash(); c.restoreState()
    _draw_full_character(w/2, 2*cm, 0.5, "girl", _SECONDARY, "happy")

    # ═══════════════════════════════════════════════════════════
    # SAYFA 6: SEKIL TAKIP — Noktalari Birlestir
    # ═══════════════════════════════════════════════════════════
    c.showPage(); _star_border()
    _page_header(f"SEKILLERI CIZ!  -  {_theme}", _WARM)
    y = h - 3.5*cm
    y = _section_box(y, "Noktalari Birlestir! (Trace the Shapes!)", _WARM)
    # 6 büyük noktalı şekil (2x3)
    _sw = (w - 4*cm) / 2; _sh = (y - 3*cm) / 3
    _shapes = ["circle", "square", "triangle", "star", "heart", "circle"]
    _shape_colors = [_PRIMARY, _WARM, _ACCENT, HexColor("#fbbf24"), HexColor("#ef4444"), _SECONDARY]
    _shape_names = ["CIRCLE", "SQUARE", "TRIANGLE", "STAR", "HEART", "CIRCLE"]
    for si in range(6):
        col, row = si%2, si//2
        sx = 2*cm + col*_sw + _sw/2 - 0.15*cm
        sy = y - row*_sh - _sh/2
        _rrect(2*cm + col*_sw, sy - _sh/2, _sw - 0.3*cm, _sh - 0.2*cm, 10,
              fill=white, stroke=_shape_colors[si], sw=1)
        _draw_dotted_shape(sx, sy, _shapes[si], min(_sw, _sh)*0.3, _shape_colors[si])
        c.setFont("Helvetica-Bold", 11); c.setFillColor(_shape_colors[si])
        c.drawCentredString(sx, sy - _sh*0.4, _shape_names[si])

    # ═══════════════════════════════════════════════════════════
    # SAYFA 7: DAIRE ICINE AL — Dogru Olani Bul
    # ═══════════════════════════════════════════════════════════
    c.showPage(); _star_border()
    _page_header(f"DOGRU OLANI BUL!  -  {_theme}", _PRIMARY)
    y = h - 3.5*cm
    y = _section_box(y, "Dogru Resmi Daire Icine Al! (Circle!)", _PRIMARY)
    # Her satir: 1 soru resmi + 3 secenekten dogrusunu bul
    _q_count = min(5, len(_all_vocab))
    _row_h = (y - 3*cm) / _q_count
    for qi in range(_q_count):
        qy = y - qi*_row_h - _row_h*0.5
        # Sol: hedef kelime
        _rrect(2*cm, qy - _row_h*0.35, 3*cm, _row_h*0.7, 8,
              fill=_BG_GREEN, stroke=_ACCENT, sw=1.5)
        c.setFont("Helvetica-Bold", 13); c.setFillColor(_ACCENT)
        c.drawCentredString(3.5*cm, qy, _all_vocab[qi].upper())
        # Sag: 3 hayvan secenegi
        _opts = ["cat", "dog", "rabbit", "bird"]
        _correct = qi % 4
        for oi in range(3):
            ox = 6.5*cm + oi*3.5*cm
            _rrect(ox - 1*cm, qy - _row_h*0.35, 3*cm, _row_h*0.7, 8,
                  fill=white, stroke=HexColor("#d1d5db"), sw=0.8)
            _draw_animal(ox + 0.5*cm, qy - _row_h*0.2, _row_h*0.01,
                        _opts[(qi + oi) % 4])
    _draw_full_character(w-1.5*cm, 2*cm, 0.5, "boy", _PRIMARY, "happy")

    # ═══════════════════════════════════════════════════════════
    # SAYFA 8: SAYI ve SAYMA
    # ═══════════════════════════════════════════════════════════
    c.showPage(); _star_border()
    _page_header(f"SAY!  -  {_theme}", _SECONDARY)
    y = h - 3.5*cm
    y = _section_box(y, "Say ve Esle! (Count and Match!)", _SECONDARY)
    # Sol: sayi, Sag: o kadar nesne
    _count_items = min(5, max(3, len(_all_vocab)))
    _cnt_h = (y - 3*cm) / _count_items
    for ci in range(_count_items):
        cy = y - ci*_cnt_h - _cnt_h*0.5
        count_val = ci + 1
        # Sol: buyuk sayi
        _rrect(2*cm, cy - _cnt_h*0.35, 2.5*cm, _cnt_h*0.7, 10,
              fill=_BG_PURPLE, stroke=_SECONDARY, sw=1.5)
        c.setFont("Helvetica-Bold", 28); c.setFillColor(_SECONDARY)
        c.drawCentredString(3.25*cm, cy - 8, str(count_val))
        # Sag: o kadar hayvan
        for ni in range(count_val):
            nx = 6*cm + ni*2*cm
            if nx < w - 2*cm:
                _draw_animal(nx, cy - _cnt_h*0.25, _cnt_h*0.012,
                            ["cat","dog","rabbit","bird"][ni%4])
    _draw_full_character(w-1.5*cm, 2*cm, 0.5, "girl", _SECONDARY, "happy")

    # ═══════════════════════════════════════════════════════════
    # SAYFA 9: LABIRENT — Yolu Bul
    # ═══════════════════════════════════════════════════════════
    c.showPage(); _star_border()
    _page_header(f"YOLU BUL!  -  {_theme}", _WARM)
    y = h - 3.5*cm
    y = _section_box(y, "Yolu Bul! (Find the Way!)", _WARM)
    # 2 basit labirent
    for mz in range(2):
        _mz_y = y - mz * (y - 3*cm) / 2
        _mz_h = (y - 3*cm) / 2 - 0.5*cm
        _rrect(2*cm, _mz_y - _mz_h, w - 4*cm, _mz_h, 10,
              fill=white, stroke=_WARM, sw=1.5)
        # Sol: karakter
        _draw_full_character(3*cm, _mz_y - _mz_h + 0.5*cm, 0.4,
                            "boy" if mz==0 else "girl",
                            _PRIMARY if mz==0 else _PINK, "happy")
        # Sag: hedef
        if mz == 0:
            _draw_star(w-3*cm, _mz_y - _mz_h/2, 15, HexColor("#fbbf24"))
        else:
            _draw_heart(w-3*cm, _mz_y - _mz_h/2, 15, HexColor("#ef4444"))
        # Labirent duvarlari (rastgele yatay/dikey cizgiler)
        c.setStrokeColor(HexColor("#9ca3af")); c.setLineWidth(2)
        _rnd.seed(unit_num * 100 + mz)
        for _ in range(8):
            rx = _rnd.uniform(4.5*cm, w-5*cm)
            ry = _rnd.uniform(_mz_y - _mz_h + 1*cm, _mz_y - 1*cm)
            rl = _rnd.uniform(1*cm, 3*cm)
            if _rnd.random() > 0.5:
                c.line(rx, ry, rx + rl, ry)
            else:
                c.line(rx, ry, rx, ry + min(rl, _mz_h*0.4))
        # Noktali yol ipucu
        _draw_dotted_line(4.5*cm, _mz_y - _mz_h/2, w-4.5*cm, _mz_y - _mz_h/2,
                         HexColor("#22c55e"))

    # ═══════════════════════════════════════════════════════════
    # SAYFA 10: KES & YAPISTIR ALANI
    # ═══════════════════════════════════════════════════════════
    c.showPage(); _star_border()
    _page_header(f"KES VE YAPISTIR!  -  {_theme}", _PINK)
    y = h - 3.5*cm
    y = _section_box(y, "Kes ve Dogru Yere Yapistir! (Cut & Paste!)", _PINK)
    # Ust kisim: yapistirma alanlari (bos kutular + isim)
    _paste_count = min(4, len(_all_vocab))
    _pw = (w - 4*cm) / _paste_count
    for pi in range(_paste_count):
        px = 2*cm + pi*_pw
        _rrect(px, y - 3.5*cm, _pw - 0.3*cm, 3*cm, 10,
              fill=white, stroke=HexColor("#d1d5db"), sw=1.5)
        c.setStrokeColor(_PINK); c.setDash(5,5); c.setLineWidth(1)
        c.rect(px + 0.3*cm, y - 3.2*cm, _pw - 0.9*cm, 2*cm, fill=0, stroke=1)
        c.setDash()
        c.setFont("Helvetica-Bold", 12); c.setFillColor(_PINK)
        c.drawCentredString(px + (_pw-0.3*cm)/2, y - 3.4*cm, _all_vocab[pi].upper())
    # Alt: kesme alani (makasla kesilecek kartlar)
    _cut_y = y - 5*cm
    _section_box(_cut_y, "Asagidaki Resimleri Kes (Cut Here)", HexColor("#6b7280"))
    _cut_y -= 1.2*cm
    # Kesim cizgisi
    c.setStrokeColor(HexColor("#9ca3af")); c.setDash(8, 4); c.setLineWidth(1.5)
    c.line(1.5*cm, _cut_y + 0.8*cm, w - 1.5*cm, _cut_y + 0.8*cm)
    c.setDash()
    # Makas ikonu (basit)
    c.setFont("Helvetica-Bold", 14); c.setFillColor(HexColor("#6b7280"))
    c.drawString(1.5*cm, _cut_y + 0.3*cm, "---")
    # Kesme kartlari
    _rnd.shuffle(_all_vocab)
    _cut_items = _all_vocab[:_paste_count]
    for ci in range(_paste_count):
        cx = 2*cm + ci*_pw
        _rrect(cx, _cut_y - 3*cm, _pw - 0.3*cm, 3*cm, 8,
              fill=_BG_CREAM, stroke=HexColor("#d1d5db"), sw=1)
        _draw_animal(cx + (_pw-0.3*cm)/2, _cut_y - 2.5*cm, 0.6,
                    ["cat","dog","rabbit","bird"][ci%4])
    # Alt susler
    _draw_flower(3*cm, 3*cm, 6, _PINK)
    _draw_flower(w-3*cm, 3*cm, 5, HexColor("#a78bfa"))
    _draw_full_character(w/2, 2*cm, 0.5, "girl", _PINK, "happy")

    # ═══════════════════════════════════════════════════════════
    # SAYFA 11: EGLENCE — Bulmaca & Cizim
    # ═══════════════════════════════════════════════════════════
    c.showPage(); _star_border()
    _page_header(f"EGLENCE!  -  {_theme}", HexColor("#e11d48"))
    _draw_sun(w-2.5*cm, h-2*cm, 12)
    _draw_cloud(3*cm, h-2*cm, 12)
    y = h - 3.5*cm
    y = _section_box(y, "Ciz ve Boya! (Draw and Colour!)", HexColor("#e11d48"))
    # 4 buyuk cizim kutusu
    _dw = (w - 4*cm) / 2; _dh = (y - 3*cm) / 2
    _draw_prompts = [f"Draw a {_all_vocab[0] if _all_vocab else 'cat'}",
                     f"Draw a {_all_vocab[1] if len(_all_vocab)>1 else 'dog'}",
                     f"Draw a {_all_vocab[2] if len(_all_vocab)>2 else 'star'}",
                     f"Draw a {_all_vocab[3] if len(_all_vocab)>3 else 'heart'}"]
    for di in range(4):
        col, row = di%2, di//2
        dx = 2*cm + col*_dw; dy = y - (row+1)*_dh
        _rrect(dx, dy, _dw - 0.3*cm, _dh - 0.3*cm, 12,
              fill=white, stroke=[_PRIMARY, _PINK, _ACCENT, _WARM][di], sw=1.5)
        c.setFont("Helvetica-Bold", 10)
        c.setFillColor([_PRIMARY, _PINK, _ACCENT, _WARM][di])
        c.drawCentredString(dx + (_dw-0.3*cm)/2, dy + _dh - 0.7*cm, _draw_prompts[di])
        # Kucuk ornek resim (soluk)
        c.saveState()
        c.setFillColor(Color(0.9, 0.9, 0.9, 0.3))
        _draw_dotted_shape(dx + (_dw-0.3*cm)/2, dy + _dh/2 - 0.3*cm,
                          ["circle","square","triangle","heart"][di],
                          min(_dw, _dh)*0.2, HexColor("#e5e7eb"))
        c.restoreState()
    # Susler
    _draw_animal(2*cm, 2*cm, 0.5, "cat")
    _draw_animal(w-2.5*cm, 2.5*cm, 0.5, "rabbit")
    _draw_heart(w/2, 3*cm, 8, HexColor("#ef4444"))

    # ═══════════════════════════════════════════════════════════
    # SAYFA 12: TEBRIKLER
    # ═══════════════════════════════════════════════════════════
    c.showPage(); _star_border()
    # Renkli arka plan
    for i in range(30):
        frac = i / 30
        c.setFillColor(Color(1.0 - frac*0.05, 0.95 - frac*0.1, 1.0 - frac*0.05))
        c.rect(0, h-(i+1)*(h/30), w, h/30+1, fill=1, stroke=0)
    _star_border()
    _draw_rainbow(1.5*cm, h - 4*cm, w - 3*cm, 3*cm)
    _draw_sun(w-3*cm, h-2.5*cm, 18)
    _draw_cloud(3*cm, h-2*cm, 16)
    # Buyuk tebrik
    _rrect(2.5*cm, h-9*cm, w-5*cm, 5*cm, 15,
          fill=Color(1,1,1,0.9), stroke=HexColor("#fbbf24"), sw=3)
    c.setFont("Helvetica-Bold", 32); c.setFillColor(HexColor("#e11d48"))
    c.drawCentredString(w/2, h-5.5*cm, "TEBRIKLER!")
    c.setFont("Helvetica-Bold", 18); c.setFillColor(_SECONDARY)
    c.drawCentredString(w/2, h-6.8*cm, "CONGRATULATIONS!")
    c.setFont("Helvetica-Bold", 14); c.setFillColor(_WARM)
    c.drawCentredString(w/2, h-8*cm, f"Unit {unit_num}: {_theme} - Tamamlandi!")
    # 5 karakter sira
    _chars = [("boy", _PRIMARY), ("girl", _PINK), ("boy", _ACCENT),
              ("girl", _SECONDARY), ("boy", _WARM)]
    for ci, (gen, clr) in enumerate(_chars):
        cx = 2*cm + ci*(w-4*cm)/5 + (w-4*cm)/10
        _draw_full_character(cx, h-14.5*cm, 1.0, gen, clr, "happy")
    # Hayvanlar alt
    _draw_animal(2*cm, h-18*cm, 0.9, "cat")
    _draw_animal(w/2-2*cm, h-18.5*cm, 0.8, "dog")
    _draw_animal(w/2+2*cm, h-18*cm, 0.7, "bird")
    _draw_animal(w-2*cm, h-18.5*cm, 0.9, "rabbit")
    # Yildizlar, kalpler, cicekler
    for sx, sy in [(3*cm,h-16*cm),(w-3*cm,h-15.5*cm),(w/2,h-16.5*cm),
                   (5*cm,h-17*cm),(w-5*cm,h-17*cm)]:
        _draw_star(sx, sy, 12, HexColor("#fbbf24"))
    _draw_heart(w/2-4*cm, h-12*cm, 10, HexColor("#ef4444"))
    _draw_heart(w/2+4*cm, h-12*cm, 10, HexColor("#f472b6"))
    _draw_flower(4*cm, h-20*cm, 8, HexColor("#f472b6"))
    _draw_flower(w-4*cm, h-19.5*cm, 7, HexColor("#a78bfa"))
    _draw_flower(w/2, h-20.5*cm, 9, HexColor("#fb923c"))
    # Kontrol listesi (veli icin)
    _rrect(2*cm, 2*cm, w-4*cm, 5*cm, 10, fill=_BG_CREAM, stroke=HexColor("#fbbf24"), sw=1)
    c.setFont("Helvetica-Bold", 9); c.setFillColor(HexColor("#92400e"))
    c.drawString(2.5*cm, 6.2*cm, "Veli Notu: Cocugunuz bu unitede sunlari yapti:")
    c.setFont("Helvetica", 8); c.setFillColor(_GRAY)
    _chk_items = ["Resimleri boyadi", "Cizgileri takip etti", "Sekilleri cizdi",
                  f"'{_theme}' kelimelerini dinledi", "Eslestirme yapti", "Sayi saydi"]
    for ci, ch in enumerate(_chk_items):
        cx_col = 2.5*cm if ci < 3 else w/2
        cy_row = 5.5*cm - (ci % 3)*0.55*cm
        c.setStrokeColor(HexColor("#92400e")); c.setLineWidth(0.8)
        c.rect(cx_col, cy_row - 2, 10, 10, fill=0, stroke=1)
        c.drawString(cx_col + 14, cy_row, ch)

    c.save()
    return buf.getvalue()


def _generate_workbook_pdf(grade: int, unit_num: int) -> bytes:
    """Ünite bazlı basılı yardımcı kitap PDF'i üretir.
    Karikatür tarzı, renkli, konuşma balonlu, çevrimdışı çalışma kitabı.
    grade=0 ise okul öncesi (yazısız) versiyona yönlendirir.
    """
    if grade == 0:
        return _generate_preschool_workbook_pdf(unit_num)

    from reportlab.lib.pagesizes import A4
    from reportlab.lib.units import cm, mm
    from reportlab.lib.colors import (
        HexColor, white, black, Color,
    )
    from reportlab.pdfgen import canvas
    from reportlab.lib.enums import TA_CENTER, TA_LEFT
    import io

    # Curriculum verisi
    _level_key = f"grade{grade}"
    _curriculum = _CURRICULUM.get(_level_key, [])
    if grade >= 9:
        # Lise: 10 ünite — ilk 6'sı 4 hafta, son 4'ü 3 hafta
        _lise_umap = {1:(1,4),2:(5,8),3:(9,12),4:(13,16),5:(17,20),
                      6:(21,24),7:(25,27),8:(28,30),9:(31,33),10:(34,36)}
        _ws, _we = _lise_umap.get(unit_num, (1, 4))
        _unit_weeks = [w for w in _curriculum if _ws <= w.get("week", 0) <= _we]
    else:
        _unit_weeks = [w for w in _curriculum if (w.get("week", 0) - 1) // 4 + 1 == unit_num
                       or (hasattr(w, "get") and w.get("unit") == unit_num)]
    if not _unit_weeks:
        # Fallback: ilk 4 haftayı al
        start = (unit_num - 1) * 4
        _unit_weeks = _curriculum[start:start + 4]

    # weekly_plans.json'dan detaylı veri
    _wp_cache = st.session_state.get("_yd_wp_outcomes_v4", {})
    _wp_grade = _wp_cache.get(str(grade), [])
    _wp_unit_weeks = [w for w in _wp_grade if w.get("unit") == unit_num]

    # Ünite bilgileri
    _theme = ""
    _theme_tr = ""
    _grammar = ""
    _all_vocab = []
    _all_outcomes = []
    _structures = []
    _skills = {}

    for w in _unit_weeks:
        if not _theme:
            _theme = w.get("theme", "")
            _theme_tr = w.get("theme_tr", "")
        _all_vocab.extend(w.get("vocab", []))
        _structures.append(w.get("structure", ""))
        _sk = w.get("skills", {})
        for k, v in _sk.items():
            if v and k not in _skills:
                _skills[k] = v
    for w in _wp_unit_weeks:
        if not _theme:
            _theme = w.get("unit_theme", "")
            _theme_tr = w.get("unit_theme_tr", "")
        if not _grammar:
            _grammar = w.get("grammar_focus", "")
        _all_outcomes.extend(w.get("outcome_codes", []))

    _all_vocab = list(dict.fromkeys(_all_vocab))
    _all_outcomes = list(dict.fromkeys(_all_outcomes))
    _structures = [s for s in _structures if s]

    buf = io.BytesIO()
    w, h = A4
    c = canvas.Canvas(buf, pagesize=A4)

    # Renk paleti
    _PRIMARY = HexColor("#1e40af")
    _SECONDARY = HexColor("#7c3aed")
    _ACCENT = HexColor("#059669")
    _WARM = HexColor("#ea580c")
    _BG_LIGHT = HexColor("#f0f9ff")
    _BG_CREAM = HexColor("#fffbeb")
    _BG_GREEN = HexColor("#ecfdf5")
    _BG_PURPLE = HexColor("#f5f3ff")
    _GRAY = HexColor("#64748b")
    _DARK = HexColor("#0B0F19")

    def _draw_rounded_rect(x, y, rw, rh, r, fill=None, stroke=None, sw=1):
        c.saveState()
        if fill:
            c.setFillColor(fill)
        if stroke:
            c.setStrokeColor(stroke)
            c.setLineWidth(sw)
        p = c.beginPath()
        p.roundRect(x, y, rw, rh, r)
        if fill and stroke:
            c.drawPath(p, fill=1, stroke=1)
        elif fill:
            c.drawPath(p, fill=1, stroke=0)
        elif stroke:
            c.drawPath(p, fill=0, stroke=1)
        c.restoreState()

    def _draw_speech_bubble(x, y, bw, bh, text, font_size=9, align="left"):
        """Konuşma balonu çizer."""
        _draw_rounded_rect(x, y, bw, bh, 8, fill=white, stroke=HexColor("#94a3b8"), sw=1.5)
        # Kuyruk (üçgen)
        c.saveState()
        c.setFillColor(white)
        c.setStrokeColor(HexColor("#94a3b8"))
        c.setLineWidth(1.5)
        p = c.beginPath()
        p.moveTo(x + bw * 0.3, y)
        p.lineTo(x + bw * 0.3 + 6, y - 8)
        p.lineTo(x + bw * 0.3 + 12, y)
        p.close()
        c.drawPath(p, fill=1, stroke=1)
        # Beyaz üstü kapat
        c.setStrokeColor(white)
        c.setLineWidth(2)
        c.line(x + bw * 0.3 + 1, y + 0.5, x + bw * 0.3 + 11, y + 0.5)
        c.restoreState()
        # Metin
        c.saveState()
        c.setFont("Helvetica-Bold", font_size)
        c.setFillColor(_DARK)
        tx = x + 8
        ty = y + bh - 14
        for line in text.split("\n"):
            c.drawString(tx, ty, line)
            ty -= font_size + 3
        c.restoreState()

    def _draw_cartoon_face(x, y, size, color, expression="happy"):
        """Basit karikatür yüz çizer."""
        c.saveState()
        c.setFillColor(HexColor("#fde68a"))
        c.setStrokeColor(color)
        c.setLineWidth(2)
        c.circle(x, y, size, fill=1, stroke=1)
        c.setFillColor(_DARK)
        eye_y = y + size * 0.15
        c.circle(x - size * 0.25, eye_y, size * 0.08, fill=1, stroke=0)
        c.circle(x + size * 0.25, eye_y, size * 0.08, fill=1, stroke=0)
        c.setStrokeColor(_DARK)
        c.setLineWidth(1.5)
        if expression == "happy":
            c.arc(x - size * 0.3, y - size * 0.45, x + size * 0.3, y - size * 0.05, 200, 140)
        elif expression == "thinking":
            c.line(x - size * 0.2, y - size * 0.25, x + size * 0.2, y - size * 0.25)
        elif expression == "surprised":
            c.circle(x, y - size * 0.25, size * 0.12, fill=0, stroke=1)
        c.restoreState()

    def _draw_full_character(x, y, scale, gender="boy", hair_color=None,
                             shirt_color=None, expression="happy", accessory=None):
        """Tam gövdeli karikatür karakter çizer (çocuk/kız/öğretmen)."""
        import math
        c.saveState()
        s = scale  # 1.0 = ~80px yükseklik
        _skin = HexColor("#fde68a") if gender != "teacher" else HexColor("#f5deb3")
        _hair = hair_color or (HexColor("#4a2c0a") if gender == "boy" else HexColor("#8B4513"))
        _shirt = shirt_color or (HexColor("#3b82f6") if gender == "boy" else HexColor("#ec4899"))
        _pants = HexColor("#1e3a5f") if gender != "girl" else HexColor("#7c3aed")
        _shoe = HexColor("#94A3B8")
        # --- Bacaklar ---
        c.setFillColor(_pants)
        c.rect(x - 8*s, y, 6*s, 20*s, fill=1, stroke=0)
        c.rect(x + 2*s, y, 6*s, 20*s, fill=1, stroke=0)
        # --- Ayakkabılar ---
        c.setFillColor(_shoe)
        c.roundRect(x - 10*s, y - 4*s, 10*s, 6*s, 3*s, fill=1, stroke=0)
        c.roundRect(x + 0*s, y - 4*s, 10*s, 6*s, 3*s, fill=1, stroke=0)
        # --- Gövde ---
        c.setFillColor(_shirt)
        c.setStrokeColor(_shirt)
        c.setLineWidth(0.5)
        c.roundRect(x - 12*s, y + 18*s, 24*s, 28*s, 5*s, fill=1, stroke=0)
        # --- Kollar ---
        c.setFillColor(_skin)
        # Sol kol
        c.saveState()
        c.setFillColor(_shirt)
        c.roundRect(x - 18*s, y + 28*s, 8*s, 16*s, 3*s, fill=1, stroke=0)
        c.setFillColor(_skin)
        c.circle(x - 14*s, y + 27*s, 4*s, fill=1, stroke=0)  # el
        c.restoreState()
        # Sağ kol
        c.saveState()
        c.setFillColor(_shirt)
        c.roundRect(x + 10*s, y + 28*s, 8*s, 16*s, 3*s, fill=1, stroke=0)
        c.setFillColor(_skin)
        c.circle(x + 14*s, y + 27*s, 4*s, fill=1, stroke=0)  # el
        c.restoreState()
        # El sallama (sağ kol yukarı)
        if accessory == "wave":
            c.setFillColor(_shirt)
            c.roundRect(x + 10*s, y + 38*s, 8*s, 18*s, 3*s, fill=1, stroke=0)
            c.setFillColor(_skin)
            c.circle(x + 14*s, y + 56*s, 4*s, fill=1, stroke=0)
        # --- Boyun ---
        c.setFillColor(_skin)
        c.rect(x - 4*s, y + 44*s, 8*s, 6*s, fill=1, stroke=0)
        # --- Kafa ---
        c.setFillColor(_skin)
        c.setStrokeColor(HexColor("#d4a574"))
        c.setLineWidth(1.5)
        head_y = y + 58*s
        head_r = 14*s
        c.circle(x, head_y, head_r, fill=1, stroke=1)
        # --- Saçlar ---
        c.setFillColor(_hair)
        if gender == "boy":
            # Kısa saç
            p = c.beginPath()
            p.arc(x - head_r - 1, head_y - head_r + 2*s, x + head_r + 1, head_y + head_r + 4*s, 0, 180)
            c.drawPath(p, fill=1, stroke=0)
        elif gender == "girl":
            # Uzun saç
            p = c.beginPath()
            p.arc(x - head_r - 1, head_y - head_r + 2*s, x + head_r + 1, head_y + head_r + 4*s, 0, 180)
            c.drawPath(p, fill=1, stroke=0)
            # Örgüler / uzun saç
            c.roundRect(x - head_r - 2*s, head_y - head_r, 6*s, -20*s, 3*s, fill=1, stroke=0)
            c.roundRect(x + head_r - 4*s, head_y - head_r, 6*s, -20*s, 3*s, fill=1, stroke=0)
            # Fiyonk / toka
            c.setFillColor(HexColor("#f472b6"))
            c.circle(x + head_r - 2*s, head_y + head_r - 2*s, 3*s, fill=1, stroke=0)
        elif gender == "teacher":
            # Öğretmen saçı
            p = c.beginPath()
            p.arc(x - head_r - 1, head_y - head_r + 2*s, x + head_r + 1, head_y + head_r + 5*s, 0, 180)
            c.drawPath(p, fill=1, stroke=0)
            # Gözlük
            c.setStrokeColor(HexColor("#94A3B8"))
            c.setLineWidth(1.2)
            c.circle(x - 5*s, head_y + 2*s, 4*s, fill=0, stroke=1)
            c.circle(x + 5*s, head_y + 2*s, 4*s, fill=0, stroke=1)
            c.line(x - 1*s, head_y + 2*s, x + 1*s, head_y + 2*s)
        # --- Gözler ---
        c.setFillColor(white)
        eye_y = head_y + 2*s
        c.circle(x - 5*s, eye_y, 3.5*s, fill=1, stroke=0)
        c.circle(x + 5*s, eye_y, 3.5*s, fill=1, stroke=0)
        c.setFillColor(_DARK)
        c.circle(x - 5*s, eye_y, 2*s, fill=1, stroke=0)
        c.circle(x + 5*s, eye_y, 2*s, fill=1, stroke=0)
        # Göz parıltısı
        c.setFillColor(white)
        c.circle(x - 4*s, eye_y + 1*s, 0.8*s, fill=1, stroke=0)
        c.circle(x + 6*s, eye_y + 1*s, 0.8*s, fill=1, stroke=0)
        # --- Yanaklar (pembe) ---
        c.setFillColor(Color(1, 0.6, 0.6, 0.3))
        c.circle(x - 9*s, head_y - 2*s, 3*s, fill=1, stroke=0)
        c.circle(x + 9*s, head_y - 2*s, 3*s, fill=1, stroke=0)
        # --- Ağız ---
        c.setStrokeColor(_DARK)
        c.setFillColor(HexColor("#ef4444"))
        c.setLineWidth(1.2)
        if expression == "happy":
            c.arc(x - 5*s, head_y - 10*s, x + 5*s, head_y - 2*s, 200, 140)
        elif expression == "thinking":
            c.setFillColor(_DARK)
            c.circle(x + 6*s, head_y - 5*s, 1.5*s, fill=1, stroke=0)
        elif expression == "surprised":
            c.circle(x, head_y - 6*s, 3*s, fill=1, stroke=1)
        elif expression == "talking":
            c.ellipse(x - 4*s, head_y - 9*s, x + 4*s, head_y - 3*s, fill=1, stroke=1)
        # --- Aksesuar: kitap ---
        if accessory == "book":
            c.setFillColor(HexColor("#3b82f6"))
            c.rect(x - 20*s, y + 26*s, 8*s, 10*s, fill=1, stroke=0)
            c.setFillColor(white)
            c.rect(x - 19*s, y + 27*s, 6*s, 2*s, fill=1, stroke=0)
            c.rect(x - 19*s, y + 30*s, 6*s, 1*s, fill=1, stroke=0)
        # --- Aksesuar: balon ---
        if accessory == "balloon":
            _bc = HexColor("#ef4444")
            c.setStrokeColor(HexColor("#9ca3af"))
            c.setLineWidth(0.8)
            c.line(x + 14*s, y + 56*s, x + 20*s, y + 82*s)
            c.setFillColor(_bc)
            c.circle(x + 20*s, y + 90*s, 8*s, fill=1, stroke=0)
            c.setFillColor(Color(1, 1, 1, 0.3))
            c.circle(x + 18*s, y + 93*s, 2*s, fill=1, stroke=0)
        c.restoreState()

    def _draw_animal(x, y, scale, animal="cat"):
        """Karikatür hayvan çizer (kedi, köpek, kuş, tavşan)."""
        import math
        c.saveState()
        s = scale
        if animal == "cat":
            # Gövde
            c.setFillColor(HexColor("#fb923c"))
            c.circle(x, y + 10*s, 12*s, fill=1, stroke=0)
            # Kafa
            c.circle(x, y + 26*s, 10*s, fill=1, stroke=0)
            # Kulaklar (üçgen)
            c.setFillColor(HexColor("#fb923c"))
            p = c.beginPath()
            p.moveTo(x - 8*s, y + 32*s)
            p.lineTo(x - 4*s, y + 42*s)
            p.lineTo(x - 0*s, y + 32*s)
            p.close()
            c.drawPath(p, fill=1, stroke=0)
            p2 = c.beginPath()
            p2.moveTo(x + 0*s, y + 32*s)
            p2.lineTo(x + 4*s, y + 42*s)
            p2.lineTo(x + 8*s, y + 32*s)
            p2.close()
            c.drawPath(p2, fill=1, stroke=0)
            # İç kulak
            c.setFillColor(HexColor("#fda4af"))
            p3 = c.beginPath()
            p3.moveTo(x - 6*s, y + 33*s)
            p3.lineTo(x - 4*s, y + 39*s)
            p3.lineTo(x - 2*s, y + 33*s)
            p3.close()
            c.drawPath(p3, fill=1, stroke=0)
            p4 = c.beginPath()
            p4.moveTo(x + 2*s, y + 33*s)
            p4.lineTo(x + 4*s, y + 39*s)
            p4.lineTo(x + 6*s, y + 33*s)
            p4.close()
            c.drawPath(p4, fill=1, stroke=0)
            # Gözler
            c.setFillColor(white)
            c.circle(x - 4*s, y + 28*s, 3*s, fill=1, stroke=0)
            c.circle(x + 4*s, y + 28*s, 3*s, fill=1, stroke=0)
            c.setFillColor(HexColor("#065f46"))
            c.circle(x - 4*s, y + 28*s, 1.8*s, fill=1, stroke=0)
            c.circle(x + 4*s, y + 28*s, 1.8*s, fill=1, stroke=0)
            c.setFillColor(white)
            c.circle(x - 3*s, y + 29*s, 0.6*s, fill=1, stroke=0)
            c.circle(x + 5*s, y + 29*s, 0.6*s, fill=1, stroke=0)
            # Burun
            c.setFillColor(HexColor("#f472b6"))
            p5 = c.beginPath()
            p5.moveTo(x - 1.5*s, y + 24*s)
            p5.lineTo(x, y + 22*s)
            p5.lineTo(x + 1.5*s, y + 24*s)
            p5.close()
            c.drawPath(p5, fill=1, stroke=0)
            # Bıyıklar
            c.setStrokeColor(HexColor("#9ca3af"))
            c.setLineWidth(0.6)
            c.line(x - 10*s, y + 24*s, x - 3*s, y + 23*s)
            c.line(x - 10*s, y + 22*s, x - 3*s, y + 22*s)
            c.line(x + 3*s, y + 23*s, x + 10*s, y + 24*s)
            c.line(x + 3*s, y + 22*s, x + 10*s, y + 22*s)
            # Kuyruk
            c.setStrokeColor(HexColor("#fb923c"))
            c.setLineWidth(2.5)
            c.arc(x + 8*s, y - 2*s, x + 22*s, y + 18*s, 180, 180)
            # Ayaklar
            c.setFillColor(HexColor("#fb923c"))
            c.circle(x - 8*s, y + 2*s, 3*s, fill=1, stroke=0)
            c.circle(x + 8*s, y + 2*s, 3*s, fill=1, stroke=0)
        elif animal == "dog":
            # Gövde
            c.setFillColor(HexColor("#a16207"))
            c.ellipse(x - 12*s, y, x + 12*s, y + 20*s, fill=1, stroke=0)
            # Kafa
            c.circle(x, y + 26*s, 10*s, fill=1, stroke=0)
            # Kulaklar (sarkık)
            c.setFillColor(HexColor("#78350f"))
            c.ellipse(x - 14*s, y + 20*s, x - 6*s, y + 34*s, fill=1, stroke=0)
            c.ellipse(x + 6*s, y + 20*s, x + 14*s, y + 34*s, fill=1, stroke=0)
            # Gözler
            c.setFillColor(white)
            c.circle(x - 4*s, y + 28*s, 3.2*s, fill=1, stroke=0)
            c.circle(x + 4*s, y + 28*s, 3.2*s, fill=1, stroke=0)
            c.setFillColor(_DARK)
            c.circle(x - 4*s, y + 28*s, 2*s, fill=1, stroke=0)
            c.circle(x + 4*s, y + 28*s, 2*s, fill=1, stroke=0)
            c.setFillColor(white)
            c.circle(x - 3*s, y + 29*s, 0.7*s, fill=1, stroke=0)
            c.circle(x + 5*s, y + 29*s, 0.7*s, fill=1, stroke=0)
            # Burun
            c.setFillColor(_DARK)
            c.circle(x, y + 23*s, 2.5*s, fill=1, stroke=0)
            # Dil
            c.setFillColor(HexColor("#f472b6"))
            c.ellipse(x - 2*s, y + 17*s, x + 2*s, y + 22*s, fill=1, stroke=0)
            # Kuyruk
            c.setStrokeColor(HexColor("#a16207"))
            c.setLineWidth(3)
            c.arc(x + 10*s, y + 8*s, x + 22*s, y + 24*s, 0, 180)
            # Ayaklar
            c.setFillColor(HexColor("#a16207"))
            c.ellipse(x - 10*s, y - 4*s, x - 4*s, y + 4*s, fill=1, stroke=0)
            c.ellipse(x + 4*s, y - 4*s, x + 10*s, y + 4*s, fill=1, stroke=0)
        elif animal == "bird":
            # Gövde
            c.setFillColor(HexColor("#3b82f6"))
            c.ellipse(x - 8*s, y, x + 8*s, y + 14*s, fill=1, stroke=0)
            # Kafa
            c.setFillColor(HexColor("#60a5fa"))
            c.circle(x, y + 18*s, 7*s, fill=1, stroke=0)
            # Gaga
            c.setFillColor(HexColor("#f59e0b"))
            p = c.beginPath()
            p.moveTo(x + 6*s, y + 17*s)
            p.lineTo(x + 14*s, y + 16*s)
            p.lineTo(x + 6*s, y + 14*s)
            p.close()
            c.drawPath(p, fill=1, stroke=0)
            # Gözler
            c.setFillColor(white)
            c.circle(x + 2*s, y + 20*s, 2.5*s, fill=1, stroke=0)
            c.setFillColor(_DARK)
            c.circle(x + 2*s, y + 20*s, 1.3*s, fill=1, stroke=0)
            c.setFillColor(white)
            c.circle(x + 2.6*s, y + 20.6*s, 0.5*s, fill=1, stroke=0)
            # Kanat
            c.setFillColor(HexColor("#2563eb"))
            c.ellipse(x - 12*s, y + 4*s, x - 2*s, y + 14*s, fill=1, stroke=0)
            # Ayaklar
            c.setStrokeColor(HexColor("#f59e0b"))
            c.setLineWidth(1.2)
            c.line(x - 2*s, y, x - 3*s, y - 5*s)
            c.line(x + 2*s, y, x + 3*s, y - 5*s)
            c.line(x - 5*s, y - 5*s, x - 1*s, y - 5*s)
            c.line(x + 1*s, y - 5*s, x + 5*s, y - 5*s)
        elif animal == "rabbit":
            # Gövde
            c.setFillColor(white)
            c.setStrokeColor(HexColor("#d1d5db"))
            c.setLineWidth(0.8)
            c.circle(x, y + 10*s, 10*s, fill=1, stroke=1)
            # Kafa
            c.circle(x, y + 24*s, 8*s, fill=1, stroke=1)
            # Kulaklar (uzun)
            c.setFillColor(white)
            c.ellipse(x - 6*s, y + 28*s, x - 1*s, y + 46*s, fill=1, stroke=1)
            c.ellipse(x + 1*s, y + 28*s, x + 6*s, y + 46*s, fill=1, stroke=1)
            c.setFillColor(HexColor("#fda4af"))
            c.ellipse(x - 5*s, y + 30*s, x - 2*s, y + 43*s, fill=1, stroke=0)
            c.ellipse(x + 2*s, y + 30*s, x + 5*s, y + 43*s, fill=1, stroke=0)
            # Gözler
            c.setFillColor(HexColor("#be185d"))
            c.circle(x - 3*s, y + 26*s, 1.8*s, fill=1, stroke=0)
            c.circle(x + 3*s, y + 26*s, 1.8*s, fill=1, stroke=0)
            c.setFillColor(white)
            c.circle(x - 2.5*s, y + 26.8*s, 0.6*s, fill=1, stroke=0)
            c.circle(x + 3.5*s, y + 26.8*s, 0.6*s, fill=1, stroke=0)
            # Burun
            c.setFillColor(HexColor("#f472b6"))
            c.circle(x, y + 22*s, 1.5*s, fill=1, stroke=0)
            # Bıyıklar
            c.setStrokeColor(HexColor("#9ca3af"))
            c.setLineWidth(0.5)
            c.line(x - 8*s, y + 22*s, x - 2*s, y + 21.5*s)
            c.line(x + 2*s, y + 21.5*s, x + 8*s, y + 22*s)
            # Ayaklar
            c.setFillColor(white)
            c.setStrokeColor(HexColor("#d1d5db"))
            c.ellipse(x - 8*s, y - 2*s, x - 2*s, y + 4*s, fill=1, stroke=1)
            c.ellipse(x + 2*s, y - 2*s, x + 8*s, y + 4*s, fill=1, stroke=1)
        c.restoreState()

    def _draw_sun(x, y, size):
        """Güneş çizer (yüzlü)."""
        import math
        c.saveState()
        # Işınlar
        c.setStrokeColor(HexColor("#fbbf24"))
        c.setLineWidth(2)
        for i in range(12):
            angle = i * math.pi / 6
            x1 = x + size * 1.3 * math.cos(angle)
            y1 = y + size * 1.3 * math.sin(angle)
            x2 = x + size * 1.8 * math.cos(angle)
            y2 = y + size * 1.8 * math.sin(angle)
            c.line(x1, y1, x2, y2)
        # Ana daire
        c.setFillColor(HexColor("#fbbf24"))
        c.circle(x, y, size, fill=1, stroke=0)
        # Yüz
        c.setFillColor(_DARK)
        c.circle(x - size * 0.25, y + size * 0.15, size * 0.08, fill=1, stroke=0)
        c.circle(x + size * 0.25, y + size * 0.15, size * 0.08, fill=1, stroke=0)
        c.setStrokeColor(_DARK)
        c.setLineWidth(1)
        c.arc(x - size * 0.3, y - size * 0.4, x + size * 0.3, y, 200, 140)
        c.restoreState()

    def _draw_cloud(x, y, size):
        """Bulut çizer."""
        c.saveState()
        c.setFillColor(Color(1, 1, 1, 0.85))
        c.circle(x, y, size * 0.6, fill=1, stroke=0)
        c.circle(x - size * 0.5, y - size * 0.1, size * 0.45, fill=1, stroke=0)
        c.circle(x + size * 0.5, y - size * 0.05, size * 0.5, fill=1, stroke=0)
        c.circle(x + size * 0.9, y - size * 0.15, size * 0.35, fill=1, stroke=0)
        c.circle(x - size * 0.85, y - size * 0.2, size * 0.3, fill=1, stroke=0)
        c.restoreState()

    def _draw_flower(x, y, size, petal_color=None):
        """Çiçek çizer."""
        import math
        c.saveState()
        _pc = petal_color or HexColor("#f472b6")
        c.setFillColor(_pc)
        for i in range(6):
            angle = i * math.pi / 3
            px = x + size * 0.6 * math.cos(angle)
            py = y + size * 0.6 * math.sin(angle)
            c.circle(px, py, size * 0.4, fill=1, stroke=0)
        c.setFillColor(HexColor("#fbbf24"))
        c.circle(x, y, size * 0.35, fill=1, stroke=0)
        # Yaprak
        c.setFillColor(HexColor("#22c55e"))
        c.setStrokeColor(HexColor("#22c55e"))
        c.setLineWidth(1.5)
        c.line(x, y - size * 0.4, x, y - size * 1.8)
        c.ellipse(x - size * 0.3, y - size * 1.5, x + size * 0.15, y - size * 1.0, fill=1, stroke=0)
        c.restoreState()

    def _draw_tree(x, y, size):
        """Ağaç çizer."""
        c.saveState()
        # Gövde
        c.setFillColor(HexColor("#92400e"))
        c.rect(x - size * 0.15, y, size * 0.3, size * 0.8, fill=1, stroke=0)
        # Yaprak küre
        c.setFillColor(HexColor("#22c55e"))
        c.circle(x, y + size * 1.1, size * 0.55, fill=1, stroke=0)
        c.setFillColor(HexColor("#16a34a"))
        c.circle(x - size * 0.25, y + size * 0.9, size * 0.4, fill=1, stroke=0)
        c.circle(x + size * 0.25, y + size * 0.9, size * 0.4, fill=1, stroke=0)
        # Meyve/çiçek
        c.setFillColor(HexColor("#ef4444"))
        c.circle(x - size * 0.15, y + size * 1.2, size * 0.08, fill=1, stroke=0)
        c.circle(x + size * 0.2, y + size * 1.0, size * 0.08, fill=1, stroke=0)
        c.restoreState()

    def _draw_heart(x, y, size, color=None):
        """Kalp çizer."""
        c.saveState()
        c.setFillColor(color or HexColor("#ef4444"))
        c.circle(x - size * 0.3, y + size * 0.2, size * 0.35, fill=1, stroke=0)
        c.circle(x + size * 0.3, y + size * 0.2, size * 0.35, fill=1, stroke=0)
        p = c.beginPath()
        p.moveTo(x - size * 0.6, y + size * 0.1)
        p.lineTo(x, y - size * 0.6)
        p.lineTo(x + size * 0.6, y + size * 0.1)
        p.close()
        c.drawPath(p, fill=1, stroke=0)
        c.restoreState()

    def _draw_rainbow(x, y, rw, rh):
        """Gökkuşağı çizer."""
        c.saveState()
        colors = ["#ef4444", "#f97316", "#eab308", "#22c55e", "#3b82f6", "#8b5cf6"]
        for i, clr in enumerate(colors):
            c.setStrokeColor(HexColor(clr))
            c.setLineWidth(3)
            c.arc(x, y, x + rw, y + rh - i * 4, 0, 180)
        c.restoreState()

    def _draw_pencil(x, y, size):
        """Kalem çizer."""
        c.saveState()
        s = size
        # Gövde
        c.setFillColor(HexColor("#fbbf24"))
        c.rect(x - 2*s, y, 4*s, 18*s, fill=1, stroke=0)
        # Şerit
        c.setFillColor(HexColor("#22c55e"))
        c.rect(x - 2*s, y + 14*s, 4*s, 4*s, fill=1, stroke=0)
        # Uç
        c.setFillColor(HexColor("#fde68a"))
        p = c.beginPath()
        p.moveTo(x - 2*s, y)
        p.lineTo(x, y - 4*s)
        p.lineTo(x + 2*s, y)
        p.close()
        c.drawPath(p, fill=1, stroke=0)
        # Uç siyah
        c.setFillColor(HexColor("#94A3B8"))
        p2 = c.beginPath()
        p2.moveTo(x - 0.8*s, y)
        p2.lineTo(x, y - 2*s)
        p2.lineTo(x + 0.8*s, y)
        p2.close()
        c.drawPath(p2, fill=1, stroke=0)
        # Silgi
        c.setFillColor(HexColor("#f472b6"))
        c.roundRect(x - 2*s, y + 18*s, 4*s, 3*s, 1*s, fill=1, stroke=0)
        c.restoreState()

    def _draw_book_icon(x, y, size, color=None):
        """Kitap ikonu çizer."""
        c.saveState()
        s = size
        _bc = color or HexColor("#3b82f6")
        # Arka kapak
        c.setFillColor(_bc)
        c.rect(x - 6*s, y, 12*s, 16*s, fill=1, stroke=0)
        # Ön kapak
        c.setFillColor(HexColor("#dbeafe"))
        c.rect(x - 5*s, y + 1*s, 10*s, 14*s, fill=1, stroke=0)
        # Sırt
        c.setFillColor(_bc)
        c.rect(x - 6*s, y, 2*s, 16*s, fill=1, stroke=0)
        # Satırlar
        c.setStrokeColor(HexColor("#93c5fd"))
        c.setLineWidth(0.5)
        for li in range(4):
            ly = y + 4*s + li * 2.5*s
            c.line(x - 3*s, ly, x + 4*s, ly)
        c.restoreState()

    def _draw_decorative_border(margin=1.2*cm, color=None, style="dots"):
        """Dekoratif sayfa kenarlığı çizer."""
        import math
        c.saveState()
        _bc = color or HexColor("#e2e8f0")
        if style == "dots":
            c.setFillColor(_bc)
            spacing = 12
            # Üst ve alt
            for ix in range(int((w - 2 * margin) / spacing)):
                c.circle(margin + ix * spacing, h - margin, 2, fill=1, stroke=0)
                c.circle(margin + ix * spacing, margin, 2, fill=1, stroke=0)
            # Sol ve sağ
            for iy in range(int((h - 2 * margin) / spacing)):
                c.circle(margin, margin + iy * spacing, 2, fill=1, stroke=0)
                c.circle(w - margin, margin + iy * spacing, 2, fill=1, stroke=0)
        elif style == "stars":
            spacing = 25
            for ix in range(int((w - 2 * margin) / spacing)):
                _draw_star(margin + ix * spacing, h - margin + 3, 4, _bc)
                _draw_star(margin + ix * spacing, margin - 3, 4, _bc)
        c.restoreState()

    def _draw_star(x, y, size, color):
        """Yıldız çizer."""
        import math
        c.saveState()
        c.setFillColor(color)
        p = c.beginPath()
        for i in range(10):
            angle = math.pi / 2 + i * math.pi / 5
            r = size if i % 2 == 0 else size * 0.4
            px = x + r * math.cos(angle)
            py = y + r * math.sin(angle)
            if i == 0:
                p.moveTo(px, py)
            else:
                p.lineTo(px, py)
        p.close()
        c.drawPath(p, fill=1, stroke=0)
        c.restoreState()

    def _new_page():
        c.showPage()

    page_num = [0]

    def _page_header(title, subtitle="", color=_PRIMARY):
        page_num[0] += 1
        # Üst banner
        _draw_rounded_rect(1.5 * cm, h - 2.5 * cm, w - 3 * cm, 1.8 * cm, 10, fill=color)
        c.setFont("Helvetica-Bold", 16)
        c.setFillColor(white)
        c.drawString(2.2 * cm, h - 1.6 * cm, title)
        if subtitle:
            c.setFont("Helvetica", 9)
            c.drawString(2.2 * cm, h - 2.1 * cm, subtitle)
        # Sayfa numarası
        c.setFont("Helvetica", 8)
        c.setFillColor(_GRAY)
        c.drawRightString(w - 1.5 * cm, 1 * cm, f"Sayfa {page_num[0]}")
        # Alt çizgi
        c.setStrokeColor(color)
        c.setLineWidth(0.5)
        c.line(1.5 * cm, 1.5 * cm, w - 1.5 * cm, 1.5 * cm)

    def _section_title(y, text, icon="", color=_PRIMARY):
        _draw_rounded_rect(1.5 * cm, y - 5, w - 3 * cm, 22, 6, fill=color)
        c.setFont("Helvetica-Bold", 11)
        c.setFillColor(white)
        c.drawString(2 * cm, y, f"{icon} {text}")
        return y - 32

    import random as _rnd
    _rnd.seed(grade * 1000 + unit_num * 10)

    # Seviye bilgileri
    _is_ortaokul = grade >= 5 and grade <= 8
    _is_lise = grade >= 9
    _cefr_map = {1:"A1",2:"A1",3:"A1",4:"A1",5:"A2",6:"A2",7:"A2",8:"A2",
                 9:"B1",10:"B1+",11:"B2",12:"B2+"}
    _cefr = _cefr_map.get(grade, "A1")
    _grade_label = f"{grade}. Sinif"

    # ═══════════════════════════════════════════════════════════════
    # SAYFA 1: KAPAK
    # ═══════════════════════════════════════════════════════════════
    for i in range(30):
        frac = i / 30
        r = 0.118 + frac * 0.15
        g = 0.251 + frac * 0.25
        b = 0.686 + frac * 0.1
        c.setFillColor(Color(min(r, 1), min(g, 1), min(b, 1)))
        c.rect(0, h - (i + 1) * (h / 30), w, h / 30 + 1, fill=1, stroke=0)
    _draw_decorative_border(1 * cm, HexColor("#fbbf24"), "stars")
    _draw_sun(w - 3 * cm, h - 3 * cm, 18)
    _draw_cloud(3 * cm, h - 2.5 * cm, 20)
    _draw_cloud(w / 2 + 2 * cm, h - 1.8 * cm, 15)
    _draw_rainbow(w / 2 - 4 * cm, h - 4 * cm, 8 * cm, 3 * cm)
    _draw_rounded_rect(2 * cm, h - 8 * cm, w - 4 * cm, 5.5 * cm, 15,
                       fill=Color(1, 1, 1, 0.95), stroke=HexColor("#fbbf24"), sw=3)
    c.setFont("Helvetica-Bold", 28)
    c.setFillColor(_PRIMARY)
    c.drawCentredString(w / 2, h - 4 * cm, "ENGLISH WORKBOOK")
    c.setFont("Helvetica-Bold", 18)
    c.setFillColor(_SECONDARY)
    c.drawCentredString(w / 2, h - 5.2 * cm, f"Unit {unit_num}: {_theme}")
    c.setFont("Helvetica", 12)
    c.setFillColor(_GRAY)
    c.drawCentredString(w / 2, h - 6.2 * cm, f"{_theme_tr}")
    c.setFont("Helvetica-Bold", 14)
    c.setFillColor(_WARM)
    c.drawCentredString(w / 2, h - 7.2 * cm,
                       f"{_grade_label}  |  CEFR {_cefr}  |  {len(_unit_weeks)} Hafta  |  {len(_all_vocab)} Kelime")
    if _is_lise:
        _cover_sp1 = f"Let's explore\n{_theme}!"
        _cover_sp2 = f"Unit {unit_num}:\nCritical thinking\nawaits!"
        _cover_sp3 = "Ready for\nacademic English?"
    elif _is_ortaokul:
        _cover_sp1 = f"Let's discover\n{_theme}!"
        _cover_sp2 = f"Unit {unit_num} is\nexciting!"
        _cover_sp3 = "Are you ready?\nLet's go!"
    else:
        _cover_sp1 = f"Let's learn\n{_theme}!"
        _cover_sp2 = f"Unit {unit_num} is\nso much fun!"
        _cover_sp3 = "Are you ready?\nLet's go!"
    _draw_full_character(3 * cm, h - 14 * cm, 1.2, gender="boy",
                        shirt_color=HexColor("#3b82f6"), expression="happy", accessory="wave")
    _draw_speech_bubble(1 * cm, h - 9.5 * cm, 4.5 * cm, 1.8 * cm, _cover_sp1, 10)
    _draw_full_character(w / 2, h - 14.5 * cm, 1.3, gender="girl",
                        shirt_color=HexColor("#ec4899"), hair_color=HexColor("#92400e"),
                        expression="happy", accessory="balloon")
    _draw_speech_bubble(w / 2 - 2.5 * cm, h - 10 * cm, 5 * cm, 1.5 * cm, _cover_sp2, 10)
    _draw_full_character(w - 3 * cm, h - 14 * cm, 1.2, gender="teacher",
                        shirt_color=HexColor("#059669"), expression="talking", accessory="book")
    _draw_speech_bubble(w - 6 * cm, h - 9.5 * cm, 5 * cm, 1.8 * cm, _cover_sp3, 10)
    _draw_animal(2 * cm, h - 18 * cm, 0.8, "cat")
    _draw_animal(w - 2.5 * cm, h - 18.5 * cm, 0.7, "bird")
    _draw_flower(5 * cm, h - 17.5 * cm, 6, HexColor("#f472b6"))
    _draw_flower(w - 5 * cm, h - 17 * cm, 5, HexColor("#a78bfa"))
    _draw_tree(7 * cm, h - 19 * cm, 18)
    _draw_tree(w - 7 * cm, h - 19.5 * cm, 15)
    for sx, sy in [(2 * cm, h - 15.5 * cm), (w - 2 * cm, h - 15 * cm),
                   (4 * cm, h - 16 * cm), (w - 4 * cm, h - 14.5 * cm)]:
        _draw_star(sx, sy, 8, HexColor("#fbbf24"))
    _draw_heart(w / 2 + 6 * cm, h - 12 * cm, 8, HexColor("#ef4444"))
    _draw_pencil(1.5 * cm, h - 22 * cm, 1.5)
    _draw_pencil(w - 1.5 * cm, h - 21 * cm, 1.3)
    _draw_rounded_rect(2 * cm, 2 * cm, w - 4 * cm, 3.5 * cm, 10,
                       fill=_BG_CREAM, stroke=HexColor("#fbbf24"), sw=1.5)
    _draw_book_icon(3 * cm, 2.5 * cm, 1.2, _PRIMARY)
    c.setFont("Helvetica-Bold", 10)
    c.setFillColor(_PRIMARY)
    c.drawCentredString(w / 2, 4.2 * cm, "SmartCampus AI  -  Yardimci Calisma Kitabi")
    c.setFont("Helvetica", 8)
    c.setFillColor(_GRAY)
    c.drawCentredString(w / 2, 3.4 * cm, f"Kazanimlar: {', '.join(_all_outcomes[:6])}")
    if _grammar:
        c.drawCentredString(w / 2, 2.6 * cm, f"Dilbilgisi: {_grammar}")

    # ═══════════════════════════════════════════════════════════════
    # SAYFA 2: VOCABULARY A — Kelime Kartlari
    # ═══════════════════════════════════════════════════════════════
    _new_page()
    _draw_decorative_border(1 * cm, HexColor("#93c5fd"), "dots")
    _page_header(f"VOCABULARY A  -  {_theme}", f"Kelime Bankasi  |  {len(_all_vocab)} kelime", _PRIMARY)
    _draw_full_character(w - 2.5 * cm, h - 7 * cm, 0.7, gender="girl",
                        shirt_color=HexColor("#ec4899"), expression="happy", accessory="book")
    _draw_speech_bubble(w - 5 * cm, h - 4 * cm, 3 * cm, 1.2 * cm, "New words!\nLet's learn!", 8)
    y = h - 3.5 * cm
    y = _section_title(y, "A) Kelimeleri Oku ve Tekrar Et", "1", _PRIMARY)
    col_w_px = (w - 4 * cm) / 2
    _card_colors = [_BG_LIGHT, _BG_CREAM, _BG_GREEN, _BG_PURPLE]
    _card_strokes = [_PRIMARY, HexColor("#f59e0b"), _ACCENT, _SECONDARY]
    for vi, vocab_word in enumerate(_all_vocab[:16]):
        col = vi % 2
        row = vi // 2
        bx = 1.8 * cm + col * col_w_px
        by = y - row * 1.4 * cm
        if by < 3 * cm:
            break
        _draw_rounded_rect(bx, by, col_w_px - 0.5 * cm, 1.1 * cm, 6,
                          fill=_card_colors[vi % 4], stroke=_card_strokes[vi % 4], sw=0.8)
        _draw_star(bx + 0.2 * cm, by + 0.85 * cm, 4, HexColor("#fbbf24"))
        c.setFont("Helvetica-Bold", 11)
        c.setFillColor(_card_strokes[vi % 4])
        c.drawString(bx + 0.6 * cm, by + 0.6 * cm, f"{vi + 1}. {vocab_word}")
        c.setStrokeColor(HexColor("#cbd5e1"))
        c.setLineWidth(0.5)
        c.setDash(3, 3)
        c.line(bx + 0.6 * cm, by + 0.2 * cm, bx + col_w_px - 0.9 * cm, by + 0.2 * cm)
        c.setDash()
    # Alt bilgi
    _draw_animal(w - 2.5 * cm, 2 * cm, 0.5, "rabbit")

    # ═══════════════════════════════════════════════════════════════
    # SAYFA 3: VOCABULARY B — Kelime Alistirma
    # ═══════════════════════════════════════════════════════════════
    _new_page()
    _draw_decorative_border(1 * cm, HexColor("#93c5fd"), "dots")
    _page_header(f"VOCABULARY B  -  {_theme}", "Kelime Alistirmalari", _PRIMARY)
    _draw_full_character(w - 2.5 * cm, h - 7 * cm, 0.6, gender="boy",
                        shirt_color=_PRIMARY, expression="thinking")
    y = h - 3.5 * cm
    # B1: Eşleştirme
    y = _section_title(y, "A) Eslestir: Kelimeyi Anlamiyla Esle", "1", _PRIMARY)
    _draw_rounded_rect(1.8 * cm, y - 4.5 * cm, w - 3.6 * cm, 5 * cm, 8,
                      fill=_BG_LIGHT, stroke=_PRIMARY, sw=0.8)
    _half = min(len(_all_vocab), 8)
    _left_words = _all_vocab[:_half]
    _right_words = list(_left_words)
    _rnd.shuffle(_right_words)
    c.setFont("Helvetica-Bold", 10)
    _my = y - 0.4 * cm
    for mi in range(_half):
        c.setFillColor(_PRIMARY)
        c.drawString(2.3 * cm, _my, f"{mi + 1}) {_left_words[mi]}")
        c.setFillColor(_GRAY)
        c.drawString(w / 2 + 1 * cm, _my, f"{'ABCDEFGH'[mi]}) ____________")
        c.setStrokeColor(HexColor("#cbd5e1"))
        c.setLineWidth(0.3)
        c.line(2.3 * cm, _my - 0.15 * cm, w - 2 * cm, _my - 0.15 * cm)
        _my -= 0.55 * cm
    y = y - 5.5 * cm

    # B2: Kategorize et
    y = _section_title(y, "B) Kategorize Et (Group the Words)", "2", _ACCENT)
    _draw_rounded_rect(1.8 * cm, y - 4 * cm, w - 3.6 * cm, 4.5 * cm, 8,
                      fill=_BG_GREEN, stroke=_ACCENT, sw=0.8)
    c.setFont("Helvetica-Bold", 10)
    c.setFillColor(_ACCENT)
    c.drawString(2.5 * cm, y - 0.3 * cm, f"Kelimeleri uygun kategoriye yaz:")
    # Kelime havuzu
    c.setFont("Helvetica", 9)
    c.setFillColor(_DARK)
    _pool = "  |  ".join(_all_vocab[:10])
    c.drawString(2.5 * cm, y - 0.9 * cm, _pool[:80])
    if len(_pool) > 80:
        c.drawString(2.5 * cm, y - 1.4 * cm, _pool[80:160])
    # 3 kategori kutusu
    _cat_w = (w - 4.5 * cm) / 3
    _cat_labels = ["Things", "Actions", "Feelings"]
    for ci in range(3):
        cx = 2 * cm + ci * (_cat_w + 0.3 * cm)
        c.setStrokeColor(_ACCENT)
        c.setLineWidth(0.8)
        c.rect(cx, y - 3.8 * cm, _cat_w, 2 * cm, fill=0, stroke=1)
        c.setFont("Helvetica-Bold", 9)
        c.setFillColor(_ACCENT)
        c.drawCentredString(cx + _cat_w / 2, y - 1.9 * cm, _cat_labels[ci])
    y = y - 5 * cm

    # B3: Bos birak / Harf tamamla
    if y > 5 * cm:
        y = _section_title(y, "C) Harfleri Tamamla (Complete the Letters)", "3", _WARM)
        _draw_rounded_rect(1.8 * cm, y - 4 * cm, w - 3.6 * cm, 4.5 * cm, 8,
                          fill=_BG_CREAM, stroke=_WARM, sw=0.8)
        c.setFont("Helvetica", 10)
        c.setFillColor(_DARK)
        _cy = y - 0.5 * cm
        for fi, vw in enumerate(_all_vocab[:8]):
            if len(vw) > 2:
                idx = _rnd.randint(1, len(vw) - 1)
                blanked = vw[:idx] + " _ " + vw[idx + 1:]
            else:
                blanked = "_ " + vw[1:] if len(vw) > 1 else vw
            c.drawString(2.5 * cm, _cy, f"{fi + 1}) {blanked}")
            _cy -= 0.5 * cm
            if _cy < y - 3.8 * cm:
                break
    _draw_animal(2 * cm, 2 * cm, 0.5, "cat")

    # ═══════════════════════════════════════════════════════════════
    # SAYFA 4: GRAMMAR A — Kurallar
    # ═══════════════════════════════════════════════════════════════
    _new_page()
